      SUBROUTINE INITHK(IBUGIN)
!
!     PURPOSE--THIS IS SUBROUTING INITHK.
!              (THE   HK    AT THE END OF    INITHK   STANDS FOR   HOUSEKE
!              THIS SUBROUTINE INITIALIZES HOUSEKEEPING VARIABLES AND PARAMETERS
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--82/7
!     ORIGINAL VERSION--NOVEMBER  1980.
!     UPDATED         --JUNE      1981.
!     UPDATED         --AUGUST    1981.
!     UPDATED         --NOVEMBER  1981.
!     UPDATED         --MARCH     1982.
!     UPDATED         --MAY       1982.
!     UPDATED         --FEBRUARY  1989.  SOFT-CODE SETTINGS (ALAN)
!     UPDATED         --NOVEMBER  1999.  VARIABLE AND ROW LABELS
!     UPDATED         --JANUARY   2004.  INITIALIZE GROUP LABELS
!     UPDATED         --APRIL     2009.  VALUE OF MAXWID
!     UPDATED         --AUGUST    2015.  FUNCTION BLOCK SWITCHES
!     UPDATED         --AUGUST    2016.  STATISTIC BLOCK SWITCHES
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IBUGIN
!
      CHARACTER*4 IBLANK
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOPA.INC'
      INCLUDE 'DPCOMC.INC'
      INCLUDE 'DPCOHK.INC'
      INCLUDE 'DPCOHO.INC'
      INCLUDE 'DPCOCO.INC'
      INCLUDE 'DPCOFB.INC'
      INCLUDE 'DPCOSB.INC'
!
!-----COMMON VARIABLES (GENERAL)--------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IBLANK=' '
      IZERO=0
      ZERO=0.0
!
      IF(IBUGIN.EQ.'ON')THEN
        WRITE(ICOUT,90)
   90   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,95)
   95   FORMAT('***** AT THE BEGINNING OF INITHK--')
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               ***********************************************
!               **  INITIALIZE THE ANSWER VECTOR             **
!               **  (THE VECTOR WHERE THE ANALYST'S ENTERED  **
!               **  COMMAND LINE IS PLACED)                  **
!               ***********************************************
!
!CCCC CAUTION--DATAPLOT COMMAND LINES ARE LIMITED TO 80 CHARACTERS
!CCCC          EVEN WHEN READING FROM A FILE.
!CCCC          SETTING MAXWID GREATER THAN 80
!CCCC          CAN CAUSE STRING OVERWRITES (IN DPRELI, DPFILE, DPTYPE).
!CCCC
!CCCC          4/2009: THE ABOVE ROUTINES HAVE BEEN ADJUSTED, SO
!CCCC                  SET MAXWID BACK TO MIN(255,MAXSTR).
!
!CCCC MAXWID=200
      MAXWID=MAXSTR
!CCCC MAXWID=80
!CCCC MAXWID=MIN(MAXSTR,255)
!
      IWIDTH=0
!
      DO 100 I=1,MAXWID
        IANS(I)=IBLANK
        IANSLC(I)=IBLANK
  100 CONTINUE
!
!               ***********************************************
!               **  INITIALIZE THE SAVED ANSWER VECTOR       **
!               **  (THE VECTOR WHERE THE ANALYST'S          **
!               **  BUFFERED REMAINING ANSWERS ARE PLACED    **
!               **  WHEN MULTIPLE COMMANDS PER LINE ARE      **
!               **  GIVEN.  THIS MAKES USE OF THE            **
!               **  SEPARATOR CHARACTOR FEATURE.             **
!               ***********************************************
!
      MAXWSV=MAXWID
      IWIDSV=IWIDTH
!
      DO 200 I=1,MAXWID
        IANSV(I)=IBLANK
  200 CONTINUE
!
!               **********************************************************
!               **  INITIALIZE THE ARGUMENT VECTORS                     **
!               **  (THE VECTORS WHERE THE ARGUMENTS OF THE DECOMPOSED  **
!               **  COMMAND LINE ARE PLACED)                            **
!               **********************************************************
!
      ICOM=IBLANK
      ICOM2=IBLANK
      ICOMLC=IBLANK
      ICOML2=IBLANK
!
!CCCC MAXARG DEFINED IN DPCOPA.INC
!CCCC MAXARG=200
      NUMARG=0
!
      DO 300 I=1,MAXARG
        IHARG(I)=IBLANK
        IHARG2(I)=IBLANK
        IARGT(I)=IBLANK
        IARG(I)=IZERO
        ARG(I)=ZERO
        IHARLC(I)=IBLANK
        IHARL2(I)=IBLANK
  300 CONTINUE
!
!               ***********************************************
!               **  INITIALIZE THE NAME VECTORS              **
!               **  (THE VECTORS WHERE THE ANALYST'S         **
!               **  PARAMETER, VARIABLE, AND FUNCTION NAMES  **
!               **  ARE PLACED).                             **
!               ***********************************************
!
!CCCC OCTOBER 1993.  DEFINE MAXNAM AS A PARAMETER FROM DPCOPA.INC
!CCCC MAXNAM=200
      MAXNAM=MAXNME
      NUMNAM=0
!
      DO 400 I=1,MAXNAM
        IHNAME(I)=IBLANK
        IHNAM2(I)=IBLANK
        IUSE(I)=IBLANK
        IVSTAR(I)=IZERO
        IVSTOP(I)=IZERO
        IN(I)=IZERO
        IVALUE(I)=IZERO
        IVALU2(I)=IZERO
        VALUE(I)=ZERO
!CCCC   ADD FOLLOWING LINE.   NOVEMBER 1999
        IVARLB(I)=' '
  400 CONTINUE
!
!CCCC ADD FOLLOWING SECTION.   NOVEMBER 1999.
      DO 410 I=1,MAXOBV
        IROWLB(I)=' '
  410 CONTINUE
!
!CCCC ADD FOLLOWING SECTION.   JANUARY 2004.
      DO 420 J=1,MAXGRP
        IGRPVN(J)='        '
        DO 425 I=1,MAXGLA
          IGRPLA(I,J)=' '
  425   CONTINUE
  420 CONTINUE
!
!               *******************************************************
!               **  DEFINE THE MACRO SWITCH                          **
!               **  (WHICH WILL BE ON WHEN A MACRO IS BEING FORMED,  **
!               **  AND OFF OTHERWISE).                              **
!               *******************************************************
!
!     THIS INITIALIZATION IS NOW DONE IN MAIN.
!CCCC IMACRO='OFF'
!
!               ********************************************
!               **  TREAT THE ALTERNATE PLOT FILE STATUS  **
!               **  (FOR CALCOMP, VERSATEC, ZETA, ETC.)   **
!               ********************************************
!
      IPLOTF='-999'
!CCCC IF(IPL1ST.EQ.'OPFI')IPLOTF='ON'
!CCCC IF(IPL1ST.EQ.'OPSF')IPLOTF='ON'
!
!
!               **************************************
!               **  TREAT THE DEFAULT COMMAND CASE  **
!               **************************************
!
      IDEFCM='NO'
      IWIDDC=0
!
!
!               **************************************
!               **  TREAT THE FUNCTION BLOCK CASE   **
!               **************************************
!
      IFBLSW='OFF'
      IFBNA1=' '
      IFBNA2=' '
      IFBNA3=' '
      IFBAN1=' '
      IFBAN2=' '
      IFBAN3=' '
      DO 510 I=1,MAXFBP
        IFBPL1(I)=' '
        IFBPL2(I)=' '
        IFBPL3(I)=' '
  510 CONTINUE
      DO 520 I=1,MAXFBL
        IFBLI1(I)=' '
        IFBLI2(I)=' '
        IFBLI3(I)=' '
  520 CONTINUE
      IFBCN1=0
      IFBCN2=0
      IFBCN3=0
!
!               **************************************
!               **  TREAT THE STATISTIC BLOCK CASE  **
!               **************************************
!
      ISBLSW='OFF'
      ISBNA1=' '
      ISBNA2=' '
      ISBNA3=' '
      ISBAN1=' '
      ISBAN2=' '
      ISBAN3=' '
      DO 560 I=1,MAXSBP
        ISBPL1(I)=' '
        ISBPL2(I)=' '
        ISBPL3(I)=' '
  560 CONTINUE
      DO 570 I=1,MAXSBL
        ISBLI1(I)=' '
        ISBLI2(I)=' '
        ISBLI3(I)=' '
  570 CONTINUE
      ISBCN1=0
      ISBCN2=0
      ISBCN3=0
!
!               *******************************
!               **  EXIT AND RETURN TO MAIN  **
!               *******************************
!
      IF(IBUGIN.EQ.'ON')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF INITHK--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9041)MAXNAM,NUMNAM
 9041   FORMAT('MAXNAM,NUMNAM = ',2I8)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE INITHK
      SUBROUTINE DPINFI(IFILE,IEXIST,IOPEN,IACC,ISUBN0,IBUGS2,   &
                        ISUBRO,IERRFI)
!
!     PURPOSE--INQUIRE ABOUT THE EXISTENCE OF A FILE
!              (BUT THERE MAY BE SOME SMALL DIFFERENCES
!              IN HOW THAT IS DONE FOR DIFFERENT COMPUTERS).
!
!     WRITTEN BY--JAMES J. FILLIBEN
!     LANGUAGE--ANSI FORTRAN (1977)
!     ORIGINAL VERSION--NOVEMBER  1986.
!     UPDATED         --NOVEMBER  1987. (FORM LOWER AND UPPER CASE NAMES)
!     UPDATED         --FEBRUARY  1989. CYBER/CDC CASE (ALAN)
!     UPDATED         --NOVEMBER  1989. IERROR TO IERRFI (NELSON)
!     UPDATED         --APRIL     1997. DUMMY DIMENSION FOR IFILE
!     UPDATED         --AUGUST    2016. ADD "OPEN" AND "ACTION" CLAUSE
!
!------------------------------------------------------------------------------
!
!CCCC FIX FOLLOWING LINE  APRIL 1997
!
!CCCC CHARACTER*80 IFILE
      CHARACTER (LEN=*) :: IFILE
      CHARACTER*4 IEXIST
      CHARACTER*4 IOPEN
      CHARACTER*10 IACC2
      CHARACTER*8 IACC
      CHARACTER*4 ISUBN0
!
      CHARACTER*4 IBUGS2
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERRFI
!
      INCLUDE 'DPCOPA.INC'
!
!CCCC CHARACTER*80 IFILE2
      CHARACTER (LEN=MAXFNC) :: IFILE2
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
      LOGICAL LEXIST
      LOGICAL LOPEN
!
!-----COMMON------------------------------------------------
!
      INCLUDE 'DPCOHO.INC'
      INCLUDE 'DPCOF2.INC'
!
!-----COMMON VARIABLES (GENERAL)--------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPIN'
      ISUBN2='FI  '
      IERRFI='NO'
!
      IF(IBUGS2.EQ.'ON'.OR.ISUBRO.EQ.'INFI')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('*****AT THE BEGINNING OF DPINFI--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IFILE(1:255)
   52   FORMAT('IFILE(1:80) = ',A255)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,55)ISUBN0,IHOST1
   55   FORMAT('ISUBN0,IHOST1 = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               ********************************************************
!               **  STEP 1--                                          **
!               **  INQUIRE ABOUT THE EXISTENCE OF A FILE.            **
!               ********************************************************
!
      ISTEPN='1'
      IF(IBUGS2.EQ.'ON'.OR.ISUBRO.EQ.'INFI')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(IHOST1.EQ.'VAX')THEN
!
!               **********************************
!               **  STEP 11--                   **
!               **  TREAT THE VAX CASE          **
!               **********************************
!
        INQUIRE(FILE=IFILE,EXIST=LEXIST)
        IEXIST='NO'
        IF(LEXIST)IEXIST='YES'
      ELSEIF(IHOST1.EQ.'CDC' .OR. IHOST1.EQ.'CYBE' .OR.   &
             IHOST1.EQ.'205' .OR. IHOST1.EQ.'NVE')THEN
!
!               *************************************
!               **  STEP 21--                      **
!               **  TREAT THE CYBER/CDC CASE--     **
!               **  STRIP OFF THE TRAILING PERIOD  **
!               **  (ELSE THE INQUIRE WILL FAIL)   **
!               *************************************
!
        IFILE2=IFILE
        DO 2150 I=MAXFNC,1,-1
          IF(IFILE2(I:I).EQ.' ')GO TO  2150
          IF(IFILE2(I:I).EQ.IFCHAR) IFILE2(I:I)=' '
          GO TO  2160
 2150   CONTINUE
 2160   CONTINUE
        INQUIRE(FILE=IFILE2,EXIST=LEXIST)
        IEXIST='NO'
        IF(LEXIST)IEXIST='YES'
      ELSE
!
!               **********************************
!               **  STEP 12--                   **
!               **  TREAT THE GENERAL CASE      **
!               **  (MODIFY AS APPROPRIATE      **
!               **  FOR YOUR COMPUTER)          **
!               **********************************
!
        IEXIST='NO'
        IOPEN='NO'
        IACC='UNDEFINE'
!
!       1. INQUIRE WITH THE FILE NAME LITERALLY AS GIVEN
!
        INQUIRE(FILE=IFILE,EXIST=LEXIST,OPENED=LOPEN,ACTION=IACC2)
        IF(LEXIST)IEXIST='YES'
        IF(LOPEN)IOPEN='YES'
        IACC=IACC2(1:8)
        IF(IEXIST.EQ.'YES')GO TO 9000
!
!       2. IF NOT FOUND WITH THE FILE NAME LITERALLY AS GIVEN,
!          THEN CONVERT THE FILE NAME TO LOWER CASE (E.G., UNIX) AND INQUIRE
!
        IFILE2=IFILE
!CCCC   THE FOLLOWING LINE WAS CORRECTED NOVEMBER 1989
!CCCC   (BUG UNCOVERED BY NELSON HSU)
!CCCC   CALL DPLO80(IFILE2,IFILE2,IBUGS2,IERROR)
!CCCC   NMAX=80
        NMAX=MAXFNC
        CALL DPLO80(IFILE2,IFILE2,NMAX,IBUGS2,IERRFI)
        INQUIRE(FILE=IFILE2,EXIST=LEXIST,OPENED=LOPEN,ACTION=IACC2)
        IF(LEXIST)IEXIST='YES'
        IF(LOPEN)IOPEN='YES'
        IACC=IACC2(1:8)
        IF(IEXIST.EQ.'YES')GO TO 9000
!
!       3. IF NOT FOUND WITH THE FILE NAME LITERALLY AS GIVEN,
!          AND IF NOT FOUND WITH THE FILE NAME AS LOWER CASE,
!          THEN CONVERT THE FILE NAME TO UPPER CASE AND INQUIRE
!
        IFILE2=IFILE
!CCCC   THE FOLLOWING LINE WAS CORRECTED NOVEMBER 1989
!CCCC   (BUG UNCOVERED BY NELSON HSU)
!CCCC   CALL DPUP80(IFILE2,IFILE2,IBUGS2,IERROR)
!CCCC   NMAX=80
        NMAX=MAXFNC
        CALL DPUP80(IFILE2,IFILE2,NMAX,IBUGS2,IERRFI)
        INQUIRE(FILE=IFILE2,EXIST=LEXIST,OPENED=LOPEN,ACTION=IACC2)
        IF(LEXIST)IEXIST='YES'
        IF(LOPEN)IOPEN='YES'
        IACC=IACC2(1:8)
        IF(IEXIST.EQ.'YES')GO TO 9000
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGS2.EQ.'ON'.OR.ISUBRO.EQ.'INFI')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('*****AT THE END       OF DPINFI--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9014)IEXIST,IOPEN,IACC,IERRFI
 9014   FORMAT('IEXIST,IOPEN,IACC,IERRFI = ',2(A4,2X),A8,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9022)IFILE2(1:255)
 9022   FORMAT('IFILE2(1:80) = ',A255)
        CALL DPWRST('XXX','BUG ')
      ENDIF
      RETURN
      END SUBROUTINE DPINFI
      SUBROUTINE DPINF3(IFILE,FTEMP,IEXIST,   &
                        ISUBN0,IERRFI,IBUGS2,ISUBRO,IERROR)
!
!     PURPOSE--INQUIRE ABOUT THE EXISTENCE OF A FILE.  THIS
!              IS A VARIANT OF DPINFI.  THE DIFFERENCES ARE:
!
!                 1) IMAGE FILES ARE OPENED BY THE GD LIBRARY.
!                    INSTEAD OF DPOPFI.  HOWEVER,  WE WANT TO
!                    SEARCH THE FILE AS DPOPFI DOES (SPECIFICALLY,
!                    CHECK FOR ALL UPPER CASE, ALL LOWER CASE,
!                    AND SEARCH THE DATAPLOT DIRECTORIES).
!
!                 2) RETURN THE FILE THAT IS ACTUALLY FOUND
!                    (IN FTEMP).
!     WRITTEN BY--JAMES J. FILLIBEN
!     LANGUAGE--ANSI FORTRAN (1977)
!     UPDATED         --AUGUST    1996.  FIX TO SUB-DIRECTORIES
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOPA.INC'
!
!CCCC CHARACTER*80 IFILE
      CHARACTER (LEN=*) :: IFILE
      CHARACTER*4 IEXIST
      CHARACTER*4 ISUBN0
      CHARACTER*4 IERRFI
!
!CCCC CHARACTER*80 IFILEL
!CCCC CHARACTER*80 IFILEU
!CCCC CHARACTER*80 IFILE2
!CCCC CHARACTER*80 FTEMP
      CHARACTER (LEN=MAXFNC) :: IFILEL
      CHARACTER (LEN=MAXFNC) :: IFILEU
      CHARACTER (LEN=MAXFNC) :: IFILE2
      CHARACTER (LEN=MAXFNC) :: FTEMP
!
      CHARACTER*4 IBUGS2
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
      CHARACTER*4 IBSLC
!
      LOGICAL LEXIST
!
!CCCC PARAMETER (MAXLEN=80)
!
!-----COMMON------------------------------------------------
!
      INCLUDE 'DPCOHO.INC'
      INCLUDE 'DPCOF2.INC'
!
!-----COMMON VARIABLES (GENERAL)--------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPIN'
      ISUBN2='F3  '
!
      NC1=0
      NC2=0
      NC3=0
      NC4=0
      NMAX=MAXFNC
!
      IF(IBUGS2.EQ.'ON'.OR.ISUBRO.EQ.'INF3')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPINF3--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGS2,ISUBRO,ISUBN0,IERROR,IERRFI,IHOST1
   52   FORMAT('IBUGS2,ISUBRO,ISUBN0,IERROR,IERRFI,IHOST1 = ',   &
               5(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,62)IFILE(1:80)
   62   FORMAT('IFILE  = ',A80)
        CALL DPWRST('XXX','BUG ')
       ENDIF
!
      IF(IHOST1.EQ.'IBM-')THEN
        CALL DPCONA(92,IBSLC)
      ELSEIF(IOPSY1.EQ.'UNIX')THEN
        CALL DPCONA(47,IBSLC)
      ELSE
        IBSLC=' '
      ENDIF
!
!               *********************************************
!               **  STEP 1--                               **
!               **  INQUIRE ABOUT THE EXISTENCE OF A FILE  **
!               *********************************************
!
      ISTEPN='1'
      IF(IBUGS2.EQ.'ON'.OR.ISUBRO.EQ.'INF3')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!     NOTE: EVEN THOUGH UNIX IS CURRENTLY ONLY SUPPORTED OPERATING
!           SYSTEM THAT IS CASE SENSITIVE, GO THROUGH SAME PROGESSION
!           FOR ALL SYSTEMS (I.E., CHECK FOR FILE WITH CASE AS GIVEN,
!           THEN CHECK WHEN CONVERTED TO ALL LOWER CASE, AND FINALLY
!           CHECK WHEN CONVERTED TO ALL UPPER CASE).
!
!-----TREAT THE GENERAL CASE (E.G., UNIX)-------------------------------
!
!  IF FILE DOES NOT EXIST, STRIP OFF TRAILING PERIOD (IF FILE NAME ENDS
!  WITH PERIOD) AND TRY TO OPEN.
!
!     1. SEE IF FILE EXISTS WITH THE NAME LITERALLY AS GIVEN
!
      FTEMP=IFILE
!
      IF(IFILE(1:1).EQ.'"')THEN
        DO 1102 I=2,NMAX
          IF(IFILE(I:I).EQ.'"')THEN
            FTEMP=' '
            FTEMP(1:I-2)=IFILE(2:I-1)
            GO TO 1103
          ENDIF
 1102   CONTINUE
 1103   CONTINUE
      ENDIF
!
      IFLAG=0
 1110 CONTINUE
        IEXIST='NO'
        INQUIRE(FILE=FTEMP,EXIST=LEXIST)
        IF(LEXIST)IEXIST='YES'
        IF(IEXIST.EQ.'NO')GO TO 1120
        GO TO 1190
!
!     2. IF CANNOT OPEN THE FILE WITH NAME LITERALLY AS GIVEN,
!        THEN CONVERT THE FILE NAME TO LOWER CASE (E.G., UNIX)
!        AND SEE IF CAN OPEN THAT
!
 1120 CONTINUE
        IFILEL=FTEMP
        CALL DPLO80(IFILEL,IFILEL,NMAX,IBUGS2,IERROR)
        IEXIST='NO'
        INQUIRE(FILE=IFILEL,EXIST=LEXIST)
        IF(LEXIST)IEXIST='YES'
        IF(IEXIST.EQ.'NO')GO TO 1130
        FTEMP=IFILEL
        GO TO 1190
!
!     3. IF CANNOT OPEN THE FILE WITH NAME LITERALLY AS GIVEN, AND IF
!        CANNOT OPEN THE FILE WITH NAME CONVERTED TO LOWER CASE, THEN
!        CONVERT THE FILE NAME TO UPPER CASE AND SEE IF CAN OPEN THAT
!
 1130 CONTINUE
        IFILEU=FTEMP
        CALL DPUP80(IFILEU,IFILEU,NMAX,IBUGS2,IERROR)
        IEXIST='NO'
        INQUIRE(FILE=IFILEU,EXIST=LEXIST)
        IF(LEXIST)IEXIST='YES'
        IF(IEXIST.EQ.'NO')GO TO 1140
        FTEMP=IFILEU
        GO TO 1190
!
!     4. IF STILL CANNOT OPEN THE FILE, THEN PERHAPS THE ANALYST IS
!        TRYING TO OPEN A FILE NOT IN HIS OWN DIRECTORY, BUT A FILE
!        RESIDING IN DATAPLOT'S DIRECTORY (E.G., ONE OF DATAPLOT'S
!        REFRENCE, DATA, MAP, FRACTAL, MACRO, ETC. FILES).  TO CHECK
!        THIS CONTINGENCY, INSERT THE NAME OF DATAPLOT'S DIRECTORY IN
!        FRONT OF THE SPECIFIED FILE NAME, AND TRY TO OPEN THAT
!        BY REPEATING THE ABOVE 3 STEPS.
!
 1140 CONTINUE
!
!     4A. CHECK FOR FILE NAME AS IS
!
      IF(IOPSY1.EQ.'UNIX') THEN
        IFILE2(1:IUNXNC)=UNIXPN(1:IUNXNC)
        NC1=IUNXNC+1
        NC2=NMAX
        NC3=1
        NC4=NMAX-IUNXNC
        NCHECK=10
      ELSEIF(IHOST1.EQ.'VAX')THEN
        IFILE2(10:80)=IFILE(1:71)
        IFILE2(1:9)='DATAPLO$:'
        NCHECK=1
      ELSEIF(IHOST1.EQ.'IBM-')THEN
        NC1=NCPATH+1
        NC2=NMAX
        NC3=1
        NC4=NMAX-NCPATH
        IFILE2(1:NCPATH)=PATH(1:NCPATH)
        NCHECK=10
      ELSE
        NCHECK=0
      ENDIF
!
      IF(NCHECK.GT.0)THEN
        DO 1141 K=1,NCHECK
           IF(K.EQ.1)THEN
              IFILE2(NC1:NC2)=IFILE(1:NC4)
           ELSE IF(K.EQ.2)THEN
              NC5=NC1
              NC6=NC5+4
              IFILE2(NC5:NC6)='help '
              IFILE2(NC6:NC6)=IBSLC
              NC7=NC6+1
              NC8=80-NC6
              IFILE2(NC7:NC2)=IFILE(NC3:NC8)
           ELSE IF(K.EQ.3)THEN
              NC5=NC1
              NC6=NC5+4
              IFILE2(NC5:NC6)='data '
              IFILE2(NC6:NC6)=IBSLC
              NC7=NC6+1
              NC8=80-NC6
              IFILE2(NC7:NC2)=IFILE(NC3:NC8)
           ELSE IF(K.EQ.4)THEN
              NC5=NC1
              NC6=NC5+3
              IFILE2(NC5:NC6)='dex '
              IFILE2(NC6:NC6)=IBSLC
              NC7=NC6+1
              NC8=80-NC6
              IFILE2(NC7:NC2)=IFILE(NC3:NC8)
           ELSE IF(K.EQ.5)THEN
              NC5=NC1
              NC6=NC5+6
              IFILE2(NC5:NC6)='macros '
              IFILE2(NC6:NC6)=IBSLC
              NC7=NC6+1
              NC8=80-NC6
              IFILE2(NC7:NC2)=IFILE(NC3:NC8)
           ELSE IF(K.EQ.6)THEN
              NC5=NC1
              NC6=NC5+8
              IFILE2(NC5:NC6)='programs '
              IFILE2(NC6:NC6)=IBSLC
              NC7=NC6+1
              NC8=80-NC6
              IFILE2(NC7:NC2)=IFILE(NC3:NC8)
           ELSE IF(K.EQ.7)THEN
              NC5=NC1
              NC6=NC5+4
              IFILE2(NC5:NC6)='text '
              IFILE2(NC6:NC6)=IBSLC
              NC7=NC6+1
              NC8=80-NC6
              IFILE2(NC7:NC2)=IFILE(NC3:NC8)
           ELSE IF(K.EQ.8)THEN
              NC5=NC1
              NC6=NC5+4
              IFILE2(NC5:NC6)='menu '
              IFILE2(NC6:NC6)=IBSLC
              NC7=NC6+1
              NC8=80-NC6
              IFILE2(NC7:NC2)=IFILE(NC3:NC8)
           ELSE IF(K.EQ.9)THEN
              NC5=NC1
              NC6=NC5+2
              IFILE2(NC5:NC6)='ps '
              IFILE2(NC6:NC6)=IBSLC
              NC7=NC6+1
              NC8=80-NC6
              IFILE2(NC7:NC2)=IFILE(NC3:NC8)
           ELSE IF(K.EQ.10)THEN
              NC5=NC1
              NC6=NC5+3
              IFILE2(NC5:NC6)='tek '
              IFILE2(NC6:NC6)=IBSLC
              NC7=NC6+1
              NC8=80-NC6
              IFILE2(NC7:NC2)=IFILE(NC3:NC8)
           END IF
!
           IEXIST='NO'
           INQUIRE(FILE=IFILE2,EXIST=LEXIST)
           IF(LEXIST)IEXIST='YES'
           IF(IEXIST.EQ.'NO')GO TO 1141
           FTEMP=IFILE2
           GO TO 1190
!
 1141   CONTINUE
!
        DO 1151 K=1,NCHECK
           IF(K.EQ.1)THEN
              IFILE2(NC1:NC2)=IFILEU(1:NC4)
           ELSE IF(K.EQ.2)THEN
              NC5=NC1
              NC6=NC5+4
              IFILE2(NC5:NC6)='help '
              IFILE2(NC6:NC6)=IBSLC
              NC7=NC6+1
              NC8=80-NC6
              IFILE2(NC7:NC2)=IFILEU(NC3:NC8)
           ELSE IF(K.EQ.3)THEN
              NC5=NC1
              NC6=NC5+4
              IFILE2(NC5:NC6)='data '
              IFILE2(NC6:NC6)=IBSLC
              NC7=NC6+1
              NC8=80-NC6
              IFILE2(NC7:NC2)=IFILEU(NC3:NC8)
           ELSE IF(K.EQ.4)THEN
              NC5=NC1
              NC6=NC5+3
              IFILE2(NC5:NC6)='dex '
              IFILE2(NC6:NC6)=IBSLC
              NC7=NC6+1
              NC8=80-NC6
              IFILE2(NC7:NC2)=IFILEU(NC3:NC8)
           ELSE IF(K.EQ.5)THEN
              NC5=NC1
              NC6=NC5+6
              IFILE2(NC5:NC6)='macros '
              IFILE2(NC6:NC6)=IBSLC
              NC7=NC6+1
              NC8=80-NC6
              IFILE2(NC7:NC2)=IFILEU(NC3:NC8)
           ELSE IF(K.EQ.6)THEN
              NC5=NC1
              NC6=NC5+8
              IFILE2(NC5:NC6)='programs '
              IFILE2(NC6:NC6)=IBSLC
              NC7=NC6+1
              NC8=80-NC6
              IFILE2(NC7:NC2)=IFILEU(NC3:NC8)
           ELSE IF(K.EQ.7)THEN
              NC5=NC1
              NC6=NC5+4
              IFILE2(NC5:NC6)='text '
              IFILE2(NC6:NC6)=IBSLC
              NC7=NC6+1
              NC8=80-NC6
              IFILE2(NC7:NC2)=IFILEU(NC3:NC8)
           ELSE IF(K.EQ.8)THEN
              NC5=NC1
              NC6=NC5+4
              IFILE2(NC5:NC6)='menu '
              IFILE2(NC6:NC6)=IBSLC
              NC7=NC6+1
              NC8=80-NC6
              IFILE2(NC7:NC2)=IFILEU(NC3:NC8)
           ELSE IF(K.EQ.9)THEN
              NC5=NC1
              NC6=NC5+2
              IFILE2(NC5:NC6)='ps '
              IFILE2(NC6:NC6)=IBSLC
              NC7=NC6+1
              NC8=80-NC6
              IFILE2(NC7:NC2)=IFILEU(NC3:NC8)
           ELSE IF(K.EQ.10)THEN
              NC5=NC1
              NC6=NC5+3
              IFILE2(NC5:NC6)='tek '
              IFILE2(NC6:NC6)=IBSLC
              NC7=NC6+1
              NC8=80-NC6
              IFILE2(NC7:NC2)=IFILEU(NC3:NC8)
           END IF
!
           IEXIST='NO'
           INQUIRE(FILE=IFILE2,EXIST=LEXIST)
           IF(LEXIST)IEXIST='YES'
           IF(IEXIST.EQ.'NO')GO TO 1151
           FTEMP=IFILE2
           GO TO 1190
!
 1151   CONTINUE
!
        DO 1161 K=1,NCHECK
           IF(K.EQ.1)THEN
              IFILE2(NC1:NC2)=IFILEL(1:NC4)
           ELSE IF(K.EQ.2)THEN
              NC5=NC1
              NC6=NC5+4
              IFILE2(NC5:NC6)='help '
              IFILE2(NC6:NC6)=IBSLC
              NC7=NC6+1
              NC8=80-NC6
              IFILE2(NC7:NC2)=IFILEL(NC3:NC8)
           ELSE IF(K.EQ.3)THEN
              NC5=NC1
              NC6=NC5+4
              IFILE2(NC5:NC6)='data '
              IFILE2(NC6:NC6)=IBSLC
              NC7=NC6+1
              NC8=80-NC6
              IFILE2(NC7:NC2)=IFILEL(NC3:NC8)
           ELSE IF(K.EQ.4)THEN
              NC5=NC1
              NC6=NC5+3
              IFILE2(NC5:NC6)='dex '
              IFILE2(NC6:NC6)=IBSLC
              NC7=NC6+1
              NC8=80-NC6
              IFILE2(NC7:NC2)=IFILEL(NC3:NC8)
           ELSE IF(K.EQ.5)THEN
              NC5=NC1
              NC6=NC5+6
              IFILE2(NC5:NC6)='macros '
              IFILE2(NC6:NC6)=IBSLC
              NC7=NC6+1
              NC8=80-NC6
              IFILE2(NC7:NC2)=IFILEL(NC3:NC8)
           ELSE IF(K.EQ.6)THEN
              NC5=NC1
              NC6=NC5+8
              IFILE2(NC5:NC6)='programs '
              IFILE2(NC6:NC6)=IBSLC
              NC7=NC6+1
              NC8=80-NC6
              IFILE2(NC7:NC2)=IFILEL(NC3:NC8)
           ELSE IF(K.EQ.7)THEN
              NC5=NC1
              NC6=NC5+4
              IFILE2(NC5:NC6)='text '
              IFILE2(NC6:NC6)=IBSLC
              NC7=NC6+1
              NC8=80-NC6
              IFILE2(NC7:NC2)=IFILEL(NC3:NC8)
           ELSE IF(K.EQ.8)THEN
              NC5=NC1
              NC6=NC5+4
              IFILE2(NC5:NC6)='menu '
              IFILE2(NC6:NC6)=IBSLC
              NC7=NC6+1
              NC8=80-NC6
              IFILE2(NC7:NC2)=IFILEL(NC3:NC8)
           ELSE IF(K.EQ.9)THEN
              NC5=NC1
              NC6=NC5+2
              IFILE2(NC5:NC6)='ps '
              IFILE2(NC6:NC6)=IBSLC
              NC7=NC6+1
              NC8=80-NC6
              IFILE2(NC7:NC2)=IFILEL(NC3:NC8)
           ELSE IF(K.EQ.10)THEN
              NC5=NC1
              NC6=NC5+3
              IFILE2(NC5:NC6)='tek '
              IFILE2(NC6:NC6)=IBSLC
              NC7=NC6+1
              NC8=80-NC6
              IFILE2(NC7:NC2)=IFILEL(NC3:NC8)
           END IF
!
           IEXIST='NO'
           INQUIRE(FILE=IFILE2,EXIST=LEXIST)
           IF(LEXIST)IEXIST='YES'
           IF(IEXIST.EQ.'NO')GO TO 1161
           FTEMP=IFILE2
           GO TO 1190
!
 1161   CONTINUE
!
      ENDIF
!
!     CHECK IF FILE ENDS WITH PERIOD (OR THE FILE CHARACTER).  IF
!     SO, STRIP IT OFF AND REPEAT THE ABOVE SEQUENCE OF OPEN COMMANDS.
!
      IFLAG=IFLAG+1
      IF(IFLAG.GT.1)GO TO 1190
      FTEMP=IFILE
      DO 1175 I=80,1,-1
        IF(FTEMP(I:I).EQ.' ')GO TO 1175
        IF(FTEMP(I:I).EQ.IFCHAR)FTEMP(I:I)=' '
        GO TO 1179
 1175 CONTINUE
 1179 CONTINUE
      GO TO 1110
!
!     THE IEXIST PARAMETER SPECIFIES WHETHER FILE FOUND OR NOT.
!     DO NOT PRINT ANY ERROR OR WARNING MESSAGE HERE (LET CALLING
!     ROUTINE PRINT AN APPROPRIATE MESSAGE).
!
 1190 CONTINUE
      GO TO 9000
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGS2.EQ.'ON'.OR.ISUBRO.EQ.'INF3')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPINF3--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IBUGS2,ISUBRO,ISUBN0,IERROR,IERRFI
 9012   FORMAT('IBUGS2,ISUBRO,ISUBN0,IERROR,IERRFI = ',4(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9022)IFILE(1:80)
 9022   FORMAT('IFILE  = ',A80)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9041)IFILEL(1:80)
 9041   FORMAT('IFILEL  = ',A80)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9042)IFILEU(1:80)
 9042   FORMAT('IFILEU  = ',A80)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9043)IFILE2(1:80)
 9043   FORMAT('IFILE2  = ',A80)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9044)FTEMP(1:80)
 9044   FORMAT('FTEMP  = ',A80)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE DPINF3
      SUBROUTINE DPCLFI(IOUNIT,IFILE,ISTAT,IFORM,IACCES,IPROT,ICURST,   &
      IENDFI,IREWIN,ISUBN0,IERRFI,IBUGS2,ISUBRO,IERROR)
!
!     PURPOSE--CLOSE A FILE
!              (BUT THERE MAY BE SOME SMALL DIFFERENCES
!              IN HOW THAT IS DONE FOR DIFFERENT COMPUTERS).
!
!     WRITTEN BY--JAMES J. FILLIBEN
!     LANGUAGE--ANSI FORTRAN (1977)
!     ORIGINAL VERSION--NOVEMBER 1985.
!
!------------------------------------------------------------------------------
!
      INCLUDE 'DPCOPA.INC'
!
!CCCC CHARACTER*80 IFILE
      CHARACTER(LEN=*) :: IFILE
      CHARACTER*12 ISTAT
      CHARACTER*12 IFORM
      CHARACTER*12 IACCES
      CHARACTER*12 IPROT
      CHARACTER*12 ICURST
      CHARACTER*4 IENDFI
      CHARACTER*4 IREWIN
      CHARACTER*4 ISUBN0
      CHARACTER*4 IERRFI
!
      CHARACTER*4 IBUGS2
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
!-----COMMON------------------------------------------------
!
      INCLUDE 'DPCOHO.INC'
!
!-----COMMON VARIABLES (GENERAL)--------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPCL'
      ISUBN2='FI  '
!
      IF(IBUGS2.EQ.'ON'.OR.ISUBRO.EQ.'CLFI')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPCLFI--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGS2,ISUBRO,IERROR,IOUNIT
   52   FORMAT('IBUGS2,ISUBRO,IERROR,IOUNT = ',3(A4,2X),I5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,62)IFILE(1:80)
   62   FORMAT('IFILE  = ',A80)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,63)ISTAT,IFORM,IACCES
   63   FORMAT('ISTAT,IFORM,IACCES  = ',2(A12,2X),A12)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,66)IPROT,ICURST
   66   FORMAT('IPROT,ICURST  = ',A12,2X,A12)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,68)IENDFI,IREWIN,ISUBN0,IERRFI,IHOST1
   68   FORMAT('IENDFI,IREWIN,ISUBN0,IERRFI,IHOST1 = ',4(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               *******************
!               **  STEP 1--     **
!               **  CLOSE A FILE **
!               *******************
!
      ISTEPN='1'
      IF(IBUGS2.EQ.'ON'.OR.ISUBRO.EQ.'CLFI')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(ICURST.NE.'CLOSED')THEN
!
!-------ENDFILE REQUIRED FOR THE UNIVAC  CASE--------------------------
!
        IF(IHOST1.EQ.'UNIV')THEN
          IF(IENDFI.EQ.'ON')ENDFILE IOUNIT
        ENDIF
!
        IF(IREWIN.EQ.'ON')REWIND IOUNIT
        CLOSE(IOUNIT)
      ENDIF
!
      ICURST='CLOSED'
      IERRFI='NO'
      IERROR='NO'
      GO TO 9000
!
!               ************************************
!               **  STEP 80--                     **
!               **  GENERATE AN ERROR MESSAGE     **
!               **  IF THE FILE CANNOT BE OPENED  **
!               ************************************
!
      IERRFI='YES'
      IERROR='YES'
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,8011)
 8011 FORMAT('***** ERROR IN CLOSE FILE (DPCLFI)--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,8012)
 8012 FORMAT('      ERROR IN ATTEMPTING TO CLOSE A FILE.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,8021)IOUNIT
 8021 FORMAT('I/O UNIT    = ',I8)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,8022)IFILE(1:255)
 8022 FORMAT('FILE NAME   = ',A255)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,8023)ISTAT
 8023 FORMAT('FILE STATUS = ',A12)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,8024)IFORM
 8024 FORMAT('FILE FORMAT = ',A12)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,8025)IACCES
 8025 FORMAT('FILE ACCESS = ',A12)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,8026)IPROT
 8026 FORMAT('FILE PROTECTION         = ',A12)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,8027)ICURST
 8027 FORMAT('FILE CURRENT STATUS     = ',A12)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,8028)ISUBN0
 8028 FORMAT('PREVIOUS (= CALLING) SUBROUTINE = ',A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,8029)IERRFI
 8029 FORMAT('FILE-FINDING ERROR FLAG = ',A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,8031)IHOST1
 8031 FORMAT('HOST COMPUTER           = ',A4)
      CALL DPWRST('XXX','BUG ')
      GO TO 9000
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
      IF(IBUGS2.EQ.'ON'.OR.ISUBRO.EQ.'CLFI')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('*****AT THE END       OF DPCLFI--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9023)ISTAT,ICURST,IERROR,IENDFI,IREWIN,IERRFI
 9023   FORMAT('ISTAT,ICURST,IERROR,IENDFI,IREWIN,IERRFI  = ',   &
               2(A12,2X),3(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE DPCLFI
      SUBROUTINE DPREFI(IOUNIT,IFILE,ISTAT,IFORM,IACCES,IPROT,ICURST,   &
                        IA,NUMCHA,   &
                        ISUBN0,IERRFI,IBUGS2,ISUBRO,IERROR)
!
!     PURPOSE--READ FROM A FILE (BUT THERE MAY BE SOME SMALL DIFFERENCES
!              IN HOW THAT IS DONE FOR DIFFERENT COMPUTERS).
!
!     WRITTEN BY--JAMES J. FILLIBEN
!     LANGUAGE--ANSI FORTRAN (1977)
!     ORIGINAL VERSION--NOVEMBER 1985.
!     UPDATED         --FEBRUARY 2003. IF NUMCHA > 0, THEN ADD CAPABILITY
!                                      TO READ LINES LONGER THAN 132
!                                      COLUMNS.
!
!------------------------------------------------------------------------------
!
      INCLUDE 'DPCOPA.INC'
!
!CCCC CHARACTER*80 IFILE
      CHARACTER (LEN=*) :: IFILE
      CHARACTER*12 ISTAT
      CHARACTER*12 IFORM
      CHARACTER*12 IACCES
      CHARACTER*12 IPROT
      CHARACTER*12 ICURST
      CHARACTER*4 IA
!
      CHARACTER*4 ISUBN0
      CHARACTER*4 IERRFI
      CHARACTER*4 IBUGS2
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
      CHARACTER*9 IFORMT
!
      DIMENSION IA(*)
!
!-----COMMON------------------------------------------------
!
      INCLUDE 'DPCOHO.INC'
!
!-----COMMON VARIABLES (GENERAL)--------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPRE'
      ISUBN2='FI  '
!
      IF(IBUGS2.EQ.'ON'.OR.ISUBRO.EQ.'REFI')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPREFI--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGS2,ISUBRO,IERROR,NUMCHAR,IOUNIT
   52   FORMAT('IBUGS2,ISUBRO,IERROR,NUMCHAR,IOUNIT = ',3(A4,2X),2I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,62)IFILE(1:80)
   62   FORMAT('IFILE  = ',A80)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,63)ISTAT,IFORM,IACCES,IPROT,ICURST
   63   FORMAT('ISTAT,IFORM,IACCES,IPROT,ICURST = ',4(A12,1X),A12)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,81)ISUBN0,IERRFI,IHOST1
   81   FORMAT('ISUBN0,IERRFI,IHOST1 = ',2(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               ************************
!               **  STEP 1--          **
!               **  READ FROM A FILE  **
!               ************************
!
      ISTEPN='1'
      IF(IBUGS2.EQ.'ON'.OR.ISUBRO.EQ.'REFI')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!-----TREAT THE GENERAL CASE------------------------------------------
!
      ISTEPN='11'
      IF(IBUGS2.EQ.'ON'.OR.ISUBRO.EQ.'REFI')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IERRFI='NO'
      IERROR='NO'
      NUMCH2=NUMCHA
!
!CCCC FEBRUARY 2003: ADD CAPABILITY TO READ LINES LONGER THAN 132
!CCCC CHARACTERS.
!
      IF(NUMCHA.LT.0 .OR. IOUNIT.EQ.IRD)THEN
        NUMCH2=255
        READ(IOUNIT,1111,END=1118,IOSTAT=IOS,ERR=8000)(IA(I),I=1,NUMCH2)
 1111   FORMAT(255A1)
      ELSE
        IFORMT=' '
        IFORMT(1:9)='(     A1)'
        IF(NUMCHA.LE.9)THEN
          WRITE(IFORMT(6:6),'(I1)')NUMCHA
        ELSEIF(NUMCHA.LE.99)THEN
          WRITE(IFORMT(5:6),'(I2)')NUMCHA
        ELSEIF(NUMCHA.LE.999)THEN
          WRITE(IFORMT(4:6),'(I3)')NUMCHA
        ELSEIF(NUMCHA.LE.9999)THEN
          WRITE(IFORMT(3:6),'(I4)')NUMCHA
        ELSE
          WRITE(IFORMT(2:6),'(I5)')NUMCHA
        ENDIF
        READ(IOUNIT,IFORMT,END=1118,IOSTAT=IOS,ERR=8000)   &
            (IA(I),I=1,NUMCHA)
      ENDIF
!
      GO TO 9000
!
 1118 CONTINUE
      NUMCHA=3
      IA(1)='E'
      IA(2)='O'
      IA(3)='F'
      GO TO 9000
!
!               ************************************
!               **  STEP 80--                     **
!               **  GENERATE AN ERROR MESSAGE     **
!               **  IF THE FILE CANNOT BE READ    **
!               ************************************
!
 8000 CONTINUE
      IERRFI='YES'
      IERROR='YES'
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,8011)
 8011 FORMAT('***** ERROR IN DPREFI--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,8012)
 8012 FORMAT('      ERROR IN ATTEMPTING TO READ FROM A FILE')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,8021)IOUNIT
 8021 FORMAT('I/O UNIT    = ',I8)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,8022)IFILE(1:255)
 8022 FORMAT('FILE NAME   = ',A255)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,8023)ISTAT
 8023 FORMAT('FILE STATUS = ',A12)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,8024)IFORM
 8024 FORMAT('FILE FORMAT = ',A12)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,8025)IACCES
 8025 FORMAT('FILE ACCESS = ',A12)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,8026)IPROT
 8026 FORMAT('FILE PROTECTION         = ',A12)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,8027)ICURST
 8027 FORMAT('FILE CURRENT STATUS     = ',A12)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,8028)ISUBN0
 8028 FORMAT('PREVIOUS (= CALLING) SUBROUTINE = ',A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,8029)IERRFI
 8029 FORMAT('FILE-FINDING ERROR FLAG = ',A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,8030)IOS
 8030 FORMAT('IO STATUS NUMBER        = ',I8)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,8031)IHOST1
 8031 FORMAT('HOST COMPUTER           = ',A4)
      CALL DPWRST('XXX','BUG ')
      GO TO 9000
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGS2.EQ.'ON'.OR.ISUBRO.EQ.'REFI')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPREFI--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IBUGS2,ISUBRO,IERROR,NUMCHA,NUMCH2
 9012   FORMAT('IBUGS2,ISUBRO,IERROR,NUMCHA,NUMCH2 = ',3(A4,2X),2I8)
        CALL DPWRST('XXX','BUG ')
        IF(NUMCHA.GE.1)THEN
          WRITE(ICOUT,9032)(IA(I)(1:1),I=1,MIN(100,NUMCHA))
 9032     FORMAT('(IA(I),I=1,NUMCHA) = ',100A1)
          CALL DPWRST('XXX','BUG ')
        ENDIF
      ENDIF
!
      RETURN
      END SUBROUTINE DPREFI
      SUBROUTINE DPCOAN(IC,IX)
