      DATA ICYTAB( 64) / 32/
!
!-----START POINT-----------------------------------------------------
!
      IBUGCO='OFF'
      ISUBRO='JUNK'
      IERROR='NO'
!
      ISUBN1='DPCO'
      ISUBN2='AN  '
!
      IXTEMP=(-999)
      IX=(-999)
!
      IF(IBUGCO.EQ.'OFF'.AND.ISUBRO.NE.'COAN')GO TO 90
      WRITE(IPR,999)
  999 FORMAT(1X)
!CCCC CALL DPWRST('XXX','BUG ')
      WRITE(IPR,51)
   51 FORMAT('***** AT THE BEGINNING OF DPCOAN--')
!CCCC CALL DPWRST('XXX','BUG ')
      WRITE(IPR,52)IBUGCO,ISUBRO,IERROR
   52 FORMAT('IBUGCO,ISUBRO,IERROR = ',A4,2X,A4,2X,A4)
!CCCC CALL DPWRST('XXX','BUG ')
      WRITE(IPR,53)IHOST1
   53 FORMAT('IHOST1 = ',A4)
!CCCC CALL DPWRST('XXX','BUG ')
      WRITE(IPR,54)IC,IXTEMP,IX
   54 FORMAT('IC,IXTEMP,IX = ',A1,I8,I8)
!CCCC CALL DPWRST('XXX','BUG ')
   90 CONTINUE
!
!               **************************
!               **  STEP 10--           **
!               **  BRANCH TO THE       **
!               **  APPROPRIATE CASE    **
!               **************************
!
!     NOTE--IF YOU ARE RUNNING ON A NON-PRIME, NON-IBM-EBCDIC,
!           AND A NON-CDC-NOS-2, THEN THE FOLLOWING 4 BRANCH
!           LINES MAY BE COMMENTED OUT
!           SO AS TO SPEED UP EXECUTION.
!
      IF(IHOST1.EQ.'PRIM')GO TO 1200
      IF(IHOST1.EQ.'IBM')GO TO 1300
      IF(IHOST1.EQ.'CDC')GO TO 1400
      GO TO 1100
!
!-----TREAT THE GENERAL CASE------------------------------------------
!
 1100 CONTINUE
      IXTEMP=ICHAR(IC)
      IX=IXTEMP
      GO TO 9000
!
!-----TREAT THE PRIME CASE------------------------------------------
!
 1200 CONTINUE
      IXTEMP=ICHAR(IC)
      IX=IXTEMP-128
      GO TO 9000
!
!-----TREAT THE IBM EBCDIC CASE------------------------------------------
!
 1300 CONTINUE
      IXTEMP=ICHAR(IC)
      IF(IXTEMP.EQ.0)IXTEMP=256
      IF(IXTEMP.LT.1)GO TO 8000
      IF(IXTEMP.GT.256)GO TO 8000
      IX=IBMTAB(IXTEMP)
      GO TO 9000
!
!-----TREAT THE CDC NOS-2 CASE------------------------------------------
!
 1400 CONTINUE
      IXTEMP=ICHAR(IC)
      IF(IXTEMP.EQ.0)IXTEMP=64
      IF(IXTEMP.LT.1)GO TO 8000
      IF(IXTEMP.GT.64)GO TO 8000
      IX=ICYTAB(IXTEMP)
      GO TO 9000
!
!               *****************************
!               **  STEP 80--              **
!               **  IF AN ERROR EXISTS,    **
!               **  WRITE AN ERROR MESSAGE **
!               *****************************
!
 8000 CONTINUE
!
      WRITE(IPR,999)
!CCCC CALL DPWRST('XXX','BUG ')
      WRITE(IPR,8011)
 8011 FORMAT('***** ERROR IN DPCOAN--')
!CCCC CALL DPWRST('XXX','BUG ')
      WRITE(IPR,8012)
 8012 FORMAT('      ILLEGAL NUMERIC OUTPUT ARGUMENT')
!CCCC CALL DPWRST('XXX','BUG ')
      WRITE(IPR,8013)
 8013 FORMAT('      FROM    ICHAR(.)   FUNCTION')
!CCCC CALL DPWRST('XXX','BUG ')
      WRITE(IPR,8014)IXTEMP
 8014 FORMAT('      THE ARGUMENT IXTEMP = ',I8)
!CCCC CALL DPWRST('XXX','BUG ')
      WRITE(IPR,8015)IC
 8015 FORMAT('IC = ',A1)
!CCCC CALL DPWRST('XXX','BUG ')
      WRITE(IPR,8016)IHOST1
 8016 FORMAT('IHOST1 = ',A4)
!CCCC CALL DPWRST('XXX','BUG ')
      IERROR='YES'
      GO TO 9000
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGCO.EQ.'OFF'.AND.ISUBRO.NE.'COAN')GO TO 9090
      WRITE(IPR,999)
!CCCC CALL DPWRST('XXX','BUG ')
      WRITE(IPR,9011)
 9011 FORMAT('***** AT THE END       OF DPCOAN--')
!CCCC CALL DPWRST('XXX','BUG ')
      WRITE(IPR,9012)IBUGCO,ISUBRO,IERROR
 9012 FORMAT('IBUGCO,ISUBRO,IERROR = ',A4,2X,A4,2X,A4)
!CCCC CALL DPWRST('XXX','BUG ')
      WRITE(IPR,9013)IHOST1
 9013 FORMAT('IHOST1 = ',A4)
!CCCC CALL DPWRST('XXX','BUG ')
      WRITE(IPR,9014)IC,IXTEMP,IX
 9014 FORMAT('IC,IXTEMP,IX = ',A1,I8,I8)
!CCCC CALL DPWRST('XXX','BUG ')
 9090 CONTINUE
!
      RETURN
      END SUBROUTINE DPCOAN
      SUBROUTINE DPCONA(IX,IC)
!
!     PURPOSE--CONVERT IX = 0 TO 127 INTO
!              THE CORRESPONDING ASCII CHARACTER.
!              FOR EXAMPLE, 0            MAPS INTO NULL
!                           27           MAPS INTO ESCAPE
!                           49           MAPS INTO 1
!                           65           MAPS INTO UPPER CASE A
!                           97           MAPS INTO LOWER CASE A
!                           127          MAPS INTO DT
!
!     NOTE--THIS SUBROUTINE MIMICS THE USUAL   CHAR(.)
!           FUNCTION ON MOST COMPUTERS.
!     NOTE--SOME COMPUTERS (E.G., IBM EBCDIC, CDC NOS-2, AND
!           PRIME) HAVE    CHAR(.)   FUNCTIONS WHICH
!           HAVE DIFFERENT INPUT VALUES FROM THE USUAL 0 TO 127.
!           IN SUCH CASE (AND IN ALL CASES),
!           THIS SUBROUTINE WILL NEVERTHELESS YIELD CHARACTERS
!           CORRESPONDING TO THE 0 TO 127 RANGE.
!           THUS EVEN FOR IBM EBCDIC COMPUTERS (FOR EXAMPLE),
!           IF THIS SUBROUTINE RECEIVES A    65    AS INPUT,
!           IT WILL RETURN AN    UPPER CASE A   AS OUTPUT.
!
!     WRITTEN BY--JAMES J. FILLIBEN
!     LANGUAGE--ANSI FORTRAN (1977)
!     ORIGINAL VERSION--NOVEMBER  1986.
!     UPDATED         --JANUARY   1989.  DATA STMT. BEFORE COMMON STMT. (ALAN)
!
!------------------------------------------------------------------------------
!
      CHARACTER*1 IC
!
