      DATA ICYTAB(126) /-99/
      DATA ICYTAB(127) /-99/
      DATA ICYTAB(128) /-99/
!
!-----START POINT-----------------------------------------------------
!
      IBUGCO='OFF'
      ISUBRO='JUNK'
      IERROR='NO'
!
      ISUBN1='DPCO'
      ISUBN2='NA  '
!
      IXTEMP=(-999)
      IXTEM2=(-999)
      IC='Z'
!
      IF(IBUGCO.EQ.'OFF'.AND.ISUBRO.NE.'CONA')GO TO 90
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,51)
   51 FORMAT('***** AT THE BEGINNING OF DPCONA--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,52)IBUGCO,ISUBRO,IERROR
   52 FORMAT('IBUGCO,ISUBRO,IERROR = ',A4,2X,A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,53)IHOST1
   53 FORMAT('IHOST1 = ',A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,54)IX,IXTEMP,IXTEM2,IC
   54 FORMAT('IX,IXTEMP,IXTEM2,IC = ',3I8,2X,A1)
      CALL DPWRST('XXX','BUG ')
   90 CONTINUE
!
!               **************************
!               **  STEP 10--           **
!               **  BRANCH TO THE       **
!               **  APPROPRIATE CASE    **
!               **************************
!
!     NOTE--IF YOU ARE RUNNING ON A NON-PRIME, NON-IBM-EBCDIC,
!           AND A NON-CDC-NOS-2, THEN THE FOLLOWING 4 BRANCH
!           LINES MAY BE COMMENTED OUT
!           SO AS TO SPEED UP EXECUTION.
!
      IF(IHOST1.EQ.'PRIM')GO TO 1200
      IF(IHOST1.EQ.'IBM')GO TO 1300
      IF(IHOST1.EQ.'CDC')GO TO 1400
      GO TO 1100
!
!-----TREAT THE GENERAL CASE------------------------------------------
!
 1100 CONTINUE
      IXTEM2=IX
      IF(IXTEM2.LT.0)GO TO 8000
      IF(IXTEM2.GT.127)GO TO 8000
      IC=CHAR(IXTEM2)
      GO TO 9000
!
!-----TREAT THE PRIME CASE------------------------------------------
!
 1200 CONTINUE
      IXTEM2=IX+128
      IF(IXTEM2.LT.0)GO TO 8000
      IF(IXTEM2.GT.255)GO TO 8000
      IC=CHAR(IXTEM2)
      GO TO 9000
!
!-----TREAT THE IBM EBCDIC CASE------------------------------------------
!
 1300 CONTINUE
      IXTEMP=IX
      IF(IXTEMP.EQ.0)IXTEMP=128
      IXTEM2=IBMTAB(IXTEMP)
      IF(IXTEM2.LT.0)GO TO 8000
      IF(IXTEM2.GT.255)GO TO 8000
      IC=CHAR(IXTEM2)
      GO TO 9000
!
!-----TREAT THE CDC NOS-2 CASE------------------------------------------
!     (NOTE THAT THE INCOMING IX SHOULD BE BETWEEN 32 AND 90)
!
 1400 CONTINUE
      IXTEMP=IX
      IF(IXTEMP.EQ.0)IXTEMP=128
      IXTEM2=ICYTAB(IXTEMP)
      IF(IXTEM2.LT.0)GO TO 8000
      IF(IXTEM2.GT.63)GO TO 8000
      IC=CHAR(IXTEM2)
      GO TO 9000
!
!               *****************************
!               **  STEP 80--              **
!               **  IF AN ERROR EXISTS,    **
!               **  WRITE AN ERROR MESSAGE **
!               *****************************
!
 8000 CONTINUE
!
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,8011)
 8011 FORMAT('***** ERROR IN DPCONA--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,8012)
 8012 FORMAT('      ILLEGAL NUMERIC INPUT ARGUMENT')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,8013)
 8013 FORMAT('      FOR    CHAR(.)   FUNCTION')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,8014)IXTEM2
 8014 FORMAT('      THE ARGUMENT IXTEM2 = ',I8)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,8015)IX,IXTEMP
 8015 FORMAT('IX,IXTEMP = ',2I8)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,8016)IHOST1
 8016 FORMAT('IHOST1 = ',A4)
      CALL DPWRST('XXX','BUG ')
      IERROR='YES'
      GO TO 9000
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGCO.EQ.'OFF'.AND.ISUBRO.NE.'CONA')GO TO 9090
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9011)
 9011 FORMAT('***** AT THE END       OF DPCONA--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9012)IBUGCO,ISUBRO,IERROR
 9012 FORMAT('IBUGCO,ISUBRO,IERROR = ',A4,2X,A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9013)IHOST1
 9013 FORMAT('IHOST1 = ',A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9014)IX,IXTEMP,IXTEM2,IC
 9014 FORMAT('IX,IXTEMP,IXTEM2,IC = ',3I8,2X,A1)
      CALL DPWRST('XXX','BUG ')
 9090 CONTINUE
!
      RETURN
      END SUBROUTINE DPCONA
      SUBROUTINE DPCOPL(NPLOTV,NPLOTP,NS,ICASPL,IAND1,IAND2,   &
                        IANGLU,MAXNPP,   &
                        IBUGG2,IBUGG3,IBUGQ,ISUBRO,IFOUND,IERROR)
!
!     PURPOSE--FORM A CONTOUR PLOT.
!
!     EXAMPLE--CONTOUR PLOT Z X Y Z0
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--87/5
!     ORIGINAL VERSION--MAY       1987.
!     UPDATED         --JANUARY   1989.  MORE CHANGES TO STANDARD FORTRAN 77--
!                                        BYTE TO CHARACTER*1,
!     UPDATED         --JULY      1989.  CORRECT BACKWARDS PLOT
!     UPDATED         --JUNE      1990. TEMPORARY ARRAYS TO GARBAGE COMMON
!     UPDATED         --JULY      1990. COLR ARRAY MADE INTEGER
!     UPDATED         --APRIL     1992. DEFINE MINN2
!     UPDATED         --FEBRUARY  2011. USE DPPARS, DPPAR5
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICASPL
      CHARACTER*4 IAND1
      CHARACTER*4 IAND2
      CHARACTER*4 IANGLU
      CHARACTER*4 IBUGG2
      CHARACTER*4 IBUGG3
      CHARACTER*4 IBUGQ
      CHARACTER*4 ISUBRO
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
!
      CHARACTER*4 IWRITE
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
      CHARACTER*4 ICASE
      CHARACTER*40 INAME
      PARAMETER (MAXSPN=30)
      CHARACTER*4 IVARN1(MAXSPN)
      CHARACTER*4 IVARN2(MAXSPN)
      CHARACTER*4 IVARTY(MAXSPN)
      REAL PVAR(MAXSPN)
      INTEGER ILIS(MAXSPN)
      INTEGER NRIGHT(MAXSPN)
      INTEGER ICOLR(MAXSPN)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOPA.INC'
      INCLUDE 'DPCOCP.INC'
      INCLUDE 'DPCOHK.INC'
      INCLUDE 'DPCODA.INC'
!
!---------------------------------------------------------------------
!
!CCCC THE FOLLOWING LINE WAS ADDED JULY 1990
      INTEGER COLR
!
!  JANUARY, 1989: MAKE BOX A CHARACTER VARIABLE
!CCCC BYTE BOX                           JANUARY 1989
      CHARACTER*1 BOX
!
      DIMENSION ZMAT(MAXIMX,MAXJMX)
!CCCC DIMENSION X(MAXIMX)
!CCCC DIMENSION Y(MAXJMX)
!CCCC DIMENSION CNV(MAXNCN)
      DIMENSION BOX(4,MAXIMX,MAXJMX)
      DIMENSION WLN(MAXNCN)
      DIMENSION IDSH(MAXNCN)
      DIMENSION COLR(MAXNCN+1)
      DIMENSION LBL(MAXNCN)
!
      DIMENSION Y1(MAXOBV)
      DIMENSION Y2(MAXOBV)
      DIMENSION Y3(MAXOBV)
      DIMENSION Y4(MAXOBV)
      DIMENSION XD(MAXOBV)
      DIMENSION YD(MAXOBV)
!CCCC FOLLOWING LINES ADDED JUNE, 1990
      INCLUDE 'DPCOZZ.INC'
      EQUIVALENCE (GARBAG(IGARB1),Y1(1))
      EQUIVALENCE (GARBAG(IGARB2),Y2(1))
      EQUIVALENCE (GARBAG(IGARB3),Y3(1))
      EQUIVALENCE (GARBAG(IGARB4),Y4(1))
      EQUIVALENCE (GARBAG(IGARB5),XD(1))
      EQUIVALENCE (GARBAG(IGARB6),YD(1))
!CCCC END CHANGE
!
!-----COMMON VARIABLES (GENERAL)--------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPCO'
      ISUBN2='PL  '
!
      IFOUND='NO'
      IERROR='NO'
!
      MAXCP1=MAXCOL+1
      MAXCP2=MAXCOL+2
      MAXCP3=MAXCOL+3
      MAXCP4=MAXCOL+4
      MAXCP5=MAXCOL+5
      MAXCP6=MAXCOL+6
!
      IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'COPL')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPCOPL--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)NPLOTV,NPLOTP,NS
   52   FORMAT('NPLOTV,NPLOTP,NS = ',3I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)ICASPL,IAND1,IAND2
   53   FORMAT('ICASPL,IAND1,IAND2 = ',A4,2X,A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,54)IANGLU,IBUGG2,IBUGG3,IBUGQ
   54   FORMAT('IANGLU,IBUGG2,IBUGG3,IBUGQ = ',3(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,56)ICASPL,MAXN,MAXNPP
   56   FORMAT('ICASPL,MAXN,MAXNPP = ',A4,2I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,57)IFOUND,IERROR
   57   FORMAT('IFOUND,IERROR = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               ***********************************
!               **  TREAT THE CONTOUR PLOT CASE  **
!               ***********************************
!
      IFOUND='YES'
      ICASPL='CONT'
!
!               ****************************************
!               **  STEP 2--                          **
!               **  EXTRACT THE VARIABLE LIST         **
!               ****************************************
!
      ISTEPN='2'
      IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'COPL')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      INAME='CONTOUR PLOT'
      MINNA=4
      MAXNA=100
      MINN2=2
      IFLAGE=99
      IFLAGM=0
      IFLAGP=0
      JMIN=2
      JMAX=NUMARG
      MINNVA=4
      MAXNVA=4
!
      CALL DPPARS(IHARG,IHARG2,IARGT,ARG,NUMARG,IANS,IWIDTH,   &
                  IHNAME,IHNAM2,IUSE,NUMNAM,IN,IVALUE,VALUE,   &
                  JMIN,JMAX,   &
                  MINN2,MINNA,MAXNA,MAXSPN,IFLAGE,INAME,   &
                  IVARN1,IVARN2,IVARTY,PVAR,   &
                  ILIS,NRIGHT,ICOLR,ISUB,NQ,ILOCQ,NUMVAR,   &
                  MINNVA,MAXNVA,   &
                  IFLAGM,IFLAGP,   &
                  IBUGG3,IBUGQ,ISUBRO,IFOUND,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
      IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'COPL')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,281)
  281   FORMAT('***** AFTER CALL DPPARS--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,282)NQ,NUMVAR
  282   FORMAT('NQ,NUMVAR = ',2I8)
        CALL DPWRST('XXX','BUG ')
        IF(NUMVAR.GT.0)THEN
          DO 285 I=1,NUMVAR
            WRITE(ICOUT,287)I,IVARN1(I),IVARN2(I),ILIS(I),NRIGHT(I),   &
                            ICOLR(I),IVARTY(I)
  287       FORMAT('I,IVARN1(I),IVARN2(I),ILIS(I),NRIGHT(I),',   &
                   'ICOLR(I),IVARTY(I) = ',I8,2X,A4,A4,2X,3I8,2X,A4)
            CALL DPWRST('XXX','BUG ')
  285     CONTINUE
        ENDIF
      ENDIF
!
!               **********************************************
!               **  STEP 33--                               **
!               **  FORM THE SUBSETTED VARIABLES            **
!               **       Y1(.)                              **
!               **       Y2(.)                              **
!               **       Y3(.)                              **
!               **  CONTAINING                              **
!               **       THE RESPONSE Z VARIABLE            **
!               **       THE HORIZONTAL AXIS VARIABLE       **
!               **       THE VERTICAL AXIS VARIABLE         **
!               **  RESPECTIVELY.                           **
!               **********************************************
!
      ISTEPN='33'
      IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'COPL')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      ICOL=1
      NUMVA2=3
      CALL DPPAR5(ICOL,IVALUE,IVALU2,IN,MAXN,MAXOBV,   &
                  INAME,IVARN1,IVARN2,IVARTY,   &
                  ILIS,NRIGHT,ICOLR,ISUB,NQ,NUMVA2,   &
                  MAXCOL,MAXCP1,MAXCP2,MAXCP3,   &
                  MAXCP4,MAXCP5,MAXCP6,   &
                  V,PRED,RES,YPLOT,XPLOT,X2PLOT,TAGPLO,   &
                  Y1,Y2,Y3,Y3,Y3,Y3,Y3,NS,   &
                  IBUGG3,ISUBRO,IFOUND,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
!               **********************************************
!               **  STEP 34--                               **
!               **  FORM THE FULL VARIABLE                  **
!               **       Y4(.)                              **
!               **  CONTAINING THE VALUES                   **
!               **  OF THE RESPONSE VARIABLE                **
!               **  WHERE IT IS DESIRED THAT                **
!               **  CONTOUR CURVES BE DETERMINED.           **
!               **********************************************
!
      ISTEPN='34'
      IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'COPL')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      ICOL=4
      NUMVA2=1
      NQ=NRIGHT(4)
      DO 3410 I=1,NQ
        ISUB(I)=1
 3410 CONTINUE
!
      CALL DPPAR3(ICOL,IVALUE,IVALU2,IN,MAXN,MAXOBV,   &
                  INAME,IVARN1,IVARN2,IVARTY,   &
                  ILIS,NRIGHT,ICOLR,ISUB,NQ,NUMVA2,   &
                  MAXCOL,MAXCP1,MAXCP2,MAXCP3,   &
                  MAXCP4,MAXCP5,MAXCP6,   &
                  V,PRED,RES,YPLOT,XPLOT,X2PLOT,TAGPLO,   &
                  Y4,Y4,Y4,N4,NLOCA2,NLOCA3,ICASE,   &
                  IBUGG3,ISUBRO,IFOUND,IERROR)
        IF(IERROR.EQ.'YES')GO TO 9000
!
!               ******************************************************
!               **  STEP 41--                                        *
!               **  FORM THE VERTICAL AND HORIZONTAL AXIS            *
!               **  VARIABLES (Y(.) AND X(.), RESPECTIVELY) FOR THE  *
!               **  PLOT.  FORM THE CURVE DESIGNATION VARIABLE D(.). *
!               **  THIS WILL BE BOTH ONES FOR BOTH CASES            *
!               **  DEFINE THE NUMBER OF PLOT POINTS    (NPLOTP).    *
!               **  DEFINE THE NUMBER OF PLOT VARIABLES (NPLOTV).    *
!               ******************************************************
!
      ISTEPN='41'
      IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'COPL')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IWRITE='OFF'
      CALL DISTIN(Y2,NS,IWRITE,XD,NXD,IBUGG3,IERROR)
      CALL DISTIN(Y3,NS,IWRITE,YD,NYD,IBUGG3,IERROR)
!
      K=0
!CCCC THE FOLLOWING 2 LINES WERE FIXED           JULY 1989
!CCCC TO FIX BACKWARDS AXES PROBLEM              JULY 1989
!CCCC DO4100I=1,NXD
!CCCC DO4200J=1,NYD
      DO 4100 J=1,NYD
      DO 4200 I=1,NXD
        K=K+1
        ZMAT(I,J)=Y1(K)
 4200 CONTINUE
 4100 CONTINUE
!
      XMN=0.0
      YMN=0.0
!
      XSCL=1.0
      YSCL=1.0
!
      DO 4300 I=1,MAXNCN
        WLN(I)=1.0
        IDSH(I)=0
        COLR(I)=1
        LBL(I)=1
 4300 CONTINUE
!
!
      LDEC=2
      SZL=10.0
      DLMM=1.0
!
      CALL DPCOP2(ZMAT,XD,YD,NXD,NYD,Y4,N4,   &
                  BOX,   &
                  XMN,YMN,XSCL,YSCL,   &
                  WLN,IDSH,COLR,LBL,   &
                  LDEC,SZL,DLMM,   &
                  Y,X,D,NPLOTP,NPLOTV,   &
                  IBUGG3,ISUBRO,IERROR)
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGG2.EQ.'ON'.OR.ISUBRO.EQ.'COPL')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPCOPL--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IFOUND,IERROR
 9012   FORMAT('IFOUND,IERROR = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9013)NPLOTV,NPLOTP,NS,ICASPL,IAND1,IAND2
 9013   FORMAT('NPLOTV,NPLOTP,NS,ICASPL,IAND1,IAND2 = ',   &
               3I8,2X,2(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9016)NLOCAL,NQ,MINN2
 9016   FORMAT('NLOCAL,NQ,MINN2 = ',3I8)
        CALL DPWRST('XXX','BUG ')
        IF(NPLOTP.GE.1)THEN
          DO 9020 I=1,NPLOTP
            WRITE(ICOUT,9021)I,Y(I),X(I),D(I)
 9021       FORMAT('I,Y(I),X(I),D(I) = ',I8,3F12.5)
            CALL DPWRST('XXX','BUG ')
 9020     CONTINUE
        ENDIF
      ENDIF
!
      RETURN
      END SUBROUTINE DPCOPL
      SUBROUTINE DPCOP2(A,X,Y,IMX,JMX,CNV,NCNN,   &
                        BOX,   &
                        XMN,YMN,XSCL,YSCL,   &
                        WLN,IDSH,COLR,LBL,   &
                        LDEC,SZL,DLMM,   &
                        YTEMP,XTEMP,TATEMP,NTEMP,NTRACE,   &
                        IBUGG3,ISUBRO,IERROR)
!
!     PURPOSE--GENERATE A CONTOUR PLOT
!
!     WRITTEN BY--DAVID W. BEHRINGER NOAA/AOML (MIAMI).
!                 AS PART OF NOAA'S CONCX V.3   MARCH 1988.
!     ORIGINAL VERSION (IN DATAPLOT)--AUGUST    1988.
!
!     NOTE--CALLING SEQUENCE--
!           DPCOPL
!               DPCOP2 (= CONCX)
!                     BNDRY.
!                     START1(2).
!                     START2.
!                     START3.
!                     START4.
!                     CHASE(5).
!                     INOUT.
!                     SIDEDI(8).
!                     DRWFIL
!                           PLYSRT
!                                 STRSWP(6).
!                                 SIDEDI(2).
!                                 INOUT(3).
!                                 CONINSRT(3)
!                                       STRSWP(3).
!                           RSURF...
!                           GWICOL...
!                           DRAW0
!                                 GDASH...
!                                 GVECT...
!                           DRAWL
!                                  GCHARJ(2)...
!                                  GCHAR(2)...
!                                  GCHARA...
!                                  DRAW0(6)
!                                        GDASH...
!                                        GVECT...
!
!     NOTE--RECOMMENDED DIMENSIONS--
!           A(IMX,JMX)
!           X(IMX)
!           Y(JMX)
!           XC(NMX,3)
!           YC(NMX,3)
!           DST(NDX)
!           IB(NMX)
!           JB(NMX)
!           NEES(2,NSGX,3)
!           CNV(NCNN)
!           LBL(NCNN)
!           WLN(NCNN)
!           IDSH(NCNN)
!           BOX(4,IMX,JMX)
!
!     ORIGINAL VERSION (IN DATAPLOT)--AUGUST    1988.
!                               MODIFICATIONS INCLUDE--
!                                  NO TABS
!                                  NO LOWER CASE
!                                  NO UNDERSCORES
!                                  NO ENTRY POINTS
!                                  NO LONG NAMES
!                                  REMOVE UNDERLYING GRAPHICS "SET" SUBROUT.--
!                                         GWICOL, GDASH, GCHARJ, GCHARA
!                                  INSERT BUG AND TRACE SWITCHES
!                                  MULTI-RETURNS TO ONE RETURN?
!                                  SPLIT DIMENSIONS--ONE PER LINE
!                                  CHAR/INT BEFORE DIMENSION STATEMENTS
!                                  SPLIT INTEGER DECLARATIONS AND DIMENSIONS
!                                  NO CARRYING DIMENSIONS VIA ARGUMENTS
!
!     UPDATED         --JANUARY   1989.  MORE CHANGES TO STANDARD FORTRAN 77--
!                                        VAX BYTE TO CHARACTER*1,
!                                        DO WHILE/END DO (ALAN HECKERT).
!     UPDATED          --JULY     1990.  999.999 TO ANINE
!     UPDATED          --JULY     1990.  REWRITE IF/THEN/ELSE DUE TO
!                                        IBM-PC COMPILER ERROR
!     UPDATED          --JULY     1990.  REWRITE IF/THEN/ELSE DUE TO
!                                        I & J = 0
!     UPDATED          --JULY     1990.  PRMTR DEF. WITH I & J = 0
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOCP.INC'
!
!---------------------------------------------------------------------
!
!CCCC PARAMETER NMX=9000,NSGX=100,NDX=MAX0(NMX,6*NSGX)   AUGUST 1988
!CCCC INTEGER NPTS(NSGX,3),SNSE(NSGX,3),CLSD(NSGX,3),NSEG(3),
!CCCC1 COLR(NCNN+1)
!CCCC BYTE BOX(4,IMX,JMX)                JANUARY 1989
!CCCC DIMENSION A(IMX,JMX),X(IMX),Y(JMX)
!CCCC DIMENSION XC(NMX,3),YC(NMX,3),DST(NDX),IB(NMX),JB(NMX),
!CCCC1 NEES(2,NSGX,3),CNV(NCNN),LBL(NCNN),WLN(NCNN),IDSH(NCNN)
!
      INTEGER NPTS
      INTEGER SNSE
      INTEGER CLSD
      INTEGER NSEG
      INTEGER COLR
!
!CCCC BYTE BOX                           JANUARY 1989
      CHARACTER*1 BOX
!
      CHARACTER*4 IBUGG3
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      DIMENSION NPTS(MAXNSG,3)
      DIMENSION SNSE(MAXNSG,3)
      DIMENSION CLSD(MAXNSG,3)
      DIMENSION NSEG(3)
      DIMENSION COLR(MAXNCN+1)
!
      DIMENSION A(MAXIMX,MAXJMX)
      DIMENSION X(MAXIMX)
      DIMENSION Y(MAXJMX)
      DIMENSION XC(MAXNMX,3)
      DIMENSION YC(MAXNMX,3)
      DIMENSION DST(MAXNDX)
      DIMENSION IB(MAXNMX)
      DIMENSION JB(MAXNMX)
      DIMENSION NEES(2,MAXNSG,3)
      DIMENSION CNV(MAXNCN)
      DIMENSION LBL(MAXNCN)
      DIMENSION WLN(MAXNCN)
      DIMENSION IDSH(MAXNCN)
!
      DIMENSION BOX(4,MAXIMX,MAXJMX)
!
      DIMENSION XTEMP(*)
      DIMENSION YTEMP(*)
      DIMENSION TATEMP(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      NTEMP=0
      NTRACE=0
!
      IF(IBUGG3.EQ.'OFF'.AND.ISUBRO.NE.'COP2')GO TO 90
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,51)
   51 FORMAT('***** AT THE BEGINNING OF DPCOP2--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,52)IBUGG3,ISUBRO
   52 FORMAT('IBUGG3,ISUBRO = ',A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,53)IMX,JMX,NCNN
   53 FORMAT('IMX,JMX,NCNN = ',3I8)
      CALL DPWRST('XXX','BUG ')
      DO 55 I=1,IMX
      WRITE(ICOUT,56)I,X(I)
   56 FORMAT('I,X(I) = ',I8,E15.7)
      CALL DPWRST('XXX','BUG ')
   55 CONTINUE
      DO 60 I=1,JMX
      WRITE(ICOUT,61)I,Y(I)
   61 FORMAT('I,Y(I) = ',I8,E15.7)
      CALL DPWRST('XXX','BUG ')
   60 CONTINUE
      DO 65 I=1,IMX
      DO 66 J=1,JMX
      WRITE(ICOUT,67)I,J,A(I,J)
   67 FORMAT('I,J,A(I,J) = ',I8,I8,E15.7)
      CALL DPWRST('XXX','BUG ')
   66 CONTINUE
   65 CONTINUE
      DO 70 I=1,NCNN
      WRITE(ICOUT,71)I,CNV(I)
   71 FORMAT('I,CNV(I) = ',I8,E15.7)
      CALL DPWRST('XXX','BUG ')
   70 CONTINUE
   90 CONTINUE
!
!   ADJUST CONTOUR LIMITS TO AVOID LATER ATTEMPTS TO USE NONEXISTENT CONTOURS
!    EXCLUDE NON-CONTOURABLE PARTS OF THE FIELD FROM THE SEARCH FOR AMIN/AMAX
!
!CCCC THE FOLLOWING LINE WAS ADDED JULY 1990
!CCCC AND ALL SUBSEQUENT OCCURRANCES OF HARD-CODED 999.999'S  JULY 1990
!CCCC WERE CHANGE TO SOFT-CODED ANINE       JULY 1990
      ANINE=999.999
!
!CCCC THE FOLLOWING 2 LINES WERE CHANGED JULY 1990
!CCCC AMIN=999.999
!CCCC AMAX=999.999
      AMIN=ANINE
      AMAX=ANINE
!
!CCCC THE FOLLOWING SECTION WAS REPLACED     JULY 1990
!CCCC DUE TO A IBM-PC COMPILER ERROR          JULY 1990
!CCCC DO1000J=1,JMX
!CCCC   DO1010I=1,IMX
!CCCC THE FOLLOWING 5 LINES WERE CHANGED JULY 1990
!CCCC     IF (A(I,J).NE.999.999.AND.
!CCCC1     ((I.GT.1.AND.A(I-1,J).NE.999.999).OR.
!CCCC2       (I.LT.IMX.AND.A(I+1,J).NE.999.999)).AND.
!CCCC3       ((J.GT.1.AND.A(I,J-1).NE.999.999).OR.
!CCCC4         (J.LT.JMX.AND.A(I,J+1).NE.999.999))) THEN
!CCCC     IF (A(I,J).NE.ANINE.AND.
!CCCC1     ((I.GT.1.AND.A(I-1,J).NE.ANINE).OR.
!CCCC2       (I.LT.IMX.AND.A(I+1,J).NE.ANINE)).AND.
!CCCC3       ((J.GT.1.AND.A(I,J-1).NE.ANINE).OR.
!CCCC4         (J.LT.JMX.AND.A(I,J+1).NE.ANINE))) THEN
!CCCC THE FOLLOWING LINE WAS CHANGED JULY 1990
!CCCC       IF (AMIN.NE.999.999) THEN
!CCCC       IF (AMIN.NE.ANINE) THEN
!CCCC         AMIN=AMIN1(AMIN,A(I,J))
!CCCC       ELSE
!CCCC         AMIN=A(I,J)
!CCCC       END IF
!CCCC THE FOLLOWING LINE WAS CHANGED JULY 1990
!CCCC       IF (AMAX.NE.999.999) THEN
!CCCC       IF (AMAX.NE.ANINE) THEN
!CCCC         AMAX=AMAX1(AMAX,A(I,J))
!CCCC       ELSE
!CCCC         AMAX=A(I,J)
!CCCC       END IF
!CCCC     END IF
!1010   CONTINUE
!1000 CONTINUE
!
!CCCC THE FOLLOWING SECTION REPLACES THE ABOVE SECTION  JULY 1990
      DO 1000 J=1,JMX
        DO 1010 I=1,IMX
          AM0=ANINE
          A0M=ANINE
          A00=ANINE
          A0P=ANINE
          AP0=ANINE
          IF(I.GT.1.AND.J.GT.0)AM0=A(I-1,J)
          IF(I.GT.0.AND.J.GT.1)A0M=A(I,J-1)
          IF(I.GT.0.AND.J.GT.0)A00=A(I,J)
          IF(I.GT.0.AND.J.LT.JMX)A0P=A(I,J+1)
          IF(I.LT.IMX.AND.J.GT.0)AP0=A(I+1,J)
          IF (A00.NE.ANINE.AND.   &
           ((AM0.NE.ANINE).OR.   &
             (AP0.NE.ANINE)).AND.   &
             ((A0M.NE.ANINE).OR.   &
               (A0P.NE.ANINE))) THEN
!
            IF (AMIN.NE.ANINE) THEN
              AMIN=AMIN1(AMIN,A(I,J))
            ELSE
              AMIN=A(I,J)
            END IF
!
            IF (AMAX.NE.ANINE) THEN
              AMAX=AMAX1(AMAX,A(I,J))
            ELSE
              AMAX=A(I,J)
            END IF
!
          END IF
 1010   CONTINUE
 1000 CONTINUE
!
!     WRITE(9,'('' AMIN/AMAX: '',2F10.3)') AMIN,AMAX
      N=1
 1100 CONTINUE
      IF(CNV(N).GE.AMIN)GO TO 1199
!CCCC DO WHILE (CNV(N).LT.AMIN)          JANUARY 1989
        N=N+1
        IF (N.GT.NCNN) GO TO 9000
!CCCC END DO                             JANUARY 1989
      GO TO 1100
 1199 CONTINUE
      NCOFF=N
      N=NCNN
!CCCC DO WHILE (CNV(N).GT.AMAX)          JANUARY 1989
 1200 CONTINUE
      IF(CNV(N).LE.AMAX)GO TO 1299
        N=N-1
        IF (N.LT.1) GO TO 9000
!CCCC END DO                             JANUARY 1989
      GO TO 1200
 1299 CONTINUE
      NCN=N+1-NCOFF
!   CONVERT X & Y FROM USER UNITS TO DEVICE UNITS (MM OR WHATEVER)
      DO 1300 I=1,IMX
        X(I)=(X(I)-XMN)*XSCL
 1300 CONTINUE
      DO 1310 J=1,JMX
        Y(J)=(Y(J)-YMN)*YSCL
 1310 CONTINUE
!   SET UP IB, JB & BOX ARRAYS TO CONTROL CONTOURING NEAR BOUNDARIES
!   DATA VOIDS CONNECTED TO PERIMETER ARE ALLOWED, BUT NO ISOLATED VOIDS
!
      CALL BNDRY(A,BOX,IMX,JMX,IB,JB,NBX,ISUBRO,IBUGG3)
      NBM=NBX-1
!     WRITE(9,'('' A'')')
!     CALL PRTMTX(9,A,IMX,JMX,1)
!     WRITE(9,'('' BOUNDARY: '',I6)') NBX
!     DO NB=1,NBX
!     I=IB(NB)
!     J=JB(NB)
!     WRITE(9,'(1X,I5,5X,2I5,5X,2F9.2)') NB,I,J,X(I),Y(J)
!CCCC END DO                             JANUARY 1989
!
!   SET UP PRMTR
      I=IB(1)
      J=JB(1)
      PRMTR=0.
      DO 1400 NB=2,NBX
        IM=I
        JM=J
        I=IB(NB)
        J=JB(NB)
        IF (I.EQ.IM) THEN
!CCCC THE FOLLOWING LINE WAS REPLACED BY SUBSEQUENT 2 LINES JULY 1990
!CCCC     PRMTR=PRMTR+ABS(Y(J)-Y(JM))
          IF(J.GE.1.AND.J.LE.JMX.AND.JM.GE.1.AND.JM.LE.JMX)   &
          PRMTR=PRMTR+ABS(Y(J)-Y(JM))
        ELSE
!CCCC THE FOLLOWING LINE WAS REPLACED BY SUBSEQUENT 2 LINES JULY 1990
!CCCC     PRMTR=PRMTR+ABS(X(I)-X(IM))
          IF(I.GE.1.AND.I.LE.IMX.AND.IM.GE.1.AND.IM.LE.IMX)   &
          PRMTR=PRMTR+ABS(X(I)-X(IM))
        END IF
 1400 CONTINUE
!   BEGIN MAIN LOOP -> SEARCH FOR STARTING POINTS OF CONTOURS
      DO 1500 NC=0,NCN
        NCC=NC+NCOFF
        IF (NC.LT.NCN) THEN
          CN=CNV(NCC)
!   RESET 'BOX' WHICH DOES BOOKEEPING FOR CONTOUR-CHASES
          DO 1510 J=1,JMX
            DO 1520 I=1,IMX
              DO 1530 L=1,4
                IF (BOX(L,I,J).EQ.'1') BOX(L,I,J)='0'
                IF (BOX(L,I,J).EQ.'3') BOX(L,I,J)='2'
 1530         CONTINUE
 1520       CONTINUE
 1510     CONTINUE
          NSG=0
          NP=1
          N=1
!   SEARCH PERIMETER OF AREA FOR CONTOUR-STARTS
          DO 1540 NB=1,NBM
            IF (IB(NB).EQ.IB(NB+1)) THEN
              I=IB(NB)
              IF (JB(NB).LT.JB(NB+1)) THEN
                JS=JB(NB)
                JE=JB(NB+1)-1
                DO 1550 J=JS,JE
                  IF (BOX(1,I,J).EQ.'2') THEN
                    NS=1
                    CALL START1(A(I,J),X(I),Y(J),   &
                                IMX,NS,CN,XC(NP,2),YC(NP,2),   &
                                ISUBRO,IBUGG3)
                    IF (NS.GT.0) THEN
!          ->  CONTOUR-START FOUND, BEGIN CHASE
                      II=I
                      JJ=J
                      CALL CHASE(A,X,Y,IMX,JMX,II,JJ,   &
                                 NS,CN,XC(NP,2),YC(NP,2),NMX,N,BOX,   &
                                 ISUBRO,IBUGG3)
                      IF (N.GT.1) THEN
                        NSG=NSG+1
                        NPTS(NSG,2)=N
                        IF (A(I,J).LT.A(I,J+1)) THEN
                          SNSE(NSG,2)=1
                        ELSE
                          SNSE(NSG,2)=-1
                        END IF
                        CLSD(NSG,2)=0
!     WRITE(9,'('' CN='',F7.2,''    SNSE='',I3)') CN,SNSE(NSG,2)
!     CALL SIDEDI(XC(NP,2),YC(NP,2),NSS,DDD,IB,JB,X,Y)
!     WRITE(9,'('' 1'',2F10.3,I6)')XC(NP,2),YC(NP,2),NSS
!     CALL SIDEDI(XC(NP+N-1,2),YC(NP+N-1,2),NSS,DDD,IB,JB,X,Y)
!     WRITE(9,'('' 1'',2F10.3,I6)')XC(NP+N-1,2),YC(NP+N-1,2),NSS
!     CALL PRT_STR(9,XC(NP,2),YC(NP,2),1,N)
                        NP=NP+N
                        N=1
                      END IF
                    END IF
                  END IF
 1550           CONTINUE
              ELSE
                JS=JB(NB)-1
                JE=JB(NB+1)
                DO 1560 J=JS,JE,-1
                  IF (BOX(3,I-1,J).EQ.'2') THEN
                    NS=3
                    CALL START3(A(I,J),X(I),Y(J),   &
                                IMX,NS,CN,XC(NP,2),YC(NP,2),   &
                                ISUBRO,IBUGG3)
                    IF (NS.GT.0) THEN
!          ->  CONTOUR-START FOUND, BEGIN CHASE
                      II=I-1
                      JJ=J
                      CALL CHASE(A,X,Y,IMX,JMX,II,JJ,   &
                                 NS,CN,XC(NP,2),YC(NP,2),NMX,N,BOX,   &
                                 ISUBRO,IBUGG3)
                      IF (N.GT.1) THEN
                        NSG=NSG+1
                        NPTS(NSG,2)=N
                        IF (A(I,J+1).LT.A(I,J)) THEN
                          SNSE(NSG,2)=1
                        ELSE
                          SNSE(NSG,2)=-1
                        END IF
                        CLSD(NSG,2)=0
!     WRITE(9,'('' CN='',F7.2,''    SNSE='',I3)') CN,SNSE(NSG,2)
!     CALL SIDEDI(XC(NP,2),YC(NP,2),NSS,DDD,IB,JB,X,Y)
!     WRITE(9,'('' 3'',2F10.3,I6)')XC(NP,2),YC(NP,2),NSS
!     CALL SIDEDI(XC(NP+N-1,2),YC(NP+N-1,2),NSS,DDD,IB,JB,X,Y)
!     WRITE(9,'('' 3'',2F10.3,I6)')XC(NP+N-1,2),YC(NP+N-1,2),NSS
!     CALL PRT_STR(9,XC(NP,2),YC(NP,2),1,N)
                        NP=NP+N
                        N=1
                      END IF
                    END IF
                  END IF
 1560         CONTINUE
            END IF
          ELSE
            J=JB(NB)
            IF(IB(NB).LT.IB(NB+1)) THEN
              IS=IB(NB)
              IE=IB(NB+1)-1
              DO 1570 I=IS,IE
                IF (BOX(2,I,J-1).EQ.'2') THEN
                  NS=2
                  CALL START2(A(I,J),X(I),Y(J),   &
                              IMX,NS,CN,XC(NP,2),YC(NP,2),   &
                              ISUBRO,IBUGG3)
                  IF (NS.GT.0) THEN
!          ->  CONTOUR-START FOUND, BEGIN CHASE
                    II=I
                    JJ=J-1
                    CALL CHASE(A,X,Y,IMX,JMX,II,JJ,   &
                               NS,CN,XC(NP,2),YC(NP,2),NMX,N,BOX,   &
                               ISUBRO,IBUGG3)
                    IF (N.GT.1) THEN
                      NSG=NSG+1
                      NPTS(NSG,2)=N
                      IF (A(I,J).LT.A(I+1,J)) THEN
                        SNSE(NSG,2)=1
                      ELSE
                        SNSE(NSG,2)=-1
                      END IF
                      CLSD(NSG,2)=0
!     WRITE(9,'('' CN='',F7.2,''    SNSE='',I3)') CN,SNSE(NSG,2)
!     CALL SIDEDI(XC(NP,2),YC(NP,2),NSS,DDD,IB,JB,X,Y)
!     WRITE(9,'('' 2'',2F10.3,I6)')XC(NP,2),YC(NP,2),NSS
!     CALL SIDEDI(XC(NP+N-1,2),YC(NP+N-1,2),NSS,DDD,IB,JB,X,Y)
!     WRITE(9,'('' 2'',2F10.3,I6)')XC(NP+N-1,2),YC(NP+N-1,2),NSS
!     CALL PRT_STR(9,XC(NP,2),YC(NP,2),1,N)
                      NP=NP+N
                      N=1
                    END IF
                  END IF
                END IF
 1570         CONTINUE
            ELSE
              IS=IB(NB)-1
              IE=IB(NB+1)
              DO 1580 I=IS,IE,-1
                IF (BOX(4,I,J).EQ.'2') THEN
                  NS=4
                  CALL START4(A(I,J),X(I),Y(J),   &
                              IMX,NS,CN,XC(NP,2),YC(NP,2),   &
                              ISUBRO,IBUGG3)
                  IF (NS.GT.0) THEN
!          ->  CONTOUR-START FOUND, BEGIN CHASE
                    II=I
                    JJ=J
                    CALL CHASE(A,X,Y,IMX,JMX,II,JJ,   &
                               NS,CN,XC(NP,2),YC(NP,2),NMX,N,BOX,   &
                               ISUBRO,IBUGG3)
                    IF (N.GT.1) THEN
                      NSG=NSG+1
                      NPTS(NSG,2)=N
                      IF (A(I+1,J).LT.A(I,J)) THEN
                        SNSE(NSG,2)=1
                      ELSE
                        SNSE(NSG,2)=-1
                      END IF
                      CLSD(NSG,2)=0
!     WRITE(9,'('' CN='',F7.2,''    SNSE='',I3)') CN,SNSE(NSG,2)
!     CALL SIDEDI(XC(NP,2),YC(NP,2),NSS,DDD,IB,JB,X,Y)
!     WRITE(9,'('' 4'',2F10.3,I6)')XC(NP,2),YC(NP,2),NSS
!     CALL SIDEDI(XC(NP+N-1,2),YC(NP+N-1,2),NSS,DDD,IB,JB,X,Y)
!     WRITE(9,'('' 4'',2F10.3,I6)')XC(NP+N-1,2),YC(NP+N-1,2),NSS
!     CALL PRT_STR(9,XC(NP,2),YC(NP,2),1,N)
                      NP=NP+N
                      N=1
                    END IF
                  END IF
                END IF
 1580         CONTINUE
            END IF
          END IF
 1540   CONTINUE
!   SEARCH INTERIOR FOR CONTOUR-STARTS OF CLOSED CONTOURS
        DO 1800 I=2,IMX-1
          DO 1810 J=JMX-1,1,-1
            IF (BOX(1,I,J).EQ.'0') THEN
              NS=1
              CALL START1(A(I,J),X(I),Y(J),   &
                       IMX,NS,CN,XC(NP,2),YC(NP,2),   &
                       ISUBRO,IBUGG3)
              IF (NS.GT.0) THEN
!           ->  CONTOUR-START FOUND, BEGIN CHASE
                II=I
                JJ=J
                CALL CHASE(A,X,Y,IMX,JMX,II,JJ,   &
                           NS,CN,XC(NP,2),YC(NP,2),NMX,N,BOX,   &
                           ISUBRO,IBUGG3)
                IF (N.GT.1) THEN
                  IF (A(I,J).NE.CN) THEN
                    JIO=J
                  ELSE
                    JIO=J+1
                  END IF
                  CALL INOUT(X(I),Y(JIO),XC(NP,2),YC(NP,2),N,IO)
                  NSG=NSG+1
                  NPTS(NSG,2)=N
                  IF (A(I,J).LT.A(I,J+1)) THEN
                    SNSE(NSG,2)=1
                  ELSE
                    SNSE(NSG,2)=-1
                  END IF
                  IF (IO.EQ.1) THEN
                    IF (A(I,JIO).GT.CN) THEN
                      CLSD(NSG,2)=1
                    ELSE
                      CLSD(NSG,2)=-1
                    END IF
                  ELSE
                    IF (A(I,JIO).LT.CN) THEN
                      CLSD(NSG,2)=1
                    ELSE
                      CLSD(NSG,2)=-1
                    END IF
                  END IF
!     NSS=0
!     WRITE(9,'('' I CN='',F7.2,''    SNSE='',I3)') CN,SNSE(NSG,2)
!     WRITE(9,'('' 1'',2F10.3,I6)')XC(NP,2),YC(NP,2),NSS
!     WRITE(9,'('' 1'',2F10.3,I6)')XC(NP+N-1,2),YC(NP+N-1,2),NSS
!     CALL PRT_STR(9,XC(NP,2),YC(NP,2),1,N)
                  NP=NP+N
                  N=1
                END IF
              END IF
            END IF
 1810     CONTINUE
 1800   CONTINUE
!   END SEARCH FOR CONTOUR STARTS
        NSEG(2)=NSG
      ELSE
        NSEG(2)=0
      END IF
!   DRAW CONTOURS; FILL BETWEEN THEM IF DESIRED
        IF (NC.EQ.0) THEN
!CCCC THE FOLLOWING LINE WAS CHANGED JULY 1990
!CCCC     WLN1=999.999
          WLN1=ANINE
          IDSH1=999
          LBL1=999
!CCCC THE FOLLOWING LINE WAS CHANGED JULY 1990
!CCCC     CN1=999.999
          CN1=ANINE
        ELSE
          NC1=NCC-1
          WLN1=WLN(NC1)
          IDSH1=IDSH(NC1)
          LBL1=LBL(NC1)
          CN1=CNV(NC1)
!CCCC THE FOLLOWING LINE WAS CHANGED JULY 1990
!CCCC     IF (IDSH1.LT.0) CN1=999.999
          IF (IDSH1.LT.0) CN1=ANINE
!     WRITE(9,'('' NP='',I6)') NP
        END IF
        CALL DRWFIL(XC,YC,NMX,NSEG,NPTS,SNSE,CLSD,NSGX,X,Y,IMX,JMX,   &
         IB,JB,NBX,PRMTR,NEES,DST,CN1,WLN1,IDSH1,COLR(NCC),LBL1,   &
         LDEC,SZL,DLMM,   &
      XTEMP,YTEMP,TATEMP,NTEMP,NTRACE,   &
      IBUGG3,ISUBRO,IERROR)
 1500 CONTINUE
!   MAIN LOOP COMPLETE -> RETURN TO CALLING PROGRAM AFTER
!    CONVERTING X & Y BACK TO USER UNITS
      DO 1900 I=1,IMX
        X(I)=XMN+X(I)/XSCL
 1900 CONTINUE
      DO 1910 J=1,JMX
        Y(J)=YMN+Y(J)/YSCL
 1910 CONTINUE
      GO TO 9000
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGG3.EQ.'OFF'.AND.ISUBRO.NE.'COP2')GO TO 9090
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9011)
 9011 FORMAT('***** AT THE END       OF DPCOP2--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9012)IBUGG3,ISUBRO
 9012 FORMAT('IBUGG3,ISUBRO = ',A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9013)NTEMP,NTRACE
 9013 FORMAT('NTEMP,NTRACE = ',2I8)
      CALL DPWRST('XXX','BUG ')
      DO 9015 I=1,NTEMP
      WRITE(ICOUT,9016)I,YTEMP(I),XTEMP(I),TATEMP(I)
 9016 FORMAT('I,YTEMP(I),XTEMP(I),TATEMP(I) = ',I8,3F10.5)
      CALL DPWRST('XXX','BUG ')
 9015 CONTINUE
 9090 CONTINUE
!
      RETURN
      END SUBROUTINE DPCOP2
      SUBROUTINE DPCORU(ICOM,IHARG,NUMARG,IFOUND,IERROR)
!
!     PURPOSE--WRITE OUT A COLUMN RULER (1 TO 132)
!              TO ALLOW THE USER TO ASSESS WHAT COLUMN LIMITS
!              ARE APPROPRIATE IN READING FROM A FILE.
!     INPUT  ARGUMENTS--ICOM
!                     --IHARG
!                     --NUMARG
!     OUTPUT ARGUMENTS--IFOUND ('YES' OR 'NO')
!                     --IERROR ('YES' OR 'NO' )
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--89/12
!     ORIGINAL VERSION--NOVEMBER 1989.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 ICOM
      CHARACTER*4 IHARG
!
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
!
!---------------------------------------------------------------------
!
      DIMENSION IHARG(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IFOUND='YES'
      IERROR='NO'
!
      IF(NUMARG.GE.1.AND.IHARG(1).EQ.'RULE')GO TO 1110
      IF(ICOM.EQ.'RULE')GO TO 1110
!
      GO TO 1120
!
 1110 CONTINUE
      WRITE(ICOUT,1111)
 1111 FORMAT('123456789.123456789.123456789.123456789.123456789.',   &
      '123456789.123456789.123456789.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1112)
 1112 FORMAT('         10        20        30        40        5',   &
      '0        60        70     ')
      CALL DPWRST('XXX','BUG ')
      GO TO 9000
!
 1120 CONTINUE
      WRITE(ICOUT,1121)
 1121 FORMAT('          123456789.123456789.123456789.123456789.',   &
      '123456789.123456789.123456789.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1122)
 1122 FORMAT('                   10        20        30        4',   &
      '0        50        60     ')
      CALL DPWRST('XXX','BUG ')
      GO TO 9000
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE DPCORU
      SUBROUTINE GRKICR
!C
!C     PURPOSE--KILL (SUPPRESS) THE CARRIAGE RETURN AFTER FUTURE WRITES
!C              ON A GENERAL GRAPHICS DEVICE
!C              THIS IS NEEDED FOR SOME DEVICES IN ORDER TO
!C              READ THE CROSS-HAIR POSITION FROM THE SCREEN.
!C     NOTE--THIS SUBROUTINE IS NON-STANDARD FORTRAN
!C           AND WILL VARY FROM SITE TO SITE.
!C           THE BODY OF THIS SUBROUTINE MUST BE
!C           CHANGED BY THE IMPLEMENTOR.
!C           THIS SUBROUTINE IS FOR UNIVAC 1100/82.
!C           THE PURPOSE OF    GRKICH  IS TO SUPPRESS THE CARRIAGE RETURN
!C           AT THE END OF A WRITE STATEMENT BECAUSE IT
!C           "GETS IN THE WAY"  DURING THE
!C           READING OF THE CROSS-HAIR.
!C     WRITTEN BY--MICHAEL VOGT
!C                 COMPUTER SERVICES DIVISION
!C                 INFORMATION TECHNOLOGY LABORATORY
!C                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!C                 GAITHERSBURG, MD 20899
!C     LANGUAGE--ANSI FORTRAN (1977)
!C     VERSION NUMBER--82.6
!C     ORIGINAL VERSION--APRIL     1978.
!C     UPDATED         --APRIL     1982.
!C     UPDATED         --MAY       1982.
!C
!C---------------------------------------------------------------------
!C
!      CHARACTER*80 ISTRIN
!C
!      DIMENSION ISPKT(8)
!C
!-----COMMON----------------------------------------------------------
!
!     INCLUDE 'DPCOHO.INC'
!
!-----COMMON VARIABLES (GENERAL)--------------------------------------
!C
      INCLUDE 'DPCOP2.INC'
!C
!C-----START POINT-----------------------------------------------------
!C
!      INCLUDE FIOP
!C
!C     THE FOLLOWING IS FOR THE UNIVAC--
!C
!      IF(IHOST1.EQ.'UNIV')GO TO 510
!      GO TO 520
!  510 CONTINUE
!      GO TO 1000
!C
!C     THE FOLLOWING IS FOR THE VAX--
!C     THE FOLLOWING IS FOR THE IBM--
!C     THE FOLLOWING IS FOR THE PERKIN-ELMER--
!C     THE FOLLOWING IS FOR THE INTERDATA--
!C     THE FOLLOWING IS FOR ALL NON-UNIVAC--
!C
