! 1100 CONTINUE
!C
!      ISPKT(1)=14
!      IFUNC(ISPKT)=FSM
!      IMODE(ISPKT)=IASC
!      IIMGAD(ISPKT)=LOC(ISTRIN)
!      ISTRIN='D,@@TTY A,2'
!      ICHCT(ISPKT)=TRMLEN(ISTRIN)
!      CALL FSYMB(ISPKT)
!C
!C               *****************
!C               **  STEP 90--  **
!C               **  EXIT       **
!C               *****************
!C
! 9000 CONTINUE
       RETURN
       END
      SUBROUTINE GRRECR
!C
!C     PURPOSE--REVIVE THE CARRIAGE RETURN FOR FUTURE WRITES
!C              THIS IS NEEDED FOR SOME DEVICES AFTER
!C              READING THE CROSS-HAIR POSITION FROM THE SCREEN.
!C     NOTE--THIS SUBROUTINE IS NON-STANDARD FORTRAN
!C           AND WILL VARY FROM SITE TO SITE.
!C           THE BODY OF THIS SUBROUTINE MUST BE
!C           CHANGED BY THE IMPLEMENTOR.
!C           THIS SUBROUTINE IS FOR UNIVAC 1100/82.
!C           THE PURPOSE OF    GRKICH  IS TO REVIVE THE CARRIAGE RETURN
!C           AT THE END OF A WRITE STATEMENT.
!C           THE REASON THAT THE CARRIAGE RETURN WOULD HAVE BEEN
!C           KILLED (SUPPRESSED) IS THAT IT (FOR EXAMPLE)
!C           "GETS IN THE WAY"  DURING THE
!C           READING OF THE CROSS-HAIR.
!C     WRITTEN BY--MICHAEL VOGT
!C                 COMPUTER SERVICES DIVISION
!C                 INFORMATION TECHNOLOGY LABORATORY
!C                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!C                 GAITHERSBURG, MD 20899
