!C
!      DIMENSION ISPKT(8)
!C
!-----COMMON----------------------------------------------------------
!
!     INCLUDE 'DPCOHO.INC'
!
!-----COMMON VARIABLES (GENERAL)--------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!------START POINT-----------------------------------------------------
!
!      INCLUDE FIOP
!
!      THE FOLLOWING IS FOR THE UNIVAC--
!
!      IF(IHOST1.EQ.'UNIV')GO TO 510
!      GO TO 520
!  510 CONTINUE
!      GO TO 1000
!C
!C     THE FOLLOWING IS FOR THE VAX--
!C     THE FOLLOWING IS FOR THE IBM--
!C     THE FOLLOWING IS FOR THE PERKIN-ELMER--
!C     THE FOLLOWING IS FOR THE INTERDATA--
!C     THE FOLLOWING IS FOR ALL NON-UNIVAC--
!C
!  520 CONTINUE
!      GO TO 9000
!C
! 1000 CONTINUE
