!      IMODE(ISPKT)=IASC
!      IIMGAD(ISPKT)=LOC(ISTRIN)
!      ISTRIN='D,@@TTY A,0'
!      ICHCT(ISPKT)=TRMLEN(ISTRIN)
!      CALL FSYMB(ISPKT)
!C
!C               *****************
!C               **  STEP 90--  **
!C               **  EXIT       **
!C               *****************
!C
! 9000 CONTINUE
      RETURN
      END SUBROUTINE GRRECR                 
      SUBROUTINE UNIRAN(N,ISEED,X)
!
!     PURPOSE--THIS SUBROUTINE GENERATES A RANDOM SAMPLE OF SIZE N
!              FROM THE UNIFORM (RECTANGULAR)
!              DISTRIBUTION ON THE UNIT INTERVAL (0,1).
!              THIS DISTRIBUTION HAS MEAN = 0.5
!              AND STANDARD DEVIATION = SQRT(1/12) = 0.28867513.
!              THIS DISTRIBUTION HAS THE PROBABILITY
!              DENSITY FUNCTION F(X) = 1.
!
!     INPUT  ARGUMENTS--N      = THE DESIRED INTEGER NUMBER
!                                OF RANDOM NUMBERS TO BE
!                                GENERATED.
!                     --ISEED  = AN INTEGER ISEED VALUE
!     OUTPUT ARGUMENTS--X      = A SINGLE PRECISION VECTOR
!                                (OF DIMENSION AT LEAST N)
!                                INTO WHICH THE GENERATED
!                                RANDOM SAMPLE WILL BE PLACED.
!     OUTPUT--A RANDOM SAMPLE OF SIZE N
!             FROM THE RECTANGULAR DISTRIBUTION ON (0,1).
!     PRINTING--NONE UNLESS AN INPUT ARGUMENT ERROR CONDITION EXISTS.
!     RESTRICTIONS--THERE IS NO RESTRICTION ON THE MAXIMUM VALUE
!                   OF N FOR THIS SUBROUTINE.
!     OTHER           SUBROUTINES NEEDED--NONE.
!     FORTRAN LIBRARY SUBROUTINES NEEDED--NONE.
!     MODE OF INTERNAL OPERATIONS--SINGLE PRECISION.
!     LANGUAGE--ANSI FORTRAN (1977)
!
!     ALGORITHM--FIBONACCI GENERATOR
!                AS DEFINED BY GEORGE MARSAGLIA.
!
!     NOTE--THIS GENERATOR IS TRANSPORTABLE.
!           IT IS NOT MACHINE-INDEPENDENT
!           IN THE SENSE THAT FOR A GIVEN VALUE
!           OF THE INPUT SEED ISEED AND FOR A GIVEN VALUE
!           OF MDIG (TO BE DEFINED BELOW),
!           THE SAME SEQUENCE OF UNIRFORM RANDOM
!           NUMBERS WILL RESULT ON DIFFERENT COMPUTERS
!           (VAX, PRIME, PERKIN-ELMER, IBM, UNIVAC, HONEYWELL, ETC.)
!
!     NOTE--IF MDIG = 32 AND IF ISEED = 305,
!           THEN THE OUTPUT FROM THIS GENERATOR SHOULD BE AS FOLLOWS--
!           THE FIRST      NUMBER TO RESULT IS .4771580...
!           THE SECOND     NUMBER TO RESULT IS .4219293...
!           THE THIRD      NUMBER TO RESULT IS .6646181...
!           ...
!           THE THOUSANDTH NUMBER TO RESULT IS .2036834...
!
!     NOTE--IF MDIG = 16 AND IF ISEED = 305,
!           THEN THE OUTPUT FROM THIS GENERATOR SHOULD BE AS FOLLOWS--
!           THE FIRST      NUMBER TO RESULT IS .027832881...
!           THE SECOND     NUMBER TO RESULT IS .56102176...
!           THE THIRD      NUMBER TO RESULT IS .41456343...
!           ...
!           THE THOUSANDTH NUMBER TO RESULT IS .19797357...
!
!     NOTE--IT IS RECOMMENDED THAT UPON
!           IMPLEMENTATION OF DATAPLOT, THE OUTPUT
!           FROM UNIRAN BE CHECKED FOR AGREEMENT
!           WITH THE ABOVE SAMPLE OUTPUT.
!           ALSO, THERE ARE MANY ANALYSIS AND DIAGNOSTIC
!           TOOLS IN DATAPLOT THAT WILL ALLOW THE
!           TESTING OF THE RANDOMNESS AND UNIFORMITY
!           OF THIS GENERATOR.
!           SUCH CHECKING IS ESPECIALLY IMPORTANT
!           IN LIGHT OF THE FACT THAT OTHER DATAPLOT RANDOM
!           NUMBER GENERATOR SUBROUTINES (NORRAN--NORMAL,
!           LOGRAN--LOGISTIC, ETC.) ALL MAKE USE OF INTERMEDIATE
!           OUTPUT FROM UNIRAN.
!
!     NOTE--THE OUTPUT FROM THIS SUBROUTINE DEPENDS
!           ON THE INPUT SEED (ISEED) AND ON THE
!           VALUE OF MDIG.
!           MDIG MAY NOT BE SMALLER THAN 16.
!           MDIG MAY NOT BE LARGER THAN MAX INTEGER ON YOUR COMPUTER.
!
!     NOTE--BECAUSE OF THE PREPONDERANCE OF MAINFRAMES
!           WHICH HAVE WORDS OF 32 BITS AND LARGER
!           (E.G, VAX (= 32 BITS), UNIVAC (= 36 BITS), CDC (= 60 BITS), ETC.)
!           MDIG HAS BEEN SET TO 32.
!           THUS THE SAME SEQUENCE OF RANDOM NUMBERS SHOULD RESULT
!           ON ALL OF THESE COMPUTERS.
!
!     NOTE--FOR SMALLER WORD SIZE COMPUTERS (E.G., 24-BIT AND 16-BIT),
!           THE VALUE OF MDIG SHOULD BE CHANGED TO 24 OR 16.
!           IN SUCH CASE, THE OUTPUT WILL NOT BE IDENTICAL TO
!           THE OUTPUT WHEN MDIG = 32.
!
!     NOTE--THE CYCLE OF THE RANDOM NUMBERS DEPENDS ON MDIG.
!           THE CYCLE FROM MDIG = 32 IS LONG ENOUGH FOR MOST
!           PRACTICAL APPLICATIONS.
!           IF A LONGER CYCLE IS DESIRED, THEN INCREASE MDIG.
!
!     NOTE--THE SEED MAY BE ANY POSITIVE INTEGER.
!           NO APPRECIABLE DIFFERENCE IN THE QUALITY
!           OF THE RANDOM NUMBERS HAS BEEN NOTED
!           BY THE CHOICE OF THE SEED.  THERE IS NO
!           NEED TO USE PRIMES, NOR TO USE EXCEPTIONALLY
!           LARGE NUMBERS, ETC.
!
!     REFERENCES--MARSAGLIA G., "COMMENTS ON THE PERFECT UNIFORM RANDOM
!                 NUMBER GENERATOR", UNPUBLISHED NOTES, WASH S. U.
!               --JOHNSON AND KOTZ, CONTINUOUS UNIVARIATE
!                 DISTRIBUTIONS--2, 1970, PAGES 57-74.
!     WRITTEN BY--JAMES BLUE
!                 SCIENTIFIC COMPUTING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899
!               --DAVID KAHANER
!                 SCIENTIFIC COMPUTING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!               --GEORGE MARSAGLIA
!                 COMPUTER SCIENCE DEPARTMENT
!                 WASHINGTON STATE UNIVERSITY
!               --JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!
!     LANGUAGE--ANSI FORTRAN (1977)
!     ORIGINAL VERSION--JUNE      1972.
!     UPDATED         --AUGUST    1974.
!     UPDATED         --SEPTEMBER 1975.
!     UPDATED         --NOVEMBER  1975.
!     UPDATED         --NOVEMBER  1981.
!     UPDATED         --MAY       1982.
!     UPDATED         --MARCH     1984.
!     UPDATED         --MAY       2002. ADD SUPPORT FOR ADDITIONAL
!                                       RANDOM NUMBER GENERATORS.
!                                       INITIAL LIST INCLUDES:
!                                       RUNIF = LINEAR CONGRUENTIAL
!                                       SUNIF = MULTIPLICATIVE
!                                               CONGRUENTIAL
!                                       NOTE THAT DEFAULT GENERATOR
!                                       IS EQUIVALENT TO CMLIB
!                                       ROUTINE "UNI" (SO WE DO NOT
!                                       INCLUDE THAT ONE).
!                                       GENERALIZED FEEDBACK SHIFT
!                                       REGISTER (GFSR) OF PAYNE AND
!                                       LEWIS (AS IMPLEMENTED BY
!                                       MONOHAN).
!                                       GENERALIZED FEEDBACK SHIFT
!                                       REGISTER (GFSR) OF FUSHIMI AND
!                                       TEZUKA (AS IMPLEMENTED BY
!                                       MONOHAN).
!                                       APPLIED STATISTICS 183 (SUM
!                                       OF 3 MULTIPLICATIVE
!                                       CONGRUENTIAL GENERATORS)
!     UPDATED         --APRIL     2003. ADD ALAN GENZ GENERATOR
!     UPDATED         --MAY       2003. ADD R250 AND RANLUX
!                                       GENERATORS
!     UPDATED         --NOVEMBER  2003. ADD MERSENNE TWISTER
!                                       ALGORITHM
!     UPDATED         --DECEMBER  2003. SEPARATE SEED VALUES FOR
!                                       DIFFERENT GENERATORS
!     UPDATED         --OCTOBER   2009. SAVE ISED1 - ISED11 IN COMMON
!                                       (SO CALLING ROUTINES CAN
!                                       "RE-INITIALIZE" SEED IF SO
!                                       DESIRED)
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!---------------------------------------------------------------------
!
      DIMENSION X(*)
!
      DIMENSION M(17)
      DIMENSION T(33)
!
      EXTERNAL UNI
      DOUBLE PRECISION UNI
!CCCC DOUBLE PRECISION GRND
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOST.INC'
      INCLUDE 'DPCOP2.INC'
!
!-----SAVE STATEMENTS-------------------------------------------------
!
      COMMON/ISED/ISED1,ISED2,ISED3,ISED4,ISED5,ISED6,   &
                  ISED7,ISED8,ISED9,ISED10,ISED11
!
      SAVE I,J,M,M1,M2
!CCCC SAVE ISED1,ISED2,ISED3,ISED4,ISED5,ISED6
!CCCC SAVE ISED7,ISED8,ISED9,ISED10,ISED11
      SAVE ISDSAV
      SAVE T
!
!-----DATA STATEMENTS-------------------------------------------------
!
      DATA M(1),M(2),M(3),M(4),M(5),M(6),M(7),M(8),M(9),M(10),M(11),   &
           M(12),M(13),M(14),M(15),M(16),M(17)   &
      /    30788,23052,2053,19346,10646,19427,23975,   &
           19049,10949,19693,29746,26748,2796,23890,   &
           29168,31924,16499/
      DATA M1,M2,I,J / 32767,256,5,17 /
      DATA ISED1 /0/
      DATA ISED2 /0/
      DATA ISED3 /0/
      DATA ISED4 /0/
      DATA ISED5 /0/
      DATA ISED6 /0/
      DATA ISED7 /0/
      DATA ISED8 /0/
      DATA ISED9 /0/
      DATA ISED10 /0/
      DATA ISED11 /0/
      DATA ISDSAV /305/
!
!-----START POINT-----------------------------------------------------
!
!               ********************************************
!               **  STEP 1--                              **
!               **  CHECK THE INPUT ARGUMENTS FOR ERRORS  **
!               ********************************************
!
      IF(N.LT.1)THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** ERROR IN UNIRAN--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)
   52   FORMAT('      THE INPUT NUMBER OF OBSERVATIONS IS ',   &
               'NON-POSITIVE.')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)N
   53   FORMAT('      N = ',I8)
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
      IF(IRANAL.EQ.'FIBO')GO TO 1000
      IF(IRANAL.EQ.'FIBC')GO TO 1500
      IF(IRANAL.EQ.'LINE')GO TO 2000
      IF(IRANAL.EQ.'MULT')GO TO 3000
      IF(IRANAL.EQ.'GFSR')GO TO 4000
      IF(IRANAL.EQ.'GFS2')GO TO 5000
      IF(IRANAL.EQ.'183 ')GO TO 6000
      IF(IRANAL.EQ.'GENZ')GO TO 7000
      IF(IRANAL.EQ.'R250')GO TO 8000
      IF(IRANAL.EQ.'LUXU')GO TO 8500
      IF(IRANAL.EQ.'MERT')GO TO 8600
!
 1000 CONTINUE
!
!               *******************************************************
!               **  STEP 2--                                         **
!               **  IF A POSITIVE INPUT SEED HAS BEEN GIVEN,         **
!               **  THEN THIS INDICATES THAT THE GENERATOR           **
!               **  SHOULD HAVE ITS INTERNAL M(.) ARRAY REDEFINED--  **
!               **  DO SO IN THIS SECTION.                           **
!               **  IF A NON-POSITIVE INPUT SEED HAS BEEN GIVEN,     **
!               **  THEN THIS INDICATES THAT THE GENERATOR           **
!               **  SHOULD CONTINUE ON FROM WHERE IT LEFT OFF,       **
!               **  AND THEREFORE THIS SECTION IS SKIPPED.           **
!               *******************************************************
!
!CCCC IF(ISEED.LE.0)GO TO 290
!
!  INITIALIZE IF NECESSARY
!
      IF(ISED1.EQ.0)THEN
        ISED1=-1
        IF(ISEED.GT.0)THEN
          ISDSAV=ISEED
        ELSE
          ISEED=ISDSAV
        ENDIF
      ELSE
        IF(ISEED.LE.0)GO TO 290
        ISDSAV=ISEED
      ENDIF
!
!  END OF INITIALIZATION
!
!
!CCCC MDIG=16
      MDIG=32
!
      M1=2**(MDIG-2)+(2**(MDIG-2)-1)
      M2=2**(MDIG/2)
!CCCC ISEED3=MIN0(IABS(ISEED),M1)
      ISEED3=IABS(ISEED)
      IF(M1.LT.IABS(ISEED))ISEED3=M1
      IF(MOD(ISEED3,2).EQ.0)ISEED3=ISEED3-1
      K0=MOD(9069,M2)
      K1=9069/M2
      J0=MOD(ISEED3,M2)
      J1=ISEED3/M2
!
      DO 200 I=1,17
      ISEED3=J0*K0
      J1=MOD(ISEED3/M2+J0*K1+J1*K0,M2/2)
      J0=MOD(ISEED3,M2)
      M(I)=J0+M2*J1
  200 CONTINUE
!
      I=5
      J=17
!
  290 CONTINUE
!
!               *************************************
!               **  STEP 3--                       **
!               **  GENERATE THE N RANDOM NUMBERS  **
!               *************************************
!
      DO 300 L=1,N
        K=M(I)-M(J)
        IF(K.LT.0)K=K+M1
        M(J)=K
        I=I-1
        IF(I.EQ.0)I=17
        J=J-1
        IF(J.EQ.0)J=17
        AK=K
        AM1=M1
        X(L)=AK/AM1
  300 CONTINUE
!
!               *****************************************************
!               **  STEP 4--                                       **
!               **  REGARDLESS OF THE VALUE OF THE INPUT SEED,     **
!               **  REDEFINE THE VALUE OF ISEED UPON EXIT HERE     **
!               **  TO -1 WITH THE NET EFFECT THAT                 **
!               **  IF THE USER DOES NOT REDEFINE THE SEED         **
!               **  VALUE BEFORE THE NEXT CALL TO THIS GENERATOR,  **
!               **  THEN THIS GENERATOR WILL PICK UP               **
!               **  WHERE IT LEFT OFF.                             **
!               *****************************************************
!
      ISEED=(-1)
      GO TO 9000
!
!               *****************************************
!               **  STEP 1500--                        **
!               **  GENERATE THE N RANDOM NUMBERS      **
!               **  USING THE COMBINED FIBONACCI/      **
!               **  CONGUENTIAL GENERATOR OF           **
!               **  KAHANER AND MARSAGALIA GIVEN       **
!               **  IN "NUMERICAL METHODS AND SOFTWARE"**
!               **  BY KAHANER, MOLER, AND NASH.       **
!               *****************************************
!
 1500 CONTINUE
!
!  INITIALIZE IF NECESSARY
!
      IF(ISED2.EQ.0)THEN
        IF(ISEED.GT.0)THEN
          ISDSAV=ISEED
          USEED=USTART(ISEED)
          ISEED=(-1)
        ELSE
          USEED=USTART(ISDSAV)
        ENDIF
        ISED2=-1
      ELSE
        IF(ISEED.GT.0)THEN
          ISDSAV=ISEED
          USEED=USTART(ISEED)
          ISEED=(-1)
        ENDIF
      ENDIF
!
!  END OF INITIALIZATION
!
      DO 1510 L=1,N
        X(L)=UNIKMN()
 1510 CONTINUE
      GO TO 9000
!
!               *************************************
!               **  STEP 2000--                    **
!               **  GENERATE THE N RANDOM NUMBERS  **
!               **  USING THE LINEAR CONGRUENTIAL  **
!               **  GENERATOR RUNIF (FROM CMLIB).  **
!               *************************************
!
!     NOTE: THIS GENERATOR DOES NOT HAVE A SEED VALUE.  SO DON'T
!           CHECK FOR THE SEED.
!
 2000 CONTINUE
      NSIZE=32
      NSTRT=1
!
!  INITIALIZE IF NECESSARY
!
!CCCC IF(ISED3.EQ.0)THEN
!CCCC   NSTRT=2
!CCCC   IF(ISEED.GT.0)THEN
!CCCC     ISDSAV=ISEED
!CCCC     X(1)=RUNIF(T,NSIZE)
!CCCC     ISEED=(-1)
!CCCC   ELSE
!CCCC     X(1)=RUNIF(T,NSIZE)
!CCCC   ENDIF
!CCCC   ISED3=-1
!CCCC ELSE
!CCCC   IF(ISEED.GT.0)THEN
!CCCC     ISDSAV=ISEED
!CCCC     X(1)=RUNIF(T,NSIZE)
!CCCC     ISEED=(-1)
!CCCC     NSTRT=2
!CCCC   ENDIF
!CCCC ENDIF
!
      IF(ISED3.EQ.0)THEN
        NSTRT=2
        ISED3=-1
      ELSE
        NSTRT=1
      ENDIF
!
!  END OF INITIALIZATION
!
      IF(NSTRT.EQ.2)THEN
        X(1)=RUNIF(T,NSIZE)
      ENDIF
!
      IF(NSTRT.LE.N)THEN
        DO 2020 L=NSTRT,N
          X(L)=RUNIF(T,NSIZE)
 2020   CONTINUE
      ENDIF
!CCCC ISEED=(-1)
      GO TO 9000
!
!               **********************************************
!               **  STEP 3000--                             **
!               **  GENERATE THE N RANDOM NUMBERS           **
!               **  USING THE MULTIPLICATIVE CONGRUENTIAL   **
!               **  GENERATOR SUNIF (FROM ACM 599).         **
!               **********************************************
!
 3000 CONTINUE
!
!  INITIALIZE IF NECESSARY
!
!  ISED3 = 0   - THIS GENERATOR HAS NOT BEEN INITIALIZED YET
!  ISEED > 0   - A NEW INITIALIZATION IS BEING REQUESTED
!
!  FOR THIS GENERATOR, THE SEED SHOULD BE OF THE FORM  4*K + 1
!
      NSTRT=1
!
!  CASE WHERE GENERATOR HAS NOT BEEN INITIALIZED.  IF ISEED IS -1 (I.E.,
!  ANOTHER GENERATOR HAS BEEN CALLED), THEN RESET DEFAULT SEED.
!
      IF(ISED3.EQ.0)THEN
        NSTRT=2
        IF(ISEED.GT.0)THEN
          ISDSAV=ISEED
          IREM=MOD(ISEED,4)
          IF(IREM.EQ.0)ISEED2=ISEED+1
          IF(IREM.EQ.1)ISEED2=ISEED
          IF(IREM.EQ.2)ISEED2=ISEED+3
          IF(IREM.EQ.3)ISEED2=ISEED+2
          X(1)=SUNIF(ISEED2)
          ISEED=ISEED2
        ELSE
          ISEED2=ISDSAV
          IREM=MOD(ISEED2,4)
          IF(IREM.EQ.0)ISEED2=ISEED2+1
          IF(IREM.EQ.1)ISEED2=ISEED2
          IF(IREM.EQ.2)ISEED2=ISEED2+3
          IF(IREM.EQ.3)ISEED2=ISEED2+2
          X(1)=SUNIF(ISEED2)
          ISEED=ISEED2
        ENDIF
        ISED3=-1
!
!  CASE WHERE GENERATOR HAS BEEN PREVIOUSLY INITIALIZED.  IF ISEED > 0,
!  THIS IMPLIES A NEW INITIALIZATION IS BEING REQUESTED.
!
      ELSE
        IF(ISEED.GT.0)THEN
          ISDSAV=ISEED
          IREM=MOD(ISEED,4)
          IF(IREM.EQ.0)ISEED2=ISEED+1
          IF(IREM.EQ.1)ISEED2=ISEED
          IF(IREM.EQ.2)ISEED2=ISEED+3
          IF(IREM.EQ.3)ISEED2=ISEED+2
          X(1)=SUNIF(ISEED2)
          ISEED=(-1)
          NSTRT=2
        ELSE
          NSTRT=1
        ENDIF
      ENDIF
!
!  END OF INITIALIZATION
!
      IF(NSTRT.LE.N)THEN
        DO 3020 L=NSTRT,N
          X(L)=SUNIF(ISEED)
 3020   CONTINUE
        ISEED=(-1)
      ENDIF
      GO TO 9000
!
!               **********************************************
!               **  STEP 4000--                             **
!               **  GENERATE THE N RANDOM NUMBERS           **
!               **  USING THE GENERALIZED FEEDACK SHIFT     **
!               **  REGISTER (GFSR) GENERATOR RANLP (FROM   **
!               **  MONOHAM, 2001).                         **
!               **********************************************
!
!     2019/11: ALTHOUGH THIS METHOD DOES NOT UTILIZED A SEED,
!              DO ALLOW IT TO BE RESET (THIS CAN BE USEFUL FOR
!              TESTING PURPOSES).
!
 4000 CONTINUE
!
      IRESET=0
      IF(ISED4.EQ.0)THEN
        ISED4=-1
        ISDSAV=ISEED
      ELSE
        IF(ISEED.GT.0 .AND. ISDSAV.NE.ISEED)THEN
          IRESET=1
          ISDSAV=ISEED
        ENDIF
      ENDIF
!
      DO 4020 L=1,N
!CCCC   X(L)=RANLP(L,IRESET)
        X(L)=RANLP(IRESET)
        IRESET=0
 4020 CONTINUE
      GO TO 9000
!
!               **********************************************
!               **  STEP 5000--                             **
!               **  GENERATE THE N RANDOM NUMBERS           **
!               **  USING THE GENERALIZED FEEDACK SHIFT     **
!               **  REGISTER (GFSR) GENERATOR RANFT (FROM   **
!               **  MONOHAM, 2001).                         **
!               **********************************************
!
!     2019/11: ALTHOUGH THIS METHOD DOES NOT UTILIZED A SEED,
!              DO ALLOW IT TO BE RESET (THIS CAN BE USEFUL FOR
!              TESTING PURPOSES).
!
 5000 CONTINUE
      IRESET=0
      IF(ISED5.EQ.0)THEN
        ISED5=-1
        ISDSAV=ISEED
      ELSE
        IF(ISEED.GT.0 .AND. ISDSAV.NE.ISEED)THEN
          IRESET=1
          ISDSAV=ISEED
        ENDIF
      ENDIF
!
      DO 5020 L=1,N
!CCCC   X(L)=RANFT(L,IRESET)
        X(L)=RANFT(IRESET)
        IRESET=0
 5020 CONTINUE
      GO TO 9000
!
!               **********************************************
!               **  STEP 6000--                             **
!               **  GENERATE THE N RANDOM NUMBERS           **
!               **  USING APPLIED STATISTICS ALGORITHM 183. **
!               **  NOTE: GENERATE 3 RANDOM NUMBERS BEFORE  **
!               **  CALLING RAN183.                         **
!               **********************************************
!
 6000 CONTINUE
!
!  INITIALIZE IF NECESSARY
!
      IF(ISED6.EQ.0)THEN
        IF(ISEED.GT.0)THEN
          ISDSAV=ISEED
        ELSE
          ISEED=ISDSAV
        ENDIF
        IREM=MOD(ISEED,4)
        IF(IREM.EQ.0)ISEED2=ISEED+1
        IF(IREM.EQ.1)ISEED2=ISEED
        IF(IREM.EQ.2)ISEED2=ISEED+3
        IF(IREM.EQ.3)ISEED2=ISEED+2
        XTEMP=SUNIF(ISEED2)
        IX=INT(30000.*XTEMP)
        XTEMP=SUNIF(ISEED2)
        IY=INT(30000.*XTEMP)
        XTEMP=SUNIF(ISEED2)
        IZ=INT(30000.*XTEMP)
        ISED6=-1
        ISEED=(-1)
      ELSE
        IF(ISEED.GT.0)THEN
          ISDSAV=ISEED
          IREM=MOD(ISEED,4)
          IF(IREM.EQ.0)ISEED2=ISEED+1
          IF(IREM.EQ.1)ISEED2=ISEED
          IF(IREM.EQ.2)ISEED2=ISEED+3
          IF(IREM.EQ.3)ISEED2=ISEED+2
          XTEMP=SUNIF(ISEED2)
          IX=INT(30000.*XTEMP)
          XTEMP=SUNIF(ISEED2)
          IY=INT(30000.*XTEMP)
          XTEMP=SUNIF(ISEED2)
          IZ=INT(30000.*XTEMP)
          ISEED=(-1)
        ELSE
          XTEMP=SUNIF(ISEED)
          IX=INT(30000.*XTEMP)
          XTEMP=SUNIF(ISEED)
          IY=INT(30000.*XTEMP)
          XTEMP=SUNIF(ISEED)
          IZ=INT(30000.*XTEMP)
        ENDIF
      ENDIF
!
!  END OF INITIALIZATION
!
!
      DO 6020 L=1,N
        X(L)=RAN183(IX,IY,IZ)
 6020 CONTINUE
      GO TO 9000
!
!               **********************************************
!               **  STEP 7000--                             **
!               **  GENERATE THE N RANDOM NUMBERS           **
!               **  USING ALGORITHM FROM ALAN GENZ.  BASED  **
!               **  ON: L'Ecuyer, Pierre (1996).  "Combined **
!               **  Multiple Recursive Random Number        **
!               **  Generator", Operations Research 44,     **
!               **  pp. 816-822.                            **
!               **********************************************
!
 7000 CONTINUE
!
!     2019/11: ALTHOUGH THIS METHOD DOES NOT UTILIZED A SEED,
!              DO ALLOW IT TO BE RESET (THIS CAN BE USEFUL FOR
!              TESTING PURPOSES).
!
      IRESET=0
      IF(ISED7.EQ.0)THEN
        ISED7=-1
        ISDSAV=ISEED
      ELSE
        IF(ISEED.GT.0 .AND. ISDSAV.NE.ISEED)THEN
          IRESET=1
          ISDSAV=ISEED
        ENDIF
      ENDIF
!
      DO 7020 L=1,N
        X(L)=REAL(UNI(IRESET))
        IRESET=0
 7020 CONTINUE
      GO TO 9000
!               **********************************************
!               **  STEP 8000--                             **
!               **  GENERATE THE N RANDOM NUMBERS           **
!               **  USING R250 ALGORITHM.                   **
!               **  BASED ON KIRKPATRICK AND STOLL          **
!               **  FAST SHIFT-REGISTER SEQUENCE GENERATOR. **
!               **********************************************
!
 8000 CONTINUE
!
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,8051)
 8051 FORMAT('***** WARNING FROM UNIRAN--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,8053)
 8053 FORMAT('      THE R250 GENERATOR IS NOT CURRENTLY WORKING.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,8055)
 8055 FORMAT('      THE RESULTS FROM THIS GENERATOR ARE NOT VALID.')
      CALL DPWRST('XXX','BUG ')
!
!
!  INITIALIZE IF NECESSARY
!
!CCCC IF(ISED8.EQ.0)THEN
!CCCC   IF(ISEED.GT.0)THEN
!CCCC     ISDSAV=ISEED
!CCCC     CALL R250IN(ISEED)
!CCCC     ISEED=(-1)
!CCCC   ELSE
!CCCC     CALL R250IN(ISDSAV)
!CCCC   ENDIF
!CCCC   ISED8=-1
!CCCC ELSE
!CCCC   IF(ISEED.GT.0)THEN
!CCCC     ISDSAV=ISEED
!CCCC     CALL R250IN(ISEED)
!CCCC     ISEED=(-1)
!CCCC   ENDIF
!CCCC ENDIF
!
!  END OF INITIALIZATION
!
!CCCC DO8050L=1,N
!CCCC   X(L)=RND250()
!8050 CONTINUE
      GO TO 9000
!               **********************************************
!               **  STEP 8500--                             **
!               **  GENERATE THE N RANDOM NUMBERS           **
!               **  USING LUXURY GENERATOR OF F. JAMES.     **
!               **  THIS IS A MODIFICATION OF MARSAGLIA AND **
!               **  ZAMAN RCARRY GENERATOR.                 **
!               **  RANLUX KEEPS TRACK OF INITIALIZATION    **
!               **********************************************
!
 8500 CONTINUE
!
      CALL RANLUX(X,N)
      GO TO 9000
!
!               **********************************************
!               **  STEP 8600--                             **
!               **  GENERATE THE N RANDOM NUMBERS           **
!               **  USING MERSENNE TWISTER GENERATOR.       **
!               **  THIS IS A FORTRAN IMPLEMENTATION        **
!               **  PROVIDED BY HIROSHI TAKANO.             **
!               **********************************************
!
!CCCC MARCH 2009: COMMENT OUT THIS GENERATOR FOR NOW
 8600 CONTINUE
!
!
!  INITIALIZE IF NECESSARY
!
!CCCC IF(ISED10.EQ.0)THEN
!CCCC   IF(ISEED.GT.0)THEN
!CCCC     ISDSAV=ISEED
!CCCC     CALL SGRND(ISEED)
!CCCC     ISEED=(-1)
!CCCC   ELSE
!CCCC     ISEED=ISDSAV
!CCCC     CALL SGRND(ISEED)
!CCCC   ENDIF
!CCCC   ISED10=-1
!CCCC ELSE
!CCCC   IF(ISEED.GT.0)THEN
!CCCC     ISDSAV=ISEED
!CCCC     CALL SGRND(ISEED)
!CCCC     ISEED=(-1)
!CCCC   ENDIF
!CCCC ENDIF
!
!  END OF INITIALIZATION
!
!CCCC DO8610I=1,N
!CCCC   X(I)=REAL(GRND())
!8610 CONTINUE
!
      GO TO 9000
!
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      RETURN
!CCCC DEBUG TRACE,INIT
!CCCC AT 90
!CCCC TRACE ON
      END SUBROUTINE UNIRAN
      SUBROUTINE DPTRAN(IHARG,IHARG2,NUMARG,   &
                        ICTRA1,NCTRA1,ICTRA2,NCTRA2,NUMTRA,   &
                        IBUGS2,ISUBRO,IFOUND,IERROR)
!
!     PURPOSE--CREATE USER-DEFINED STRING TRANSLATIONS
!              WHICH WILL ALLOW EVERY SUB-STRING THAT COMES OUT
!              OF SUBROUTINE    GRWRST   TO BE TRANSLATED
!              IF SO DESIRED.
!     EXAMPLE OF USE--THE UNIVERSITY OF MARYLAND GANDOLPH
!                     COMMUNICATIONS BOX EATSD UP ESCAPES
!                     (NOT ONLY FROM THE TERMINAL) BUT ALSO
!                     FROM THE HOSST--THUS AN ESCAPE FORMFEED
!                     FROM THE HOST TO CLEAR THE SCREEN RESULTS
!                     IN ONLY A FORMFEED (AND THUS THERE IS NO
!                     HOST-GENERATED WAY TO CLEAR THE SCREEN).
!                     THIS PROBLEM CAN NOW BE SOLVED VIA THE
!                     TRANSLATE COMMAND BY TELLING DATAPLOT
!                     TRANSLATE ESC FF TO ESC ESC FF
!                     AND THUS THE SECOND ESC WILL GET THROUGH
!                     AND THE SCREEN WILL BE CLEARED.
!      INPUT  ARGUMENTS--IHARG   (A CHARACTER VECTOR)
!                      --IHARG2  (A CHARACTER VECTOR)
!                      --NUMARG
!      OUTPUT ARGUMENTS--ICTRA1
!                        NCTRA1
!                        ICTRA2
!                        NCTRA2
!                        NUMTRA
!                        IFOUND
!                        IERROR
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--86/6
!     ORIGINAL VERSION--FEBRUARY  1986.
!     UPDATED         --JANUARY   1989.  BUG FIX FROM JJF NOTES (ALAN)
!
!-----NON-COMMON VARIABLES----------------------------------------
!
      CHARACTER*4 IHARG
      CHARACTER*4 IHARG2
!
      CHARACTER*30 ICTRA1
      CHARACTER*30 ICTRA2
!
      CHARACTER*1 IC1
      CHARACTER*4 IC4
      CHARACTER*30 ISTRIN
!
      CHARACTER*4 IBUGS2
      CHARACTER*4 ISUBRO
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
!
      DIMENSION IHARG(*)
      DIMENSION IHARG2(*)
!
      DIMENSION ICTRA1(*)
      DIMENSION NCTRA1(*)
      DIMENSION ICTRA2(*)
      DIMENSION NCTRA2(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCONP.INC'
!
!-----COMMON VARIABLES (GENERAL)--------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPTR'
      ISUBN2='AN  '
      IFOUND='YES'
      IERROR='NO'
!
      IF(IBUGS2.EQ.'ON' .OR. ISUBRO.EQ.'DEFI')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('AT THE BEGINNING OF DPTRAN--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)IBUGS2,ISUBRO,IFOUND,IERROR,NUMARG,NUMTRA
   53   FORMAT('IBUGS2,ISUBRO,IFOUND,IERROR,NUMARG,NUMTRA = ',   &
               4(A4,2X),2I8)
        CALL DPWRST('XXX','BUG ')
        IF(NUMARG.GE.1)THEN
          DO 56 I=1,NUMARG
            WRITE(ICOUT,57)I,IHARG(I),IHARG2(I)
   57       FORMAT('I,IHARG(I),IHARG2(I) = ',I8,2(2X,A4))
            CALL DPWRST('XXX','BUG ')
   56     CONTINUE
        ENDIF
        IF(NUMTRA.GE.1)THEN
          DO 62 I=1,NUMTRA
            WRITE(ICOUT,63)I,ICTRA1(I),NCTRA1(I)
   63       FORMAT('I,ICTRA1(I),NCTRA1(I) = ',I8,2X,A30,I8)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,64)I,ICTRA2(I),NCTRA2(I)
   64       FORMAT('I,ICTRA2(I),NCTRA2(I) = ',I8,2X,A30,I8)
            CALL DPWRST('XXX','BUG ')
   62     CONTINUE
        ENDIF
      ENDIF
!
!               ************************************************
!               **  STEP 11--                                 **
!               **  LOCATE THE LOCATION IN THE ARGUMENT LIST  **
!               **  OF THE WORD    TO     .                   **
!               ************************************************
!
      ILOCTO=0
      IF(NUMARG.LE.0)GO TO 1120
      DO 1100 I=1,NUMARG
        ILOCTO=I
        IF(IHARG(I).EQ.'TO  ')GO TO 1190
 1100 CONTINUE
!
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1111)
 1111 FORMAT('***** ERROR IN SUBROUTINE DPTRAN--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1112)
 1112 FORMAT('      WHEN USING THE TRANSLATE COMMAND, YOU MUST ',   &
             'USE   TO')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1114)
 1114 FORMAT('      TO SEPARATE THE OLD STRING FROM THE NEW STRING, ',   &
             'AS IN')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1116)
 1116 FORMAT('         TRANSLATE ESC FF TO ESC ESC FF')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1117)
 1117 FORMAT('      PROBLEM--   TO   WAS NOT FOUND.')
      CALL DPWRST('XXX','BUG ')
      IERROR='YES'
      GO TO 9000
!
 1120 CONTINUE
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1121)
 1121 FORMAT('***** ERROR IN SUBROUTINE DPTRAN--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1122)
 1122 FORMAT('      NO ARGUMENTS FOUND AFTER THE WORD   ',   &
             'TRANSLATE')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1124)NUMARG
 1124 FORMAT('NUMARG = ',I8)
      CALL DPWRST('XXX','BUG ')
      IERROR='YES'
      GO TO 9000
!
 1190 CONTINUE
!
!               ***************************************************
!               **  STEP 12--                                    **
!               **  DETERMINE THE ELEMENT NUMBER FOR THE STRING  **
!               ***************************************************
!
      I2=NUMTRA+1
      IF(I2.LE.100)GO TO 1290
!
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1211)
 1211 FORMAT('***** ERROR IN SUBROUTINE DPTRAN--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1212)
 1212 FORMAT('      WHEN USING THE TRANSLATE COMMAND, YOU CAN HAVE')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1214)
 1214 FORMAT('      AT MOST 100 SEQUENCES TO TRANSLATE;')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1215)
 1215 FORMAT('      YOU HAVE JUST EXCEEDED 100.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1216)I2
 1216 FORMAT('      I2 = ',I8)
      CALL DPWRST('XXX','BUG ')
      IERROR='YES'
      GO TO 9000
!
 1290 CONTINUE
!
!               ***************************************************
!               **  STEP 21--                                    **
!               **  EXTRACT THE INPUT SEQUENCE.                   **
!               ***************************************************
!
      ISTRIN(1:30)='                              '
      ICTRA1(I2)=ISTRIN(1:30)
      NCTRA1(I2)=0
!
      J=0
      IMAX=ILOCTO-1
      IF(IMAX.LE.0)GO TO 2180
      DO 2100 I=1,IMAX
      J=J+1
      IC4=IHARG(I)
!
      IC1=IC4(1:1)
      IF(IC4(1:3).EQ.'NUL')IC1=INULC
      IF(IC4(1:3).EQ.'SOH')IC1=ISOHC
      IF(IC4(1:3).EQ.'STX')IC1=ISTXC
      IF(IC4(1:3).EQ.'ETX')IC1=IETXC
      IF(IC4(1:3).EQ.'EOT')IC1=IEOTC
      IF(IC4(1:3).EQ.'ENQ')IC1=IENQC
      IF(IC4(1:3).EQ.'ACK')IC1=IACKC
      IF(IC4(1:3).EQ.'BEL')IC1=IBELC
      IF(IC4(1:2).EQ.'BS')IC1=IBSC
      IF(IC4(1:3).EQ.'HTX')IC1=IHTC
      IF(IC4(1:2).EQ.'LF')IC1=ILFC
      IF(IC4(1:2).EQ.'VT')IC1=IVTC
      IF(IC4(1:2).EQ.'FF')IC1=IFFC
      IF(IC4(1:2).EQ.'CR')IC1=ICRC
      IF(IC4(1:2).EQ.'SO')IC1=ISOC
      IF(IC4(1:2).EQ.'SI')IC1=ISIC
      IF(IC4(1:3).EQ.'DLE')IC1=IDLEC
      IF(IC4(1:3).EQ.'DC1')IC1=IDC1C
      IF(IC4(1:3).EQ.'DC2')IC1=IDC2C
      IF(IC4(1:3).EQ.'DC3')IC1=IDC3C
      IF(IC4(1:3).EQ.'DC4')IC1=IDC4C
      IF(IC4(1:3).EQ.'NAK')IC1=INAKC
      IF(IC4(1:3).EQ.'SYN')IC1=ISYNC
      IF(IC4(1:3).EQ.'ETB')IC1=IETBC
      IF(IC4(1:3).EQ.'CAN')IC1=ICANC
      IF(IC4(1:2).EQ.'EM')IC1=IEMC
      IF(IC4(1:3).EQ.'SUB')IC1=ISUBC
      IF(IC4(1:3).EQ.'ESC')IC1=IESCC
      IF(IC4(1:2).EQ.'FS')IC1=IFSC
      IF(IC4(1:2).EQ.'GS')IC1=IGSC
      IF(IC4(1:2).EQ.'RS')IC1=IRSC
      IF(IC4(1:2).EQ.'US')IC1=IUSC
      IF(IC4(1:2).EQ.'BL')IC1=' '
      IF(IC4(1:3).EQ.'BLA')IC1=' '
      IF(IC4(1:4).EQ.'BLAN')IC1=' '
      IF(IC4(1:2).EQ.'SP')IC1=' '
      IF(IC4(1:3).EQ.'SPA')IC1=' '
      IF(IC4(1:4).EQ.'SPAC')IC1=' '
      IF(IC4(1:4).EQ.'SEMI')IC1=';'
!
      ISTRIN(J:J)=IC1
 2100 CONTINUE
      GO TO 2190
!
 2180 CONTINUE
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,2181)
 2181 FORMAT('***** ERROR IN SUBROUTINE DPTRAN--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,2182)
 2182 FORMAT('      WHEN USING THE TRANSLATE COMMAND,')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,2183)
 2183 FORMAT('      YOU CANNOT HAVE THE WORD   TO')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,2184)
 2184 FORMAT('      AS THE FIRST ARGUMENT AFTER   TRANSLATE')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,2185)
 2185 FORMAT('      (YOU WOULD BE ATTEMPTING TO TRANSLATE ')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,2186)
 2186 FORMAT('      NOTHING TO SOMETHING).')
      CALL DPWRST('XXX','BUG ')
      IERROR='YES'
      GO TO 9000
!
 2190 CONTINUE
      ICTRA1(I2)=ISTRIN(1:30)
      NCTRA1(I2)=J
!
!               ***************************************************
!               **  STEP 22--                                    **
!               **  EXTRACT THE OUTPUT SEQUENCE.                  **
!               ***************************************************
!
      ISTRIN(1:30)='                              '
      ICTRA2(I2)=ISTRIN(1:30)
      NCTRA2(I2)=0
!
      J=0
      ILOCTP=ILOCTO+1
      IF(ILOCTP.GT.NUMARG)GO TO 2290
      DO 2200 I=ILOCTP,NUMARG
      J=J+1
      IC4=IHARG(I)
!
      IC1=IC4(1:1)
      IF(IC4(1:3).EQ.'NUL')IC1=INULC
      IF(IC4(1:3).EQ.'SOH')IC1=ISOHC
      IF(IC4(1:3).EQ.'STX')IC1=ISTXC
      IF(IC4(1:3).EQ.'ETX')IC1=IETXC
      IF(IC4(1:3).EQ.'EOT')IC1=IEOTC
      IF(IC4(1:3).EQ.'ENQ')IC1=IENQC
      IF(IC4(1:3).EQ.'ACK')IC1=IACKC
      IF(IC4(1:3).EQ.'BEL')IC1=IBELC
      IF(IC4(1:2).EQ.'BS')IC1=IBSC
      IF(IC4(1:3).EQ.'HTX')IC1=IHTC
      IF(IC4(1:2).EQ.'LF')IC1=ILFC
      IF(IC4(1:2).EQ.'VT')IC1=IVTC
      IF(IC4(1:2).EQ.'FF')IC1=IFFC
      IF(IC4(1:2).EQ.'CR')IC1=ICRC
      IF(IC4(1:2).EQ.'SO')IC1=ISOC
      IF(IC4(1:2).EQ.'SI')IC1=ISIC
      IF(IC4(1:3).EQ.'DLE')IC1=IDLEC
      IF(IC4(1:3).EQ.'DC1')IC1=IDC1C
      IF(IC4(1:3).EQ.'DC2')IC1=IDC2C
      IF(IC4(1:3).EQ.'DC3')IC1=IDC3C
      IF(IC4(1:3).EQ.'DC4')IC1=IDC4C
      IF(IC4(1:3).EQ.'NAK')IC1=INAKC
      IF(IC4(1:3).EQ.'SYN')IC1=ISYNC
      IF(IC4(1:3).EQ.'ETB')IC1=IETBC
      IF(IC4(1:3).EQ.'CAN')IC1=ICANC
      IF(IC4(1:2).EQ.'EM')IC1=IEMC
      IF(IC4(1:3).EQ.'SUB')IC1=ISUBC
      IF(IC4(1:3).EQ.'ESC')IC1=IESCC
      IF(IC4(1:2).EQ.'FS')IC1=IFSC
      IF(IC4(1:2).EQ.'GS')IC1=IGSC
      IF(IC4(1:2).EQ.'RS')IC1=IRSC
      IF(IC4(1:2).EQ.'US')IC1=IUSC
      IF(IC4(1:2).EQ.'BL')IC1=' '
      IF(IC4(1:3).EQ.'BLA')IC1=' '
      IF(IC4(1:4).EQ.'BLAN')IC1=' '
      IF(IC4(1:2).EQ.'SP')IC1=' '
      IF(IC4(1:3).EQ.'SPA')IC1=' '
      IF(IC4(1:4).EQ.'SPAC')IC1=' '
      IF(IC4(1:4).EQ.'SEMI')IC1=';'
!
      ISTRIN(J:J)=IC1
 2200 CONTINUE
!
 2290 CONTINUE
      ICTRA2(I2)=ISTRIN(1:30)
      NCTRA2(I2)=J
      IF(I2.GT.NUMTRA)NUMTRA=I2
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGS2.EQ.'ON' .OR. ISUBRO.EQ.'DEFI')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('AT THE END       OF DPTRAN--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9021)I2,NUMTRA
 9021   FORMAT('I2,NUMTRA = ',2I8)
        CALL DPWRST('XXX','BUG ')
        IF(NUMTRA.GE.1)THEN
          DO 9022 I=1,NUMTRA
            WRITE(ICOUT,9023)I,ICTRA1(I),NCTRA1(I)
 9023       FORMAT('I,ICTRA1(I),NCTRA1(I) = ',I8,2X,A30,I8)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,9024)I,ICTRA2(I),NCTRA2(I)
 9024       FORMAT('I,ICTRA2(I),NCTRA2(I) = ',I8,2X,A30,I8)
            CALL DPWRST('XXX','BUG ')
 9022     CONTINUE
        ENDIF
        WRITE(ICOUT,9051)IFOUND,IERROR
 9051   FORMAT('IFOUND,IERROR = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE DPTRAN
      SUBROUTINE DPOPMS(IANS,IWIDTH,IBUGS2,ISUBRO,IFOUND,IERROR)
!
!     PURPOSE--SEND A MESSAGE TO THE HOST CONSOLE OPERATOR.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--86/1
!     ORIGINAL VERSION--NOVEMBER  1980.
!     UPDATED         --MAY       1982.
!     UPDATED         --JANUARY   1986.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IANS
      CHARACTER*4 IBUGS2
      CHARACTER*4 ISUBRO
      CHARACTER*4 IFOUND
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
      CHARACTER*4 ISTAT
!
      CHARACTER*80 ICANS
      CHARACTER*80 ISTRIN
!
      DIMENSION IANS(*)
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOPA.INC'
      INCLUDE 'DPCOF2.INC'
!
!-----COMMON VARIABLES (GENERAL)--------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPOP'
      ISUBN2='MS  '
      IFOUND='YES'
      IERROR='NO'
!
      IF(IBUGS2.EQ.'ON' .OR. ISUBRO.EQ.'OPMS')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPOPMS--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)IBUGS2,ISUBRO,IERROR,IWIDTH
   53   FORMAT('IBUGS2,ISUBRO,IERROR,IWIDTH = ',3(A4,2X),I8)
        CALL DPWRST('XXX','BUG ')
        IF(IWIDTH.GE.1)THEN
          WRITE(ICOUT,55)(IANS(I),I=1,MIN(80,IWIDTH))
   55     FORMAT('(IANS(I),I=1,IWIDTH) = ',80A1)
          CALL DPWRST('XXX','BUG ')
        ENDIF
      ENDIF
!
!               ****************************
!               **  STEP 13--             **
!               **  EXTRACT THE MESSAGE   **
!               ****************************
!
      ISTEPN='13'
      IF(IBUGS2.EQ.'ON'.OR.ISUBRO.EQ.'MAIL')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      DO 1310 I=1,80
      ICANS(I:I)=IANS(I)
 1310 CONTINUE
!
      ISTART=1
      ISTOP=IWIDTH
      IWORD=2
      CALL DPEXWO(ICANS,ISTART,ISTOP,IWORD,   &
      ICOL1,ICOL2,ISTRIN,NCSTRI,   &
      IBUGS2,ISUBRO,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
!
      J=0
      IF(ICOL1.GT.IWIDTH)GO TO 1339
      DO 1330 I=ICOL1,IWIDTH
      J=J+1
      ISTRIN(J:J)=ICANS(I:I)
 1330 CONTINUE
      NCSTRI=J
 1339 CONTINUE
!
      NMAX=80
      CALL DPDB80(ISTRIN,JMAX,NMAX,IBUGS2,ISUBRO,IERROR)
      IF(IERROR.EQ.'YES')GO TO 9000
      NCSTRI=JMAX
!
      IF(NCSTRI.GE.1)GO TO 1349
      IERROR='YES'
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1341)
 1341 FORMAT('***** ERROR IN DPOPMS--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1342)
 1342 FORMAT('      A MESSAGE IS REQUIRED')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1343)
 1343 FORMAT('      IN THE OPERATOR COMMAND')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1344)
 1344 FORMAT('      (FOR EXAMPLE,    OPERATOR HOW DO I GENERATE ',   &
      '3-D PLOTS?)')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1346)
 1346 FORMAT('      THE ENTERED COMMAND LINE WAS AS FOLLOWS--')
      CALL DPWRST('XXX','BUG ')
      IF(IWIDTH.GE.1)WRITE(ICOUT,1347)(IANS(I),I=1,IWIDTH)
 1347 FORMAT('      ',80A1)
      IF(IWIDTH.GE.1)CALL DPWRST('XXX','BUG ')
      IF(IWIDTH.LE.0)WRITE(ICOUT,999)
      IF(IWIDTH.LE.0)CALL DPWRST('XXX','BUG ')
      GO TO 9000
 1349 CONTINUE
!
!               **********************************************
!               **  STEP 14--                               **
!               **  IF THE NEEDED SYSTEM CALL               **
!               **  EXISTS AT THIS COMPUTER INSTALLATION,   **
!               **  THEN HAVE THE DATAPLOT IMPLEMENTOR      **
!               **  ENTER THE CODE FOR SUCH A CALL.         **
!               **  IF THE NEEDED SYSTEM CALL               **
!               **  DOES NOT EXIST (THE DEFAULT) AT THIS    **
!               **  COMPUTER INSTALLATION,                  **
!               **  THEN WRITE OUT AN ERROR MESSAGE.        **
!               **********************************************
!
      ISTEPN='12'
      IF(IBUGS2.EQ.'ON'.OR.ISUBRO.EQ.'OPMS')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      ISTAT='NONE'
!
      IF(ISTAT.EQ.'NONE')GO TO 1200
      GO TO 1290
 1200 CONTINUE
      IERROR='YES'
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1211)
 1211 FORMAT('***** ERROR IN DPOPMS--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1212)
 1212 FORMAT('      THE ENTERED MESSAGE TO THE OPERATOR')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1213)
 1213 FORMAT('      CANNOT BE SENT BECAUSE')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1214)
 1214 FORMAT('      THE REQUIRED CALL TO A SYSTEM-DEPENDENT')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1215)
 1215 FORMAT('      ROUTINE TO SEND SUCH MESSAGES')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1216)
 1216 FORMAT('      HAS NOT BEEN IMPLEMENTED')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1217)
 1217 FORMAT('      AT THIS INSTALLATION.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1218)ISTAT
 1218 FORMAT('      ISTAT = ',A12)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1221)
 1221 FORMAT('      PLEASE REQUEST THE IMPLEMENTOR')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1222)
 1222 FORMAT('      TO ENTER THE CODE INTO THIS SUBROUTINE')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1223)
 1223 FORMAT('      (DPOPMS) TO CALL SUCH A SYSTEM-DEPENDENT')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,1224)
 1224 FORMAT('      ROUTINE.')
      CALL DPWRST('XXX','BUG ')
      GO TO 9000
 1290 CONTINUE
!
!CCCC CALL XXX(ISTRIN,NCSTRI)
!
!               ****************
!               **  STEP 90-- **
!               **  EXIT.     **
!               ****************
!
 9000 CONTINUE
      IF(IBUGS2.EQ.'ON' .OR. ISUBRO.EQ.'OPMS')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPOPMS--')
        CALL DPWRST('XXX','BUG ')
        IF(IWIDTH.GE.1)THEN
          WRITE(ICOUT,9042)(IANS(I),I=1,MIN(80,IWIDTH))
 9042     FORMAT('(IANS(I),I=1,IWIDTH) = ',80A1)
          CALL DPWRST('XXX','BUG ')
        ENDIF
        WRITE(ICOUT,9043)IERROR,NCSTRI
 9043   FORMAT('IERROR,NCSTRI = ',A4,2X,I8)
        CALL DPWRST('XXX','BUG ')
        IF(NCSTRI.GE.1)THEN
          WRITE(ICOUT,9044)(ISTRIN(I:I),I=1,NCSTRI)
 9044     FORMAT('(ISTRIN(I:I),I=1,NCSTRI) = ',80A1)
          CALL DPWRST('XXX','BUG ')
        ENDIF
      ENDIF
!
      RETURN
      END SUBROUTINE DPOPMS
      SUBROUTINE DPUPPE(IA,IWIDTH,IB,IBUGMA,IERROR)
!
!     PURPOSE--CONVERT LOWER CASE ALPHABETIC (A TO Z) ASCII CHARACTERS
!              TO UPPER CASE ASCII CHARACTERS.
!              DO SO FOR EACH OF THE    IWIDTH    CHARACTERS
!              IN THE CHARACTER ARRAY IA(.).
!              IT IS ASSUMED THAT IA IS CHARACTER*4
!              AND HAS 1 CHARACTER (LEFT-JUSTIFIED) PER WORD.
!
!     INPUT  ARGUMENTS--IA     = HOLLERITH ARRAY WITH 1 CHARACTER PER WORD
!                       IWIDTH = INTEGER NUMBER OF WORDS IN IA.
!                       IBUGMA = HOLLERITH BUG (= TRACE) VARIABLE
!                       IERROR = HOLLERITH VARIABLE
!     OUTPUT ARGUMENTS--IB     = HOLLERITH ARRAY WITH 1 CHARACTER PER WORD
!
!     NOTE--IF SO DESIRED, THE CALLING SEQUENCE FOR DPUPPE
!           MAY HAVE IB(.) IDENTICAL TO IA(.).
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--82/7
!     ORIGINAL VERSION--JANUARY 1981.
!     UPDATED         --MAY       1982.
!     UPDATED         --OCTOBER   1991. ONLY FIRST CHARACTER WAS
!                                       BEING CONVERTED. FIX.
!                                       EXTENSIVELY MODIFIED.  ALAN
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IA
      CHARACTER*4 IB
!
      CHARACTER*1 IA1
      CHARACTER*1 IB1
!
      CHARACTER*4 IBUGMA
      CHARACTER*4 IERROR
!
!CCCC CHARACTER*4 IA4
!
!---------------------------------------------------------------------
!
      DIMENSION IA(*)
      DIMENSION IB(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IF(IBUGMA.EQ.'ON')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPUPPE--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IWIDTH,IBUGMA,IERROR
   52   FORMAT('IWIDTH,IBUGMA,IERROR = ',I8,2X,A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)(IA(I),I=1,MIN(100,IWIDTH))
   53   FORMAT('(IA(I),I=1,IWIDTH) = ',100A1)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,54)(IB(I),I=1,MIN(100,IWIDTH))
   54   FORMAT('(IB(I),I=1,IWIDTH) = ',100A1)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               *******************************************************
!               **  THE FOLLOWING CODE WILL CARRY OUT THE LOWER CASE **
!               **  TO UPPER CASE CONVERSION FOR ALL COMPUTERS WITH  **
!               **  AN ANSI 77 FORTRAN COMPILER--IT MAKES USE OF THE **
!               **  ANSI FORTRAN 77 INTRINSIC FUNCTIONS              **
!               **     1) ICHAR (FOR ASCII CHARACTER TO ASCII NUMERIC**
!               **        CONVERSION                                 **
!               **     2) CHAR  (FOR ASCII NUMERIC TO ASCII CHARACTER**
!               **        CONVERSION                                 **
!               *******************************************************
!
!
      IF(IWIDTH.LE.0)GO TO 9000
      DO 100 I=1,IWIDTH
!
!  OCTOBER, 1991.  ADD INNER LOOP (I.E., J LOOP)
        DO 200 J=1,4
          IA1=IA(I)(J:J)
          CALL DPCOAN(IA1,IVALUE)
          IF(97.LE.IVALUE.AND.IVALUE.LE.122)THEN
            IVAM32=IVALUE-32
            CALL DPCONA(IVAM32,IB1)
            IB(I)(J:J)=IB1
            GO TO 200
          ELSE
            IB(I)(J:J)=IA(I)(J:J)
            GO TO 200
          ENDIF
!
  200   CONTINUE
  100 CONTINUE
!
      GO TO 9000
!
!               *******************************************************
!               **  CONVERSION TO UPPER CASE FOR THE UNIVAC 1100     **
!               **  SERIES. FTN COM                                  **
!               *******************************************************
!
!CCCC IF(IWIDTH.LE.0)GO TO 1190
!CCCC DO1100I=1,IWIDTH
!CCCC IA4=IA(I)
!CCCC IB(I)=UPPERC(IA4)
!1100 CONTINUE
!1190 CONTINUE
!CCCC GO TO 9000
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
      IF(IBUGMA.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPUPPE--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IWIDTH,IBUGMA,IERROR
 9012   FORMAT('IWIDTH,IBUGMA,IERROR = ',I8,2X,A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9013)(IA(I),I=1,MIN(100,IWIDTH))
 9013   FORMAT('(IA(I),I=1,IWIDTH) = ',100A1)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9014)(IB(I),I=1,MIN(100,IWIDTH))
 9014   FORMAT('(IB(I),I=1,IWIDTH) = ',100A1)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE DPUPPE
      SUBROUTINE DPUPP2(IA,IWIDTH,IB,IWIDT2,IBUGMA,IERROR)
!
!     PURPOSE--CONVERT LOWER CASE ALPHABETIC (A TO Z) ASCII CHARACTERS
!              TO UPPER CASE ASCII CHARACTERS.
!              DO SO FOR EACH OF THE    IWIDTH    CHARACTERS
!              IN THE CHARACTER SRING IA.
!
!              ALSO STRIP OUT LEADING SPACES AND REPLICATED SPACES.
!
!     INPUT  ARGUMENTS--IA     = CHARACTER STRING
!                       IWIDTH = INTEGER NUMBER OF WORDS IN IA.
!                       IBUGMA = CHARACTER VARIABLE (= TRACE) VARIABLE
!                       IERROR = CHARACTER VARIABLE
!     OUTPUT ARGUMENTS--IB     = CHARACTER STRING
!
!     NOTE--IF SO DESIRED, THE CALLING SEQUENCE FOR DPUPP2
!           MAY HAVE IB IDENTICAL TO IA.
!     WRITTEN BY--ALAN HECKERT
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORTORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899-8980
!                 PHONE--301-975-2899
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2014/11
!     ORIGINAL VERSION--NOVEMBER  2014.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*(*) IA
      CHARACTER*(*) IB
!
      CHARACTER*1 IA1
      CHARACTER*1 IB1
!
      CHARACTER*4 IBUGMA
      CHARACTER*4 IERROR
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IF(IBUGMA.EQ.'ON')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPUPP2--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IWIDTH,IBUGMA,IERROR
   52   FORMAT('IWIDTH,IBUGMA,IERROR = ',I8,2X,A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)(IA(I:I),I=1,MIN(100,IWIDTH))
   53   FORMAT('(IA(I),I=1,IWIDTH) = ',100A1)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               *******************************************************
!               **  THE FOLLOWING CODE WILL CARRY OUT THE LOWER CASE **
!               **  TO UPPER CASE CONVERSION FOR ALL COMPUTERS WITH  **
!               **  AN ANSI 77 FORTRAN COMPILER--IT MAKES USE OF THE **
!               **  ANSI FORTRAN 77 INTRINSIC FUNCTIONS              **
!               **     1) ICHAR (FOR ASCII CHARACTER TO ASCII NUMERIC**
!               **        CONVERSION                                 **
!               **     2) CHAR  (FOR ASCII NUMERIC TO ASCII CHARACTER**
!               **        CONVERSION                                 **
!               *******************************************************
!
!
      IF(IWIDTH.GE.1)THEN
        IWIDT2=IWIDT2+1
        NBLANK=0
        NLEAD=0
        DO 100 I=1,IWIDTH
          IA1=IA(I:I)
          IF(IA1.EQ.' ')THEN
            IF(NLEAD.EQ.0)GO TO 100
            IF(NBLANK.EQ.0)THEN
              IWIDT2=IWIDT2+1
              IB(IWIDT2:IWIDT2)=IA1
              NBLANK=NBLANK+1
            ENDIF
          ELSE
            NLEAD=1
            CALL DPCOAN(IA1,IVALUE)
            IF(97.LE.IVALUE.AND.IVALUE.LE.122)THEN
              IVAM32=IVALUE-32
              CALL DPCONA(IVAM32,IB1)
              IWIDT2=IWIDT2+1
              IB(IWIDT2:IWIDT2)=IB1
            ENDIF
          ENDIF
  100   CONTINUE
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
      IF(IBUGMA.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPUPP2--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IWIDTH,IWIDT2,IERROR
 9012   FORMAT('IWIDTH,IWIDT2,IERROR = ',2I8,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9014)(IB(I:I),I=1,MIN(100,IWIDT2))
 9014   FORMAT('(IB(I:I),I=1,IWIDT2) = ',100A1)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE DPUPP2
      SUBROUTINE DPNONP(IA,IWIDTH,IB,IBUGMA,ISUBRO,IERROR)
!
!     PURPOSE--CONVERT NON-PRINTING CHARACTERS TO SPACES
!     INPUT  ARGUMENTS--IA     = HOLLERITH ARRAY WITH 1 CHARACTER PER WORD
!                       IWIDTH = INTEGER NUMBER OF WORDS IN IA.
!                       IBUGMA = HOLLERITH BUG (= TRACE) VARIABLE
!                       IERROR = HOLLERITH VARIABLE
!     OUTPUT ARGUMENTS--IB     = HOLLERITH ARRAY WITH 1 CHARACTER PER WORD
!
!     NOTE--IF SO DESIRED, THE CALLING SEQUENCE FOR DPNONP
!           MAY HAVE IB(.) IDENTICAL TO IA(.).
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--93/10
!     ORIGINAL VERSION--OCTOBER   1993
!     UPDATED         --FEBRUARY  2019 OPTION TO SPECIFY HOW MANY SPACES
!                                      TABS WILL BE CONVERTED TO
!     UPDATED         --MARCH     2019 ADD ISUBRO TO CALL LIST
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IA(*)
      CHARACTER*4 IB(*)
!
      INCLUDE 'DPCOPA.INC'
!
!CCCC CHARACTER*4 IC(255)
      CHARACTER*4 IC(MAXSTR)
      CHARACTER*1 IA1
      CHARACTER*4 IBUGMA
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
      CHARACTER*4 IFLAG
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOST.INC'
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IF(IBUGMA.EQ.'ON' .OR. ISUBRO.EQ.'NONP')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPNONP--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,52)IBUGMA,IERROR,IWIDTH,ITABNC
   52   FORMAT('IBUGMA,IERROR,IWIDTH,ITABNC = ',2(A4,2X),2I8)
        CALL DPWRST('XXX','BUG ')
        DO 55 I=1,IWIDTH
          WRITE(ICOUT,53)I,IA(I)
   53     FORMAT('I,IA(I) = ',I5,2X,A4)
          CALL DPWRST('XXX','BUG ')
   55   CONTINUE
      ENDIF
!
      MAXWID=IWIDTH
      DO 60 II=IWIDTH,1,-1
        IF(IA(II).NE.'    ')THEN
          IWIDTH=II
          GO TO 69
        ENDIF
   60 CONTINUE
      IWIDTH=0
   69 CONTINUE
!
!               ******************************************************
!               **  THE FOLLOWING CODE WILL CONVERT NON_PRINTING    **
!               **  CHARACTERS TO SPACES.                           **
!               ******************************************************
!
      IF(IWIDTH.GE.1)THEN
        IFLAG='ON'
        DO 90 II=1,MAXWID
          IC(II)='   '
   90   CONTINUE
!
!       CHECK FOR:
!
!          1. CHARACTERS ENCLOSED WITHIN SINGLE OR DOUBLE QUOTES ARE
!             NOT REPLACED.
!
!          2. FOR TAB CHARACTERS:
!
!               ITABNC = 0  => LEAVE TAB CHARACTER IN
!               ITABNC = 1  => REPLACE TAB WITH SINGLE SPACE
!               ITABNC > 1  => REPLACE TAB WITH ITABNC SPACES
!
!           3. IF NOT IN QUOTES, REPLACE ANY NON-TAB NON-PRINTING
!              CHARACTERS WITH A SINGLE SPACE.
!
        IWIDT2=0
        DO 100 I=1,IWIDTH
          IA1=IA(I)(1:1)
          CALL DPCOAN(IA1,IVALUE)
!
          IF(IBUGMA.EQ.'ON' .OR. ISUBRO.EQ.'NONP')THEN
            WRITE(ICOUT,101)I,IVALUE,IA1,IFLAG
  101       FORMAT('AT 100: I,IVALUE,IA1 = ',2I5,2X,A1,2X,A4)
            CALL DPWRST('XXX','BUG ')
          ENDIF
!
          IF(IFLAG.EQ.'ON')THEN
            IF(IVALUE.EQ.34.OR.IVALUE.EQ.39)THEN
              IFLAG='OFF'
              IF(IWIDT2.GE.MIN(MAXWID,MAXSTR))GO TO 199
              IWIDT2=IWIDT2+1
              IC(IWIDT2)=IA(I)
            ELSEIF(IVALUE.EQ.9)THEN
!
              IF(IBUGMA.EQ.'ON' .OR. ISUBRO.EQ.'NONP')THEN
                WRITE(ICOUT,103)ITABNC,MAXWID
  103           FORMAT('AT TAB CASE: ITABNC,MAXWID = ',2I6)
                CALL DPWRST('XXX','BUG ')
              ENDIF
!
              IF(ITABNC.LE.0)THEN
                IF(IWIDT2.GE.MIN(MAXWID,MAXSTR))GO TO 199
                IWIDT2=IWIDT2+1
                IC(IWIDT2)=IA(I)
              ELSEIF(ITABNC.GE.1)THEN
                DO 110 II=1,ITABNC
                  IF(IWIDT2.GE.MIN(MAXWID,MAXSTR))GO TO 199
                  IWIDT2=IWIDT2+1
                  IC(IWIDT2)='    '
  110           CONTINUE
              ENDIF
            ELSEIF(IVALUE.LE.31.OR.IVALUE.GE.128)THEN
              IF(IWIDT2.GE.MIN(MAXWID,MAXSTR))GO TO 199
              IWIDT2=IWIDT2+1
              IC(IWIDT2)='    '
            ELSE
              IF(IWIDT2.GE.MIN(MAXWID,MAXSTR))GO TO 199
              IWIDT2=IWIDT2+1
              IC(IWIDT2)=IA(I)
            ENDIF
          ELSEIF(IFLAG.EQ.'OFF')THEN
            IF(IVALUE.EQ.34.OR.IVALUE.EQ.39)THEN
              IFLAG='ON'
            ENDIF
            IF(IWIDT2.GE.MIN(MAXWID,MAXSTR))GO TO 199
            IWIDT2=IWIDT2+1
            IC(IWIDT2)=IA(I)
          ENDIF
  100   CONTINUE
  199   CONTINUE
        IWIDTH=IWIDT2
        IF(IWIDT2.GE.1)THEN
          DO 210 II=1,IWIDT2
            IB(II)=IC(II)
  210     CONTINUE
        ENDIF
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
      IF(IBUGMA.EQ.'ON' .OR. ISUBRO.EQ.'NONP')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPNONP--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IERROR,IWIDTH
 9012   FORMAT('IERROR,IWIDTH = ',A4,2X,I5)
        CALL DPWRST('XXX','BUG ')
        DO 9015 II=1,IWIDTH
          WRITE(ICOUT,9014)II,IB(II)
 9014     FORMAT('II,IB(II) = ',I5,2X,A4)
          CALL DPWRST('XXX','BUG ')
 9015   CONTINUE
      ENDIF
!
      RETURN
      END SUBROUTINE DPNONP
      SUBROUTINE DPUPP4(IA4,IB4,IBUGMA,IERROR)
!
!     PURPOSE--CONVERT 4-CHARACTER LOWER CASE ALPHABETIC (A TO Z)
!              ASCII WORD IA4
!              TO UPPER CASE ASCII WORD IB4.
!     NOTE--IA4 AND IB4 ARE ASSUMED TO BE CHARACTER*4
!     NOTE--IA4 AND IB4 MAY BE THE SAME VARIABLE IN THE CALLING ROUTINE.
!     WRITTEN BY--JAMES J. FILLIBEN
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--86/9
!     ORIGINAL VERSION--AUGUST 1986.
!
!---------------------------------------------------------------------
!
      CHARACTER*4 IA4
      CHARACTER*4 IB4
      CHARACTER*4 IBUGMA
      CHARACTER*4 IERROR
!
      CHARACTER*1 IA1
      CHARACTER*1 IB1
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IF(IBUGMA.EQ.'OFF')GO TO 90
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,51)
   51 FORMAT('***** AT THE BEGINNING OF DPUPP4--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,52)IA4
   52 FORMAT('IA4 = ',A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,53)IBUGMA,IERROR
   53 FORMAT('IBUGMA,IERROR = ',A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
   90 CONTINUE
!
!               ********************************************************
!               **  STEP 11--
!               **  THE FOLLOWING CODE WILL CARRY OUT THE LOWER CASE
!               **  TO UPPER CASE CONVERSION FOR ALL COMPUTERS
!               **  WITH AN ANSI 77 FORTRAN COMPILER--IT MAKES
!               **  USE OF THE ANSI FORTRAN 77 INTRINSIC FUNCTIONS
!               **     1) ICHAR (FOR ASCII CHARACTER TO ASCII NUMERIC CO
!               **     2) CHAR  (FOR ASCII NUMERIC TO ASCII CHARACTER CO
!               ********************************************************
!
      IB4=IA4
!
      IA1=' '
      IB1=' '
!
      DO 1100 I=1,4
!
      IA1=IA4(I:I)
      IVALUE=ICHAR(IA1)
      IF(97.LE.IVALUE.AND.IVALUE.LE.122)GO TO 1110
      GO TO 1100
!
 1110 CONTINUE
      IVAM32=IVALUE-32
      IB1=CHAR(IVAM32)
      IB4(I:I)=IB1
      GO TO 1100
!
 1100 CONTINUE
!
      GO TO 9000
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
 9000 CONTINUE
      IF(IBUGMA.EQ.'OFF')GO TO 9090
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9011)
 9011 FORMAT('***** AT THE END       OF DPUPP4--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9012)IA4,IA1,IB1,IB4
 9012 FORMAT('IA4,IA1,IB1,IB4 = ',A4,2X,A1,2X,A1,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,9013)IBUGMA,IERROR
 9013 FORMAT('IBUGMA,IERROR = ',A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
 9090 CONTINUE
!
      RETURN
      END SUBROUTINE DPUPP4
      SUBROUTINE DPUPNT(IHNAME,IHNAM2,IUSE,IVALUE,VALUE,IN,   &
      IVSTAR,IVSTOP,MAXNAM,NUMNAM,V,MAXN,MAXCOL,NUMCOL,   &
      IBUGS2,IERROR)
!
!     PURPOSE--HANDLE THE CASE IN WHICH ARBITRARY ENTRIES HAVE
!              BEEN EARMARKED FOR DELETION IN THE NAME TABLE
!              (BY IN(.) BEING SET TO NON-POSITIVE)
!              AND SO ENTIRES
!              MUST BE SHIFTED TO AVOID HOLES IN THE TABLE.
!              UPDATE HOUSEKEEPING TABLES ACCORDINGLY.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!           THIS SUBROUTINE MAY NOT BE COPIED, EXTRACTED,
!           MODIFIED, OR OTHERWISE USED IN A CONTEXT
!           OUTSIDE OF THE DATAPLOT LANGUAGE/SYSTEM.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--89/1
!     ORIGINAL VERSION--DECEMBER  1988.
!     UPDATED         --NOVEMBER  1998. BUG FIX.  ONLY DELETE IF
!                                       IN(.) IS NEGATIVE
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IHNAME
      CHARACTER*4 IHNAM2
      CHARACTER*4 IUSE
      CHARACTER*4 IBUGS2
      CHARACTER*4 IERROR
!
      CHARACTER*4 ISUBN1
      CHARACTER*4 ISUBN2
      CHARACTER*4 ISTEPN
!
!---------------------------------------------------------------------
!
      DIMENSION IHNAME(*)
      DIMENSION IHNAM2(*)
      DIMENSION IUSE(*)
      DIMENSION IVALUE(*)
      DIMENSION VALUE(*)
      DIMENSION IN(*)
      DIMENSION IVSTAR(*)
      DIMENSION IVSTOP(*)
!
      DIMENSION V(*)
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      ISUBN1='DPUP'
      ISUBN2='NT  '
!
      IERROR='NO'
!
      IF(IBUGS2.EQ.'OFF')GO TO 90
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,51)
   51 FORMAT('***** AT THE BEGINNING OF DPUPNT--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,52)IBUGS2,IERROR
   52 FORMAT('IBUGS2,IERROR = ',A4,2X,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,53)MAXNAM,NUMNAM
   53 FORMAT('MAXNAM,NUMNAM = ',2I8)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,54)MAXN,MAXCOL,NUMCOL
   54 FORMAT('MAXN,MAXCOL,NUMCOL = ',3I8)
      CALL DPWRST('XXX','BUG ')
      DO 60 I=1,NUMNAM
      WRITE(ICOUT,61)I,IHNAME(I),IHNAM2(I),IUSE(I),IVALUE(I),VALUE(I)
   61 FORMAT('I,IHNAME(I),IHNAM2(I),IUSE(I),IVALUE(I),VALUE(I) = ',   &
      I8,2X,A4,A4,2X,A4,I8,E15.7)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,62)I,IHNAME(I),IHNAM2(I),IN(I),IVSTAR(I),IVSTOP(I)
   62 FORMAT('I,IHNAME(I),IHNAM2(I),IN(I),IVSTAR(I),IVSTOP(I)  = ',   &
      I8,2X,A4,A4,6X,I8,I8,I8)
      CALL DPWRST('XXX','BUG ')
   60 CONTINUE
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      DO 70 J=1,NUMCOL
      IJ=MAXN*(J-1)+1
      WRITE(ICOUT,71)J,MAXN,IJ,V(IJ)
   71 FORMAT('J,MAXN,IJ,V(IJ) = ',I8,I8,I8,E15.7)
      CALL DPWRST('XXX','BUG ')
   70 CONTINUE
   90 CONTINUE
!
!               *********************************************
!               **  STEP 1--                               **
!               **  UPDATE THE HOUSEKEEPING TABLES.        **
!               **  ELIMINATE ANY ENTRIES IN THESE TABLES  **
!               **  WHICH HAVE LENGTH OF VARIABLE = NON-POSITIVE;   **
!               **  THAT IS, WHICH HAVE IN(.) = NON-POSITIVE.         **
!               *********************************************
!
      ISTEPN='1'
      IF(IBUGS2.EQ.'ON')CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(NUMNAM.LE.0)GO TO 1129
      J=0
 1101 CONTINUE
      J=J+1
      IF(J.GT.NUMNAM)GO TO 1129
      IF(IHNAME(J).EQ.'PRED'.AND.IHNAM2(J).EQ.'    ')GO TO 1100
      IF(IHNAME(J).EQ.'RES '.AND.IHNAM2(J).EQ.'    ')GO TO 1100
      IF(IHNAME(J).EQ.'YPLO'.AND.IHNAM2(J).EQ.'T   ')GO TO 1100
      IF(IHNAME(J).EQ.'XPLO'.AND.IHNAM2(J).EQ.'T   ')GO TO 1100
      IF(IHNAME(J).EQ.'X2PL'.AND.IHNAM2(J).EQ.'OT  ')GO TO 1100
      IF(IHNAME(J).EQ.'TAGP'.AND.IHNAM2(J).EQ.'LOT ')GO TO 1100
!CCCC BUG FIX.  ONLY DELETE IF NEGATIVE.  STRINGS AND PARAMETERS
!CCCC ARE ZERO BY DEFAULT, DON'T NECCESSARILY WANT TO DELETE.  11/98.
!CCCC IF(IN(J).LE.0)GO TO 1109
      IF(IN(J).LT.0)GO TO 1109
      GO TO 1100
 1109 CONTINUE
!
      JP1=J+1
      IF(JP1.GT.NUMNAM)GO TO 1119
      DO 1110 K=JP1,NUMNAM
      KM1=K-1
      IHNAME(KM1)=IHNAME(K)
      IHNAM2(KM1)=IHNAM2(K)
      IUSE(KM1)=IUSE(K)
      IVALUE(KM1)=IVALUE(K)
      VALUE(KM1)=VALUE(K)
      IN(KM1)=IN(K)
      IVSTAR(KM1)=IVSTAR(K)
      IVSTOP(KM1)=IVSTOP(K)
 1110 CONTINUE
 1119 CONTINUE
      NUMNAM=NUMNAM-1
      J=J-1
!
 1100 CONTINUE
      GO TO 1101
 1129 CONTINUE
!
!               ************************************************
!               **  STEP 2--                                  **
!               **  DETERMINE THE LARGEST COLUMN REFERENCED.  **
!               ************************************************
!
      ISTEPN='2'
      IF(IBUGS2.EQ.'ON')CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      ICOLMX=0
      IF(NUMNAM.LE.0)GO TO 2159
      DO 2150 J=1,NUMNAM
      IF(IHNAME(J).EQ.'PRED'.AND.IHNAM2(J).EQ.'    ')GO TO 2150
      IF(IHNAME(J).EQ.'RES '.AND.IHNAM2(J).EQ.'    ')GO TO 2150
      IF(IHNAME(J).EQ.'YPLO'.AND.IHNAM2(J).EQ.'T   ')GO TO 2150
      IF(IHNAME(J).EQ.'XPLO'.AND.IHNAM2(J).EQ.'T   ')GO TO 2150
      IF(IHNAME(J).EQ.'X2PL'.AND.IHNAM2(J).EQ.'OT  ')GO TO 2150
      IF(IHNAME(J).EQ.'TAGP'.AND.IHNAM2(J).EQ.'LOT ')GO TO 2150
      IF(IUSE(J).EQ.'V'.AND.IVALUE(J).GT.ICOLMX)ICOLMX=IVALUE(J)
 2150 CONTINUE
 2159 CONTINUE
!
!               *******************************************************
!               **  STEP 3--                                         **
!               **  TREAT THE CASE WHERE THERE IS AT LEAST           **
!               **  1 VARIABLE IN THE DATA ARRAY WHICH MAY           **
!               **  (AT LEAST POTENTIALLY) BE SHIFTED (COMPRESSED).  **
!               *******************************************************
!
      ISTEPN='3'
      IF(IBUGS2.EQ.'ON')CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      ICODE=0
      NUMCO2=NUMCOL
      IF(ICOLMX.LE.0)GO TO 3900
      DO 3300 ICOL=1,ICOLMX
!
      IPASS=0
      IF(NUMNAM.LE.0)GO TO 3900
      DO 3400 J=1,NUMNAM
      IF(IHNAME(J).EQ.'PRED'.AND.IHNAM2(J).EQ.'    ')GO TO 3400
      IF(IHNAME(J).EQ.'RES '.AND.IHNAM2(J).EQ.'    ')GO TO 3400
      IF(IHNAME(J).EQ.'YPLO'.AND.IHNAM2(J).EQ.'T   ')GO TO 3400
      IF(IHNAME(J).EQ.'XPLO'.AND.IHNAM2(J).EQ.'T   ')GO TO 3400
      IF(IHNAME(J).EQ.'X2PL'.AND.IHNAM2(J).EQ.'OT  ')GO TO 3400
      IF(IHNAME(J).EQ.'TAGP'.AND.IHNAM2(J).EQ.'LOT ')GO TO 3400
      IF(IUSE(J).EQ.'V'.AND.IVALUE(J).EQ.ICOL)GO TO 3450
      GO TO 3400
!
 3450 CONTINUE
      IPASS=IPASS+1
      IF(IPASS.EQ.1)ICODE=ICODE+1
      IF(IPASS.EQ.1)GO TO 3460
      GO TO 3470
!
 3460 CONTINUE
      IF(IVALUE(J).EQ.ICODE)GO TO 3490
      ICOLOL=IVALUE(J)
!
      IMAX=MAXN
      DO 3461 I=1,IMAX
      IJ=MAXN*(ICODE-1)+I
      V(IJ)=CPUMIN
 3461 CONTINUE
!
      IMAX=IN(J)
      DO 3462 I=1,IMAX
      IJ=MAXN*(ICODE-1)+I
      IJOL=MAXN*(ICOLOL-1)+I
      V(IJ)=V(IJOL)
 3462 CONTINUE
!
      IMAX=MAXN
      DO 3463 I=1,IMAX
      IJOL=MAXN*(ICOLOL-1)+I
      V(IJOL)=CPUMIN
 3463 CONTINUE
!
      GO TO 3470
!
 3470 CONTINUE
      IVALUE(J)=ICODE
      VALUE(J)=IVALUE(J)
      IVSTAR(J)=MAXN*(ICODE-1)+1
      IVSTOP(J)=MAXN*(ICODE-1)+IN(J)
!
 3490 CONTINUE
 3400 CONTINUE
 3300 CONTINUE
 3900 CONTINUE
      NUMCOL=ICODE
!
!               *****************************************
!               **  STEP 4--                           **
!               **  TREAT THE CASE WHERE NO VARIABLES  **
!               **  REMAIN IN THE DATA ARRAY.          **
!               *****************************************
!
      ISTEPN='4'
      IF(IBUGS2.EQ.'ON')CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
      IF(ICOLMX.LE.0)GO TO 4100
      GO TO 4900
 4100 CONTINUE
      IF(NUMCO2.LE.0)GO TO 4900
      DO 4200 J=1,NUMCO2
      DO 4300 I=1,MAXN
      IJ=MAXN*(J-1)+I
      V(IJ)=CPUMIN
 4300 CONTINUE
 4200 CONTINUE
 4900 CONTINUE
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
      IF(IBUGS2.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPUPNT--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9014)MAXN,MAXCOL,NUMCOL,NUMNAM,IERROR
 9014   FORMAT('MAXN,MAXCOL,NUMCOL,NUMNAM,IERROR = ',4I8,2X,A4)
        CALL DPWRST('XXX','BUG ')
        DO 9020 I=1,NUMNAM
          WRITE(ICOUT,9021)I,IHNAME(I),IHNAM2(I),IUSE(I),IVALUE(I),   &
                           VALUE(I)
 9021     FORMAT('I,IHNAME(I),IHNAM2(I),IUSE(I),IVALUE(I),VALUE(I) = ',   &
                 I8,2X,2A4,2X,A4,I8,G15.7)
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,9022)I,IHNAME(I),IHNAM2(I),IN(I),   &
                            IVSTAR(I),IVSTOP(I)
 9022    FORMAT('I,IHNAME(I),IHNAM2(I),IN(I),IVSTAR(I),IVSTOP(I)  = ',   &
                I8,2X,2A4,6X,3I8)
         CALL DPWRST('XXX','BUG ')
 9020   CONTINUE
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        DO 9030 J=1,NUMCOL
          IJ=MAXN*(J-1)+1
          WRITE(ICOUT,9031)J,MAXN,IJ,V(IJ)
 9031     FORMAT('J,MAXN,IJ,V(IJ) = ',I8,I8,I8,E15.7)
          CALL DPWRST('XXX','BUG ')
 9030   CONTINUE
      ENDIF
!
      RETURN
      END SUBROUTINE DPUPNT
      SUBROUTINE DPUP80(IA,IB,NMAX,IBUGS2,IERROR)
!
!     PURPOSE--FOR THE CHARACTER*80 VARIABLE IA,
!              CONVERT LOWER CASE ALPHABETIC (A TO Z) ASCII CHARACTERS
!              TO UPPER CASE ASCII CHARACTERS.
!              DO SO FOR ALL    80    CHARACTERS.
!              DO SO FOR STRLEZ(IA)
!
!     INPUT  ARGUMENTS--IA     = CHARACTER*80 VARIABLE
!                       IBUGS2 = HOLLERITH BUG (= TRACE) VARIABLE
!                       IERROR = HOLLERITH VARIABLE
!     OUTPUT ARGUMENTS--IB     = CHARACTER*80 VARIABLE
!     NOTE--IT IS PERMISSIBLE FOR IB TO BE THE SAME AS IA
!
!     NOTE--IF SO DESIRED, THE CALLING SEQUENCE FOR DPUP80
!           MAY HAVE IB IDENTICAL TO IA.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--87/11
!     ORIGINAL VERSION--OCTOBER 1987.
!     UPDATED         --MARCH   1992. OTG COMPILER ERROR
!     UPDATED         --APRIL   2018. ADD NMAX ARGUMENT SO CAN
!                                     BE USED FOR STRINGS WITH
!                                     LENGTH OTHER THAN 80
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER (LEN=*) :: IA
      CHARACTER (LEN=*) :: IB
!
      CHARACTER*1 IA1
      CHARACTER*1 IB1
!
      CHARACTER*4 IBUGS2
      CHARACTER*4 IERROR
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!CCCC THE FOLLOWING LINE WAS FIXED    MARCH 1992
!CCCC IWIDTH=80
      CALL STRLEZ(IA,NMAX,IWIDTH)
!
      IF(IBUGS2.EQ.'ON')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPUP80--')
        CALL DPWRST('XXX','BUG ')
        CALL STRLEZ(IA,NMAX,NIA)
        CALL STRLEZ(IB,NMAX,NIB)
        WRITE(ICOUT,52)IBUGS2,IERROR,NIA,NIB,NMAX,IWIDTH
   52   FORMAT('IBUGS2,IERROR,NIA,NIB,NMAX,IWIDTH = ',2(A4,2X),4I5)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)IA(1:MIN(80,NMAX))
   53   FORMAT('IA = ',A80)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,54)IB(1:MIN(80,NMAX))
   54   FORMAT('IB = ',A80)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               ****************************************************************
!               **  THE FOLLOWING CODE WILL CARRY OUT THE LOWER CASE
!               **  TO UPPER CASE CONVERSION FOR ALL COMPUTERS
!               **  WITH AN ANSI 77 FORTRAN COMPILER--IT MAKES
!               **  USE OF THE ANSI FORTRAN 77 INTRINSIC FUNCTIONS
!               **     1) ICHAR (FOR ASCII CHARACTER TO ASCII NUMERIC CONVERSION
!               **     2) CHAR  (FOR ASCII NUMERIC TO ASCII CHARACTER CONVERSIO
!               ****************************************************************
!
      DO 100 I=1,IWIDTH
!
        IA1=IA(I:I)
        CALL DPCOAN(IA1,IVALUE)
        IF(97.LE.IVALUE.AND.IVALUE.LE.122)THEN
          IVAM32=IVALUE-32
          CALL DPCONA(IVAM32,IB1)
          IB(I:I)=IB1
          GO TO 100
        ENDIF
!
        IF(IBUGS2.EQ.'ON')THEN
          WRITE(ICOUT,777)I,IA1,IB(I:I)
  777     FORMAT('I,IA1,IB(I:I) = ',I8,2(2X,A1))
          CALL DPWRST('XXX','BUG ')
        ENDIF
!
        IB(I:I)=IA1
  100 CONTINUE
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
      IF(IBUGS2.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPUP80--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IERROR
 9012   FORMAT('IERROR = ',A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,54)IB(1:MIN(80,NMAX))
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE DPUP80
      SUBROUTINE DPLO80(IA,IB,NMAX,IBUGS2,IERROR)
!
!     PURPOSE--FOR THE CHARACTER*80 VARIABLE IA, CONVERT UPPER CASE
!              ALPHABETIC (A TO Z) ASCII CHARACTERS TO LOWER CASE ASCII
!              CHARACTERS.  DO SO FOR ALL    80    CHARACTERS.
!
!     INPUT  ARGUMENTS--IA     = CHARACTER*80 VARIABLE
!                       IBUGS2 = HOLLERITH BUG (= TRACE) VARIABLE
!                       IERROR = HOLLERITH VARIABLE
!     OUTPUT ARGUMENTS--IA     = CHARACTER*80 VARIABLE
!
!     NOTE--IF SO DESIRED, THE CALLING SEQUENCE FOR DPLO80
!           MAY HAVE IB IDENTICAL TO IA.
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--87/11
!     ORIGINAL VERSION--OCTOBER  1987.
!     UPDATED         --JANUARY  1988. MISSING COMMON IN FORMAT 52
!     UPDATED         --APRIL    1989. CORRECTED RANGE FOR UPPER CASE
!     UPDATED         --AUGUST   1990. OTG COMPILER ERROR?
!     UPDATED         --APRIL    2018. ADD NMAX ARGUMENT SO CAN
!                                      BE USED FOR STRINGS WITH
!                                      LENGTH OTHER THAN 80
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
!CCCC CHARACTER*80 IA
!CCCC CHARACTER*80 IB
      CHARACTER (LEN=*) :: IA
      CHARACTER (LEN=*) :: IB
!
      CHARACTER*1 IA1
      CHARACTER*1 IB1
!
      CHARACTER*4 IBUGS2
      CHARACTER*4 IERROR
!
!---------------------------------------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
!CCCC THE FOLLOWING LINE WAS FIXED    MARCH 1992
!CCCC IWIDTH=80
      CALL STRLEZ(IA,NMAX,IWIDTH)
!
      IF(IBUGS2.EQ.'ON')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF DPLO80--')
        CALL DPWRST('XXX','BUG ')
        CALL STRLEZ(IA,NMAX,NIA)
        CALL STRLEZ(IB,NMAX,NIB)
        WRITE(ICOUT,52)IBUGS2,IERROR,NIA,NIB,NMAXIWIDTH
   52   FORMAT('IBUGS2,IERROR,NIA,NIB,NMAX,IWIDTH = ',2(A4,2X),4I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)IA(1:MIN(80,NMAX))
   53   FORMAT('IA = ',A80)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,54)IB(1:MIN(80,NMAX))
   54   FORMAT('IB = ',A80)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               ****************************************************************
!               **  THE FOLLOWING CODE WILL CARRY OUT THE UPPER CASE
!               **  TO LOWER CASE CONVERSION FOR ALL COMPUTERS
!               **  WITH AN ANSI 77 FORTRAN COMPILER--IT MAKES
!               **  USE OF THE ANSI FORTRAN 77 INTRINSIC FUNCTIONS
!               **     1) ICHAR (FOR ASCII CHARACTER TO ASCII NUMERIC CONVERSION
!               **     2) CHAR  (FOR ASCII NUMERIC TO ASCII CHARACTER CONVERSIO
!               ****************************************************************
!
      DO 100 I=1,IWIDTH
!
        IA1=IA(I:I)
        CALL DPCOAN(IA1,IVALUE)
        IF(65.LE.IVALUE.AND.IVALUE.LE.90)THEN
          IVAP32=IVALUE+32
          CALL DPCONA(IVAP32,IB1)
          IB(I:I)=IB1
          GO TO 100
        ENDIF
!
        IB(I:I)=IA1
!
  100 CONTINUE
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT.      **
!               *****************
!
      IF(IBUGS2.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF DPLO80--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9012)IERROR
 9012   FORMAT('IERROR = ',A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)IA(1:MIN(80,NMAX))
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,54)IB(1:MIN(80,NMAX))
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE DPLO80
