      IERROR='NO'
      ISUBN1='DPSE'
      ISUBN2='T   '
      ICASPR='    '
      IFILQZ=IFILQU
      IFILQU='ON'
      ISTRIN=' '
!
      IF(ISUBRO.EQ.'PSET')THEN
        WRITE(ICOUT,11)
   11   FORMAT('****** AT THE BEGINNING OF DPSET')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,13)IFOUND,IERROR
   13   FORMAT('IFOUND,IERROR = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!     2016/10: IF LAST ARGUMENT IS A PARAMETER OR STRING
!              NAME, THEN PLACE CONTENTS INTO IHV, IHV2
!
      IHV=IHARG(NUMARG)
      IHV2=IHARG2(NUMARG)
      IHWUSE='P'
      MESSAG='NO'
      CALL CHECKN(IHV,IHV2,IHWUSE,   &
                  IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
                  ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOCV,IERROR)
      IF(IERROR.EQ.'NO')THEN
        AV=VALUE(ILOCV)
        IF(AV.GE.0.0)THEN
          IV=INT(AV+0.5)
        ELSE
          IV=INT(AV-0.5)
        ENDIF
        ICTEMP=' '
        WRITE(ICTEMP,'(I8)')IV
        ICTEMP=ADJUSTL(ICTEMP)
        IHV=ICTEMP(1:4)
        IHV2=ICTEMP(5:8)
      ELSEIF(IERROR.EQ.'YES')THEN
!
!       NOW CHECK TO SEE IF THE NAME IS A STRING
!
        IHWUSE='F'
        MESSAG='NO'
        CALL CHECKN(IHV,IHV2,IHWUSE,   &
                    IHNAME,IHNAM2,IUSE,IN,IVALUE,VALUE,NUMNAM,MAXNAM,   &
                    ISUBN1,ISUBN2,MESSAG,IANS,IWIDTH,ILOCV,IERROR)
        IF(IERROR.EQ.'NO')THEN
          ISTART=IVSTAR(ILOCV)
          ISTOP=IVSTOP(ILOCV)
          NLEN=ISTOP-ISTART+1
          IF(NLEN.GT.8)NLEN=8
          ISTOP=ISTART+NLEN-1
          ICNT=0
          ICTEMP=' '
          DO 1011 J=ISTART,ISTOP
            ICNT=ICNT+1
            ICTEMP(ICNT:ICNT)=IFUNC(J)(1:1)
 1011     CONTINUE
          IHV=ICTEMP(1:4)
          IHV2=ICTEMP(5:8)
        ENDIF
      ENDIF
      IERROR='NO'
!
!               ***************************************
!               **  STEP 11--                        **
!               **  TREAT THE PREPLOT/POSTPLOT CASE  **
!               ***************************************
!
      IF(NUMARG.GE.1)THEN
        IF(IHARG(1).EQ.'PRE' .OR. IHARG(1).EQ.'PREP' .OR.   &
          (IHARG(1).EQ.'POST' .AND. IHARG2(1).NE.'SCRI' .AND.   &
           IHARG(2).NE.'CONV'))THEN
          CALL DPPRPO(ICOM,IHARG,IHARG2,IARG,ARG,IARGT,NUMARG,   &
                      IPPDE1,IPPDE2,   &
                      IBUGS2,IFOUND,IERROR)
          GO TO 9000
        ENDIF
      ENDIF
!
!               *********************************************
!               **  STEP 12--                              **
!               **  TREAT THE    SET READ FORMAT    CASE   **
!               *********************************************
!
      IF(NUMARG.GE.2.AND.IHARG(1).EQ.'READ'.AND.   &
         IHARG(2).EQ.'FORM')THEN
        ICREAF(1:40)='                                        '
        ICREAF(41:80)='                                        '
        NCREAF=0
        IF(NUMARG.LE.2 .OR. IHARG(NUMARG).EQ.'OFF' .OR.   &
           IHARG(NUMARG).EQ.'AUTO')THEN
          NCSTRI=0
          IFOUND='YES'
          IF(IFEEDB.EQ.'ON')THEN
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,1251)
 1251       FORMAT('THE (FORTRAN-LIKE) READ FORMAT HAS JUST BEEN ',   &
                   'TURNED OFF;')
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,1252)
 1252       FORMAT('THUS SUBSEQUENT READS WILL BE FREE-FORMAT.')
            CALL DPWRST('XXX','BUG ')
          ENDIF
          GO TO 9000
        ENDIF
!
        ICANS=' '
        DO 1230 I=1,MIN(IWIDTH,130)
          ICANS(I:I)=IANS(I)
 1230   CONTINUE
!
        ISTART=1
        ISTOP=IWIDTH
        IWORD=NUMARG+1
        CALL DPEXWO(ICANS,ISTART,ISTOP,IWORD,   &
                    ICOL1,ICOL2,ISTRIN,NCSTRI,   &
                    IBUGS2,ISUBRO,IERROR)
!
        IF(NCSTRI.GE.1)THEN
          NCREAF=NCSTRI
          NCP2=NCREAF+2
          IF(NCP2.GT.80)NCP2=80
          ICREAF(2:80)=ISTRIN(1:79)
          ICREAF(1:1)='('
          ICREAF(NCP2:NCP2)=')'
          NCREAF=NCP2
          IFOUND='YES'
          IF(IFEEDB.EQ.'ON')THEN
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,1241)
 1241       FORMAT('THE (FORTRAN-LIKE) READ FORMAT HAS JUST BEEN ',   &
                   'SET TO')
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,1242)(ICREAF(I:I),I=1,NCREAF)
 1242       FORMAT(80A1)
            CALL DPWRST('XXX','BUG ')
          ENDIF
          GO TO 9000
        ELSE
          NCSTRI=0
          IFOUND='YES'
          IF(IFEEDB.EQ.'ON')THEN
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,1251)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,1252)
            CALL DPWRST('XXX','BUG ')
          ENDIF
          GO TO 9000
        ENDIF
      ENDIF
!
!               *********************************************
!               **  STEP 13--                              **
!               **  TREAT THE    SET WRITE FORMAT   CASE   **
!               *********************************************
!
      IF(NUMARG.GE.2 .AND.   &
        (IHARG(1).EQ.'WRIT' .OR. IHARG(1).EQ.'PRIN') .AND.   &
         IHARG(2).EQ.'FORM')THEN
        ICWRIF(1:40)='                                        '
        ICWRIF(41:80)='                                        '
        NCWRIF=0
        IF(NUMARG.LE.2)GO TO 1350
        IF(IHARG(NUMARG).EQ.'OFF')GO TO 1350
        IF(IHARG(NUMARG).EQ.'AUTO')GO TO 1350
!
        DO 1330 I=1,80
          ICANS(I:I)=IANS(I)
 1330   CONTINUE
!
        ISTART=1
        ISTOP=IWIDTH
        IWORD=4
        CALL DPEXWO(ICANS,ISTART,ISTOP,IWORD,   &
                    ICOL1,ICOL2,ISTRIN,NCSTRI,   &
                    IBUGS2,ISUBRO,IERROR)
!
        ISTART=1
        ISTOP=IWIDTH
        IWORD=NUMARG+1
        CALL DPEXWO(ICANS,ISTART,ISTOP,IWORD,   &
                    ICOL3,ICOL4,ISTRIN,NCSTRI,   &
                    IBUGS2,ISUBRO,IERROR)
!
        NCSTRI=ICOL4-ICOL1+1
        IF(NCSTRI.GE.1)THEN
          NCWRIF=NCSTRI
          NCP2=NCWRIF+2
          IF(NCP2.GT.80)NCP2=80
          DO 1341 I=2,80
            J=ICOL1-2+I
            IF(J.LE.ICOL4)ICWRIF(I:I)=ICANS(J:J)
            IF(J.GT.ICOL4)ICWRIF(I:I)=' '
 1341     CONTINUE
          ICWRIF(1:1)='('
          ICWRIF(NCP2:NCP2)=')'
          NCWRIF=NCP2
          IFOUND='YES'
          IF(IFEEDB.EQ.'ON')THEN
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,1342)
 1342       FORMAT('THE (FORTRAN-LIKE) WRITE FORMAT HAS JUST BEEN ',   &
                   'SET TO')
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,1343)(ICWRIF(I:I),I=1,NCWRIF)
 1343       FORMAT(80A1)
            CALL DPWRST('XXX','BUG ')
          ENDIF
          GO TO 9000
        ENDIF
!
 1350   CONTINUE
        NCSTRI=0
        IFOUND='YES'
        IF(IFEEDB.EQ.'ON')THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1351)
 1351     FORMAT('THE (FORTRAN-LIKE) WRITE FORMAT HAS JUST BEEN',   &
                 'TURNED OFF;')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1352)
 1352     FORMAT('THUS SUBSEQUENT WRITES WILL BE FREE-FORMAT.')
          CALL DPWRST('XXX','BUG ')
        ENDIF
        GO TO 9000
      ENDIF
!
!               *********************************************
!               **  STEP 14--                              **
!               **  TREAT THE    SET READ REWIND    CASE   **
!               *********************************************
!
      IF(NUMARG.GE.2 .AND. IHARG(1).EQ.'READ' .AND.   &
         IHARG(2).EQ.'REWI')THEN
        IREARW='ON'
        IF(NUMARG.GE.3.AND.IHARG(3).EQ.'OFF')IREARW='OFF'
        IF(NUMARG.GE.3.AND.IHARG(3).EQ.'AUTO')IREARW='OFF'
        IF(NUMARG.GE.3.AND.IHARG(3).EQ.'DEFA')IREARW='OFF'
        IFOUND='YES'
        IF(IFEEDB.EQ.'ON')THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1421)IREARW
 1421     FORMAT('THE     READ REWIND    SWITCH HAS JUST BEEN SET TO ',   &
                 A4)
          CALL DPWRST('XXX','BUG ')
        ENDIF
        GO TO 9000
      ENDIF
!
!               *********************************************
!               **  STEP 15--                              **
!               **  TREAT THE    SET WRITE REWIND    CASE  **
!               *********************************************
!
      IF(NUMARG.GE.2 .AND.   &
        (IHARG(1).EQ.'WRIT' .OR. IHARG(1).EQ.'PRIN') .AND.   &
         IHARG(2).EQ.'REWI')THEN
        IWRIRW='ON'
        IF(NUMARG.GE.3.AND.IHARG(3).EQ.'OFF')IWRIRW='OFF'
        IF(NUMARG.GE.3.AND.IHARG(3).EQ.'AUTO')IWRIRW='OFF'
        IF(NUMARG.GE.3.AND.IHARG(3).EQ.'DEFA')IWRIRW='OFF'
        IFOUND='YES'
        IF(IFEEDB.EQ.'ON')THEN
          WRITE(ICOUT,999)
