!
      IF(NUMARG.GE.2 .AND.   &
        (IHARG(1).EQ.'WRIT' .OR. IHARG(1).EQ.'PRIN') .AND.   &
         IHARG(2).EQ.'DECI')THEN
        IPART1='WRIT'
        IPART2='DECI'
        IF(NUMARG.EQ.2)THEN
          IFORSW='E'
        ELSE
