!               **  EXTRACT THE SECOND ARGUMENT STRING    **
!               ********************************************
!
      ISTEPN='18'
      IF(IBUGS2.EQ.'ON'.OR.ISUBRO.EQ.'SET')   &
      CALL TRACE2(ISTEPN,ISUBN1,ISUBN2)
!
!     DEFINE MAXIMUM NUMBER OF CHARACTERS FOR COMMAND LINE FOR THOSE
!     SET COMMANDS THAT EXTRACT PATH OR FILE NAMES
!
      MAXTMP=256
      ICMDTI=' '
      ISTRIZ=' '
!
      IV=(-999)
      AV=(-999.0)
      IHV='-999'
      IHV2='-999'
      IF(NUMARG.GT.1)THEN
        IV=IARG(NUMARG)
        AV=ARG(NUMARG)
        IHV=IHARG(NUMARG)
        IHV2=IHARG2(NUMARG)
        IHV12=' '
        IHV12(1:4)=IHV
        IHV12(5:8)=IHV2
        IHV12(9:12)='    '
      ENDIF
!
!CCCC OCTOBER 2002.  FILE NAMES FOR UNIX ARE CASE SENSITIVE, SO USE
!CCCC LOWER CASE CHARACTERS (FOR ISTRIN).
!
      DO 1830 I=1,MAXTMP
!CCCC   ICANS(I:I)=IANS(I)
        ICANS(I:I)=IANSLC(I)
 1830 CONTINUE
!
      ISTART=1
      ISTOP=IWIDTH
      IWORD=3
      IF(NUMARG.LE.1)IWORD=2
      CALL DPEXWO(ICANS,ISTART,ISTOP,IWORD,   &
                  ICOL1,ICOL2,ISTRIN,NCSTRI,   &
                  IBUGS2,ISUBRO,IERROR)
!
!CCCC IF(NCSTRI.LT.1)THEN
!CCCC   IERROR='YES'
!CCCC   WRITE(ICOUT,999)
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,1841)
!1841   FORMAT('***** ERROR IN DPSET--')
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,1842)
!1842   FORMAT('      THE SET COMMAND REQUIRES AT LEAST TWO ARGUMENTS.')
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,1844)
!1844   FORMAT('      (FOR EXAMPLE,    SET IPL1NA DPPL1F.TEX)')
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,1845)
!1845   FORMAT('      BUT NO SECOND ARGUMENT EXISTED HERE .')
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   WRITE(ICOUT,1846)
!1846   FORMAT('      THE ENTERED COMMAND LINE WAS AS FOLLOWS--')
!CCCC   CALL DPWRST('XXX','BUG ')
!CCCC   IF(IWIDTH.GE.1)THEN
!CCCC     WRITE(ICOUT,1847)(IANS(I),I=1,MIN(80,IWIDTH))
!1847     FORMAT('      ',80A1)
!CCCC     CALL DPWRST('XXX','BUG ')
!CCCC   ELSE
!CCCC     WRITE(ICOUT,999)
!CCCC     CALL DPWRST('XXX','BUG ')
!CCCC   ENDIF
!CCCC   GO TO 9000
!CCCC ENDIF
!CCCC THE FOLLOWING SECTION WAS ADDED    NOVEMBER 1993
!
!               ***********************************
