         IF(IHARG(3).EQ.'=   ')IWORD=5
         ICASEZ='BKVW'
         ICMDTI='THE PATH FOR THE POSTSCRIPT VIEWER ='
         CALL DPEXFN(IANS,IANSLC,ICANS,MAXTMP,IWIDTH,NUMARG,   &
                     ISTRIN,IWORD,ICMDTI,ITEMP,   &
                     ICASEZ,IBCKVW,NCBKVW,   &
                     IBUGS2,ISUBRO,IFOUND,IERROR)
         GO TO 9000
      ENDIF
