!
!         FOR LINUX, IF "DEFAULT" IS SPECIFIED CHECK SETTING OF "EDITOR"
!         ENVIRONMENT VARIABLE.
!
#ifdef LINUX
          IF(IEDITR(1:7).EQ.'SYSTEM' .OR.   &
             IEDITR(1:7).EQ.'system')THEN
            CALL getenv('EDITOR',IEDITR)
            DO 67101 II=80,1,-1
              IF(IEDITR(II:II).NE.' ')THEN
                NCEDIT=II
                GO TO 67109
              ENDIF
67101       CONTINUE
            IEDITR='FED'
            NCEDIT=3
67109       CONTINUE
          ENDIF
#endif
        ELSEIF(IHOST1.EQ.'IBM-')THEN
!
!         FOR WINDOWS INTEL COMPILER, CHECK IF WORDPAD ENTERED.  IF SO,
!         REPLACE WITH "WRITE.EXE".
