           ENDIF
         ENDIF
         GO TO 9000
      ENDIF
!
!CCCC FOLLOWING SECTION ADDED DECEMBER  2015
!               ***********************************************
!               **  TREAT THE  SET STANDARD INPUT      CASE  **
!               ***********************************************
!
!     NOTE: CHECK FOR "SET STANDARD INPUT POLL <FILE-NAME>".  FOR THIS
!           CASE, SET UP LOOP TO CHECK FOR EXISTENCE OF SPECIFIED FILE.
!           THIS OPTION IS INTENDED FOR CASE WHEN EXTERNAL PROGRAM IS
!           CONTROLLING INPUT TO DATAPLOT.
!
!           THE COMMAND
!
!               SET RESUME POLL    (OR POLL RESUME)
!
!           IS A SYNONYM FOR
!
!               SET STANDARD INPUT POLL
!
!           THE COMMAND
!
!               SET SUSPEND POLL    (OR POLL SUSPEND)
!
!           IS A SYNONYM FOR
!
!               SET STANDARD INPUT
!
!           THE SET RESUME POLL AND SET SUSPEND POLL DO NOT TAKE A
!           FILE NAME ARGUMENT (THEY WILL USE THE PREVIOUSLY DEFINED
!           FILE NAME).
!
!     NOTE: CHECK FOR
!
!               SET STANDARD INPUT CLOSE
!               SET STANDARD INPUT POLL CLOSE
!
!           THESE WILL CLOSE THE SPECIFIED FILE IN "DELETE" MODE.  THE
!           FIRST OPTION RETURNS CONTROL BACK TO THE TERMINAL WHILE THE
!           SECOND OPTION RESUMES POLLING MODE.  THE IDEA IS THAT AN
!           EXTERNAL PROGRAM CAN SEND AN UPDATED SET OF COMMANDS WITH
!           OPTION TO RETURN CONTROL TO THE END USER.
!
      IFLAGD=0
      IF(NUMARG.EQ.2 .AND. IHARG(1).EQ.'RESU' .AND.   &
         IHARG(2).EQ.'POLL')THEN
        NUMARG=3
        IHARG(1)='STAN'
        IHARG2(1)='ARD '
        IHARG(2)='INPU'
        IHARG2(2)='T   '
        IHARG(3)='POLL'
        IHARG2(3)='    '
        IHARG(4)='    '
        IHARG2(4)='    '
      ELSEIF(NUMARG.EQ.2 .AND. IHARG(1).EQ.'POLL' .AND.   &
         IHARG(2).EQ.'RESU')THEN
        NUMARG=3
        IHARG(1)='STAN'
        IHARG2(1)='ARD '
        IHARG(2)='INPU'
        IHARG2(2)='T   '
        IHARG(3)='POLL'
        IHARG2(3)='    '
        IHARG(4)='    '
        IHARG2(4)='    '
      ELSEIF(NUMARG.EQ.2 .AND. IHARG(1).EQ.'SUSP' .AND.   &
         IHARG(2).EQ.'POLL')THEN
        IF(IRD.NE.I1MACH(1))THEN
          CLOSE(IRD)
        ENDIF
        IRD=I1MACH(1)
        IF(IFEEDB.EQ.'ON')THEN
          WRITE(ICOUT,1847)
          CALL DPWRST('XXX','BUG ')
        ENDIF
        IFOUND='YES'
        GO TO 9000
      ELSEIF(NUMARG.EQ.2 .AND. IHARG(1).EQ.'POLL' .AND.   &
         IHARG(2).EQ.'SUSP')THEN
        IF(IRD.NE.I1MACH(1))THEN
          CLOSE(IRD)
        ENDIF
        IRD=I1MACH(1)
        IF(IFEEDB.EQ.'ON')THEN
          WRITE(ICOUT,1847)
          CALL DPWRST('XXX','BUG ')
        ENDIF
        IFOUND='YES'
        GO TO 9000
      ENDIF
!
      IF(NUMARG.GE.2.AND.IHARG(1).EQ.'STAN'.AND.   &
         IHARG(2).EQ.'INPU')THEN
!
         IF(NUMARG.EQ.2)THEN
           IFLAGP=0
           ISTDIN='NULL'
           NCSTIN=-1
           IF(IRD.NE.I1MACH(1))THEN
             CLOSE(IRD)
           ENDIF
           IRD=I1MACH(1)
           IF(IFEEDB.EQ.'ON')THEN
             WRITE(ICOUT,1847)
 1847        FORMAT('STANDARD INPUT WILL REVERT TO THE TERMINAL.')
             CALL DPWRST('XXX','BUG ')
           ENDIF
           IFOUND='YES'
           GO TO 9000
         ELSEIF(NUMARG.EQ.3)THEN
           IF(IHARG(3).EQ.'NULL' .OR.   &
              IHARG(3).EQ.'DEFA' .OR. IHARG(3).EQ.'ON' .OR.   &
              IHARG(3).EQ.'OFF'  .OR. IHARG(3).EQ.'YES' .OR.   &
              IHARG(3).EQ.'NO'   .OR. IHARG(3).EQ.'TERM')THEN
             IFLAGP=0
             ISTDIN='NULL'
             NCSTIN=-1
             IF(IRD.NE.I1MACH(1))THEN
               CLOSE(IRD)
             ENDIF
             IRD=I1MACH(1)
             IF(IFEEDB.EQ.'ON')THEN
               WRITE(ICOUT,1847)
               CALL DPWRST('XXX','BUG ')
             ENDIF
             IFOUND='YES'
             GO TO 9000
           ENDIF
         ENDIF
!
         IF(IHARG(3).EQ.'POLL' .AND. IHARG2(3).EQ.'    ' .AND.   &
           (IHARG(4).EQ.'CLOS' .OR. IHARG(4).EQ.'DELE'))THEN
           IFLAGD=1
           IFLAGP=1
           IWORD=6
           IF(IHARG(5).EQ.'=   ')IWORD=7
           IFOUND='YES'
         ELSEIF(IHARG(4).EQ.'POLL' .AND. IHARG2(4).EQ.'    ' .AND.   &
           (IHARG(3).EQ.'CLOS' .OR. IHARG(3).EQ.'DELE'))THEN
           IFLAGD=1
           IFLAGP=1
           IWORD=6
           IF(IHARG(5).EQ.'=   ')IWORD=7
           IFOUND='YES'
         ELSEIF((IHARG(3).EQ.'CLOS' .AND. IHARG2(3).EQ.'E   ') .OR.   &
                (IHARG(3).EQ.'DELE' .AND. IHARG2(3).EQ.'TE  '))THEN
           IFLAGD=1
           IFLAGP=0
           IWORD=5
           IF(IHARG(4).EQ.'=   ')IWORD=6
           IFOUND='YES'
         ELSEIF(IHARG(3).EQ.'POLL' .AND. IHARG2(3).EQ.'    ')THEN
           IFLAGD=0
           IFLAGP=1
           IWORD=5
           IF(IHARG(4).EQ.'=   ')IWORD=6
           IFOUND='YES'
         ELSE
           IFLAGD=0
           IFLAGP=0
           IWORD=4
           IF(IHARG(3).EQ.'=   ')IWORD=5
           IFOUND='YES'
         ENDIF
!
         IF(IFLAGD.EQ.1 .AND. IFLAGP.EQ.0)THEN
!
!          IF DELETE SPECIFIED WITHOUT FURTHER POLLING, DO NOT
!          CHECK FOR A FILE NAME.
!
           CONTINUE
         ELSEIF(IFLAGD.EQ.1 .AND. IFLAGP.EQ.1)THEN
!
!          IF DELETE SPECIFIED WITH FURTHER POLLING, CAN EITHER
!          SPECIFY A NEW FILE NAME TO BE POLLED OR CAN USE
!          PREVIOUSLY DEFINED NAME.
!
           IF(IHARG(IWORD-1).NE.'    ')THEN
             ICASEZ='STIN'
             ICMDTI='THE STANDARD INPUT HAS BEEN SET TO'
             CALL DPEXFN(IANS,IANSLC,ICANS,MAXTMP,IWIDTH,NUMARG,   &
                         ISTRIN,IWORD,ICMDTI,ITEMP,   &
                         ICASEZ,ISTDIN,NCSTIN,   &
                         IBUGS2,ISUBRO,IFOUND,IERROR)
           ENDIF
!
         ELSE
           IF(IHARG(IWORD-1).NE.'    ')THEN
             ICASEZ='STIN'
             ICMDTI='THE STANDARD INPUT HAS BEEN SET TO'
             CALL DPEXFN(IANS,IANSLC,ICANS,MAXTMP,IWIDTH,NUMARG,   &
                         ISTRIN,IWORD,ICMDTI,ITEMP,   &
                         ICASEZ,ISTDIN,NCSTIN,   &
                         IBUGS2,ISUBRO,IFOUND,IERROR)
           ENDIF
         ENDIF
!
!        PROCESS DELETE FIRST
!
         IF(IFLAGD.EQ.1)THEN
           IF(IRD.NE.I1MACH(1))THEN
             REWIND(IRD)
             CLOSE(IRD,STATUS='DELETE')
             IRD=I1MACH(1)
             ASLEEP=2.0
             IF(PSTDSL.GT.0.0)ASLEEP=PSTDSL
             CALL DPSLE2(ASLEEP,IBUGS2,ISUBRO,IERROR)
           ENDIF
           IFLAGD=0
           IF(IFLAGP.EQ.0)GO TO 9000
         ENDIF
!
         IF(NCSTIN.EQ.0)THEN
           ISTDIN='NULL'
           NCSEDI=-1
           WRITE(ICOUT,1847)
           CALL DPWRST('XXX','BUG ')
           IF(IRD.NE.I1MACH(1))THEN
             CLOSE(IRD)
           ENDIF
           IRD=I1MACH(1)
         ELSE
           IF(IFLAGP.EQ.0)THEN
             IERROR='NO'
             CALL DPINFI(ISTDIN,IEXIST,IOPEN,IACC,ISUBN0,IBUGS2,   &
                         ISUBRO,IERROR)
             IF(IEXIST.EQ.'YES' .AND. IERROR.EQ.'NO')THEN
               IRD=9
               OPEN(IRD,FILE=ISTDIN,STATUS='OLD')
               REWIND(9)
             ELSE
               IF(IFEEDB.EQ.'ON')THEN
                 WRITE(ICOUT,1848)ISTDIN
 1848            FORMAT('FILE: ',A80)
                 CALL DPWRST('XXX','BUG ')
                 WRITE(ICOUT,1849)
 1849            FORMAT('DOES NOT EXIST.  STANDARD INPUT NOT CHANGED.')
                 CALL DPWRST('XXX','BUG ')
               ENDIF
             ENDIF
             GO TO 9000
           ELSE
             ASLEEP=2.0
             IF(PSTDSL.GT.0.0)ASLEEP=PSTDSL
             ICNT=0
 1851        CONTINUE
             ICNT=ICNT+1
             IF(ISTDCN.GT.0 .AND. ICNT.GT.ISTDCN)GO TO 9000
             IERROR='NO'
             CALL DPINFI(ISTDIN,IEXIST,IOPEN,IACC,ISUBN0,IBUGS2,   &
                         ISUBRO,IERROR)
             IF(IEXIST.EQ.'YES' .AND. IERROR.EQ.'NO')THEN
               IRD=9
               CLOSE(IRD)
               OPEN(IRD,FILE=ISTDIN,STATUS='OLD',IOSTAT=IOS)
               REWIND(IRD)
               GO TO 9000
             ELSE
               CALL DPSLE2(ASLEEP,IBUGS2,ISUBRO,IERROR)
               GO TO 1851
             ENDIF
           ENDIF
           GO TO 9000
         ENDIF
         GO TO 9000
      ENDIF
!
!CCCC THE FOLLOWING SECTION WAS ADDED        DECEMBER 2015
!     ******************************************
!     **  SET MAXIMUM COUNTER STANDARD INPUT  **
!     ******************************************
!
      IPART1='MAXI'
      IPART2='COUN'
      IPART3='STAN'
      IPART4='INPU'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2.AND.   &
         IHARG(3).EQ.IPART3.AND.IHARG(4).EQ.IPART4)THEN
         ISTDCN=IV
         IF(ISTDCN.LT.0)ISTDCN=0
         GO TO 5150
      ENDIF
!
!CCCC THE FOLLOWING SECTION WAS ADDED        DECEMBER 2015
!     ******************************************
!     **  SET DELAY STANDARD INPUT            **
!     ******************************************
!
      IPART1='DELA'
      IPART2='STAN'
      IPART3='INPU'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2.AND.   &
         IHARG(3).EQ.IPART3)THEN
        PSTDSL=AV
        IF(PSTDSL.LE.0.0)PSTDSL=2.0
        GO TO 5170
      ENDIF
!
!CCCC FOLLOWING SECTION ADDED APRIL 1995.
!     *********************************
!     **  SET UNFORMATTED COLUMNS    **
!     *********************************
!
      IPART1='UNFO'
      IPART2='COLU'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2)THEN
        IUNFMC=IV
        IF(IUNFMC.LT.0)IUNFMC=0
        IV=IUNFMC
        GO TO 5150
      ENDIF
!
!CCCC FOLLOWING SECTION ADDED APRIL 1995.
!     *********************************
!     **  SET UNFORMATTED RECORDS    **
!     *********************************
!
      IPART1='UNFO'
      IPART2='RECO'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2)THEN
        IUNFNR=IV
        IF(IUNFNR.LT.0)IUNFNR=0
        IV=IUNFNR
        GO TO 5150
      ENDIF
!
!CCCC FOLLOWING SECTION ADDED APRIL 1995.
!     *********************************
!     **  SET UNFORMATTED OFFSET     **
!     *********************************
!
      IPART1='UNFO'
      IPART2='OFFS'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2)THEN
        IUNFOF=IV
        IF(IUNFOF.LT.0)IUNFOF=0
        IV=IUNFOF
        GO TO 5150
      ENDIF
!
!CCCC THE FOLLOWING SECTION WAS ADDED        JULY 1995.
!     ******************************************
!     **  SET FIT ITERATIONS (#)              **
!     ******************************************
!
      IPART1='FIT'
      IPART2='ITER'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2)THEN
         IFITIT=IV
         GO TO 5150
      ENDIF
!
!CCCC THE FOLLOWING SECTION WAS ADDED        JULY 1995.
!     ******************************************
!     **  SET FIT STANDARD DEVIATION (#)      **
!     ******************************************
!
      IPART1='FIT '
      IPART2='STAN'
      IPART3='DEVI'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2)THEN
         IF(IHARG(3).EQ.IPART3)THEN
            FITSD=AV
            GO TO 5170
         ENDIF
      ENDIF
!
      IPART1='FIT '
      IPART2='SD'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2)THEN
         FITSD=AV
         GO TO 5170
      ENDIF
!
!CCCC THE FOLLOWING SECTION WAS ADDED        JULY 1995.
!     ******************************************
!     **  SET FIT ADDITIVE CONSTANT (ON/OFF)  **
!     ******************************************
!
      IPART1='FIT '
      IPART2='ADDI'
      IPART3='CONS'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2)THEN
         IF(IHARG(3).EQ.IPART3)THEN
            IFITAC=IHV
            GO TO 5160
         ENDIF
      ENDIF
!
      IPART1='FIT '
      IPART2='CONS'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2)THEN
         IFITAC=IHV
         GO TO 5160
      ENDIF
!
!CCCC FOLLOWING SECTION ADDED MARCH 1996.
!     ********************************************
!     **  SET RELATIVE HISTOGRAM <AREA/PERCENT> **
!     ********************************************
!
      IPART1='RELA'
      IPART2='HIST'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2)THEN
        IRHSTG=IHV
        IF(IRHSTG.NE.'AREA'.AND.IRHSTG.NE.'PERC')THEN
          IRHSTG='AREA'
        ENDIF
        GO TO 5160
      ENDIF
!
!CCCC FOLLOWING SECTION ADDED MAY 1998.
!     ***************************************************
!     **  SET KAPLAN MEIER            <RELI/CDF    >   **
!     ***************************************************
!
      IPART1='KAPL'
      IPART2='MEIE'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2)THEN
        IKAPSW=IHV
        IF(IKAPSW.NE.'CDF ')IKAPSW='RELI'
        GO TO 5160
      ENDIF
      IF(IHARG(1).EQ.IPART1)THEN
        IKAPSW=IHV
        IF(IKAPSW.NE.'CDF ')IKAPSW='RELI'
        GO TO 5160
      ENDIF
!
!CCCC FOLLOWING SECTION ADDED MAY 1998.
!     ***************************************************
!     **  SET CENSORING <TYPE 1/TYPE 2>                **
!     ***************************************************
!
      IPART1='CENS'
      IPART2='TYPE'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2)THEN
        ICENTY=IHV
        IF(ICENTY.EQ.'TIME')ICENTY='1   '
        IF(ICENTY.EQ.'MULT')ICENTY='3   '
        IF(ICENTY.NE.'1   '.AND.ICENTY.NE.'3   '.AND.   &
           ICENTY.NE.'NONE')ICENTY='2   '
        GO TO 5160
      ENDIF
!
!CCCC FOLLOWING SECTION ADDED JUNE 1998.
!     ***************************************************
!     **  SET MATRIX SCALE <NONE/SD/RANGE/ZSCORE/MEAN> **
!     ***************************************************
!
      IPART1='MATR'
      IPART2='SCAL'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2)THEN
        IMATSC=IHV
        IF(IMATSC.EQ.'ZSCO')IMATSC='Z-SC'
        IF(IMATSC.EQ.'SCOR')IMATSC='Z-SC'
        IF(IMATSC.NE.'SD  '.AND.IMATSC.NE.'RANG'.AND.   &
          IMATSC.NE.'Z-SC'.AND.IMATSC.NE.'MEAN')   &
          IMATSC='NONE'
        GO TO 5160
      ENDIF
!
!CCCC FOLLOWING SECTION ADDED APRIL 1997.
!     ***************************************************
!     **  SET CONTROL CHART WEIGHTING <CENTER/RIGHT>   **
!     ***************************************************
!
      IPART1='CONT'
      IPART2='CHAR'
      IPART3='WEIG'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2.AND.   &
      IHARG(3).EQ.IPART3)THEN
        ICCHWT=IHV
        IF(ICCHWT.NE.'CENT'.AND.ICCHWT.NE.'RIGH')THEN
          ICCHWT='RIGH'
        ENDIF
        GO TO 5160
      ENDIF
!
!CCCC FOLLOWING SECTION ADDED SEPTEMBER  2009
!     *************************************************************
!     **  SET CONTROL CHART LIMITS <DEFAULT/WECO/ISO 13528>      **
!     *************************************************************
!
      IPART1='CONT'
      IPART2='CHAR'
      IPART3='LIMI'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2.AND.   &
         IHARG(3).EQ.IPART3)THEN
        IF(IHARG(NUMARG).EQ.'WECO')THEN
          ICONWC='WECO'
        ELSEIF(IHARG(NUMARG).EQ.'ISO ')THEN
          ICONWC='ISO'
        ELSEIF(IHARG(4).EQ.'ISO ' .AND. IHARG(5).EQ.'1352')THEN
          ICONWC='ISO'
        ELSE
          ICONWC='DEFA'
        ENDIF
        IHV=ICONWC
        GO TO 5160
      ENDIF
!
!CCCC FOLLOWING SECTION ADDED APRIL 1997.
!     ********************************************
!     **  SET CONTROL CHART      <DATA/PRIOR>   **
!     ********************************************
!
      IPART1='CONT'
      IPART2='CHAR'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2)THEN
        ICCHPR=IHV
        IF(ICCHPR.NE.'DATA'.AND.ICCHPR.NE.'PRIO')THEN
          ICCHPR='DATA'
        ENDIF
        GO TO 5160
      ENDIF
!
!CCCC FOLLOWING SECTION ADDED AUGUST 2013
!     ********************************************
!     **  SET RGB MAXIMUM VALUE <VALUE>         **
!     ********************************************
!
      IPART1='RGB '
      IPART2='MAXI'
      IPART3='VALU'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2.AND.   &
         IHARG(3).EQ.IPART3)THEN
        IRGBMX=IV
        IF(IRGBMX.LT.255)IRGMX=255
        GO TO 5150
      ENDIF
!
!CCCC FOLLOWING SECTION ADDED AUGUST 2013
!     *******************************************************
!     **  SET MCCOOL WEIBULL LOCATION TEST <VALUE>         **
!     *******************************************************
!
      IPART1='MCCO'
      IPART2='WEIB'
      IPART3='LOCA'
      IPART4='TEST'
      IPART5='R1  '
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2.AND.   &
         IHARG(3).EQ.IPART3.AND.IHARG(4).EQ.IPART4.AND.   &
         IHARG(5).EQ.IPART5)THEN
        IMCCR1=IV
        IF(IMCCR1.LT.0)IRGMX=0
        GO TO 5150
      ENDIF
!
!CCCC FOLLOWING SECTION ADDED SEPTEMBER 1998.
!     ************************************************************
!     **  SET PERCENT POINT PLOT <BINNED/UNBINNED/INTERPOLATED> **
!     ************************************************************
!
      IPART1='PERC'
      IPART2='POIN'
      IPART3='PLOT'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2.AND.   &
         IHARG(3).EQ.IPART3)THEN
        IPPTBI=IHV
        IF(IPPTBI.NE.'UNBI'.AND.IPPTBI.NE.'INTE')THEN
          IPPTBI='BINN'
        ENDIF
        GO TO 5160
      ENDIF
!
!CCCC FOLLOWING SECTION ADDED SEPTEMBER 1998.
!     ****************************************************************
!     **  SET QUANTILE-QUANTILE PLOT <BINNED/UNBINNED/INTERPOLATED> **
!     ****************************************************************
!
      IPART1='PERC'
      IPART2='POIN'
      IPART3='PLOT'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2.AND.   &
         IHARG(3).EQ.IPART3)THEN
        IQQPBI=IHV
        IF(IQQPBI.NE.'UNBI'.AND.IQQPBI.NE.'INTE')THEN
          IQQPBI='BINN'
        ENDIF
        GO TO 5160
      ENDIF
!
!CCCC FOLLOWING SECTION ADDED SEPTEMBER 1998.
!     ************************************************************
!     **  SET PIE CHART          <BINNED/UNBINNED/INTERPOLATED> **
!     ************************************************************
!
      IPART1='PIE '
      IPART2='CHAR'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2)THEN
        IPIEBI=IHV
        IF(IPIEBI.NE.'UNBI'.AND.IPIEBI.NE.'INTE')THEN
          IPIEBI='BINN'
        ENDIF
        GO TO 5160
      ENDIF
!
!CCCC FOLLOWING SECTION ADDED JULY 1999.
!     ****************************************************************
!     **  SET AUTOCORRELATION BAND <WHITE NOISE/BOX-JENKINS> **
!     ****************************************************************
!
      IPART1='AUTO'
      IPART2='BAND'
      IPART3='PLOT'
      IF(IHARG(1).EQ.IPART1.AND.   &
         (IHARG(2).EQ.IPART2.OR.IHARG(2).EQ.IPART3))THEN
        IAUTCP='WHIT'
        IAUTCP=IHV
        IF(IAUTCP.EQ.'ARMA'.OR.IAUTCP.EQ.'BOX'.OR.IAUTCP.EQ.'JENK'   &
           .OR.IAUTCP.EQ.'BOXJ'.OR.IAUTCP.EQ.'ARIM')THEN
          IAUTCP='BOXJ'
        ELSE
          IAUTCP='WHIT'
        ENDIF
        IHV=IAUTCP
        GO TO 5160
      ENDIF
!
!CCCC FOLLOWING SECTION ADDED FEBRUARY 2003.
!     *********************************************************
!     **  SET AUTOCORRELATION LAG ZERO <ON/OFF>              **
!     *********************************************************
!
      IPART1='AUTO'
      IPART2='LAG'
      IPART3='ZERO'
      IPART4='0'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2.AND.   &
         (IHARG(3).EQ.IPART3.OR.IHARG(2).EQ.IPART4))THEN
        IAUTL0=IHV
        IF(IAUTL0.EQ.'OFF'.OR.IAUTL0.EQ.'NO'.OR.IAUTL0.EQ.'NONE'   &
           .OR.IAUTL0.EQ.'FALS')THEN
          IAUTL0='OFF'
        ELSE
          IAUTL0='ON'
        ENDIF
        IHV=IAUTL0
        GO TO 5160
      ENDIF
!
!CCCC FOLLOWING SECTION ADDED FEBRUARY 2003.
!     *********************************************************
!     **  SET PARALLEL COORDINATES STANDARDIZE <NONE/USCORE/ **
!      **  ZSCORE>                                           **
!     *********************************************************
!
      IPART1='PARA'
      IPART2='COOR'
      IPART3='STAN'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2.AND.   &
         IHARG(3).EQ.IPART3)THEN
        IPCCST=IHV
        IF(IPCCST.EQ.'OFF'.OR.IPCCST.EQ.'NO'.OR.IPCCST.EQ.'NONE'   &
           .OR.IPCCST.EQ.'FALS')THEN
          IPCCST='NONE'
        ELSEIF(IPCCST.EQ.'ON'.OR.IPCCST.EQ.'YES'.OR.   &
           IPCCST.EQ.'TRUE')THEN
          IPCCST='USCO'
        ENDIF
        IF(IPCCST.EQ.'ZSCO'.OR.IPCCST.EQ.'NONE'.OR.   &
           IPCCST.EQ.'ZSCO')THEN
          IHV=IPCCST
        ELSE
          IHV='USCO'
        ENDIF
        GO TO 5160
      ENDIF
!
!CCCC FOLLOWING SECTION ADDED FEBRUARY 2003.
!     *********************************************************
!     **  SET BOOTSTRAP GROUPS <INDEPENDENT/DEPENDENT>       **
!     *********************************************************
!
      IPART1='BOOT'
      IPART2='GROU'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2)THEN
        IBOOGR=IHV
        IF(IBOOGR.EQ.'OFF'.OR.IBOOGR.EQ.'NO'.OR.IBOOGR.EQ.'NONE'.OR.   &
           IBOOGR.EQ.'FALS'.OR.IBOOGR.EQ.'DEFA'.OR.   &
           IBOOGR.EQ.'ON'.OR.IBOOGR.EQ.'YES'.OR.   &
           IBOOGR.EQ.'TRUE')THEN
          IBOOGR='INDE'
        ENDIF
        IF(IBOOGR.NE.'DEPE')IBOOGR='INDE'
        IHV=IBOOGR
        GO TO 5160
      ENDIF
!
!CCCC FOLLOWING SECTION ADDED MAY 2003.
!     *************************************************************
!     **  SET MULTIVARIATE NORMAL <SADMVN/RANMVN/KROMVN/SPHMVN>  **
!     *************************************************************
!
      IPART1='MULT'
      IPART2='NORM'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2)THEN
        IMVNTY=IHV
        IF(IMVNTY.NE.'RANM'.AND.IMVNTY.NE.'KROM'.AND.   &
           IMVNTY.NE.'SPHM')IMVNTY='SADM'
        IHV=IMVNTY
        GO TO 5160
      ENDIF
!
!CCCC FOLLOWING SECTION ADDED SEPTEMBER 2003.
!     *************************************************************
!     **  SET TABLE BORDER <OFF/ON/RULE/COLS>                    **
!     *************************************************************
!
      IPART1='TABL'
      IPART2='BORD'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2)THEN
        IF(IHV.EQ.'ON' .OR. IHV.EQ.'YES')THEN
          IHV='ON'
        ELSEIF(IHV.EQ.'OFF' .OR. IHV.EQ.'NO' .OR. IHV.EQ.'NONE')THEN
          IHV='OFF'
        ELSEIF(IHV.EQ.'RULE' .OR. IHV.EQ.'TOP')THEN
          IHV='RULE'
        ELSEIF(IHV.EQ.'COLS' .OR. IHV.EQ.'COLU' .OR. IHV.EQ.'COL')THEN
          IHV='COLS'
        ELSE
          IHV='OFF'
        ENDIF
        ITABBR=IHV
        GO TO 5160
      ENDIF
!
!CCCC FOLLOWING SECTION ADDED JULY 2010.
!     *************************************************************
!     **  SET TABLE HEADER <OFF/ON>                              **
!     *************************************************************
!
      IPART1='TABL'
      IPART2='HEAD'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2)THEN
        IF(IHV.EQ.'ON' .OR. IHV.EQ.'YES' .OR. IHV.EQ.'TRUE')THEN
          IHV='ON'
        ELSEIF(IHV.EQ.'OFF' .OR. IHV.EQ.'NO' .OR. IHV.EQ.'NONE' .OR.   &
               IHV.EQ.'FALS')THEN
          IHV='OFF'
        ELSE
          IHV='ON'
        ENDIF
        ITABHD=IHV
        GO TO 5160
      ENDIF
!
!CCCC FOLLOWING SECTION ADDED SEPTEMBER 2003.
!     *************************************************************
!     **  SET TABLE SPACING <VALUE>                              **
!     *************************************************************
!
      IPART1='TABL'
      IPART2='SPAC'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2)THEN
        ITABSP=IV
        IF(ITABSP.LT.0)ITABSP=0
        IV=ITABSP
        GO TO 5150
      ENDIF
!
!CCCC FOLLOWING SECTION ADDED SEPTEMBER 2003.
!     *************************************************************
!     **  SET TABLE WIDTH   <VALUE>                              **
!     *************************************************************
!
      IPART1='TABL'
      IPART2='WIDT'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2)THEN
        ITABWD=IV
        IF(ITABWD.LE.0)ITABWD=0
        IV=ITABWD
        GO TO 5150
      ENDIF
!
!CCCC FOLLOWING SECTION ADDED SEPTEMBER 2003.
!     *************************************************************
!     **  SET TABLE HEIGHT  <VALUE>                              **
!     *************************************************************
!
      IPART1='TABL'
      IPART2='HEIG'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2)THEN
        ITABHT=IV
        IF(ITABHT.LE.0)ITABHT=0
        IV=ITABHT
        GO TO 5150
      ENDIF
!
!CCCC FOLLOWING SECTION ADDED JANUARY 2004.
!     *************************************************************
!     **  SET READ VARIABLE LABEL <ON/OFF/ROWLABEL>              **
!     *************************************************************
!
      IPART1='READ'
      IPART2='VARI'
      IPART3='LABE'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2.AND.   &
         IHARG(3).EQ.IPART3)THEN
        IF(IHV.EQ.'ON' .OR. IHV.EQ.'YES')THEN
          IHV='ON'
        ELSEIF(IHV.EQ.'OFF' .OR. IHV.EQ.'NO' .OR. IHV.EQ.'NONE')THEN
          IHV='OFF'
        ELSEIF(IHARG(4).EQ.'ROW ' .OR. IHARG(4).EQ.'ROWL')THEN
          IHV='ROWL'
        ELSE
          IHV='OFF'
        ENDIF
        IVARLA=IHV
        GO TO 5160
      ENDIF
!
!CCCC FOLLOWING SECTION ADDED JANUARY 2004.
!     *****************************************************************
!     **  SET CONVERT CHARACTER <ERROR/IGNORE/CHARACTER/CATEGORICAL> **
!     *****************************************************************
!
      IPART1='CONV'
      IPART2='CHAR'
      IF((IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2) .OR.    &
         (IHARG(1).EQ.IPART2.AND.IHARG(2).EQ.IPART1))THEN
        IF(IHV.EQ.'CHAR' .OR. IHV.EQ.'ON' .OR. IHV.EQ.'YES')THEN
          IHV='CHAR'
        ELSEIF(IHV.EQ.'ERRO' .OR. IHV.EQ.'DEFA')THEN
          IHV='ERRO'
        ELSEIF(IHV.EQ.'IGNO' .OR. IHV.EQ.'OFF' .OR. IHV.EQ.'NO' .OR.   &
               IHV.EQ.'NONE')THEN
          IHV='IGNO'
        ELSEIF(IHV.EQ.'CATE')THEN
          IHV='CATE'
        ELSE
          IHV='ERRO'
        ENDIF
        IGRPAU=IHV
        GO TO 5160
      ENDIF
!
!CCCC FOLLOWING SECTION ADDED JUNE 2018.
!     *************************************************************
!     **  SET ROW LABEL COLUMN <VALUE>                           **
!     *************************************************************
!
      IPART1='ROW'
      IPART2='LABE'
      IPART3='COLU'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2.AND.   &
         IHARG(3).EQ.IPART3)THEN
        IF(IHARG(4).EQ.'DEFA' .OR. IHARG(4).EQ.'NO' .OR.   &
           IHARG(4).EQ.'OFF')THEN
          IV=-1
        ELSEIF(IHARG(4).EQ.'ON' .OR. IHARG(4).EQ.'YES')THEN
          IV=1
        ELSE
          IV=IARG(4)
          IF(IV.LT.1)IV=-1
          IF(IV.GT.50)IV=-1
        ENDIF
        IRWLCO=IV
        GO TO 5150
      ENDIF
!
!CCCC FOLLOWING SECTION ADDED JULY 2018.
!     *************************************************************
!     **  SET KERNEL DENSITY RANDOM NUMBERS <VALUE>              **
!     *************************************************************
!
      IPART1='KERN'
      IPART2='DENS'
      IPART3='RAND'
      IPART4='NUMB'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2.AND.   &
         IHARG(3).EQ.IPART3.AND.IHARG(4).EQ.IPART4)THEN
        IF(IHARG(5).EQ.'DEFA' .OR. IHARG(5).EQ.'NO' .OR.   &
           IHARG(5).EQ.'OFF'  .OR. IHARG(5).EQ.'ON' .OR.   &
           IHARG(5).EQ.'YES')THEN
          IV=0
        ELSE
          IV=IARG(5)
          IF(IV.LT.1)IV=0
          IF(IV.GT.MAXOBV)IV=0
        ENDIF
        IKDERN=IV
        GO TO 5150
      ENDIF
!
!CCCC FOLLOWING SECTION ADDED JULY 2018.
!     *************************************************************
!     **  SET KERNEL DENSITY PROBABILITY FUNCTION <PDF/CDF/PPF>  **
!     *************************************************************
!
      IPART1='KERN'
      IPART2='DENS'
      IPART3='PROB'
      IPART4='FUNC'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2.AND.   &
         IHARG(3).EQ.IPART3.AND.IHARG(4).EQ.IPART4)THEN
        IF(IHARG(5).EQ.'CDF')THEN
          IHV='CDF'
        ELSEIF(IHARG(5).EQ.'PPF')THEN
          IHV='PPF'
        ELSEIF(IHARG(5).EQ.'INVE' .AND. IHARG(6).EQ.'CDF')THEN
          IHV='PPF'
        ELSE
          IHV='PDF'
        ENDIF
        IKDEPF=IHV
        GO TO 5160
      ENDIF
!
!CCCC FOLLOWING SECTION ADDED JANUARY 2004.
!     *************************************************************
!     **  SET READ DELIMITER <VALUE>                             **
!     *************************************************************
!
!     2012/09: TABS ARE COMMONLY USED AS DELIMITERS.  HOWEVER, TABS
!              ARE CONVERTED TO SPACES ON COMMAND LINES.  SO ALLOW
!              EXPLICITLY CHECK FOR "TAB" TO SET THE DELIMITER TO
!              A TAB.
!
      IPART1='READ'
      IPART2='DELI'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2)THEN
        IF(IHV.EQ.'TAB')THEN
          IHV='    '
          IVAL=9
          CALL DPCONA(IVAL,IHV(1:1))
        ELSEIF(IHV.EQ.'ON' .OR. IHV.EQ.'YES' .OR. IHV.EQ.'DEFA')THEN
          IHV=' '
        ELSEIF(IHV.EQ.'OFF' .OR. IHV.EQ.'NO' .OR. IHV.EQ.'NONE')THEN
          IHV=' '
        ENDIF
        IREADL=IHV
        GO TO 5160
      ENDIF
!
!CCCC FOLLOWING SECTION ADDED JANUARY 2010.
!     *************************************************************
!     **  SET READ NON-PRINTING CHARACTERS <SPACE/DELETE>        **
!     *************************************************************
!
      IPART1='READ'
      IPART2='NONP'
      IPART3='CHAR'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2.AND.   &
         IHARG(3).EQ.IPART3)THEN
        IF(IHV.EQ.'SPAC')THEN
          IHV='SPAC'
        ELSE
          IHV='DELE'
        ENDIF
        IREANP=IHV
        GO TO 5160
      ENDIF
!
      IPART2='NON '
      IPART3='PRIN'
