      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2.AND.   &
        (IHARG(3).EQ.IPART3.OR.IHARG(3).EQ.IPART4))THEN
        IF(IHV.EQ.'REVE')THEN
          IHV='REVE'
        ELSE
          IHV='DEFA'
        ENDIF
        INPLAX=IHV
        GO TO 5160
      ENDIF
