!CCCC FOLLOWING SECTION ADDED SEPTEMBER 2004.
!     *************************************************************
!     **  SET HISTOGRAM CLASS WIDTH <DEFAULT/NORMAL/NORMAL       **
!     **  CORRECTED/SD/STANDARD DEVIATION/IQ/IQ RANGE/           **
!     **  INTERQUARTILE RANGE>                                   **
!     *************************************************************
!
      IPART1='HIST'
      IPART2='CLAS'
      IPART3='WIDT'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2.AND.   &
         IHARG(3).EQ.IPART3)THEN
        IF(IHARG(4).EQ.'DEFA' .OR. IHARG(4).EQ.'SD  '.OR.   &
          (IHARG(4).EQ.'STAN' .AND. IHARG(5).EQ.'DEVI'))THEN
          IHV='DEFA'
        ELSEIF(IHARG(4).EQ.'NORM' .AND. IHARG(5).EQ.'CORR')THEN
          IHV='NCOR'
        ELSEIF(IHARG(4).EQ.'NORM')THEN
          IHV='NORM'
        ELSEIF((IHARG(4).EQ.'IQ  ' .AND. IHARG(5).EQ.'RANG') .OR.   &
               (IHARG(4).EQ.'INTE' .AND. IHARG(5).EQ.'RANG') .OR.   &
          IHARG(4).EQ.'IQ  ')THEN
          IHV='IQ  '
        ELSE
          IHV='DEFA'
        ENDIF
        IHSTCW=IHV
        GO TO 5160
      ENDIF
