!CCCC FOLLOWING SECTION ADDED JANUARY  2010
!     *************************************************************
!     **  SET HISTOGRAM EMPTY BINS <ON/OFF>                      **
!     *************************************************************
!
      IPART1='HIST'
      IPART2='EMPT'
      IPART3='BINS'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2.AND.   &
         IHARG(3).EQ.IPART3)THEN
        IF(IHV.EQ.'ON' .OR. IHV.EQ.'YES' .OR. IHV.EQ.'TRUE' .OR.   &
           IHV.EQ.'DEFA')THEN
          IHV='ON'
        ELSEIF(IHV.EQ.'OFF' .OR. IHV.EQ.'NO' .OR. IHV.EQ.'NONE' .OR.   &
               IHV.EQ.'FALS')THEN
          IHV='OFF'
        ELSE
