!     *************************************************************
!     **  SET HISTOGRAM OUTLIERS   <ON/OFF>                      **
!     *************************************************************
!
      IPART1='HIST'
      IPART2='OUTL'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2)THEN
        IF(IHV.EQ.'ON' .OR. IHV.EQ.'YES' .OR. IHV.EQ.'TRUE' .OR.   &
           IHV.EQ.'DEFA')THEN
