          IHV='ON'
        ELSEIF(IHV.EQ.'OFF' .OR. IHV.EQ.'NO' .OR. IHV.EQ.'NONE' .OR.   &
               IHV.EQ.'FALS' .OR. IHV.EQ.'DEFA')THEN
          IHV='OFF'
        ELSE
          IHV='OFF'
        ENDIF
        IBXPDI=IHV
        GO TO 5160
      ENDIF
!
!CCCC THE FOLLOWING SECTION WAS ADDED        JUNE 2016.
!     *********************************************
!     **  SET STREAM READ SIZE          <VALUE>  **
!     *********************************************
!
      IPART1='STRE'
      IPART2='READ'
      IPART3='SIZE'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2.AND.   &
         IHARG(3).EQ.IPART3)THEN
        IV=IARG(NUMARG)
        ISRESI=IV
        IF(ISRESI.LE.0)ISRESI=100
        IF(ISRESI.GT.MAXOBV)ISRESI=MAXOBV
        IV=ISRESI
        GO TO 5150
      ENDIF
!
!CCCC THE FOLLOWING SECTION WAS ADDED        JUNE 2016.
!     ***************************************************************
!     **  SET STREAM READ NUMBER OF PERCENTLES <VALUE>             **
!     ***************************************************************
!
      IPART1='STRE'
      IPART2='READ'
      IPART3='NUMB'
      IPART4='OF  '
      IPART5='PERC'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2.AND.   &
         IHARG(3).EQ.IPART3.AND.IHARG(4).EQ.IPART4.AND.   &
         IHARG(5).EQ.IPART5)THEN
        IF(NUMARG.EQ.5 .OR. IHARG(6).EQ.'DEFA' .OR.   &
           IHARG(6).EQ.'OFF'  .OR. IHARG(6).EQ.'ON' .OR.   &
           IHARG(6).EQ.'NO'   .OR. IHARG(6).EQ.'YES' .OR.   &
           IHARG(6).EQ.'FALS' .OR. IHARG(6).EQ.'TRUE')THEN
          ISRENP=999
          IV=ISRENP
          GO TO 5150
        ELSE
          IV=IARG(NUMARG)
          ISRENP=IV
          IF(ISRENP.LE.9)THEN
            ISRENP=9
          ELSEIF(ISRENP.GE.10 .AND. ISRENP.LE.99)THEN
            ISRENP=99
          ELSEIF(ISRENP.GE.100 .AND. ISRENP.LE.999)THEN
            ISRENP=999
          ELSE
            ISRENP=9999
          ENDIF
          IV=ISRENP
          GO TO 5150
        ENDIF
      ENDIF
!
!CCCC FOLLOWING SECTION ADDED JULY 2016.
!     ***********************************************************
!     **  SET STREAM READ GROUP VARIABLE <NONE/VARIABLE NAME>  **
!     ***********************************************************
!
      IPART1='STRE'
      IPART2='READ'
      IPART3='GROU'
      IPART4='VARI'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2.AND.   &
         IHARG(3).EQ.IPART3.AND.IHARG(4).EQ.IPART4)THEN
        IF(IHV.EQ.'NO' .OR. IHV.EQ.'OFF' .OR. IHV.EQ.'FALS')THEN
          ISREVN='NONE'
        ELSEIF(IHV.EQ.'YES' .OR. IHV.EQ.'ON' .OR. IHV.EQ.'TRUE' .OR.   &
               IHV.EQ.'DEFA')THEN
          ISREVN='NONE'
        ELSE
          ISREVN(1:4)=IHV
          ISREVN(5:8)=IHV2
        ENDIF
        IFOUND='YES'
        IF(IFEEDB.EQ.'ON')THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,55271)ISREVN
55271     FORMAT('THE STREAM READ GROUP VARIABLE HAS ',   &
                 'BEEN SET TO ',A8)
          CALL DPWRST('XXX','BUG ')
        ENDIF
        GO TO 9000
      ENDIF
!
!CCCC FOLLOWING SECTION ADDED JULY 2016.
!     ***********************************************************
!     **  SET STREAM READ RESPONSE VARIABLE <ONE/TWO/THREE>    **
!     **      <NONE/VARIABLE NAME>                             **
!     ***********************************************************
!
      IPART1='STRE'
      IPART2='READ'
      IPART3='RESP'
      IPART4='VARI'
      IPART5='ONE'
      IPART6='TWO'
      IPART7='THRE'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2.AND.   &
         IHARG(3).EQ.IPART3.AND.IHARG(4).EQ.IPART4)THEN
        IF(IHARG(5).EQ.IPART5)THEN
          IF(IHV.EQ.'NO' .OR. IHV.EQ.'OFF' .OR. IHV.EQ.'FALS' .OR.   &
             IHV.EQ.'YES' .OR. IHV.EQ.'ON' .OR. IHV.EQ.'TRUE' .OR.   &
             IHV.EQ.'DEFA')THEN
            ISRER1='NONE'
          ELSE
            ISRER1(1:4)=IHV
            ISRER1(5:8)=IHV2
          ENDIF
          IFOUND='YES'
          IF(IFEEDB.EQ.'ON')THEN
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,55273)ISRER1
55273       FORMAT('THE STREAM READ RESPONSE VARIABLE ONE HAS ',   &
                   'BEEN SET TO ',A8)
            CALL DPWRST('XXX','BUG ')
          ENDIF
          GO TO 9000
        ELSEIF(IHARG(5).EQ.IPART6)THEN
          IF(IHV.EQ.'NO' .OR. IHV.EQ.'OFF' .OR. IHV.EQ.'FALS' .OR.   &
             IHV.EQ.'YES' .OR. IHV.EQ.'ON' .OR. IHV.EQ.'TRUE' .OR.   &
             IHV.EQ.'DEFA')THEN
            ISRER2='NONE'
          ELSE
            ISRER2(1:4)=IHV
            ISRER2(5:8)=IHV2
          ENDIF
          IFOUND='YES'
          IF(IFEEDB.EQ.'ON')THEN
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,55274)ISRER2
55274       FORMAT('THE STREAM READ RESPONSE VARIABLE TWO HAS ',   &
                   'BEEN SET TO ',A8)
            CALL DPWRST('XXX','BUG ')
          ENDIF
          GO TO 9000
        ELSEIF(IHARG(5).EQ.IPART7)THEN
          IF(IHV.EQ.'NO' .OR. IHV.EQ.'OFF' .OR. IHV.EQ.'FALS' .OR.   &
             IHV.EQ.'YES' .OR. IHV.EQ.'ON' .OR. IHV.EQ.'TRUE' .OR.   &
             IHV.EQ.'DEFA')THEN
            ISRER3='NONE'
          ELSE
            ISRER3(1:4)=IHV
            ISRER3(5:8)=IHV2
          ENDIF
          IFOUND='YES'
          IF(IFEEDB.EQ.'ON')THEN
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,55275)ISRER3
55275       FORMAT('THE STREAM READ RESPONSE VARIABLE THREE HAS ',   &
                   'BEEN SET TO ',A8)
            CALL DPWRST('XXX','BUG ')
          ENDIF
          GO TO 9000
        ENDIF
      ENDIF
!
!CCCC FOLLOWING SECTION ADDED JULY 2016.
!     *****************************************************************
!     **  SET STREAM READ CROSS TABULATE VARIABLE <ONE/TWO/THREE/    **
!     **      FOUR> <NONE/VARIABLE NAME>                             **
!     *****************************************************************
!
      IPART1='STRE'
