          IF(NUMARG.GE.3)THEN
            IEXCSH(1:4)=IHARLC(3)(1:4)
            IEXCSH(5:8)=IHARL2(3)(1:4)
          ENDIF
          IF(NUMARG.GE.4)THEN
            IEXCSH(9:12)=IHARLC(4)(1:4)
            IEXCSH(13:16)=IHARL2(4)(1:4)
          ENDIF
          IF(IEXCSH.EQ.' ')IEXCSH='Sheet1'
        ENDIF
        IFOUND='YES'
        IF(IFEEDB.EQ.'ON')THEN
          WRITE(ICOUT,999)
