!
!CCCC FOLLOWING SECTION ADDED APRIL 2020.
!     ***********************************************************
!     **  SET EXCEL START COLUMN   <VALUE>                     **
!     ***********************************************************
!
!     CONVERT COLUMN "A" ... "ZZ" TO NUMERIC COLUMN
!
      IPART1='EXCE'
      IPART2='STAR'
      IPART3='COLU'
      IF(NUMARG.EQ.4 .AND. IHARG(4)(3:3).EQ.' ')THEN
        CALL DPCOAN(IHARG(4)(1:1),IVAL1)
        CALL DPCOAN(IHARG(4)(2:2),IVAL2)
        IF(IVAL1.LT.65 .OR. IVAL1.GT.90)THEN
          IVAL1=-1
        ELSE
          IVAL1=IVAL1-64
        ENDIF
        IF(IVAL2.LT.65 .OR. IVAL2.GT.90)THEN
          IVAL2=-1
        ELSE
          IVAL2=IVAL2-64
        ENDIF
      ELSE
        IVAL1=-1
        IVAL2=-1
      ENDIF
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2.AND.   &
         IHARG(3).EQ.IPART3)THEN
        IF(IHV.EQ.'NO' .OR. IHV.EQ.'OFF' .OR. IHV.EQ.'FALS')THEN
          IEXCC1=-1
          IV=-1
        ELSEIF(IHV.EQ.'YES' .OR. IHV.EQ.'ON' .OR. IHV.EQ.'TRUE' .OR.   &
               IHV.EQ.'DEFA')THEN
          IEXCC1=-1
          IV=-1
        ELSEIF(NUMARG.LT.4)THEN
          IEXCC1=-1
          IV=-1
        ELSEIF(IVAL1.GT.0 .AND. IVAL2.LT.0)THEN
          IEXCC1=IVAL1
          IV=IVAL1
        ELSEIF(IVAL1.GT.0 .AND. IVAL2.GT.0)THEN
          IEXCC1=26 + IVAL2
          IV=IEXCC1
        ELSE
          IV=IARG(4)
          IF(IV.LT.1)IV=-1
          IEXCC1=IV
        ENDIF
        GO TO 5150
      ENDIF
!
!CCCC FOLLOWING SECTION ADDED APRIL 2020.
!     ***********************************************************
!     **  SET EXCEL STOP COLUMN    <VALUE>                     **
!     ***********************************************************
!
!     CONVERT COLUMN "A" ... "ZZ" TO NUMERIC COLUMN
!
      IPART1='EXCE'
      IPART2='STOP'
      IPART3='COLU'
      IF(NUMARG.EQ.4 .AND. IHARG(4)(3:3).EQ.' ')THEN
        CALL DPCOAN(IHARG(4)(1:1),IVAL1)
        CALL DPCOAN(IHARG(4)(2:2),IVAL2)
        IF(IVAL1.LT.65 .OR. IVAL1.GT.90)THEN
          IVAL1=-1
        ELSE
          IVAL1=IVAL1-64
        ENDIF
        IF(IVAL2.LT.65 .OR. IVAL2.GT.90)THEN
          IVAL2=-1
        ELSE
          IVAL2=IVAL2-64
        ENDIF
      ELSE
        IVAL1=-1
        IVAL2=-1
      ENDIF
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2.AND.   &
         IHARG(3).EQ.IPART3)THEN
        IF(IHV.EQ.'NO' .OR. IHV.EQ.'OFF' .OR. IHV.EQ.'FALS')THEN
          IEXCC2=-1
          IV=-1
        ELSEIF(IHV.EQ.'YES' .OR. IHV.EQ.'ON' .OR. IHV.EQ.'TRUE' .OR.   &
               IHV.EQ.'DEFA')THEN
          IEXCC2=-1
          IV=-1
        ELSEIF(NUMARG.LT.4)THEN
          IEXCC2=-1
          IV=-1
        ELSEIF(IVAL1.GT.0 .AND. IVAL2.LT.0)THEN
          IEXCC2=IVAL1
          IV=IVAL1
        ELSEIF(IVAL1.GT.0 .AND. IVAL2.GT.0)THEN
          IEXCC2=26 + IVAL2
          IV=IEXCC2
        ELSE
          IV=IARG(4)
          IF(IV.LT.1)IV=-1
          IEXCC2=IV
        ENDIF
        GO TO 5150
      ENDIF
