!CCCC FOLLOWING SECTION ADDED SEPTEMBER  2012
!     *************************************************************
!     **  SET FIELD <ICOL> TYPE <NUMERIC/CHARACTER>              **
!     *************************************************************
!
      IPART1='FIEL'
      IPART3='TYPE'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(3).EQ.IPART3)THEN
!
!       CHECK FOR COLUMN NUMBER
!
        IV=IARG(2)
        IFOUND='YES'
        IF(IV.LT.1 .OR. IV.GT.250)THEN
          WRITE(ICOUT,25251)
25251     FORMAT('***** ERROR IN THE SET COMMAND--')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,25253)
25253     FORMAT('      FOR THE   SET FIELD <ICOL> TYPE  COMMAND, THE')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,25255)IV
25255     FORMAT('      SPECIFIED COLUMN, ',I8,', IS OUTSIDE THE ',   &
                 '1 TO 250 RANGE.')
          CALL DPWRST('XXX','BUG ')
          GO TO 9000
        ENDIF
        IF(IHV.EQ.'CHAR')THEN
          IFIETY(IV)=1
          WRITE(ICOUT,25263)IV
25263     FORMAT('THE TYPE FOR FIELD ',I3,' FOR SUBSEQUENT READ ',   &
                 'COMMANDS HAS BEEN SET TO CHARACTER.')
          CALL DPWRST('XXX','BUG ')
        ELSE
          IFIETY(IV)=0
          WRITE(ICOUT,25261)IV
25261     FORMAT('THE TYPE FOR FIELD ',I3,' FOR SUBSEQUENT READ ',   &
                 'COMMANDS HAS BEEN SET TO NUMERIC.')
          CALL DPWRST('XXX','BUG ')
        ENDIF
        GO TO 9000
      ENDIF
