        IF(IHARG(3).EQ.'BEFO')THEN
          IHV='BEFO'
        ELSE
          IHV='AFTE'
        ENDIF
        IGRDOR=IHV
        GO TO 5160
      ENDIF
!
!CCCC FOLLOWING SECTION ADDED MARCH     2021
!     *************************************************************
!     **  SET SHANNON LOG BASE     <E/2/10>                      **
!     *************************************************************
!
      IPART1='SHAN'
      IPART2='LOG '
      IPART3='BASE'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2.AND.   &
         IHARG(3).EQ.IPART3)THEN
        IF(IHARG(4).EQ.'10  ')THEN
          IHV='10  '
        ELSEIF(IHARG(4).EQ.'2   ')THEN
          IHV='2   '
        ELSE
          IHV='E   '
        ENDIF
        ISHALB=IHV
        GO TO 5160
      ENDIF
!
!CCCC FOLLOWING SECTION ADDED JUNE      2021
!     *************************************************************
!     **  SET UNIFORM CONFIDENCE LIMIT   <LOWER/UPPER/BOTH>      **
!     *************************************************************
!
      IPART1='UNIF'
      IPART2='CONF'
      IPART3='LIMI'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2.AND.   &
         IHARG(3).EQ.IPART3)THEN
        IF(IHARG(4).EQ.'LOWE')THEN
          IHV='LOWE'
        ELSEIF(IHARG(4).EQ.'UPPE')THEN
          IHV='UPPE'
        ELSEIF(IHARG(4).EQ.'NONE')THEN
          IHV='NONE'
        ELSEIF(IHARG(4).EQ.'OFF ')THEN
          IHV='NONE'
        ELSE
          IHV='BOTH'
        ENDIF
        IUNILI=IHV
        GO TO 5160
      ENDIF
!
!CCCC FOLLOWING SECTION ADDED JUNE      2020
!
!CCCC FOLLOWING SECTION ADDED JUNE      2020
!     *************************************************************
!     **  SET X11 SELECTION <CLIPBOARD/PRIMARY/SECONDARY>        **
!     **  SET X11 CLIPBOARD <CUT BUFFER/SELECTION/PRIMARY>       **
!     **  SET X11 FONT TYPE <FIXED/SCALABLE>                     **
!     **  SET X11 CAP <CAP STYLE>                                **
!     **  SET X11 JOIN <JOIN STYLE>                              **
!     **  SET X11 PIXMAP <ON/OFF>                                **
!     **  SET X11 PAUSE <ON/OFF>                                 **
!     **  SET X11 HARDWARE FILL <ON/OFF>                         **
!     **  SET X11 WINDOW ID <STRING>                             **
!     *************************************************************
!
      IPART1='X11 '
      IF(IHARG(1).EQ.IPART1)THEN
        IF(IHARG(2).EQ.'SELE')THEN
          IPART2='SELE'
          IF(IHV.EQ.'PRIM')THEN
            IHV='PRIM'
          ELSEIF(IHV.EQ.'SECO')THEN
            IHV='SECO'
          ELSE
            IHV='CLIP'
          ENDIF
          IX11SE=IHV
          GO TO 5160
        ELSEIF(IHARG(2).EQ.'CLIP')THEN
          IPART2='CLIP'
          IF(IHARG(3).EQ.'CUT')THEN
            IHV='CUTB'
          ELSEIF(IHARG(3).EQ.'BUFF')THEN
            IHV='CUTB'
          ELSEIF(IHARG(3).EQ.'PRIM')THEN
            IHV='PRIM'
          ELSEIF(IHARG(3).EQ.'XA_P')THEN
            IHV='PRIM'
          ELSEIF(IHARG(3).EQ.'SECO')THEN
            IHV='SECO'
          ELSEIF(IHARG(3).EQ.'XA_S')THEN
            IHV='SECO'
          ELSEIF(IHARG(3).EQ.'CLIP')THEN
            IHV='CLIP'
          ELSEIF(IHARG(3).EQ.'XA_C')THEN
            IHV='CLIP'
          ELSE
            IHV='CLIP'
          ENDIF
          IX11CB=IHV
          GO TO 5160
        ELSEIF(IHARG(2).EQ.'FONT' .AND. IHARG(3).EQ.'TYPE')THEN
          IPART2='FONT'
          IF(IHARG(4).EQ.'SCAL')THEN
            IHV='SCAL'
          ELSE
            IHV='FIXE'
          ENDIF
          IX11FT=IHV
          GO TO 5160
        ELSEIF(IHARG(2).EQ.'PIXM')THEN
          IPART2='PIXM'
          IHV=IHARG(NUMARG)
          IX11PM=IHV
          GO TO 5160
        ELSEIF(IHARG(2).EQ.'PAUS')THEN
          IPART2='PAUS'
          IHV=IHARG(NUMARG)
          IF(IHV.EQ.'ON  ' .OR. IHV.EQ.'YES ' .OR. IHV.EQ.'TRUE')THEN
            IHV='ON  '
          ELSEIF(IHV.EQ.'OFF ' .OR. IHV.EQ.'NO  ' .OR.   &
                 IHV.EQ.'FALS')THEN
            IHV='OFF '
          ELSE
            IHV='ON  '
          ENDIF
          IX11PA=IHV
          GO TO 5160
        ELSEIF(IHARG(2).EQ.'CAP ')THEN
          IPART2='CAP '
          IX11CS(1:4)=IHARG(NUMARG)
          IX11CS(5:8)=IHARG2(NUMARG)
          GO TO 5165
        ELSEIF(IHARG(2).EQ.'JOIN')THEN
          IPART2='JOIN'
          IX11JS(1:4)=IHARG(NUMARG)
          IX11JS(5:8)=IHARG2(NUMARG)
          GO TO 5165
        ELSEIF(IHARG(2).EQ.'WIND' .AND. IHARG(3).EQ.'ID  ')THEN
          IPART2='WIND'
          IX11W2(1:4)=IHARG(NUMARG)
          IX11W2(5:8)=IHARG2(NUMARG)
          GO TO 5165
        ELSEIF(IHARG(2).EQ.'HARD' .AND. IHARG(3).EQ.'FILL')THEN
          IPART2='HARD'
          IHV=IHARG(NUMARG)
          IF(IHV.EQ.'ON  ' .OR. IHV.EQ.'YES ' .OR. IHV.EQ.'TRUE')THEN
            IHV='ON  '
          ELSEIF(IHV.EQ.'OFF ' .OR. IHV.EQ.'NO  ' .OR.   &
                 IHV.EQ.'FALS')THEN
            IHV='OFF '
          ELSE
            IHV='ON  '
          ENDIF
          IX11FS=IHV
          GO TO 5160
        ELSEIF(IHARG(2).EQ.'DISP' .AND. IHARG(3).EQ.'NAME')THEN
!
          IX11DN=' '
          NCTEMP=0
          IF(NUMARG.LE.2             .OR. IHARG(NUMARG).EQ.'OFF ' .OR.   &
             IHARG(NUMARG).EQ.'AUTO' .OR. IHARG(NUMARG).EQ.'DEFA')THEN
            IX11DN='DEFAULT'
            GO TO 2550
          ENDIF
!
!  CHECK THE POSITION OF THE WORD  NAME  AND EXTRACT IANSLC FROM THE
!  FIRST CHARACTER PAST "NAME" TO THE LAST NON-BLANK CHARACTER
!
          IX11DN='DEFAULT'
          DO 2530 I=1,IWIDTH
            IF(I+3.GT.IWIDTH)GO TO 2550
            IF(IANS(I).EQ.'N'   .AND. IANS(I+1).EQ.'A' .AND.   &
               IANS(I+2).EQ.'M' .AND. IANS(I+3).EQ.'E' .AND.   &
               IANS(I+4).EQ.' ')THEN
!
              ISTART=I+4+1
              DO 2540 J=ISTART,IWIDTH
                IF(IANS(J).EQ.' ')GO TO 2540
                ISTART=J
                GO TO 2545
 2540         CONTINUE
              GO TO 2550
 2545         CONTINUE
              ISTOP=ISTART+79
              IF(ISTOP.GT.IWIDTH)ISTOP=IWIDTH
              IF(ISTART.GT.ISTOP)GO TO 2550
              NCTEMP=ISTOP-ISTART+1
              ICOUNT=0
              DO 2548 II=ISTART,ISTOP
                ICOUNT=ICOUNT+1
                IX11DN(ICOUNT:ICOUNT)=IANSLC(II)(1:1)
 2548         CONTINUE
!
            ENDIF
 2530     CONTINUE
          GO TO 2550
!
 2550     CONTINUE
          IFOUND='YES'
          IF(IFEEDB.EQ.'ON')THEN
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,2551)
 2551       FORMAT('THE X11 DISPLAY NAME HAS BEEN SET TO ')
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,2552)IX11DN
 2552       FORMAT(A80)
            CALL DPWRST('XXX','BUG ')
          ENDIF
!
        ELSEIF(IHARG(2).EQ.'SCAL' .AND. IHARG(3).EQ.'FONT')THEN
          IX11SF(1:40)='                                        '
          IX11SF(41:80)='                                        '
          NCTEMP=0
          IF(NUMARG.LE.3)GO TO 2450
          IF(IHARG(NUMARG).EQ.'OFF' .OR. IHARG(NUMARG).EQ.'AUTO' .OR.   &
             IHARG(NUMARG).EQ.'DEFA')THEN
            IX11SF='NULL'
            GO TO 2450
          ENDIF
!
!         CHECK THE POSITION OF THE WORD SCALABLE FONT AND EXTRACT  IANS
!         FROM THE FIRST CHARACTER PAST "FONT" TO THE LAST NON-BLANK
!         CHARACTER
!
          IX11SF='NULL'
          DO 2430 I=1,IWIDTH
            IF(I+13.GT.IWIDTH)GO TO 2450
            IF(IANS(I).EQ.'S'    .AND. IANS(I+1).EQ.'C' .AND.   &
               IANS(I+2).EQ.'A'  .AND. IANS(I+3).EQ.'L' .AND.   &
               IANS(I+4).EQ.'A'  .AND. IANS(I+5).EQ.'B' .AND.   &
               IANS(I+6).EQ.'L'  .AND. IANS(I+7).EQ.'E' .AND.   &
               IANS(I+8).EQ.' '  .AND. IANS(I+9).EQ.'F' .AND.   &
               IANS(I+10).EQ.'O' .AND. IANS(I+11).EQ.'N' .AND.   &
               IANS(I+12).EQ.'T' .AND. IANS(I+13).EQ.' ')THEN
!
              ISTART=I+13+1
              ISTOP=IWIDTH
              DO 2440 J=IWIDTH,ISTART,-1
                ISTOP=J
                IF(IANS(J).NE.' ')THEN
                  IF(ISTART.GT.ISTOP)GO TO 2450
                  NCTEMP=ISTOP-ISTART+1
                  IF(NCTEMP.GT.80)ISTOP=ISTART+79
                  IF(NCTEMP.GT.80)NCTEMP=80
                  ICOUNT=0
                  DO 2448 II=ISTART,ISTOP
                    ICOUNT=ICOUNT+1
                    IX11SF(ICOUNT:ICOUNT)=IANSLC(II)(1:1)
 2448             CONTINUE
                ENDIF
 2440         CONTINUE
              GO TO 2450
            ENDIF
 2430     CONTINUE
!
 2450     CONTINUE
          IFOUND='YES'
          IF(IFEEDB.EQ.'ON')THEN
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,2451)
 2451       FORMAT('THE X11 SCALABLE FONT HAS BEEN SET TO ')
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,2452)IX11SF
 2452       FORMAT(A80)
            CALL DPWRST('XXX','BUG ')
          ENDIF
          GO TO 9000
        ELSEIF(IHARG(2).EQ.'FONT')THEN
          IX11FN(1:40)='                                        '
          IX11FN(41:80)='                                        '
          NCTEMP=0
          IF(NUMARG.LE.2)GO TO 2250
          IF(IHARG(NUMARG).EQ.'OFF' .OR. IHARG(NUMARG).EQ.'AUTO' .OR.   &
             IHARG(NUMARG).EQ.'DEFA')THEN
            IX11FN='8X13'
            GO TO 2250
          ENDIF
!
!         CHECK THE POSITION OF THE WORD FONT AND EXTRACT  IANS  FROM
!         THE FIRST CHARACTER PAST "FONT" TO THE LAST NON-BLANK CHARACTER
!
          IX11FN='8X13'
          DO 2230 I=1,IWIDTH
            IF(I+3.GT.IWIDTH)GO TO 2250
            IF(IANS(I).EQ.'F'  .AND. IANS(I+1).EQ.'O' .AND.   &
               IANS(I+2).EQ.'N'.AND. IANS(I+3).EQ.'T' .AND.   &
               IANS(I+4).EQ.' ')THEN
!
              ISTART=I+4+1
              ISTOP=IWIDTH
              DO 2240 J=IWIDTH,ISTART,-1
                ISTOP=J
                IF(IANS(J).NE.' ')THEN
                  IF(ISTART.GT.ISTOP)GO TO 2250
                  NCTEMP=ISTOP-ISTART+1
                  IF(NCTEMP.GT.80)ISTOP=ISTART+79
                  IF(NCTEMP.GT.80)NCTEMP=80
                  ICOUNT=0
                  DO 2248 II=ISTART,ISTOP
                    ICOUNT=ICOUNT+1
                    IX11FN(ICOUNT:ICOUNT)=IANS(II)(1:1)
 2248             CONTINUE
                ENDIF
 2240         CONTINUE
              GO TO 2250
            ENDIF
 2230     CONTINUE
!
 2250     CONTINUE
          IFOUND='YES'
          IF(IFEEDB.EQ.'ON')THEN
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,2251)
 2251       FORMAT('THE X11 FONT HAS BEEN SET TO ')
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,2252)IX11FN
 2252       FORMAT(A80)
            CALL DPWRST('XXX','BUG ')
          ENDIF
          GO TO 9000
        ENDIF
      ENDIF
!
