         IHARG(3).EQ.IPART3)THEN
        IF(IHARG(4).EQ.'OFF')THEN
          IHV='OFF'
        ELSEIF(IHARG(4).EQ.'NONE')THEN
          IHV='OFF'
        ELSEIF(IHARG(4).EQ.'FALS')THEN
