!CCCC FOLLOWING SECTION ADDED OCTOBER  2011
!     **********************************************************
!     **  SET BOOTSTRAP SMOOTHING STANDARD DEVIATION <VALUE>  **
!     **********************************************************
!
      IPART1='BOOT'
      IPART2='SMOO'
      IPART3='STAN'
      IPART4='DEVI'
      IPART5='ERRO'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2.AND.   &
         IHARG(3).EQ.IPART3.AND.   &
        (IHARG(4).EQ.IPART4.OR.IHARG(4).EQ.IPART5))THEN
        IF(IHARG(5).EQ.'DEFA' .OR. IHARG(5).EQ.'ON' .OR.   &
           IHARG(5).EQ.'OFF')THEN
          PBOOSM=CPUMIN
        ELSE
          PBOOSM=ARG(5)
        ENDIF
        AV=PBOOSM
        GO TO 5170
      ENDIF
!
      IPART3='SD'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2.AND.   &
         IHARG(3).EQ.IPART3)THEN
        IF(IHARG(4).EQ.'DEFA' .OR. IHARG(4).EQ.'ON' .OR.   &
           IHARG(4).EQ.'OFF')THEN
          PBOOSM=CPUMIN
        ELSE
          PBOOSM=ARG(4)
        ENDIF
        AV=PBOOSM
        GO TO 5170
      ENDIF
!
!CCCC FOLLOWING SECTION ADDED OCTOBER  2011
!     ******************************************************
!     **  SET BOOTSTRAP SMOOTHING <ON/OFF>                **
!     ******************************************************
!
      IPART1='BOOT'
      IPART2='SMOO'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2)THEN
        IF(IHARG(3).EQ.'ON')THEN
          IHV='ON  '
          PBOOSM=CPUMIN
        ELSEIF(IHARG(3).EQ.'OFF' .OR. IHARG(3).EQ.'DEFAU' .OR.   &
               IHARG(3).EQ.'   ')THEN
          IHV='OFF '
          PBOOSM=CPUMIN
        ELSE
          IBOOSM='OFF'
        ENDIF
        IBOOSM=IHV
        GO TO 5160
      ENDIF
!
!CCCC FOLLOWING SECTION ADDED OCTOBER  2011
!     *************************************************************
!     **  SET BOOTSTRAP T PERCENTILE STANDARD DEVIATION <VALUE>  **
!     *************************************************************
!
      IPART1='BOOT'
      IPART2='T   '
      IPART3='PERC'
      IPART4='STAN'
      IPART5='DEVI'
      IPART6='ERRO'
      IF(IHARG(1).EQ.IPART1.AND.   &
        ((IHARG(2).EQ.IPART2.AND.IHARG(3).EQ.IPART3).OR.   &
         (IHARG(2).EQ.IPART3.AND.IHARG(3).EQ.IPART2)).AND.   &
          IHARG(4).EQ.IPART4.AND.   &
         (IHARG(5).EQ.IPART5.OR.IHARG(5).EQ.IPART6))THEN
        IF(IHARG(6).EQ.'DEFA' .OR. IHARG(6).EQ.'ON' .OR.   &
           IHARG(6).EQ.'OFF')THEN
          PBOOTS=CPUMIN
        ELSE
          PBOOTS=ARG(6)
        ENDIF
        AV=PBOOTS
        GO TO 5170
      ENDIF
!
      IPART4='SD  '
      IF(IHARG(1).EQ.IPART1.AND.   &
        ((IHARG(2).EQ.IPART2.AND.IHARG(3).EQ.IPART3).OR.   &
         (IHARG(2).EQ.IPART3.AND.IHARG(3).EQ.IPART2)).AND.   &
          IHARG(4).EQ.IPART4)THEN
        IF(IHARG(5).EQ.'DEFA' .OR. IHARG(5).EQ.'ON' .OR.   &
           IHARG(5).EQ.'OFF')THEN
          PBOOTS=CPUMIN
        ELSE
          PBOOTS=ARG(5)
        ENDIF
        AV=PBOOTS
        GO TO 5170
      ENDIF
