        ELSEIF(IHARG(5).EQ.'ONE' .AND. IHARG(6).EQ.'STAN' .AND.   &
               IHARG(7).EQ.'ERRO')THEN
          IHV='1SE'
        ELSEIF(IHARG(5).EQ.'ONE' .AND. IHARG(6).EQ.'STAN' .AND.   &
               IHARG(7).EQ.'DEVI')THEN
