      ENDIF
!
!CCCC FOLLOWING SECTION ADDED JUNE  2013
!     *************************************************************
!     **  SET CONSENSUS MEAN TABLE ONE    <ON/OFF>               **
!     *************************************************************
!
      IPART1='CONS'
      IPART2='MEAN'
      IPART3='TABL'
      IPART4='ONE '
      IPART5='1   '
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2.AND.   &
         IHARG(3).EQ.IPART3.AND.   &
         (IHARG(4).EQ.IPART4.OR.IHARG(5).EQ.IPART5))THEN
        IF(IHV.EQ.'ON' .OR. IHV.EQ.'YES' .OR. IHV.EQ.'TRUE' .OR.   &
