               IHV.EQ.'DEFA')THEN
          ICMETB='NONE'
        ELSE
          ICMETB(1:4)=IHV
          ICMETB(5:8)=IHV2
        ENDIF
        IFOUND='YES'
        IF(IFEEDB.EQ.'ON')THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,55171)ICMETB
55171     FORMAT('THE CONSENSUS MEAN TYPE B VARIABLE HAS ',   &
                 'BEEN SET TO ',A8)
