!CCCC FOLLOWING SECTION ADDED NOVEMBER  2016
!     *************************************************************
!     **  SET CONSENSUS MEAN PLOT OMIT LABS <LIST OF LABS>       **
!     *************************************************************
!
!     MAXIMUM NUMBER OF LABS TO OMIT SET BY MAXOLB
!
      IPART1='CONS'
      IPART2='MEAN'
      IPART3='PLOT'
      IPART4='OMIT'
      IPART5='LABS'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2.AND.   &
         IHARG(3).EQ.IPART3.AND.IHARG(4).EQ.IPART4.AND.   &
         IHARG(5).EQ.IPART5)THEN
        IFOUND='YES'
        IF(IHV.EQ.'ON'   .OR. IHV.EQ.'YES' .OR. IHV.EQ.'TRUE' .OR.   &
           IHV.EQ.'DEFA' .OR. IHV.EQ.'OFF' .OR. IHV.EQ.'NO'   .OR.   &
           IHV.EQ.'NONE' .OR. IHV.EQ.'FALS' .OR. NUMARG.LE.5)THEN
          ICMPNL=0
          DO 5012 II=1,MAXOLB
            ICMPLL(II)=-1
 5012     CONTINUE
        ELSE
          ISTRT=6
          ISTOP=NUMARG
          NTEMP=ISTOP-ISTRT+1
          IF(NTEMP.GT.MAXOLB)ISTOP=ISTRT+9
          ICMPNL=0
          DO 5014 II=ISTRT,ISTOP
            ICMPNL=ICMPNL+1
            ICMPLL(ICMPNL)=IARG(II)
            WRITE(ICOUT,5013)ICMPLL(ICMPNL)
 5013       FORMAT('LAB ',I8,' WILL BE OMITTED FROM THE CONSENSUS ',   &
                   'MEAN PLOT (BUT NOT THE ANALYSIS)')
            CALL DPWRST('XXX','BUG ')
 5014     CONTINUE
        ENDIF
        GO TO 9000
      ENDIF
