        ELSEIF(IHARG(2).EQ.'VERT' .AND. IHARG(3).EQ.'POSI')THEN
          IF(NUMARG.EQ.4)THEN
            IINDX=1
            IF(IHV.EQ.'ON' .OR. IHV.EQ.'YES' .OR. IHV.EQ.'DEFA' .OR.   &
               IHV.EQ.'OFF' .OR. IHV.EQ.'NO' .OR. IHV.EQ.'NONE')THEN
              AVAL=CPUMIN
            ELSE
              AVAL=ARG(4)
            ENDIF
          ELSEIF(NUMARG.EQ.5)THEN
            AINDX=ARG(4)
            IINDX=INT(AINDX+0.5)
            IF(IINDX.LT.1)IINDX=1
            IF(IINDX.GT.10)IINDX=10
            IF(IHV.EQ.'ON' .OR. IHV.EQ.'YES' .OR. IHV.EQ.'DEFA' .OR.   &
               IHV.EQ.'OFF' .OR. IHV.EQ.'NO' .OR. IHV.EQ.'NONE')THEN
              AVAL=CPUMIN
            ELSE
              AVAL=ARG(5)
            ENDIF
          ELSE
            GO TO 9000
          ENDIF
          PTABVP(IINDX)=AVAL
          IFOUND='YES'
          IF(IFEEDB.EQ.'ON')THEN
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,31181)IINDX,PTABVP(IINDX)
31181       FORMAT('THE VERTICAL POSITION FOR TAB ',I3,   &
                   ' IS SET TO ',G15.7)
            CALL DPWRST('XXX','BUG ')
          ENDIF
          GO TO 9000
        ENDIF
        GO TO 5160
      ENDIF
