!CCCC FOLLOWING SECTION ADDED MARCH    2014
!     *****************************************************************
!     **  SET BINOMIAL METHOD <WILSON/ADJUSTED WALD/JEFFREYS/EXACT/  **
!     **                       NORMAL APPROXIMATION/CONTINUITY CORR> **
!     *****************************************************************
!
!     NOTE THAT WHAT WE PREVIOSLY CALLED "AGRESTI-COUL" IS MORE
!     COMMONLY CALLED "WILSON" IN THE LITERATURE AND WHAT IS
!     COMMONLY CALLED "AGRESTI-COUL" IS THE "ADJUSTED WALD".  DUE
!     TO THIS AMBIGUITY IN NOTATION, DON'T USE AGRESTI-COUL, BUT
!     SPECIFICALLY USE "WILSON" AND "ADJUSTED WALD".
!
      IPART1='BINO'
      IPART2='METH'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2)THEN
        IF(IHV.EQ.'JEFF')THEN
          IHV='JEFF'
        ELSEIF(IHARG(3).EQ.'ADJU' .AND. IHARG(4).EQ.'WALD')THEN
          IHV='WALD'
        ELSEIF(IHARG(3).EQ.'EXAC')THEN
          IHV='EXAC'
        ELSEIF(IHARG(3).EQ.'NORM')THEN
          IHV='NORM'
        ELSEIF(IHARG(3).EQ.'CONT')THEN
          IHV='CCOR'
        ELSE
          IHV='WILS'
        ENDIF
        IBINME=IHV
        GO TO 5160
      ENDIF
