      IPART2='NUMB'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2)THEN
        ICAPNM=IHV
        IF(ICAPNM.EQ.'YES'.OR.ICAPNM.EQ.'TRUE')ICAPNM='ON'
        IF(ICAPNM.EQ.'NO'.OR.ICAPNM.EQ.'FALS'.OR.ICAPNM.EQ.'DEFA')   &
           ICAPNM='OFF'
        IHV=ICAPNM
        GO TO 5160
      ENDIF
!
!CCCC FOLLOWING SECTION ADDED JUNE 2002
!     ****************************************************************
!     **  SET CAPTURE BOX    <ON/OFF>                               **
!     ****************************************************************
!
      IPART1='CAPT'
      IPART2='BOX '
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2)THEN
        ICAPBX=IHV
        IF(ICAPBX.EQ.'YES'.OR.ICAPNM.EQ.'TRUE')ICAPNM='ON'
        IF(ICAPBX.EQ.'NO'.OR.ICAPNM.EQ.'FALS'.OR.ICAPNM.EQ.'DEFA')   &
           ICAPBX='OFF'
        IHV=ICAPBX
        GO TO 5160
      ENDIF
!
!CCCC FOLLOWING SECTION ADDED JULY 2002
!     ****************************************************************
!     **  SET QUANTILE METHOD <ORDER/HERRELL-DAVIS/R8>              **
!     ****************************************************************
!
      IPART1='QUAN'
      IPART2='METH'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2)THEN
        IF(IHARG(3).EQ.'HD' .OR. IHARG(3).EQ.'HERR' .OR.   &
           IHARG(3).EQ.'DAVI')THEN
          IQUAME='HD'
        ELSEIF(IHARG(3).EQ.'H' .AND. IHARG(4).EQ.'D')THEN
          IQUAME='HD'
        ELSEIF(IHARG(3).EQ.'R8')THEN
          IQUAME='R8'
        ELSEIF(IHARG(3).EQ.'R7')THEN
          IQUAME='R7'
        ELSEIF(IHARG(3).EQ.'R6')THEN
          IQUAME='R6'
        ELSEIF(IHARG(3).EQ.'AVER')THEN
          IQUAME='AVER'
        ELSE
          IQUAME='ORDE'
        ENDIF
        IHV=IQUAME
        GO TO 5160
      ENDIF
!
!CCCC FOLLOWING SECTION ADDED JULY 2002
!     ****************************************************************
!     **  SET QUANTILE STANDARD ERROR METHOD                        **
!     **      <MARITZ-JARRET/KERNEL DENSITY>                        **
!     ****************************************************************
!
      IPART1='QUAN'
      IPART2='STAN'
      IPART3='ERRO'
      IPART4='METH'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2.AND.   &
         IHARG(3).EQ.IPART3.AND.IHARG(4).EQ.IPART4)THEN
        IQUASE=IHARG(5)
        IF(IQUASE.EQ.'KERN'.OR.IQUASE.EQ.'DENS')THEN
          IQUASE='KERD'
        ELSE
          IQUASE='MJ'
        ENDIF
        IHV=IQUASE
        GO TO 5160
      ELSEIF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2.AND.   &
         IHARG(3).EQ.IPART3)THEN
        IQUASE=IHARG(4)
        IF(IQUASE.EQ.'KERN'.OR.IQUASE.EQ.'DENS')THEN
          IQUASE='KERD'
        ELSE
          IQUASE='MJ'
        ENDIF
        IHV=IQUASE
        GO TO 5160
      ENDIF
!
!CCCC FOLLOWING SECTION ADDED JULY 2002
!     ****************************************************************
!     **  SET COVARIANCE TYPE <DEFAULT/BIWEIGHT MIDCOVARIANCE/      **
!     **      WINSORIZED VARIANCE/PERCENTAGE BEND/RANK>             **
!     ****************************************************************
!
      IPART1='COVA'
      IPART2='TYPE'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2)THEN
        ICOVTY='DEFA'
        IF(IHARG(3).EQ.'BIWE')ICOVTY='BIWE'
        IF(IHARG(3).EQ.'WINS')ICOVTY='WINS'
!CCCC   IF(IHARG(3).EQ.'PERC')ICOVTY='PBEN'
        IF(IHARG(3).EQ.'RANK')ICOVTY='RANK'
        IHV=ICOVTY
        GO TO 5160
      ENDIF
!
!CCCC FOLLOWING SECTION ADDED JULY 2002
!     ****************************************************************
!     **  SET CORRELATION TYPE <DEFAULT/WINSORIZED/RANK/            **
!     **      PERCENTAGE BEND/BIWEIGHT MIDCORRELATION/KENDELL TAU>  **
!     ****************************************************************
!
      IPART1='CORR'
      IPART2='TYPE'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2)THEN
        ICORTY='DEFA'
        IF(IHARG(3).EQ.'WINS')ICORTY='WINS'
        IF(IHARG(3).EQ.'RANK')ICORTY='RANK'
        IF(IHARG(3).EQ.'PERC')ICORTY='PBCR'
        IF(IHARG(3).EQ.'BIWE')ICORTY='BIWE'
        IF(IHARG(3).EQ.'MIDC')ICORTY='BIWE'
        IF(IHARG(3).EQ.'KEND')ICORTY='KTAU'
        IF(IHARG(3).EQ.'TAU ')ICORTY='KTAU'
        IHV=ICORTY
        GO TO 5160
      ENDIF
!
!CCCC FOLLOWING SECTION ADDED SEPTEMBER 2016
!     ****************************************************************
!     **  SET CORRELATION ABSOLUTE VALUE <ON/OFF>                   **
!     ****************************************************************
!
      IPART1='CORR'
      IPART2='ABSO'
      IPART3='VALU'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2.AND.   &
         IHARG(3).EQ.IPART3)THEN
        IF(IHARG(4).EQ.'ON' .OR. IHARG(4).EQ.'YES' .OR.   &
           IHARG(4).EQ.'TRUE')THEN
          ICORAV='ON'
        ELSE
          ICORAV='OFF'
        ENDIF
        IHV=ICORAV
        GO TO 5160
      ENDIF
!
!CCCC FOLLOWING SECTION ADDED SEPTEMBER 2016
!     ****************************************************************
!     **  SET CORRELATION PERCENTAGE VALUE <ON/OFF>                 **
!     ****************************************************************
!
      IPART1='CORR'
      IPART2='PERC'
      IPART3='VALU'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2.AND.   &
         IHARG(3).EQ.IPART3)THEN
        IF(IHARG(4).EQ.'ON' .OR. IHARG(4).EQ.'YES' .OR.   &
           IHARG(4).EQ.'TRUE')THEN
          ICORPV='ON'
        ELSE
          ICORPV='OFF'
        ENDIF
        IHV=ICORPV
        GO TO 5160
      ENDIF
!
!CCCC FOLLOWING SECTION ADDED SEPTEMBER 2016
!     ****************************************************************
!     **  SET CORRELATION DIGITS <VALUE>                            **
!     ****************************************************************
!
      IPART1='CORR'
      IPART2='DIGI'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2)THEN
        IF(NUMARG.GT.2)THEN
          ICORDG=IARG(3)
          IF(ICORDG.LT.0)ICORDG=-1
          IF(ICORDG.GT.6)ICORDG=-1
        ELSE
          ICORDG=-1
        ENDIF
        IV=ICORDG
        GO TO 5150
      ENDIF
!
!CCCC FOLLOWING SECTION ADDED OCTOBER 2016
!     ****************************************************************
!     **  SET PSVIEW FILE CLOSE <ON/OFF>                            **
!     ****************************************************************
!
      IPART1='PSVI'
      IPART2='FILE'
      IPART3='CLOS'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2.AND.   &
         IHARG(3).EQ.IPART3)THEN
        IF(IHARG(4).EQ.'ON' .OR. IHARG(4).EQ.'YES' .OR.   &
           IHARG(4).EQ.'TRUE')THEN
          IPSVCL='ON'
        ELSE
          IPSVCL='OFF'
        ENDIF
        IHV=IPSVCL
        GO TO 5160
      ENDIF
!
!CCCC FOLLOWING SECTION ADDED JULY 2002
!     ****************************************************************
!     **  SET FILE NAME QUOTE <ON/OFF>                              **
!     **  2/2008: ADD "NOFILE" OPTION (FOR PRINT "99.99 ...."       **
!     ****************************************************************
!
      IPART1='FILE'
      IPART2='NAME'
      IPART3='QUOT'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2.AND.   &
         IHARG(3).EQ.IPART3)THEN
        IFILQU='OFF'
        IF(IHARG(4).EQ.'ON')IFILQU='ON'
        IF(IHARG(4).EQ.'YES')IFILQU='ON'
        IF(IHARG(4).EQ.'NOFI')IFILQU='NOFI'
        IF(IHARG(4).EQ.'NO  '.AND.IHARG(5).EQ.'FILE')IFILQU='NOFI'
        IHV=IFILQU
        IFILQZ=IFILQU
        GO TO 5160
      ENDIF
!
!CCCC FOLLOWING SECTION ADDED JULY 2002
!     ****************************************************************
!     **  SET BOOTSTRAP FIT METHOD <RESIDUALS/DATA>                 **
!     ****************************************************************
!
      IPART1='BOOT'
      IPART2='FIT '
      IPART3='METH'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2.AND.   &
         IHARG(3).EQ.IPART3)THEN
        IBOOME='RESI'
        IF(IHARG(4).EQ.'EFRO')IBOOME='RESI'
        IF(IHARG(4).EQ.'DATA')IBOOME='DATA'
        IF(IHARG(4).EQ.'WU')IBOOME='DATA'
        IHV=IBOOME
        GO TO 5160
      ENDIF
!
!CCCC FOLLOWING SECTION ADDED JULY 2002
!     ****************************************************************
!     **  SET DISTRIBUTIONAL BOOTSTRAP <NONPARAMETERIC/PARAMETRIC>  **
!     ****************************************************************
!
      IPART1='DIST'
      IPART2='BOOT'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2)THEN
        IBOOPA='NONP'
        IF(IHARG(3).EQ.'PARA')IBOOPA='PARA'
        IHV=IBOOPA
        GO TO 5160
      ENDIF
!
!CCCC FOLLOWING SECTION ADDED APRIL 2005
!     ****************************************************************
!     **  SET DECIMAL POINT                                         **
!     ****************************************************************
!
      IPART1='DECI'
      IPART2='POIN'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2)THEN
        IDECPT=IHARG(3)
        IF(IHARG(3).EQ.'DEFA')IDECPT='.'
        IF(IHARG(3).EQ.'ON  ')IDECPT='.'
        IF(IHARG(3).EQ.'NONE')IDECPT='.'
        IF(IHARG(3).EQ.'YES ')IDECPT='.'
        IF(IHARG(3).EQ.'NO  ')IDECPT='.'
        IF(IHARG(3).EQ.'OFF ')IDECPT='.'
        IF(IHARG(3).EQ.'    ')IDECPT='.'
        IHV=IDECPT
        GO TO 5160
      ENDIF
!
!CCCC FOLLOWING SECTION ADDED APRIL 2005
!     ****************************************************************
!     **  SET PEAKS OVER THRESHOLD METHOD                           **
!     ****************************************************************
!
      IPART1='POT '
      IPART2='METH'
      IPART3='PEAK'
      IPART4='OVER'
      IPART5='THRE'
      IF((IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2) .OR.   &
         (IHARG(1).EQ.IPART3.AND.IHARG(2).EQ.IPART4.AND.   &
          IHARG(3).EQ.IPART5.AND.IHARG(4).EQ.IPART2))THEN
        IPOTME=IHARG(NUMARG)
        IF(IPOTME.EQ.'DEFA')IPOTME='DEHA'
        IF(IPOTME.EQ.'ON  ')IPOTME='DEHA'
        IF(IPOTME.EQ.'NONE')IPOTME='DEHA'
        IF(IPOTME.EQ.'YES ')IPOTME='DEHA'
        IF(IPOTME.EQ.'NO  ')IPOTME='DEHA'
        IF(IPOTME.EQ.'OFF ')IPOTME='DEHA'
        IF(IPOTME.EQ.'    ')IPOTME='DEHA'
        IF(IPOTME.EQ.'CME ')THEN
          IHV=IPOTME
        ELSEIF(IPOTME.EQ.'MOME')THEN
          IHV=IPOTME
        ELSEIF(IPOTME.EQ.'MLE ')THEN
          IPOTME='DEHA'
          IHV=IPOTME
        ELSEIF(IPOTME.EQ.'ML  ')THEN
          IPOTME='MLE '
          IHV=IPOTME
        ELSEIF(IPOTME.EQ.'MAXI')THEN
          IPOTME='MLE '
          IHV=IPOTME
        ELSEIF(IPOTME.EQ.'LIKE')THEN
          IPOTME='MLE '
          IHV=IPOTME
        ELSEIF(IPOTME.EQ.'PPCC')THEN
          IPOTME='PPCC'
          IHV=IPOTME
        ELSEIF(IPOTME.EQ.'PLOT')THEN
          IPOTME='PPCC'
          IHV=IPOTME
        ELSEIF(IPOTME.EQ.'PROB')THEN
          IPOTME='PPCC'
          IHV=IPOTME
        ELSEIF(IPOTME.EQ.'KS  ')THEN
          IPOTME='KS  '
          IHV=IPOTME
        ELSEIF(IPOTME.EQ.'KOLM')THEN
          IPOTME='KS  '
          IHV=IPOTME
        ELSEIF(IPOTME.EQ.'SMIR')THEN
          IPOTME='KS  '
          IHV=IPOTME
        ELSE
          IPOTME='DEHA'
          IHV=IPOTME
        ENDIF
        GO TO 5160
      ENDIF
!
!CCCC FOLLOWING SECTION ADDED APRIL 2005
!     ****************************************************************
!     **  SET PEAKS OVER THRESHOLD LOAD FACTOR                      **
!     ****************************************************************
!
      IPART1='POT '
      IPART2='PEAK'
      IPART3='OVER'
      IPART4='THRE'
      IPART5='LOAD'
      IPART6='FACT'
      IF(   &
         (IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART5.AND.   &
          IHARG(3).EQ.IPART6) .OR.   &
         (IHARG(1).EQ.IPART2.AND.IHARG(2).EQ.IPART3.AND.   &
          IHARG(3).EQ.IPART4.AND.IHARG(4).EQ.IPART5.AND.   &
          IHARG(5).EQ.IPART6))THEN
        IPOTLF=IHARG(NUMARG)
        IF(IPOTLF.EQ.'DEFA')IPOTLF='OFF'
        IF(IPOTLF.EQ.'ON  ')IPOTLF='ON'
        IF(IPOTLF.EQ.'NONE')IPOTLF='OFF'
        IF(IPOTLF.EQ.'YES ')IPOTLF='ON'
        IF(IPOTLF.EQ.'NO  ')IPOTLF='OFF'
        IF(IPOTLF.EQ.'OFF ')IPOTLF='OFF'
        IF(IPOTLF.EQ.'    ')IPOTLF='OFF'
        IF(IPOTLF.NE.'ON')IPOTLF='OFF'
        IHV=IPOTLF
        GO TO 5160
      ENDIF
!
!CCCC FOLLOWING SECTION ADDED APRIL 2005
!     ****************************************************************
!     **  SET PEAKS OVER THRESHOLD X AXIS                           **
!     ****************************************************************
!
      IPART1='POT '
      IPART2='PEAK'
      IPART3='OVER'
      IPART4='THRE'
      IPART5='X   '
      IPART6='AXIS'
      IF(   &
         (IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART5.AND.   &
          IHARG(3).EQ.IPART6) .OR.   &
         (IHARG(1).EQ.IPART2.AND.IHARG(2).EQ.IPART3.AND.   &
          IHARG(3).EQ.IPART4.AND.IHARG(4).EQ.IPART5.AND.   &
          IHARG(5).EQ.IPART6))THEN
        IPOTAX=IHARG(NUMARG)
        IF(IPOTAX.EQ.'DEFA')IPOTAX='POIN'
        IF(IPOTAX.EQ.'ON  ')IPOTAX='POIN'
        IF(IPOTAX.EQ.'NONE')IPOTAX='POIN'
        IF(IPOTAX.EQ.'YES ')IPOTAX='POIN'
        IF(IPOTAX.EQ.'NO  ')IPOTAX='POIN'
        IF(IPOTAX.EQ.'OFF ')IPOTAX='POIN'
        IF(IPOTAX.EQ.'    ')IPOTAX='POIN'
        IF(IPOTAX.NE.'THRE')IPOTAX='POIN'
        IHV=IPOTAX
        GO TO 5160
      ENDIF
!
!CCCC FOLLOWING SECTION ADDED APRIL 2005
!     ****************************************************************
!     **  SET PEAKS OVER THRESHOLD ITERATIONS                       **
!     ****************************************************************
!
      IPART1='POT '
      IPART2='ITER'
      IPART3='PEAK'
      IPART4='OVER'
      IPART5='THRE'
      IF((IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2) .OR.   &
         (IHARG(1).EQ.IPART3.AND.IHARG(2).EQ.IPART4.AND.   &
          IHARG(3).EQ.IPART5.AND.IHARG(4).EQ.IPART2))THEN
        IF(IHARG(NUMARG).EQ.'DEFA')THEN
          IPOTIT=50
        ELSEIF(IHARG(NUMARG).EQ.'DEFA')THEN
          IPOTIT=50
        ELSEIF(NUMARG.EQ.3 .OR. NUMARG.EQ.4)THEN
          IPOTIT=50
        ELSE
          IPOTIT=IARG(NUMARG)
        ENDIF
        IF(IPOTIT.LT.10)IPOTIT=10
        IV=IPOTIT
        GO TO 5150
      ENDIF
!
!CCCC FOLLOWING SECTION ADDED AUGUST  2008
!     ********************************************
!     **  SET MERGE MATCH VARIABLES             **
!     ********************************************
!
      IPART1='MERG'
      IPART2='MATC'
      IPART3='VARI'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2 .AND.   &
         IHARG(3).EQ.IPART3)THEN
        IV=IARG(NUMARG)
        IF(IV.LT.0)IV=1
        IMERMA=IV
        GO TO 5150
      ENDIF
!
!CCCC FOLLOWING SECTION ADDED AUGUST  2008
!     ********************************************
!     **  SET MERGE CARRY VARIABLES             **
!     ********************************************
!
!     NOTE JUNE 2009: IF 2 VALUES ARE SPECIFIED, THEN
!                     THE 2 SETS OF DATA CAN HAVE A DIFFERENT
!                     NUMBER OF CARRY VARIABLES.
!
      IPART1='MERG'
      IPART2='CARR'
      IPART3='VARI'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2 .AND.   &
         IHARG(3).EQ.IPART3)THEN
        IF(NUMARG.EQ.3)THEN
          IMERCA=1
          IMERC2=IMERCA
        ELSEIF(NUMARG.EQ.4)THEN
          IV=IARG(NUMARG)
          IF(IV.LT.0)IV=0
          IMERCA=IV
          IMERC2=IMERCA
        ELSEIF(NUMARG.EQ.5)THEN
          IV=IARG(4)
          IF(IV.LT.0)IV=0
          IMERCA=IV
          IVJUNK=IARG(5)
          IF(IVJUNK.LT.0)IVJUNK=0
          IMERC2=IVJUNK
        ENDIF
        GO TO 5150
      ENDIF
!
!CCCC FOLLOWING SECTION ADDED MARCH  2009
!     **********************************************
!     **  SET CONVERT DENSITY HORIZONTAL <VALUE>  **
!     **********************************************
!
      IPART1='CONV'
      IPART2='DENS'
      IPART3='HORI'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2 .AND.   &
         IHARG(3).EQ.IPART3)THEN
        IV=IARG(NUMARG)
        IF(IV.LT.72)IV=72
        ICONDH=IV
        GO TO 5150
      ENDIF
!
!CCCC FOLLOWING SECTION ADDED MARCH  2009
!     ********************************************
!     **  SET CONVERT DENSITY VERTICAL  <VALUE> **
!     ********************************************
!
      IPART1='CONV'
      IPART2='DENS'
      IPART3='VERT'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2 .AND.   &
         IHARG(3).EQ.IPART3)THEN
        IV=IARG(NUMARG)
        IF(IV.LT.72)IV=72
        ICONDV=IV
        GO TO 5150
      ENDIF
!
!CCCC FOLLOWING SECTION ADDED MARCH  2009
!     ********************************************
!     **  SET CONVERT DENSITY           <VALUE> **
!     ********************************************
!
      IPART1='CONV'
      IPART2='DENS'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2)THEN
        IV=IARG(NUMARG)
        IF(IV.LT.72)IV=72
        ICONDH=IV
        ICONDV=IV
        GO TO 5150
      ENDIF
!
!CCCC FOLLOWING SECTION ADDED APRIL  2009
!     ****************************************
!     **  SET LATEX POINT SIZE   <VALUE>    **
!     ****************************************
!
      IPART1='LATE'
      IPART2='POIN'
      IPART3='SIZE'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2 .AND.   &
         IHARG(3).EQ.IPART3)THEN
        IF(NUMARG.GT.3)THEN
          IV=IARG(NUMARG)
          IF(IV.LT.6)IV=6
          IF(IV.GT.24)IV=24
        ELSE
          IV=12
        ENDIF
        ILATPS=IV
        GO TO 5150
      ENDIF
!
!CCCC FOLLOWING SECTION ADDED JUNE  2009
!     **********************************************
!     **  SET CODE CROSS TABULATE OFFSET <VALUE>  **
!     **********************************************
!
      IPART1='CODE'
      IPART2='CROS'
      IPART3='TABU'
      IPART4='OFFS'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2 .AND.   &
         IHARG(3).EQ.IPART3.AND.IHARG(4).EQ.IPART4)THEN
        IF(NUMARG.GT.4)THEN
          IF(IHARG(5).EQ.'DEFA')THEN
            IV=0
          ELSEIF(IHARG(5).EQ.'ON')THEN
            IV=0
          ELSEIF(IHARG(5).EQ.'OFF')THEN
            IV=0
          ELSEIF(IHARG(5).EQ.'YES')THEN
            IV=0
          ELSEIF(IHARG(5).EQ.'NO')THEN
            IV=0
          ELSE
            IV=IARG(NUMARG)
            IF(IV.LT.0)IV=0
          ENDIF
        ELSE
          IV=0
        ENDIF
        ICCTOF=IV
        GO TO 5150
      ENDIF
!
!CCCC FOLLOWING SECTION ADDED JUNE  2009
!     ***************************************************
!     **  SET CODE CROSS TABULATE GROUP SIZE <VALUE>  **
!     **************************************************
!
      IPART1='CODE'
      IPART2='CROS'
      IPART3='TABU'
      IPART4='GROU'
      IPART5='SIZE'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2 .AND.   &
         IHARG(3).EQ.IPART3.AND.IHARG(4).EQ.IPART4 .AND.   &
         IHARG(5).EQ.IPART5)THEN
        IJUNK=6
        IF(IHARG(6).EQ.'ONE')IJUNK=7
        IF(IHARG(6).EQ.'TWO')IJUNK=7
        IF(IHARG(6).EQ.'THRE')IJUNK=7
        IF(IHARG(6).EQ.'FOUR')IJUNK=7
        IF(IHARG(6).EQ.'FIVE')IJUNK=7
        IF(IHARG(6).EQ.'SIX')IJUNK=7
        IF(NUMARG.GT.IJUNK-1)THEN
          IF(IHARG(IJUNK).EQ.'DEFA')THEN
            IV=0
          ELSEIF(IHARG(IJUNK).EQ.'ON')THEN
            IV=0
          ELSEIF(IHARG(IJUNK).EQ.'OFF')THEN
            IV=0
          ELSEIF(IHARG(IJUNK).EQ.'YES')THEN
            IV=0
          ELSEIF(IHARG(IJUNK).EQ.'NO')THEN
            IV=0
          ELSE
            IV=IARG(NUMARG)
            IF(IV.LT.0)IV=0
          ENDIF
        ELSE
          IV=0
        ENDIF
        IF(IHARG(6).EQ.'ONE')THEN
          ICCTG1=IV
        ELSEIF(IHARG(6).EQ.'TWO')THEN
          ICCTG2=IV
        ELSEIF(IHARG(6).EQ.'THRE')THEN
          ICCTG3=IV
        ELSEIF(IHARG(6).EQ.'FOUR')THEN
          ICCTG4=IV
        ELSEIF(IHARG(6).EQ.'FIVE')THEN
          ICCTG5=IV
        ELSEIF(IHARG(6).EQ.'SIX')THEN
          ICCTG6=IV
        ELSE
          ICCTG1=IV
        ENDIF
        GO TO 5150
      ENDIF
!
!CCCC FOLLOWING SECTION ADDED APRIL 2005
!     ****************************************************************
!     **  SET PEAKS OVER THRESHOLD INITIAL POINTS                   **
!     ****************************************************************
!
      IPART1='POT '
      IPART2='INIT'
      IPART3='POIN'
      IPART4='PEAK'
      IPART5='OVER'
      IPART6='THRE'
      IF((IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2.AND.   &
          IHARG(3).EQ.IPART3) .OR.   &
         (IHARG(1).EQ.IPART4.AND.IHARG(2).EQ.IPART5.AND.   &
          IHARG(3).EQ.IPART6.AND.IHARG(4).EQ.IPART2.AND.   &
          IHARG(5).EQ.IPART3))THEN
