        ELSEIF(IHARG(6).EQ.'MAXI' .AND. IHARG(7).EQ.'LIKE')THEN
          IGOFFM='ML'
        ELSEIF(IHARG(NUMARG).EQ.'DEFA')THEN
          IGOFFM='DEFA'
        ELSE
          IGOFFM='NULL'
        ENDIF
        IHV=IGOFFM
        GO TO 5160
      ENDIF
!
!CCCC FOLLOWING SECTION ADDED OCTOBER    2009
!     *************************************************************
!     **  SET GOODNESS OF FIT FULLY SPECIFIED <ON/OFF>           **
!     *************************************************************
!
      IPART1='GOOD'
      IPART2='OF  '
      IPART3='FIT '
      IPART4='FULL'
      IPART5='SPEC'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2.AND.   &
         IHARG(3).EQ.IPART3.AND.IHARG(4).EQ.IPART4.AND.   &
         IHARG(5).EQ.IPART5)THEN
        IF(IHARG(NUMARG).EQ.'DEFA')THEN
          IGOFFS='ON'
        ELSEIF(IHARG(NUMARG).EQ.'OFF ')THEN
          IGOFFS='OFF'
        ELSEIF(IHARG(NUMARG).EQ.'NO  ')THEN
          IGOFFS='OFF'
        ELSEIF(IHARG(NUMARG).EQ.'FALS')THEN
          IGOFFS='OFF'
        ELSEIF(NUMARG.EQ.5)THEN
          IGOFFS='ON'
        ELSEIF(IHARG(NUMARG).EQ.'ON  ')THEN
          IGOFFS='ON'
        ELSEIF(IHARG(NUMARG).EQ.'YES ')THEN
          IGOFFS='ON'
        ELSEIF(IHARG(NUMARG).EQ.'TRUE')THEN
          IGOFFS='ON'
        ELSE
          IGOFFS='ON'
        ENDIF
        IHV=IGOFFS
        GO TO 5160
      ENDIF
!
!CCCC FOLLOWING SECTION ADDED MARCH 2008
!     *************************************************************
!     **  SET COLOR MAXIMUM  <VALUE>                             **
!     *************************************************************
!
!CCCC FOLLOWING SECTION ADDED MARCH 2008
!     *************************************************************
!     **  SET COLOR MAXIMUM  <VALUE>                             **
!     *************************************************************
!
      IPART1='COLO'
      IPART2='MAXI'
      IF((IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2) .OR.   &
         (IHARG(2).EQ.IPART2.AND.IHARG(2).EQ.IPART1))THEN
        IF(IHARG(NUMARG).EQ.'DEFA')THEN
          PCOLMX=255.
        ELSEIF(IHARG(NUMARG).EQ.'ON  ')THEN
          PCOLMX=255.
        ELSEIF(IHARG(NUMARG).EQ.'YES ')THEN
          PCOLMX=255.
        ELSEIF(IHARG(NUMARG).EQ.'OFF ')THEN
          PCOLMX=255.
        ELSEIF(IHARG(NUMARG).EQ.'NO  ')THEN
          PCOLMX=255.
        ELSEIF(NUMARG.EQ.3)THEN
          PCOLMX=255.
        ELSE
          PCOLMX=ARG(NUMARG)
        ENDIF
        AV=PCOLMX
        GO TO 5170
      ENDIF
!
!CCCC FOLLOWING SECTION ADDED NOVEMBER 2002
!     ****************************************************************
!     **  SET QWIN SYSTEM <SYSTEMQQ/WINEXEC/RUNQQ/SHELL EXECUTE/    **
!     **                   CREATE PROCESS/EXECUTE COMMAND LINE>     **
!     ****************************************************************
!
!     2016/08: ADD RUNQQ OPTION
!     2018/04: ADD SHELL EXECUTE OPTION
!     2018/04: TREAT WINEXEC, SHELL EXECUTE, SHELL PROCESS AS EQUIVALENT
!              TO "EXECUTE COMMAND LINE"
!
      IPART1='QWIN'
      IPART2='SYST'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2)THEN
        IQWNSY='SYST'
        IF(IHARG(3).EQ.'RUNQ')IQWNSY='RUNQ'
!CCCC   IF(IHARG(3).EQ.'WINE')IQWNSY='WINE'
!CCCC   IF(IHARG(3).EQ.'SHEL')IQWNSY='SHEL'
!CCCC   IF(IHARG(3).EQ.'CREA')IQWNSY='CREA'
        IF(IHARG(3).EQ.'WINE')IQWNSY='COMM'
        IF(IHARG(3).EQ.'SHEL')IQWNSY='COMM'
        IF(IHARG(3).EQ.'CREA')IQWNSY='COMM'
        IF(IHARG(3).EQ.'COMM')IQWNSY='COMM'
        IF(IHARG(3).EQ.'EXEC')IQWNSY='COMM'
        IHV=IQWNSY
        GO TO 5160
      ENDIF
!
!CCCC FOLLOWING SECTION ADDED APRIL 2018
!     ****************************************************************
!     **  SET LINUX SYSTEM <SYSTEM/COMMAND LINE EXECUTE>            **
!     ****************************************************************
!
      IPART1='LINU'
      IPART2='SYST'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2)THEN
        ILINSY='SYST'
        IF(IHARG(3).EQ.'COMM')ILINSY='COMM'
        IHV=ILINSY
        GO TO 5160
      ENDIF
!
!CCCC FOLLOWING SECTION ADDED NOVEMBER 2002
!     ****************************************************************
!     **  SET GHOSTSCRIPT PRINTER <ON/OFF>                          **
!     ****************************************************************
!
      IPART1='GHOS'
      IPART2='PRIN'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2)THEN
        IPRNGS='OFF'
        IF(IHARG(3).EQ.'ON')IPRNGS='ON'
        IF(IHARG(3).EQ.'YES')IPRNGS='ON'
        IHV=IPRNGS
        GO TO 5160
      ENDIF
!
!CCCC FOLLOWING SECTION ADDED JANUARY 2003
!     ****************************************************************
!     **  SET POSTSCRIPT BOUNDING BOX <FIXED/FLOAT>                 **
!     ****************************************************************
!
      IPART1='POST'
      IPART2='BOUN'
      IPART3='BOX '
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2.AND.   &
         IHARG(3).EQ.IPART3)THEN
        IPSTBB='FIXE'
        IF(IHARG(4).EQ.'FLOA')IPSTBB='FLOA'
        IHV=IPSTBB
        GO TO 5160
      ENDIF
!
!CCCC FOLLOWING SECTION ADDED JANUARY 2003
!CCCC MODIFIED OCTOBER 2007: ADD KEYWORD TO SPECIFY WHETHER
!CCCC CONVERSION PERFORMED BY "GHOSTSCRIPT" OR "CONVERT".
!     ****************************************************************
!     **  SET POSTSCRIPT CONVERT <GHOSTSCRIPT/CONVERT/PS2PDF>       **
!     **                         <JPEG/PDF/TIFF/PBM/PNG/PNM/PPM>    **
!     ****************************************************************
!
      IPART1='POST'
      IPART2='CONV'
      IPART3='OUTP'
      IPART4='DEVI'
      IPART5='GHOS'
      IPART6='PS2P'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2)THEN
        IPSTDV='NULL'
!
        IPSTD2='GHOS'
        IF(IHARG(3).EQ.IPART2)THEN
          IPSTD2='CONV'
        ELSEIF(IHARG(3).EQ.IPART6)THEN
          IPSTD2='PS2P'
        ENDIF
!
        IF(IHARG(3).EQ.'JPEG')IPSTDV='JPEG'
        IF(IHARG(3).EQ.'PDF ')IPSTDV='PDF '
        IF(IHARG(3).EQ.'TIFF')IPSTDV='TIFF'
        IF(IHARG(3).EQ.'PBM ')IPSTDV='PBM '
        IF(IHARG(3).EQ.'PNG ')IPSTDV='PNG '
        IF(IHARG(3).EQ.'PGM ')IPSTDV='PGM '
        IF(IHARG(3).EQ.'PNM ')IPSTDV='PNM '
        IF(IHARG(3).EQ.'PPM ')IPSTDV='PPM '
        IF(IHARG(4).EQ.'JPEG')IPSTDV='JPEG'
        IF(IHARG(4).EQ.'PDF ')IPSTDV='PDF '
        IF(IHARG(4).EQ.'TIFF')IPSTDV='TIFF'
        IF(IHARG(4).EQ.'PBM ')IPSTDV='PBM '
        IF(IHARG(4).EQ.'PNG ')IPSTDV='PNG '
        IF(IHARG(4).EQ.'PGM ')IPSTDV='PGM '
        IF(IHARG(4).EQ.'PNM ')IPSTDV='PNM '
        IF(IHARG(4).EQ.'PPM ')IPSTDV='PPM '
        IF(IPSTD2.EQ.'PS2P')IPSTDV='PDF'
        IHV=IPSTDV
        GO TO 5160
      ELSEIF(IHARG(1).EQ.IPART3.AND.IHARG(2).EQ.IPART4)THEN
        IPSTDV='NULL'
!
        IPSTD2='GHOS'
        IF(IHARG(3).EQ.IPART2)THEN
          IPSTD2='CONV'
        ELSEIF(IHARG(3).EQ.IPART6)THEN
          IPSTD2='PS2P'
        ENDIF
!
        IF(IHARG(3).EQ.'JPEG')IPSTDV='JPEG'
        IF(IHARG(3).EQ.'PDF ')IPSTDV='PDF '
        IF(IHARG(3).EQ.'TIFF')IPSTDV='TIFF'
        IF(IHARG(3).EQ.'PBM ')IPSTDV='PBM '
        IF(IHARG(3).EQ.'PNG ')IPSTDV='PNG '
        IF(IHARG(3).EQ.'PGM ')IPSTDV='PGM '
        IF(IHARG(3).EQ.'PNM ')IPSTDV='PNM '
        IF(IHARG(3).EQ.'PPM ')IPSTDV='PPM '
        IF(IHARG(4).EQ.'JPEG')IPSTDV='JPEG'
        IF(IHARG(4).EQ.'PDF ')IPSTDV='PDF '
        IF(IHARG(4).EQ.'TIFF')IPSTDV='TIFF'
        IF(IHARG(4).EQ.'PBM ')IPSTDV='PBM '
        IF(IHARG(4).EQ.'PNG ')IPSTDV='PNG '
        IF(IHARG(4).EQ.'PGM ')IPSTDV='PGM '
        IF(IHARG(4).EQ.'PNM ')IPSTDV='PNM '
        IF(IHARG(4).EQ.'PPM ')IPSTDV='PPM '
        IHV=IPSTDV
        GO TO 5160
      ENDIF
!
!CCCC FOLLOWING SECTION ADDED FEBRUARY 2005
!     ****************************************************************
!     **  SET PARAMETER EXPANSION DIGIT <VALUE>                     **
!     ****************************************************************
!
      IPART1='PARA'
      IPART2='EXPA'
      IPART3='DIGI'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2.AND.   &
         IHARG(3).EQ.IPART3)THEN
        IF(IHARG(4).EQ.'DEFAU' .OR. IHARG(4).EQ.'ON' .OR.   &
           IHARG(4).EQ.'OFF')THEN
          IEXPDI=-1
        ELSE
          IEXPDI=IV
        ENDIF
        IV=IEXPDI
        GO TO 5150
      ENDIF
!
!CCCC FOLLOWING SECTION ADDED MARCH 2005
!     ********************************************************
!     **  SET LINE PRINTER COLUMNS <VALUE>                  **
!     ********************************************************
!
      IPART1='LINE'
      IPART2='PRIN'
      IPART3='COLU'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2.AND.   &
         IHARG(3).EQ.IPART3)THEN
        IF(IHARG(4).EQ.'DEFAU' .OR. IHARG(4).EQ.'ON' .OR.   &
           IHARG(4).EQ.'OFF')THEN
          ILPRCO=80
        ELSE
          ILPRCO=IV
        ENDIF
        IF(ILPRCO.LT.72)ILPRCO=72
        IF(ILPRCO.GT.132)ILPRCO=132
        IV=ILPRCO
        GO TO 5150
      ENDIF
!
!CCCC FOLLOWING SECTION ADDED NOVEMBER 1999.
!     ****************************************************************
!     **  SET PARAMETER EXPANSION <NUMERIC/EXPONENTIAL/ROUND>       **
!     ****************************************************************
!
      IPART1='PARA'
      IPART2='EXPA'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2)THEN
        IF(IHV.EQ.'EXPO')THEN
          IEXPPA='EXPO'
        ELSEIF(IHV.EQ.'ROUN')THEN
          IEXPPA='ROUN'
        ELSE
          IEXPPA='NUME'
        ENDIF
        IHV=IEXPPA
        GO TO 5160
      ENDIF
!
!CCCC FOLLOWING SECTION ADDED NOVEMBER 1999.
!     ****************************************************************
!     **  SET VARIABLE LABEL EXPAND <ON/OFF>                        **
!     ****************************************************************
!
      IPART1='VARI'
      IPART2='LABE'
      IPART3='EXPA'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2.AND.   &
        IHARG(3).EQ.IPART3)THEN
        IVNMEX=IHARG(4)
        IF(IVNMEX.EQ.'OFF'.OR.IVNMEX.EQ.'NO'.OR.IVNMEX.EQ.'FALS')THEN
          IVNMEX='OFF'
        ELSE
          IVNMEX='ON'
        ENDIF
        IHV=IVNMEX
        GO TO 5160
      ENDIF
!
!CCCC FOLLOWING SECTION ADDED JANUARY 2000.
!     ****************************************************************
!     **  SET CROSS TABULATE PLOT DIMENSION <<1/2>                  **
!     ****************************************************************
!
      IPART1='CROS'
      IPART2='TABU'
      IPART3='PLOT'
      IPART4='DIME'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2.AND.   &
        IHARG(3).EQ.IPART3.AND.IHARG(4).EQ.IPART4)THEN
        ICTBDI=IHV
        IF(ICTBDI.EQ.'2'.OR.ICTBDI.EQ.'TWO')THEN
          ICTBDI='2'
        ELSE
          ICTBDI='1'
        ENDIF
        IHV=ICTBDI
        GO TO 5160
      ENDIF
!
!CCCC FOLLOWING SECTION ADDED JANUARY 2000.
!     ****************************************************************
!     **  SET SORT DIRECTION <ASCENDING/DESCENDING>                 **
!     ****************************************************************
!
      IPART1='SORT'
      IPART2='DIRE'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2)THEN
        ISORDI=IHV
        IF(ISORDI.EQ.'DESC')THEN
          ISORDI='DESC'
        ELSE
          ISORDI='ASCE'
        ENDIF
        IHV=ISORDI
        GO TO 5160
      ENDIF
!
!CCCC FOLLOWING SECTION ADDED FEBRUARY 2000.
!     ****************************************************************
!     **  SET DEX CONTOUR PLOT DIRECTION <MINIMUM/MAXIMUM>          **
!     **  SET DEX CONTOUR PLOT MODEL <LINEAR/QUADRATIC>             **
!     ****************************************************************
!
      IPART1='DEX '
      IPART2='CONT'
      IPART3='PLOT'
      IPART4='DIRE'
      IPART5='MODE'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2.AND.   &
      IHARG(3).EQ.IPART3)THEN
        IF(IHARG(4).EQ.IPART4)THEN
          IF(IHV.EQ.'QUAD')THEN
            IDCPDI='QUAD'
          ELSE
            IDCPDI='LINE'
          ENDIF
        ELSEIF(IHARG(4).EQ.IPART5)THEN
          IF(IHV.EQ.'MINI'.OR.IHV.EQ.'MIN ')THEN
            IDCPFI='MINI'
          ELSE
            IDCPFI='MAXI'
          ENDIF
        ELSEIF(IHARG(4).EQ.'LINE')THEN
          IDCPFI='LINE'
        ELSEIF(IHARG(4).EQ.'QUAD')THEN
          IDCPFI='QUAD'
        ELSEIF(IHARG(4).EQ.'MIN '.OR.IHARG(4).EQ.'MINI')THEN
          IDCPDI='MINI'
        ELSEIF(IHARG(4).EQ.'MAX '.OR.IHARG(4).EQ.'MAXI')THEN
          IDCPDI='MAXI'
        ENDIF
        IHV=IDCPDI
        GO TO 5160
      ENDIF
!
!CCCC FOLLOWING SECTION ADDED OCTOBER 2000.
!     ****************************************************************
!     **  SET MANDEL PAULE <REGULAR/MODIFIED>                       **
!     ****************************************************************
!
      IPART1='MAND'
      IPART2='PAUL'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2)THEN
        IMANPA=IHV
        IF(IMANPA.NE.'MODI')THEN
          IMANPA='REGU'
        ENDIF
        IHV=IMANPA
        GO TO 5160
      ENDIF
!
!CCCC FOLLOWING SECTION ADDED MARCH 2001.
!     ****************************************************************
!     **  SET LOCATION STATISTIC <MEAN/MEDIAN/MIDMEAN/TRIMMED MEAN/ **
!     **    MINIMUM/HARMONIC MEAN/GEOMETRIC MEAN/WINS MEAN/MIDRANGE/ *
!     **    BIWEIGHT LOCATION/HODGES LEHMAN/H10/H12/H15/H17/H20>    **
!     ****************************************************************
!
      IPART1='LOCA'
      IPART2='STAT'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2)THEN
        ISTALO=IHV
        IF(IHARG(3).EQ.'GEOM'.AND.IHARG(4).EQ.'MEAN')THEN
          ISTALO='GEOM'
        ELSEIF(IHARG(3).EQ.'HARM'.AND.IHARG(4).EQ.'MEAN')THEN
          ISTALO='HARM'
        ELSEIF(IHARG(3).EQ.'WINS'.AND.IHARG(4).EQ.'MEAN')THEN
          ISTALO='WINS'
        ELSEIF(IHARG(3).EQ.'BIWE'.AND.IHARG(4).EQ.'LOCA')THEN
          ISTALO='BILO'
        ELSEIF(IHARG(3).EQ.'HODG'.AND.IHARG(4).EQ.'LEHM')THEN
          ISTALO='HLEH'
        ELSEIF(IHARG(3).EQ.'H10 '.AND.IHARG(4).EQ.'LOCA')THEN
          ISTALO='H10 '
        ELSEIF(IHARG(3).EQ.'H12 '.AND.IHARG(4).EQ.'LOCA')THEN
          ISTALO='H12 '
        ELSEIF(IHARG(3).EQ.'H15 '.AND.IHARG(4).EQ.'LOCA')THEN
          ISTALO='H15 '
        ELSEIF(IHARG(3).EQ.'H17 '.AND.IHARG(4).EQ.'LOCA')THEN
          ISTALO='H17 '
        ELSEIF(IHARG(3).EQ.'H20 '.AND.IHARG(4).EQ.'LOCA')THEN
          ISTALO='H20 '
        ENDIF
        IF(ISTALO.EQ.'MIN')ISTALO='MINI'
        IF(ISTALO.EQ.'BIWE')ISTALO='BILO'
        IF(ISTALO.EQ.'H10 ')ISTALO='H10L'
        IF(ISTALO.EQ.'H12 ')ISTALO='H12L'
        IF(ISTALO.EQ.'H15 ')ISTALO='H15L'
        IF(ISTALO.EQ.'H17 ')ISTALO='H17L'
        IF(ISTALO.EQ.'H20 ')ISTALO='H20L'
        IF(ISTALO.NE.'MEAN'.AND.ISTALO.NE.'MEDI'.AND.   &
           ISTALO.NE.'MIDM'.AND.ISTALO.NE.'TRIM'.AND.   &
           ISTALO.NE.'MIDM'.AND.ISTALO.NE.'TRIM'.AND.   &
           ISTALO.NE.'GEOM'.AND.ISTALO.NE.'HARM'.AND.   &
           ISTALO.NE.'WINS'.AND.ISTALO.NE.'BILO'.AND.   &
           ISTALO.NE.'HLEH'.AND.ISTALO.NE.'H10L'.AND.   &
           ISTALO.NE.'H12L'.AND.ISTALO.NE.'H15L'.AND.   &
           ISTALO.NE.'H17L'.AND.ISTALO.NE.'H20L'.AND.   &
           ISTALO.NE.'MIDR'.AND.ISTALO.NE.'MINI')THEN
          ISTALO='MEAN'
        ENDIF
        IHV=ISTALO
        GO TO 5160
      ENDIF
!
!CCCC FOLLOWING SECTION ADDED MARCH 2001.
!     ****************************************************************
!     **  SET SCALE STATISTIC  SD/AAD/MAD/IQ RANGE/GEOM SD/         **
!     **      BIWEIGHT MIDVARIANCE/PERCENTAGE BEND MIDVARIANCE      **
!     **      WINSORIZED SD/BIWEIGHT SCALE/SN/QN/H10/H12/H15/       **
!     **      H17/H20/RANGE                                         **
!     ****************************************************************
!
      IPART1='SCAL'
      IPART2='STAT'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2)THEN
        ISTASC=IHV
        IF(IHARG(3).EQ.'GEOM'.AND.IHARG(4).EQ.'SD  ')THEN
          ISTASC='GEOM'
        ELSEIF(IHARG(3).EQ.'GEOM'.AND.IHARG(4).EQ.'STAN'.AND.   &
               IHARG(5).EQ.'DEVI')THEN
          ISTASC='GEOM'
        ELSEIF(IHARG(3).EQ.'IQ  '.AND.IHARG(4).EQ.'RANG')THEN
          ISTASC='IQRA'
        ELSEIF(IHARG(3).EQ.'NORM'.AND.IHARG(4).EQ.'IQ  '.AND.   &
               IHARG(5).EQ.'RANG')THEN
          ISTASC='NIQR'
        ELSEIF(IHARG(3).EQ.'SCAL'.AND.IHARG(4).EQ.'MEDI'.AND.   &
               IHARG(5).EQ.'ABSO'.AND.IHARG(6).EQ.'DEVI')THEN
          ISTASC='MADN'
        ELSEIF(IHARG(3).EQ.'SCAL'.AND.IHARG(4).EQ.'MAD ')THEN
          ISTASC='MADN'
        ELSEIF(IHARG(3).EQ.'INTE'.AND.IHARG(4).EQ.'RANG')THEN
          ISTASC='IQRA'
        ELSEIF(IHARG(3).EQ.'BIWE'.AND.IHARG(4).EQ.'SCAL')THEN
          ISTASC='BISC'
        ELSEIF(IHARG(3).EQ.'SN'.AND.IHARG(4).EQ.'SCAL')THEN
          ISTASC='SNSC'
        ELSEIF(IHARG(3).EQ.'SN')THEN
          ISTASC='SNSC'
        ELSEIF(IHARG(3).EQ.'QN'.AND.IHARG(4).EQ.'SCAL')THEN
          ISTASC='QNSC'
        ELSEIF(IHARG(3).EQ.'QN')THEN
          ISTASC='QNSC'
        ELSEIF(IHARG(3).EQ.'RANG')THEN
          ISTASC='RANG'
        ELSEIF(IHARG(3).EQ.'BIWE'.AND.IHARG(4).EQ.'MIDV')THEN
          ISTASC='BIMV'
        ELSEIF(IHARG(3).EQ.'WINS'.AND.IHARG(4).EQ.'SD')THEN
          ISTASC='WISD'
        ELSEIF(IHARG(3).EQ.'WINS'.AND.IHARG(4).EQ.'STAN'.AND.   &
               IHARG(5).EQ.'DEVI')THEN
          ISTASC='WISD'
        ELSEIF(IHARG(3).EQ.'PERC'.AND.IHARG(4).EQ.'BEND'.AND.   &
               IHARG(5).EQ.'MIDV')THEN
          ISTASC='PBMV'
        ELSEIF(IHARG(3).EQ.'H10 '.AND.IHARG(4).EQ.'SCAL')THEN
          ISTASC='H10 '
        ELSEIF(IHARG(3).EQ.'H12 '.AND.IHARG(4).EQ.'SCAL')THEN
          ISTASC='H12 '
        ELSEIF(IHARG(3).EQ.'H15 '.AND.IHARG(4).EQ.'SCAL')THEN
          ISTASC='H15 '
        ELSEIF(IHARG(3).EQ.'H17 '.AND.IHARG(4).EQ.'SCAL')THEN
          ISTASC='H17 '
        ELSEIF(IHARG(3).EQ.'H20 '.AND.IHARG(4).EQ.'SCAL')THEN
          ISTASC='H20 '
        ENDIF
        IF(ISTASC.EQ.'AVER')ISTASC='AAD'
        IF(ISTASC.EQ.'MEDI')ISTASC='MAD'
        IF(ISTASC.EQ.'STAN')ISTASC='SD'
        IF(ISTASC.EQ.'BIWE')ISTASC='BISC'
        IF(ISTASC.EQ.'H10 ')ISTASC='H10S'
        IF(ISTASC.EQ.'H12 ')ISTASC='H12S'
        IF(ISTASC.EQ.'H15 ')ISTASC='H15S'
        IF(ISTASC.EQ.'H17 ')ISTASC='H17S'
        IF(ISTASC.EQ.'H20 ')ISTASC='H20S'
        IF(ISTASC.NE.'AAD'.AND.ISTASC.NE.'MAD'.AND.   &
           ISTASC.NE.'RANG'.AND.ISTASC.NE.'GEOM'.AND.   &
           ISTASC.NE.'BIMV'.AND.ISTASC.NE.'PBMV'.AND.   &
           ISTASC.NE.'WISD'.AND.ISTASC.NE.'H10S'.AND.   &
           ISTASC.NE.'H12S'.AND.ISTASC.NE.'H15S'.AND.   &
           ISTASC.NE.'H17S'.AND.ISTASC.NE.'H20S'.AND.   &
           ISTASC.NE.'IQRA'.AND.ISTASC.NE.'BISC')THEN
          ISTASC='SD'
        ENDIF
        IHV=ISTASC
        GO TO 5160
      ENDIF
!
!CCCC FOLLOWING SECTION ADDED MARCH 2001.
!     **************************************************************
!     **  SET SUPERSCRIPT HORIZONTAL SCALE <SIZE>                 **
!     **************************************************************
!
      IPART1='SUPE'
      IPART2='HORI'
      IPART3='SCAL'
      IPART4='SUBS'
      IPART5='X   '
      IF((IHARG(1).EQ.IPART1.OR.IHARG(1).EQ.IPART4).AND.   &
         (IHARG(2).EQ.IPART2.OR.IHARG(2).EQ.IPART5).AND.   &
          IHARG(3).EQ.IPART3)THEN
        PSUPXS=AV
        IF(PSUPXS.LE.0.0 .OR. PSUPXS.GE.20.0)PSUPXS=0.5
        AV=PSUPXS
        GO TO 5170
      ENDIF
!
!CCCC FOLLOWING SECTION ADDED MARCH 2001.
!     **************************************************************
!     **  SET SUPERSCRIPT VERTICAL   SCALE <SIZE>                 **
!     **************************************************************
!
      IPART1='SUPE'
      IPART2='VERT'
      IPART3='SCAL'
      IPART4='SUBS'
      IPART5='Y   '
      IF((IHARG(1).EQ.IPART1.OR.IHARG(1).EQ.IPART4).AND.   &
         (IHARG(2).EQ.IPART2.OR.IHARG(2).EQ.IPART5).AND.   &
          IHARG(3).EQ.IPART3)THEN
        PSUPYS=AV
