!CCCC FOLLOWING SECTION ADDED NOVEMBER 1999
!               *****************************************************
!               **  TREAT THE SET X2LABEL SUFFIX  CASE             **
!               *****************************************************
!
      IF(NUMARG.GE.2.AND.IHARG(1).EQ.'X2LA'.AND.   &
      IHARG(2).EQ.'SUFF')GO TO 9510
      GO TO 9590
!
 9510 CONTINUE
      ISPX2S='DEFAULT'
      NCHSUF=7
      IF(NUMARG.LE.2)GO TO 9550
      IF(IHARG(NUMARG).EQ.'OFF')THEN
        ISPX2S=' '
        NCHSUF=0
        GO TO 9550
      ENDIF
      IF(IHARG(NUMARG).EQ.'AUTO')GO TO 9550
      IF(IHARG(NUMARG).EQ.'DEFA')GO TO 9550
!
      DO 9530 I=1,80
      ICANS(I:I)=IANSLC(I)
 9530 CONTINUE
!
      ISTART=1
      ISTOP=IWIDTH
      IWORD=NUMARG+1
      DO 9532 I=ISTART,ISTOP-4
        IF(IANS(I).EQ.'S   '.AND.IANS(I+1).EQ.'U'.AND.   &
           IANS(I+2).EQ.'F'.AND.IANS(I+3).EQ.'F')THEN
          ISTRT2=I+3
          DO 9534 J=ISTRT2,ISTOP
            IF(ICANS(J:J).EQ.' ')THEN
              NCSTRI=ISTOP-J
              ISTRIN(1:NCSTRI)=ICANS(J+1:IWIDTH)
              GO TO 9539
            ENDIF
 9534     CONTINUE
          NCSTRI=0
        ENDIF
 9532 CONTINUE
 9539 CONTINUE
!
      IF(NCSTRI.GE.1)GO TO 9540
      ISPX2S=' '
      NCHSUF=0
      GO TO 9550
!
 9540 CONTINUE
      ISPX2S=' '
      NCHSUF=NCSTRI
      IF(NCHSUF.GT.16)NCHSUF=16
      ISPX2S(1:NCHSUF)=ISTRIN(1:NCHSUF)
!
 9550 CONTINUE
