!CCCC FOLLOWING SECTION ADDED SEPTEMBER 1999.
!     ****************************************************************
!     **  SET FACTOR       PLOT PLOT TYPE <PLOT/HIST/PERC>          **
!     ****************************************************************
!
      IPART1='FACT'
      IPART2='PLOT'
