!CCCC FOLLOWING SECTION ADDED SEPTEMBER 1999.
!     ***************************************************************
!     **  SET SCATTER PLOT MATRIX LIMITS <LOWL1> <UPPL1>           **
!     **      <LOWL2> <UPPL2>  ETC.                                **
!     **    (CAN SPECIFY UP TO 25 PAIRS)                           **
!     ***************************************************************
!
      IPART1='SCAT'
      IPART2='PLOT'
      IPART3='MATR'
      IPART4='LIMI'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2.AND.   &
         IHARG(3).EQ.IPART3.AND.IHARG(4).EQ.IPART4)THEN
        DO 22509 I=1,25
          PSPLLL(I)=CPUMIN
          PSPLUL(I)=CPUMIN
22509   CONTINUE
        IF(NUMARG.GE.5)THEN
          IT1=0
          DO 22511 I=5,NUMARG,2
            IF(I+1.GT.NUMARG)GO TO 22511
            IF(IT1.GT.24)GO TO 22511
            IT1=IT1+1
            PSPLLL(IT1)=ARG(I)
            PSPLUL(IT1)=ARG(I+1)
22511     CONTINUE
        ENDIF
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,22513)IT1
22513   FORMAT(I8,' LIMIT PAIRS HAVE BEEN SET FOR THE SCATTER PLOT ',   &
               'MATRIX')
        CALL DPWRST('XXX','BUG ')
        IFOUND='YES'
        GO TO 9000
      ENDIF
!
      IPART1='MATR'
      IPART2='PLOT'
      IPART3='LIMI'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2.AND.   &
         IHARG(3).EQ.IPART3)THEN
        IF(NUMARG.GE.3)THEN
          IT1=0
          DO 22519 I=1,25
            PSPLLL(I)=CPUMIN
            PSPLUL(I)=CPUMIN
22519     CONTINUE
          DO 22521 I=4,NUMARG,2
            IF(I+1.GT.NUMARG)GO TO 22521
            IF(IT1.GT.24)GO TO 22521
            IT1=IT1+1
            PSPLLL(IT1)=ARG(I)
            PSPLUL(IT1)=ARG(I+1)
22521     CONTINUE
        ENDIF
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,22523)IT1
22523   FORMAT(I8,' LIMIT PAIRS HAVE BEEN SET FOR THE MATRIX PLOT ')
        CALL DPWRST('XXX','BUG ')
        IFOUND='YES'
        GO TO 9000
      ENDIF
