        DO 36503 II=4,NUMARG
          IVAL1=IARG(II)
          IF(IVAL1.LE.0 .OR. IVAL1.GT.20)GO TO 36504
          IPSTDP(II-3,5)=IVAL1
36503   CONTINUE
36504   CONTINUE
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,36505)
36505   FORMAT('THE POSTSCRIPT DA3 PATTERN HAS BEEN SET TO:')
        CALL DPWRST('XXX','BUG ')
        DO 36507 II=1,10
          IF(IPSTDP(II,5).LE.0)GO TO 36509
          WRITE(ICOUT,36508)II,IPSTDP(II,5)
36508     FORMAT('    SETTING ',I2,' IS ',I5)
          CALL DPWRST('XXX','BUG ')
36507   CONTINUE
36509   CONTINUE
        GO TO 9000
      ENDIF
!
      IPART1='POST'
      IPART2='DA4 '
      IPART3='PATT'
      IF(IHARG(1).EQ.IPART1 .AND. IHARG(2).EQ.IPART2 .AND.   &
         IHARG(3).EQ.IPART3)THEN
        IFOUND='YES'
        DO 36601 II=1,10
          IPSTDP(II,6)=-1
36601   CONTINUE
        IF(NUMARG.EQ.3 .OR. IHARG(4).EQ.'DEFA' .OR.   &
           IHARG(4).EQ.'OFF' .OR. IHARG(4).EQ.'ON')THEN
           WRITE(ICOUT,999)
           CALL DPWRST('XXX','BUG ')
           WRITE(ICOUT,36602)
36602      FORMAT('THE POSTSCRIPT DA4 PATTERN HAS BEEN RESET TO THE ',   &
                  'DEFAULT SETTING.')
           CALL DPWRST('XXX','BUG ')
           GO TO 9000
        ENDIF
        DO 36603 II=4,NUMARG
          IVAL1=IARG(II)
          IF(IVAL1.LE.0 .OR. IVAL1.GT.20)GO TO 36604
          IPSTDP(II-3,6)=IVAL1
36603   CONTINUE
36604   CONTINUE
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,36605)
36605   FORMAT('THE POSTSCRIPT DA4 PATTERN HAS BEEN SET TO:')
        CALL DPWRST('XXX','BUG ')
        DO 36607 II=1,10
          IF(IPSTDP(II,6).LE.0)GO TO 36609
          WRITE(ICOUT,36608)II,IPSTDP(II,6)
36608     FORMAT('    SETTING ',I2,' IS ',I5)
          CALL DPWRST('XXX','BUG ')
36607   CONTINUE
36609   CONTINUE
        GO TO 9000
      ENDIF
!
      IPART1='POST'
      IPART2='DA5 '
      IPART3='PATT'
      IF(IHARG(1).EQ.IPART1 .AND. IHARG(2).EQ.IPART2 .AND.   &
         IHARG(3).EQ.IPART3)THEN
        IFOUND='YES'
        DO 36701 II=1,10
          IPSTDP(II,7)=-1
36701   CONTINUE
        IF(NUMARG.EQ.3 .OR. IHARG(4).EQ.'DEFA' .OR.   &
           IHARG(4).EQ.'OFF' .OR. IHARG(4).EQ.'ON')THEN
           WRITE(ICOUT,999)
           CALL DPWRST('XXX','BUG ')
           WRITE(ICOUT,36702)
36702      FORMAT('THE POSTSCRIPT DA5 PATTERN HAS BEEN RESET TO THE ',   &
                  'DEFAULT SETTING.')
           CALL DPWRST('XXX','BUG ')
           GO TO 9000
        ENDIF
        DO 36703 II=4,NUMARG
          IVAL1=IARG(II)
          IF(IVAL1.LE.0 .OR. IVAL1.GT.20)GO TO 36704
          IPSTDP(II-3,7)=IVAL1
36703   CONTINUE
36704   CONTINUE
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,36705)
36705   FORMAT('THE POSTSCRIPT DA5 PATTERN HAS BEEN SET TO:')
        CALL DPWRST('XXX','BUG ')
        DO 36707 II=1,10
          IF(IPSTDP(II,7).LE.0)GO TO 36709
          WRITE(ICOUT,36708)II,IPSTDP(II,7)
36708     FORMAT('    SETTING ',I2,' IS ',I5)
          CALL DPWRST('XXX','BUG ')
36707   CONTINUE
36709   CONTINUE
        GO TO 9000
      ENDIF
!
      IPART1='POST'
      IPART2='DOT '
      IPART3='PATT'
      IPART4='DOTT'
      IF(IHARG(1).EQ.IPART1 .AND.   &
         (IHARG(2).EQ.IPART2 .OR. IHARG(2).EQ.IPART4) .AND.   &
         IHARG(3).EQ.IPART3)THEN
        DO 36801 II=1,10
          IPSTDP(II,1)=-1
36801   CONTINUE
        IF(NUMARG.EQ.3 .OR. IHARG(4).EQ.'DEFA' .OR.   &
           IHARG(4).EQ.'OFF' .OR. IHARG(4).EQ.'ON')THEN
           WRITE(ICOUT,999)
           CALL DPWRST('XXX','BUG ')
           WRITE(ICOUT,36802)
36802      FORMAT('THE POSTSCRIPT DOTTED PATTERN HAS BEEN RESET TO ',   &
                  'THE DEFAULT SETTING.')
           CALL DPWRST('XXX','BUG ')
           GO TO 9000
        ENDIF
        DO 36803 II=4,NUMARG
          IVAL1=IARG(II)
          IF(IVAL1.LE.0 .OR. IVAL1.GT.20)GO TO 36804
          IPSTDP(II-3,1)=IVAL1
36803   CONTINUE
36804   CONTINUE
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,36805)
36805   FORMAT('THE POSTSCRIPT DOTTED PATTERN HAS BEEN SET TO:')
        CALL DPWRST('XXX','BUG ')
        DO 36807 II=1,10
          IF(IPSTDP(II,1).LE.0)GO TO 36809
          WRITE(ICOUT,36808)II,IPSTDP(II,1)
36808     FORMAT('    SETTING ',I2,' IS ',I5)
          CALL DPWRST('XXX','BUG ')
36807   CONTINUE
36809   CONTINUE
        GO TO 9000
      ENDIF
!
!     ***********************************
!     **  CHECK FOR MARGINS            **
!     ***********************************
!
      IPART1='POST'
      IPART2='LAND'
      IPART3='LEFT'
      IPART4='MARG'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2   &
      .AND.IHARG(3).EQ.IPART3.AND.IHARG(4).EQ.IPART4)IPSTLM=IV
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2   &
      .AND.IHARG(3).EQ.IPART3.AND.IHARG(4).EQ.IPART4)GO TO 5150
!
      IPART1='POST'
      IPART2='LAND'
      IPART3='RIGH'
      IPART4='MARG'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2   &
      .AND.IHARG(3).EQ.IPART3.AND.IHARG(4).EQ.IPART4)IPSTRM=IV
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2   &
      .AND.IHARG(3).EQ.IPART3.AND.IHARG(4).EQ.IPART4)GO TO 5150
!
      IPART1='POST'
      IPART2='LAND'
      IPART3='TOP '
      IPART4='MARG'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2   &
      .AND.IHARG(3).EQ.IPART3.AND.IHARG(4).EQ.IPART4)IPSTTM=IV
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2   &
      .AND.IHARG(3).EQ.IPART3.AND.IHARG(4).EQ.IPART4)GO TO 5150
!
      IPART1='POST'
      IPART2='LAND'
      IPART3='BOTT'
      IPART4='MARG'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2   &
      .AND.IHARG(3).EQ.IPART3.AND.IHARG(4).EQ.IPART4)IPSTBM=IV
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2   &
      .AND.IHARG(3).EQ.IPART3.AND.IHARG(4).EQ.IPART4)GO TO 5150
!
      IPART1='POST'
      IPART2='PORT'
      IPART3='LEFT'
      IPART4='MARG'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2   &
      .AND.IHARG(3).EQ.IPART3.AND.IHARG(4).EQ.IPART4)IPS2LM=IV
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2   &
      .AND.IHARG(3).EQ.IPART3.AND.IHARG(4).EQ.IPART4)GO TO 5150
!
      IPART1='POST'
      IPART2='PORT'
      IPART3='RIGH'
      IPART4='MARG'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2   &
      .AND.IHARG(3).EQ.IPART3.AND.IHARG(4).EQ.IPART4)IPS2RM=IV
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2   &
      .AND.IHARG(3).EQ.IPART3.AND.IHARG(4).EQ.IPART4)GO TO 5150
!
      IPART1='POST'
      IPART2='PORT'
      IPART3='TOP '
      IPART4='MARG'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2   &
      .AND.IHARG(3).EQ.IPART3.AND.IHARG(4).EQ.IPART4)IPS2TM=IV
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2   &
      .AND.IHARG(3).EQ.IPART3.AND.IHARG(4).EQ.IPART4)GO TO 5150
!
      IPART1='POST'
      IPART2='PORT'
      IPART3='BOTT'
      IPART4='MARG'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2   &
      .AND.IHARG(3).EQ.IPART3.AND.IHARG(4).EQ.IPART4)IPS2BM=IV
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2   &
      .AND.IHARG(3).EQ.IPART3.AND.IHARG(4).EQ.IPART4)GO TO 5150
!
!     *********************************
!     **  SET POINTS PER INCH (PPI)  **
!     *********************************
!
      IPART1='POST'
      IPART2='PPI '
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2)PSTPPI=AV
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2)GO TO 5170
!
!     *******************************************
!     **  CHECK FOR POSTSCRIPT SPACE <ON/OFF>  **
!     **  ADDED OCTOBER 1991.                  **
!     *******************************************
!
      IPART1='POST'
      IPART2='SPAC'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2)IPSTSP=IHV
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2)GO TO 5160
!
!     ***************************************************
!     **  CHECK FOR POSTSCRIPT HARDWARE FILL <ON/OFF>  **
!     **  ADDED JUNE 1994.                             **
!     ***************************************************
!
      IPART1='POST'
      IPART2='HARD'
      IPART3='FILL'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2.AND.   &
         IHARG(3).EQ.IPART3)IPSTFS=IHV
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2.AND.   &
         IHARG(3).EQ.IPART3)GO TO 5160
!
!     ************************************************************
!     **  ADDED MARCH 2005                                      **
!     **  SET AQUATERM FONT <NAME>                              **
!     **  SET AQUATERM CAP <CAP STYLE>                          **
!     **  SET AQUATERM JOIN <JOIN STYLE>                        **
!     **  SET AQUATERM HARDWARE FILL <ON/OFF>                   **
!     ************************************************************
!
!     ******************************************************
!     **  CHECK FOR FONT                                  **
!     **  NOTE THAT FONT NAME CAN BE UP TO 80 CHARACTERS  **
!     **  LONG, SO THIS HANDLED SOMEWHAT DIFFERENTLY THAN **
!     **  THE OTHER COMMANDS.                             **
!     ******************************************************
!
      IF(NUMARG.GE.2.AND.IHARG(1).EQ.'AQUA'.AND.   &
      IHARG(2).EQ.'FONT')GO TO 22210
      GO TO 22290
!
22210 CONTINUE
      IAQUFN(1:40)='                                        '
      IAQUFN(41:80)='                                        '
      NCTEMP=0
      IF(NUMARG.LE.2)GO TO 22250
      IF(IHARG(NUMARG).EQ.'OFF')GO TO 22250
      IF(IHARG(NUMARG).EQ.'AUTO')GO TO 22250
      IF(IHARG(NUMARG).EQ.'DEFA')GO TO 22250
!
!  CHECK THE POSITION OF THE WORD FONT
!  EXTRACT IANSLC FROM THE FIRST CHARACTER PAST "FONT" TO
!  THE LAST NON-BLANK CHARACTER
!
      DO 22230 I=1,IWIDTH
      IP1=I+1
      IP2=I+2
      IP3=I+3
      IP4=I+4
      IF(IP3.GT.IWIDTH)GO TO 22250
      IF(IANS(I).EQ.'F'.AND.IANS(IP1).EQ.'O'.AND.   &
      IANS(IP2).EQ.'N'.AND.IANS(IP3).EQ.'T'.AND.   &
      IANS(IP4).EQ.' ')GO TO 22235
22230 CONTINUE
      GO TO 22250
!
22235 CONTINUE
      ISTART=IP4+1
!
      ISTOP=IWIDTH
      DO 22240 I=IWIDTH,ISTART,-1
      ISTOP=I
      IF(IANS(I).NE.' ')GO TO 22245
22240 CONTINUE
      GO TO 22250
22245 CONTINUE
      IF(ISTART.GT.ISTOP)GO TO 22250
      NCTEMP=ISTOP-ISTART+1
      IF(NCTEMP.GT.80)ISTOP=ISTART+79
      IF(NCTEMP.GT.80)NCTEMP=80
      ICOUNT=0
      DO 22248 I=ISTART,ISTOP
      ICOUNT=ICOUNT+1
      IAQUFN(ICOUNT:ICOUNT)=IANSLC(I)(1:1)
22248 CONTINUE
      IFOUND='YES'
      IF(IFEEDB.EQ.'OFF')GO TO 9000
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,22251)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,22252)IAQUFN
      CALL DPWRST('XXX','BUG ')
      GO TO 9000
!
22250 CONTINUE
      IAQUFN='Helvetica'
      IFOUND='YES'
      IF(IFEEDB.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,22251)
22251   FORMAT('THE AQUATERM FONT HAS BEEN SET TO ')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,22252)IAQUFN
22252   FORMAT(A80)
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
22290 CONTINUE
!
!     ***********************************
!     **  CHECK FOR AQUATERM CAP       **
!     ***********************************
!
      IPART1='AQUA'
      IPART2='CAP '
      IPART3='STYL'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2.AND.   &
         IHARG(3).EQ.IPART3)THEN
        IF(IHARG(4).EQ.'ROUN')THEN
          IHV='ROUN'
        ELSEIF(IHARG(4).EQ.'SQUA')THEN
          IHV='SQUA'
        ELSE
          IHV='BUTT'
        ENDIF
        IAQUCS(1:4)=IHV
        IAQUCS(5:8)=' '
        IFOUND='YES'
        IF(IFEEDB.EQ.'OFF')GO TO 9000
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,22310)IAQUCS
22310   FORMAT('THE AQUATERM CAP STYLE HAS BEEN SET TO ',A8)
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
!     ***********************************
!     **  CHECK FOR AQUATERM JOIN      **
!     ***********************************
!
      IPART1='AQUA'
      IPART2='JOIN'
      IPART3='STYL'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2.AND.   &
         IHARG(3).EQ.IPART3)THEN
        IF(IHARG(4).EQ.'ROUN')THEN
          IHV='ROUN'
        ELSEIF(IHARG(4).EQ.'SQUA')THEN
          IHV='SQUA'
        ELSE
          IHV='BUTT'
        ENDIF
        IAQUJS(1:4)=IHARG(NUMARG)
        IAQUJS(5:8)=IHARG2(NUMARG)
        IFOUND='YES'
        IF(IFEEDB.EQ.'OFF')GO TO 9000
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,22410)IAQUJS
22410   FORMAT('THE AQUATERM JOIN STYLE HAS BEEN SET TO ',A8)
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
!     ****************************************
!     **  CHECK FOR AQUATERM HARDWARE FILL  **
!     ****************************************
!
      IPART1='AQUA'
      IPART2='HARD'
      IPART3='FILL'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2.AND.   &
         IHARG(3).EQ.IPART3)THEN
         IF(IHV.EQ.'ON')IHV='ON'
         IF(IHV.EQ.'DEFA')IHV='ON'
         IF(IHV.EQ.'YES')IHV='ON'
         IF(IHV.EQ.'TRUE')IHV='ON'
         IF(IHV.EQ.'OFF')IHV='OFF'
         IF(IHV.EQ.'NO')IHV='OFF'
         IF(IHV.EQ.'FALS')IHV='OFF'
         IAQUFS=IHV
         GO TO 5160
      ENDIF
!
!     ****************************************
!     **  CHECK FOR LATEX    HARDWARE FILL  **
!     ****************************************
!
      IPART1='LATE'
      IPART2='HARD'
      IPART3='FILL'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2.AND.   &
         IHARG(3).EQ.IPART3)THEN
         IF(IHV.EQ.'ON')IHV='ON'
         IF(IHV.EQ.'DEFA')IHV='ON'
         IF(IHV.EQ.'YES')IHV='ON'
         IF(IHV.EQ.'TRUE')IHV='ON'
         IF(IHV.EQ.'HARD')IHV='ON'
         IF(IHV.EQ.'OFF')IHV='OFF'
         IF(IHV.EQ.'NO')IHV='OFF'
         IF(IHV.EQ.'FALS')IHV='OFF'
         IF(IHV.EQ.'SOFT')IHV='OFF'
         ILATFS=IHV
         GO TO 5160
      ENDIF
!
!     ****************************************
!     **  CHECK FOR LATEX    LINE THICKNESS **
!     ****************************************
!
      IPART1='LATE'
      IPART2='LINE'
      IPART3='THIC'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2.AND.   &
         IHARG(3).EQ.IPART3)THEN
         IF(IHV.EQ.'HARD')IHV='ON'
         IF(IHV.EQ.'DEFA')IHV='HARD'
         IF(IHV.EQ.'YES')IHV='HARD'
         IF(IHV.EQ.'TRUE')IHV='HARD'
         IF(IHV.EQ.'HARD')IHV='HARD'
         IF(IHV.EQ.'SOFT')IHV='SOFT'
         IF(IHV.EQ.'NO')IHV='SOFT'
         IF(IHV.EQ.'FALS')IHV='SOFT'
         IF(IHV.EQ.'SOFT')IHV='SOFT'
         ILATLT=IHV
         GO TO 5160
      ENDIF
!
!     ****************************************
!     **  CHECK FOR LATEX    COLOR          **
!     ****************************************
!
      IPART1='LATE'
      IPART2='COLO'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2)THEN
         IF(IHV.EQ.'ON')IHV='ON'
         IF(IHV.EQ.'DEFA')IHV='ON'
         IF(IHV.EQ.'YES')IHV='ON'
         IF(IHV.EQ.'TRUE')IHV='ON'
         IF(IHV.EQ.'OFF')IHV='OFF'
         IF(IHV.EQ.'NO')IHV='OFF'
         IF(IHV.EQ.'FALS')IHV='OFF'
         ILATCO=IHV
         GO TO 5160
      ENDIF
!
!     ****************************************
!     **  CHECK FOR GD       COLOR          **
!     ****************************************
!
      IPART1='GD  '
      IPART2='COLO'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2)THEN
         IF(IHARG(3).EQ.'COLO')IHV='TRUE'
         IF(IHARG(3).EQ.'TRUE')IHV='TRUE'
         IF(IHARG(3).EQ.'RGB ')IHV='TRUE'
         IF(IHARG(3).EQ.'ON')IHV='TRUE'
         IF(IHARG(3).EQ.'DEFA')IHV='TRUE'
         IF(IHARG(3).EQ.'YES')IHV='TRUE'
         IF(IHARG(3).EQ.'TRUE')IHV='TRUE'
         IF(IHARG(3).EQ.'FIXE')IHV='FIXE'
         IF(IHARG(3).EQ.'OFF')IHV='FIXE'
         IF(IHARG(3).EQ.'NO')IHV='FIXE'
         IF(IHARG(3).EQ.'FALS')IHV='FIXE'
         IF(IHV.NE.'TRUE' .AND. IHV.NE.'FIXE')IHV='FIXE'
         IGDCO=IHV
         GO TO 5160
      ENDIF
!
!     ****************************************
!     **  CHECK FOR GD       HARDWARE FILL  **
!     ****************************************
!
      IPART1='GD  '
      IPART2='HARD'
      IPART3='FILL'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2.AND.   &
         IHARG(3).EQ.IPART3)THEN
         IF(IHV.EQ.'ON' .OR. IHV.EQ.'TRUE' .OR. IHV.EQ.'YES'.OR.   &
            IHV.EQ.'HARD')THEN
           IHV='ON'
         ELSE
           IHV='OFF'
         ENDIF
         IGDFS=IHV
         GO TO 5160
      ENDIF
!
!     ******************************************************
!     **  CHECK FOR GD FONT                               **
!     **  NOTE THAT FONT NAME CAN BE UP TO 80 CHARACTERS  **
!     **  LONG, SO THIS HANDLED SOMEWHAT DIFFERENTLY THAN **
!     **  THE OTHER COMMANDS.                             **
!     ******************************************************
!
      IF(NUMARG.GE.2.AND.IHARG(1).EQ.'GD  '.AND.   &
      IHARG(2).EQ.'FONT')GO TO 22510
      GO TO 22590
!
22510 CONTINUE
      IGDFN(1:40)='                                        '
      IGDFN(41:80)='                                        '
      NCTEMP=0
      IF(NUMARG.LE.2)GO TO 22550
      IF(IHARG(NUMARG).EQ.'OFF')GO TO 22550
      IF(IHARG(NUMARG).EQ.'AUTO')GO TO 22550
      IF(IHARG(NUMARG).EQ.'DEFA')GO TO 22550
!
!  CHECK THE POSITION OF THE WORD FONT
!  EXTRACT IANSLC FROM THE FIRST CHARACTER PAST "FONT" TO
!  THE LAST NON-BLANK CHARACTER
!
      DO 22530 I=1,IWIDTH
      IP1=I+1
      IP2=I+2
      IP3=I+3
      IP4=I+4
      IF(IP3.GT.IWIDTH)GO TO 22550
      IF(IANS(I).EQ.'F'.AND.IANS(IP1).EQ.'O'.AND.   &
      IANS(IP2).EQ.'N'.AND.IANS(IP3).EQ.'T'.AND.   &
      IANS(IP4).EQ.' ')GO TO 22535
22530 CONTINUE
      GO TO 22550
!
22535 CONTINUE
      ISTART=IP4+1
!
      ISTOP=IWIDTH
      DO 22540 I=IWIDTH,ISTART,-1
      ISTOP=I
      IF(IANS(I).NE.' ')GO TO 22545
22540 CONTINUE
      GO TO 22550
22545 CONTINUE
      IF(ISTART.GT.ISTOP)GO TO 22550
      NCTEMP=ISTOP-ISTART+1
      IF(NCTEMP.GT.80)ISTOP=ISTART+79
      IF(NCTEMP.GT.80)NCTEMP=80
      ICOUNT=0
      DO 22548 I=ISTART,ISTOP
      ICOUNT=ICOUNT+1
      IGDFN(ICOUNT:ICOUNT)=IANSLC(I)(1:1)
22548 CONTINUE
!
!     CONVERT BUILT-IN FONTS TO UPPER-CASE
!
      IF(   &
        (IGDFN(1:1).EQ.'S' .OR. IGDFN(1:1).EQ.'s') .AND.   &
        (IGDFN(2:2).EQ.'M' .OR. IGDFN(2:2).EQ.'m') .AND.   &
        (IGDFN(3:3).EQ.'A' .OR. IGDFN(3:3).EQ.'a') .AND.   &
        (IGDFN(4:4).EQ.'L' .OR. IGDFN(4:4).EQ.'l') .AND.   &
        (IGDFN(5:5).EQ.'L' .OR. IGDFN(5:5).EQ.'l')   &
        ) IGDFN='SMALL'
!
      IF(   &
        (IGDFN(1:1).EQ.'L' .OR. IGDFN(1:1).EQ.'l') .AND.   &
        (IGDFN(2:2).EQ.'A' .OR. IGDFN(2:2).EQ.'a') .AND.   &
        (IGDFN(3:3).EQ.'R' .OR. IGDFN(3:3).EQ.'r') .AND.   &
        (IGDFN(4:4).EQ.'G' .OR. IGDFN(4:4).EQ.'g') .AND.   &
        (IGDFN(5:5).EQ.'E' .OR. IGDFN(5:5).EQ.'e')   &
        ) IGDFN='LARGE'
!
      IF(   &
        (IGDFN(1:1).EQ.'G' .OR. IGDFN(1:1).EQ.'g') .AND.   &
        (IGDFN(2:2).EQ.'I' .OR. IGDFN(2:2).EQ.'i') .AND.   &
        (IGDFN(3:3).EQ.'A' .OR. IGDFN(3:3).EQ.'a') .AND.   &
        (IGDFN(4:4).EQ.'N' .OR. IGDFN(4:4).EQ.'n') .AND.   &
        (IGDFN(5:5).EQ.'T' .OR. IGDFN(5:5).EQ.'t')   &
        ) IGDFN='GIANT'
!
      IF(   &
        (IGDFN(1:1).EQ.'T' .OR. IGDFN(1:1).EQ.'t') .AND.   &
        (IGDFN(2:2).EQ.'I' .OR. IGDFN(2:2).EQ.'i') .AND.   &
        (IGDFN(3:3).EQ.'N' .OR. IGDFN(3:3).EQ.'n') .AND.   &
        (IGDFN(4:4).EQ.'Y' .OR. IGDFN(4:4).EQ.'y')   &
        ) IGDFN='TINY'
!
      IF(   &
        (IGDFN(1:1).EQ.'M' .OR. IGDFN(1:1).EQ.'m') .AND.   &
        (IGDFN(2:2).EQ.'E' .OR. IGDFN(2:2).EQ.'e') .AND.   &
        (IGDFN(3:3).EQ.'D' .OR. IGDFN(3:3).EQ.'d') .AND.   &
        (IGDFN(4:4).EQ.'I' .OR. IGDFN(4:4).EQ.'i') .AND.   &
        (IGDFN(5:5).EQ.'U' .OR. IGDFN(5:5).EQ.'u') .AND.   &
        (IGDFN(6:6).EQ.'M' .OR. IGDFN(6:6).EQ.'m')   &
        ) IGDFN='MEDIUMBOLD'
!
      IFOUND='YES'
      IF(IFEEDB.EQ.'OFF')GO TO 9000
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,22551)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,22552)IGDFN
      CALL DPWRST('XXX','BUG ')
      GO TO 9000
!
22550 CONTINUE
      IGDFN='Null'
      IFOUND='YES'
      IF(IFEEDB.EQ.'OFF')GO TO 22559
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,22551)
22551 FORMAT('THE GD FONT HAS BEEN SET TO ')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,22552)IGDFN
22552 FORMAT(A80)
      CALL DPWRST('XXX','BUG ')
22559 CONTINUE
      GO TO 9000
22590 CONTINUE
!
!     ************************************************************
!     **  ADDED APRIL 2009                                      **
!     **  SET LIBPLOT FONT <NAME>                               **
!     **  SET LIBPLOT CAP <CAP STYLE>                           **
!     **  SET LIBPLOT JOIN <JOIN STYLE>                         **
!     **  SET LIBPLOT HARDWARE FILL <ON/OFF>                    **
!     **  SET LIBPLOT PAUSE <ON/OFF>                            **
!     ************************************************************
!
!     ******************************************************
!     **  CHECK FOR FONT                                  **
!     **  NOTE THAT FONT NAME CAN BE UP TO 80 CHARACTERS  **
!     **  LONG, SO THIS HANDLED SOMEWHAT DIFFERENTLY THAN **
!     **  THE OTHER COMMANDS.                             **
!     ******************************************************
!
      IF(NUMARG.GE.2.AND.IHARG(1).EQ.'LIBP'.AND.   &
      IHARG(2).EQ.'FONT')GO TO 26210
      GO TO 26290
!
26210 CONTINUE
      ILPLFN(1:40)='                                        '
      ILPLFN(41:80)='                                        '
      NCTEMP=0
      IF(NUMARG.LE.2)GO TO 26250
      IF(IHARG(NUMARG).EQ.'OFF')GO TO 26250
      IF(IHARG(NUMARG).EQ.'AUTO')GO TO 26250
      IF(IHARG(NUMARG).EQ.'DEFA')GO TO 26250
!
!  CHECK THE POSITION OF THE WORD FONT
!  EXTRACT IANSLC FROM THE FIRST CHARACTER PAST "FONT" TO
!  THE LAST NON-BLANK CHARACTER
!
      DO 26230 I=1,IWIDTH
      IP1=I+1
      IP2=I+2
      IP3=I+3
      IP4=I+4
      IF(IP3.GT.IWIDTH)GO TO 26250
      IF(IANS(I).EQ.'F'.AND.IANS(IP1).EQ.'O'.AND.   &
      IANS(IP2).EQ.'N'.AND.IANS(IP3).EQ.'T'.AND.   &
      IANS(IP4).EQ.' ')GO TO 26235
26230 CONTINUE
      GO TO 26250
!
26235 CONTINUE
      ISTART=IP4+1
!
      ISTOP=IWIDTH
      DO 26240 I=IWIDTH,ISTART,-1
      ISTOP=I
      IF(IANS(I).NE.' ')GO TO 26245
26240 CONTINUE
      GO TO 26250
26245 CONTINUE
      IF(ISTART.GT.ISTOP)GO TO 26250
      NCTEMP=ISTOP-ISTART+1
      IF(NCTEMP.GT.80)ISTOP=ISTART+79
      IF(NCTEMP.GT.80)NCTEMP=80
      ICOUNT=0
      DO 26248 I=ISTART,ISTOP
      ICOUNT=ICOUNT+1
      ILPLFN(ICOUNT:ICOUNT)=IANSLC(I)(1:1)
26248 CONTINUE
      IFOUND='YES'
      IF(IFEEDB.EQ.'OFF')GO TO 9000
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,26251)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,26252)ILPLFN
      CALL DPWRST('XXX','BUG ')
      GO TO 9000
!
26250 CONTINUE
      ILPLFN='Helvetica'
      IFOUND='YES'
      IF(IFEEDB.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,26251)
26251   FORMAT('THE LIBPLOT FONT HAS BEEN SET TO ')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,26252)ILPLFN
26252   FORMAT(A80)
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
      ENDIF
!
26290 CONTINUE
!
!     ***********************************
!     **  CHECK FOR LIBPLOT CAP        **
!     ***********************************
!
      IPART1='LIBP'
      IPART2='CAP '
      IPART3='STYL'
!
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2.AND.   &
         IHARG(3).EQ.IPART3)THEN
        IF(IHARG(4).EQ.'ROUN')THEN
          IHV='ROUN'
        ELSEIF(IHARG(4).EQ.'PROJ')THEN
          IHV='PROJ'
        ELSE
          IHV='BUTT'
        ENDIF
        ILPLCS=IHV
        GO TO 5160
      ELSEIF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2)THEN
        IF(IHARG(3).EQ.'ROUN')THEN
          IHV='ROUN'
        ELSEIF(IHARG(3).EQ.'PROJ')THEN
          IHV='PROJ'
        ELSE
          IHV='BUTT'
        ENDIF
        ILPLCS=IHV
        GO TO 5160
      ENDIF
!
!     ***********************************
!     **  CHECK FOR LIBPLOT JOIN       **
!     ***********************************
!
      IPART1='LIBP'
      IPART2='JOIN'
      IPART3='STYL'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2.AND.   &
         IHARG(3).EQ.IPART3)THEN
        IF(IHARG(4).EQ.'ROUN')THEN
          IHV='ROUN'
        ELSEIF(IHARG(4).EQ.'BEVE')THEN
          IHV='BEVE'
        ELSE
          IHV='MITE'
        ENDIF
        ILPLJS=IHV
        GO TO 5160
      ELSEIF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2)THEN
        IF(IHARG(3).EQ.'ROUN')THEN
          IHV='ROUN'
        ELSEIF(IHARG(3).EQ.'BEVE')THEN
          IHV='BEVE'
        ELSE
          IHV='MITE'
        ENDIF
        ILPLJS=IHV
        GO TO 5160
      ENDIF
!
!     ****************************************
!     **  CHECK FOR LIBPLOT HARDWARE FILL   **
!     ****************************************
!
      IPART1='LIBP'
      IPART2='HARD'
      IPART3='FILL'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2.AND.   &
         IHARG(3).EQ.IPART3)THEN
         IHV='ON'
         IF(IHARG(NUMARG).EQ.'ON')IHV='ON'
         IF(IHARG(NUMARG).EQ.'DEFA')IHV='ON'
         IF(IHARG(NUMARG).EQ.'YES')IHV='ON'
         IF(IHARG(NUMARG).EQ.'TRUE')IHV='ON'
         IF(IHARG(NUMARG).EQ.'OFF')IHV='OFF'
         IF(IHARG(NUMARG).EQ.'NO')IHV='OFF'
         IF(IHARG(NUMARG).EQ.'FALS')IHV='OFF'
         ILPLFS=IHV
         GO TO 5160
      ENDIF
!
!     ****************************************
!     **  CHECK FOR LIBPLOT PAUSE           **
!     **  (CURRENTLY NOT ACTIVE, BUT MAY    **
!     **  ADD AT LATER DATE)                **
!     ****************************************
!
      IPART1='LIBP'
      IPART2='PAUS'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2)THEN
         IHV='OFF'
         IF(IHARG(NUMARG).EQ.'ON')IHV='ON'
         IF(IHARG(NUMARG).EQ.'DEFA')IHV='ON'
         IF(IHARG(NUMARG).EQ.'YES')IHV='ON'
         IF(IHARG(NUMARG).EQ.'TRUE')IHV='ON'
         IF(IHARG(NUMARG).EQ.'OFF')IHV='OFF'
         IF(IHARG(NUMARG).EQ.'NO')IHV='OFF'
         IF(IHARG(NUMARG).EQ.'FALS')IHV='OFF'
         ILPLPA=IHV
         GO TO 5160
      ENDIF
!
!     ****************************************
!     **  CHECK FOR LIBPLOT X SIZE          **
!     ****************************************
!
      IPART1='LIBP'
      IPART2='X'
      IPART3='SIZE'
      IPART4='XSIZ'
      IF((IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART4) .OR.   &
         (IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2  .OR.   &
          IHARG(3).EQ.IPART3))THEN
         IV=570
         IF(IARGT(NUMARG).EQ.'NUMB')IV=IARG(NUMARG)
         IF(IHARG(NUMARG).EQ.'ON')IV=570
         IF(IHARG(NUMARG).EQ.'DEFA')IV=570
         IF(IHARG(NUMARG).EQ.'YES')IV=570
         IF(IHARG(NUMARG).EQ.'OFF')IV=570
         IF(IHARG(NUMARG).EQ.'NO')IV=570
         IF(IV.LE.100)IV=100
         IF(IV.GE.10000)IV=10000
         ILPLXS=IV
         GO TO 5150
      ENDIF
!
!     ****************************************
!     **  CHECK FOR LIBPLOT Y SIZE          **
!     ****************************************
!
      IPART1='LIBP'
      IPART2='Y'
      IPART3='SIZE'
      IPART4='YSIZ'
      IF((IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART4) .OR.   &
         (IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2.OR.   &
          IHARG(3).EQ.IPART3))THEN
         IV=570
         IF(IARGT(NUMARG).EQ.'NUMB')IV=IARG(NUMARG)
         IF(IHARG(NUMARG).EQ.'ON')IV=570
         IF(IHARG(NUMARG).EQ.'DEFA')IV=570
         IF(IHARG(NUMARG).EQ.'YES')IV=570
         IF(IHARG(NUMARG).EQ.'OFF')IV=570
         IF(IHARG(NUMARG).EQ.'NO')IV=570
         IF(IV.LE.100)IV=100
         IF(IV.GE.10000)IV=10000
         ILPLYS=IV
         GO TO 5150
      ENDIF
!
!     ****************************************
!     **  CHECK FOR LIBPLOT ROTATE          **
!     ****************************************
!
      IPART1='LIBP'
      IPART2='ROTA'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART4)THEN
         AV=0.0
         IF(IHARG(NUMARG).EQ.'ON')AV=0.0
         IF(IHARG(NUMARG).EQ.'DEFA')AV=0.0
         IF(IHARG(NUMARG).EQ.'YES')AV=0.0
         IF(IHARG(NUMARG).EQ.'OFF')AV=0.0
         IF(IHARG(NUMARG).EQ.'NO')AV=0.0
         IF(AV.NE.0.0 .AND. AV.NE.90.0)AV=0.0
         PLPLRO=AV
         GO TO 5170
      ENDIF
!
!     ****************************************
!     **  CHECK FOR LATEX    HARDWARE FILL  **
!     ****************************************
!
      IPART1='LATE'
      IPART2='HARD'
      IPART3='FILL'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2.AND.   &
         IHARG(3).EQ.IPART3)THEN
         IF(IHV.EQ.'ON')IHV='ON'
         IF(IHV.EQ.'DEFA')IHV='ON'
         IF(IHV.EQ.'YES')IHV='ON'
         IF(IHV.EQ.'TRUE')IHV='ON'
         IF(IHV.EQ.'HARD')IHV='ON'
         IF(IHV.EQ.'OFF')IHV='OFF'
         IF(IHV.EQ.'NO')IHV='OFF'
         IF(IHV.EQ.'FALS')IHV='OFF'
         IF(IHV.EQ.'SOFT')IHV='OFF'
         ILATFS=IHV
         GO TO 5160
      ENDIF
!
!     ************************************************************
!     **  ADDED SEPTEMBER 1988                                  **
!     **  SET CALCOMP COLORS <NUMBER>                           **
!     **  SET CALCOMP WIDTH <NUMBER>                            **
!     ************************************************************
!
!     ***********************************
!     **  CHECK FOR COLORS             **
!     ***********************************
!
      IPART1='CALC'
      IPART2='COLO'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2)ICALCL=IV
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2)GO TO 5150
!
!     ***********************************
!     **  CHECK FOR PEN WIDTH          **
!     ***********************************
!
      IPART1='CALC'
      IPART2='WIDT'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2)PCALTH=AV
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2)GO TO 5170
!
!     ************************************************************
!     **  ADDED SEPTEMBER 1988                                  **
!     **  SET ZETA    COLORS <NUMBER>                           **
!     **  SET ZETA    WIDTH <NUMBER>                            **
!     ************************************************************
!
!     ***********************************
!     **  CHECK FOR COLORS             **
!     ***********************************
!
      IPART1='ZETA'
      IPART2='COLO'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2)IZETCL=IV
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2)GO TO 5150
!
!     ***********************************
!     **  CHECK FOR PEN WIDTH          **
!     ***********************************
!
      IPART1='ZETA'
      IPART2='WIDT'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2)PZETTH=AV
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2)GO TO 5170
!
!     ************************************************************
!     **  ADDED JULY 1996                                       **
!     **  SET LAHEY   SWITCH   <ON/OFF>                         **
!     **  SET LAHEY   GRAPHICS <DIRECT/BIOS>                    **
!     **  SET LAHEY   CLOSE    <ON/OFF>                         **
!     **  SET LAHEY   PAUSE    <ON/OFF>                         **
!     **  SET LAHEY   WIDTH   <NUMBER>                          **
!     ************************************************************
!
!     ***********************************
!     **  CHECK FOR SWITCH             **
!     ***********************************
!
      IPART1='LAHE'
      IPART2='SWIT'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2)ILAHSW=IHV
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2)GO TO 5160
!
!     ***********************************
!     **  CHECK FOR GRAPHICS           **
!     ***********************************
!
      IPART1='LAHE'
      IPART2='GRAP'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2)ILAHCL=IHV
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2)GO TO 5160
!
!     ***********************************
!     **  CHECK FOR CLOSE              **
!     ***********************************
!
      IPART1='LAHE'
      IPART2='CLOS'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2)ILAHCL=IHV
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2)GO TO 5160
!
!     ***********************************
!     **  CHECK FOR PAUSE              **
!     ***********************************
!
      IPART1='LAHE'
      IPART2='PAUS'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2)ILAHPA=IHV
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2)GO TO 5160
!
!     ***********************************
!     **  CHECK FOR PEN WIDTH          **
!     ***********************************
!
      IPART1='LAHE'
      IPART2='WIDT'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2)PLAHTH=AV
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2)GO TO 5170
!
!     ************************************************************
!     **  ADDED FEBRUARY 2001                                   **
!     **  SET LAHEY   WINTERACTOR FONT  <FIXED/STANDARD/DUPLEXR **
!     **                                 TRIPLEXR/SWIS>         **
!     **  SET LAHEY   WINTERACTOR COLOR <RGB/VGA>               **
!     **  SET LAHEY   WINTERACTOR HORIZONTAL  <VALUE>          **
!     **  SET LAHEY   WINTERACTOR VERTICAL L  <VALUE>          **
!     ************************************************************
!
      IPART1='LAHE'
      IPART2='WINT'
      IPART3='FONT'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2.AND.   &
        IHARG(3).EQ.IPART3)IWINFN=IHV
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2.AND.   &
        IHARG(3).EQ.IPART3)GO TO 5160
!
      IPART1='LAHE'
      IPART2='WINT'
      IPART3='COLO'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2.AND.   &
        IHARG(3).EQ.IPART3)IWINCL=IHV
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2.AND.   &
        IHARG(3).EQ.IPART3)GO TO 5160
!
      IPART1='LAHE'
      IPART2='WINT'
      IPART3='HORI'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2.AND.   &
        IHARG(3).EQ.IPART3)IWINHP=IV
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2.AND.   &
        IHARG(3).EQ.IPART3)GO TO 5150
!
      IPART1='LAHE'
      IPART2='WINT'
      IPART3='VERT'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2.AND.   &
        IHARG(3).EQ.IPART3)IWINVP=IV
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2.AND.   &
        IHARG(3).EQ.IPART3)GO TO 5150
!
!     ************************************************************
!     **  ADDED NOVEMBER 1996                                   **
!     **  SET QUICK-WIN   FOCUS    <TEXT/GRAPHICS>              **
!     **  SET QUICK-WIN   COLOR    <VGA/SVGA/DIRE>              **
!     **  SET QUICK-WIN   FONT     <NAME>                       **
!     ************************************************************
!
!     ***********************************
!     **  CHECK FOR FOCUS              **
!     ***********************************
!
      IPART1='QWIN'
      IPART2='FOCU'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2)IQWNFC=IHV
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2)GO TO 5160
!
!     ***********************************
!     **  CHECK FOR COLOR              **
!     ***********************************
!
      IPART1='QWIN'
      IPART2='COLO'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2)THEN
        IQWNCL=IHV
        IF(IQWNCL.EQ.'OFF')IQWNCL='VGA'
        IF(IQWNCL.EQ.'ON')IQWNCL='RGB'
        IF(IQWNCL.EQ.'SVGA')IQWNCL='RGB'
        IF(IQWNCL.EQ.'DIRE')IQWNCL='RGB'
        IF(IQWNCL.NE.'RGB'.AND.IQWNCL.NE.'VGA')IQWNCL='VGA'
        IF(IQWNCL.EQ.'RGB')THEN
          IQWNBC=1
          IQWNF2=0
        ENDIF
        GO TO 5160
      ENDIF
!
!     **************************************
!     **  CHECK FOR TEXT BACKGROUND COLOR **
!     **************************************
!
      IPART1='QWIN'
      IPART2='TEXT'
      IPART3='FORE'
      IPART4='COLO'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2.AND.   &
         IHARG(3).EQ.IPART3.AND.IHARG(4).EQ.IPART4)THEN
         IQWNF2=IV
         IF(IQWNCL.EQ.'VGA')THEN
           IF(IQWNF2.LT.0)IQWNF2=0
           IF(IQWNF2.GT.15)IQWNF2=15
         ELSEIF(IQWNCL.EQ.'RGB')THEN
           IF(IQWNF2.LT.0)IQWNF2=0
           IF(IQWNF2.GT.88)IQWNF2=0
         ENDIF
         GO TO 5150
      ENDIF
!
!     **************************************
!     **  CHECK FOR TEXT BACKGROUND COLOR **
!     **************************************
!
      IPART1='QWIN'
      IPART2='TEXT'
      IPART3='BACK'
      IPART4='COLO'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2.AND.   &
         IHARG(3).EQ.IPART3.AND.IHARG(4).EQ.IPART4)THEN
         IQWNBC=IV
         IF(IQWNCL.EQ.'VGA')THEN
           IF(IQWNBC.LT.0)IQWNBC=0
           IF(IQWNBC.GT.15)IQWNBC=15
         ELSEIF(IQWNCL.EQ.'RGB')THEN
           IF(IQWNBC.LT.0)IQWNBC=1
           IF(IQWNBC.GT.88)IQWNBC=1
         ENDIF
         GO TO 5150
      ENDIF
!
!     ***********************************
!     **  CHECK FOR FONT NAME          **
!     ***********************************
!
      IF(NUMARG.GE.2.AND.IHARG(1).EQ.'QWIN '.AND.   &
      IHARG(2).EQ.'FONT')GO TO 2610
      GO TO 2690
!
 2610 CONTINUE
      IQWNFZ=' '
      NCTEMP=0
      IF(NUMARG.LE.2)GO TO 2650
      IF(IHARG(NUMARG).EQ.'OFF')GO TO 2650
      IF(IHARG(NUMARG).EQ.'AUTO')GO TO 2650
      IF(IHARG(NUMARG).EQ.'DEFA')GO TO 2650
!
!  CHECK THE POSITION OF THE WORD FONT
!  EXTRACT IANS FROM THE FIRST CHARACTER PAST "FONT" TO
!  THE LAST NON-BLANK CHARACTER
!
      DO 2630 I=1,IWIDTH
      IP1=I+1
      IP2=I+2
      IP3=I+3
      IP4=I+4
      IF(IP3.GT.IWIDTH)GO TO 2650
      IF(IANS(I).EQ.'F'.AND.IANS(IP1).EQ.'O'.AND.   &
      IANS(IP2).EQ.'N'.AND.IANS(IP3).EQ.'T'.AND.   &
      IANS(IP4).EQ.' ')GO TO 2635
 2630 CONTINUE
      GO TO 2650
!
 2635 CONTINUE
      ISTART=IP4+1
!
      ISTOP=IWIDTH
      DO 2640 I=IWIDTH,ISTART,-1
      ISTOP=I
      IF(IANS(I).NE.' ')GO TO 2645
 2640 CONTINUE
      GO TO 2650
 2645 CONTINUE
      IF(ISTART.GT.ISTOP)GO TO 2650
      NCTEMP=ISTOP-ISTART+1
      IF(NCTEMP.GT.80)ISTOP=ISTART+79
      IF(NCTEMP.GT.80)NCTEMP=80
      ICOUNT=0
      DO 2648 I=ISTART,ISTOP
      ICOUNT=ICOUNT+1
      IQWNFZ(ICOUNT:ICOUNT)=IANS(I)(1:1)
 2648 CONTINUE
      IFOUND='YES'
      IF(IFEEDB.EQ.'OFF')GO TO 9000
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,2651)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,2652)IQWNFN
      CALL DPWRST('XXX','BUG ')
      GO TO 9000
!
 2650 CONTINUE
      IQWNFZ='COURIER'
      IFOUND='YES'
      IF(IFEEDB.EQ.'OFF')GO TO 2659
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,2651)
 2651 FORMAT('THE MICROSOFT QUICK-WIN FONT HAS BEEN SET TO ')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,2652)IQWNFZ
 2652 FORMAT(A80)
      CALL DPWRST('XXX','BUG ')
 2659 CONTINUE
      GO TO 9000
 2690 CONTINUE
!
!     ************************************************************
!     **  ADDED MARCH 2002                                      **
!     **  SET SVG FONT <SANS-SERIF/SERIF/MONOSPACE>             **
!     **  SET SVG FONT WEIGHT <BOLD/NORM>                       **
!     **  SET SVG FONT STYLE <NORM/ITALIC>                      **
!     **  SET SVG CAP <BUTT/ROUND/SQUARE/NONE>                  **
!     **  SET SVG JOIN <MITER/ROUND/BEVEL/NONE>                 **
!     **  SET SVG FOREGROUND COLOR <COLOR>                      **
!     **  SET SVG HARDWARE FILL <EVENODD/NONZERO/OFF>           **
!     **  SET SVG STYLE SHEET <NONE/INTERNAL/EXTERNAL USE/      **
!     **                      EXTERNAL CREATE>                  **
!     **  SET SVG STYLE SHEET NAME                              **
!     **  ADDED OCTOBER 2010                                    **
!     **  SET SVG URL <URL>                                     **
!     ************************************************************
!
!     ******************************************************
!     **  CHECK FOR URL                                   **
!     **  NOTE THAT URL  NAME CAN BE UP TO 80 CHARACTERS  **
!     **  LONG, SO THIS HANDLED SOMEWHAT DIFFERENTLY THAN **
!     **  THE OTHER COMMANDS.                             **
!     ******************************************************
!
      IF(NUMARG.GE.2.AND.IHARG(1).EQ.'SVG '.AND.   &
      IHARG(2).EQ.'URL ')GO TO 2810
      GO TO 2890
!
 2810 CONTINUE
      ISVGUR(1:40)='                                        '
      ISVGUR(41:80)='                                        '
      NCTEMP=0
      IF(NUMARG.LE.2)GO TO 2850
      IF(IHARG(NUMARG).EQ.'OFF')GO TO 2850
      IF(IHARG(NUMARG).EQ.'AUTO')GO TO 2850
      IF(IHARG(NUMARG).EQ.'DEFA')GO TO 2850
!
!  CHECK THE POSITION OF THE WORD URL
!  EXTRACT IANS FROM THE FIRST CHARACTER PAST "URL" TO
!  THE LAST NON-BLANK CHARACTER
!
      DO 2830 I=1,IWIDTH
      IP1=I+1
      IP2=I+2
      IF(IP2.GT.IWIDTH)GO TO 2850
      IF(IANS(I).EQ.'U'.AND.IANS(IP1).EQ.'R'.AND.   &
      IANS(IP2).EQ.'L')GO TO 2835
 2830 CONTINUE
      GO TO 2850
!
 2835 CONTINUE
      ISTART=IP2+1
!
      ISTOP=IWIDTH
      DO 2840 I=IWIDTH,ISTART,-1
      ISTOP=I
      IF(IANS(I).NE.' ')GO TO 2845
 2840 CONTINUE
      GO TO 2850
 2845 CONTINUE
      IF(ISTART.GT.ISTOP)GO TO 2850
      NCTEMP=ISTOP-ISTART+1
      IF(NCTEMP.GT.80)ISTOP=ISTART+79
      IF(NCTEMP.GT.80)NCTEMP=80
      ICOUNT=0
      DO 2848 I=ISTART,ISTOP
      ICOUNT=ICOUNT+1
      ISVGUR(ICOUNT:ICOUNT)=IANSLC(I)(1:1)
 2848 CONTINUE
      IFOUND='YES'
      IF(IFEEDB.EQ.'OFF')GO TO 9000
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,2851)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,2852)ISVGUR
      CALL DPWRST('XXX','BUG ')
      GO TO 9000
!
 2850 CONTINUE
      ISVGUR='NULL'
      IFOUND='YES'
      IF(IFEEDB.EQ.'OFF')GO TO 2859
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,2851)
 2851 FORMAT('THE SVG URL HAS BEEN SET TO ')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,2852)ISVGUR
 2852 FORMAT(A80)
      CALL DPWRST('XXX','BUG ')
 2859 CONTINUE
      GO TO 9000
 2890 CONTINUE
!
!     ***********************************
!     **  CHECK FOR SVG FONT WEIGHT    **
!     ***********************************
!
      IPART1='SVG '
      IPART2='FONT'
      IPART3='WEIG'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2.AND.   &
         IHARG(3).EQ.IPART3)THEN
        ISVGFW=IHARG(NUMARG)
        IF(ISVGFW.NE.'NORM')ISVGFW='BOLD'
        IHV=ISVGFW
        GO TO 5160
      ENDIF
!     ***********************************
!     **  CHECK FOR SVG FONT STYLE     **
!     ***********************************
!
      IPART1='SVG '
      IPART2='FONT'
      IPART3='STYL'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2.AND.   &
         IHARG(3).EQ.IPART3)THEN
        ISVGST=IHARG(NUMARG)
        IF(ISVGST.NE.'ITAL')ISVGST='NORM'
        IHV=ISVGST
        GO TO 5160
      ENDIF
!
!     ******************************************************
!     **  CHECK FOR FONT NAME                             **
!     **  NOTE THAT FONT NAME CAN BE UP TO 32 CHARACTERS  **
!     **  LONG, SO THIS HANDLED SOMEWHAT DIFFERENTLY THAN **
!     **  THE OTHER COMMANDS.                             **
!     ******************************************************
!
      IF(NUMARG.GE.2.AND.IHARG(1).EQ.'SVG '.AND.   &
      IHARG(2).EQ.'FONT')GO TO 2910
      GO TO 2990
!
 2910 CONTINUE
      ISVGFN(1:32)='                                '
      NCTEMP=0
      IF(NUMARG.LE.2)GO TO 2970
      IF(IHARG(NUMARG).EQ.'OFF')GO TO 2970
      IF(IHARG(NUMARG).EQ.'AUTO')GO TO 2970
      IF(IHARG(NUMARG).EQ.'DEFA')GO TO 2970
!
!  CHECK THE POSITION OF THE WORD FONT
!  EXTRACT IANS FROM THE FIRST CHARACTER PAST "FONT" TO
!  THE LAST NON-BLANK CHARACTER
!
      DO 2930 I=1,IWIDTH
      IP1=I+1
      IP2=I+2
      IP3=I+3
      IP4=I+4
      IF(IP3.GT.IWIDTH)GO TO 2970
      IF(IANS(I).EQ.'F'.AND.IANS(IP1).EQ.'O'.AND.   &
      IANS(IP2).EQ.'N'.AND.IANS(IP3).EQ.'T'.AND.   &
      IANS(IP4).EQ.' ')GO TO 2935
 2930 CONTINUE
      GO TO 2970
!
 2935 CONTINUE
      ISTART=IP4+1
!
      ISTOP=IWIDTH
      DO 2940 I=IWIDTH,ISTART,-1
      ISTOP=I
      IF(IANS(I).NE.' ')GO TO 2945
 2940 CONTINUE
      GO TO 2970
 2945 CONTINUE
      IF(ISTART.GT.ISTOP)GO TO 2970
      NCTEMP=ISTOP-ISTART+1
      IF(NCTEMP.GT.32)THEN
        ISTOP=ISTART+31
        NCTEMP=80
      ENDIF
      ICOUNT=0
      DO 2948 I=ISTART,ISTOP
      ICOUNT=ICOUNT+1
      ISVGFN(ICOUNT:ICOUNT)=IANSLC(I)(1:1)
 2948 CONTINUE
      IFOUND='YES'
      IF(IFEEDB.EQ.'OFF')GO TO 9000
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,2971)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,2972)ISVGFN
      CALL DPWRST('XXX','BUG ')
      GO TO 9000
!
 2970 CONTINUE
      ISVGFN='sans-serif'
      IFOUND='YES'
      IF(IFEEDB.EQ.'OFF')GO TO 2979
      WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,2971)
 2971 FORMAT('THE SVG FONT HAS BEEN SET TO ')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,2972)ISVGFN
 2972 FORMAT(A32)
      CALL DPWRST('XXX','BUG ')
 2979 CONTINUE
      GO TO 9000
 2990 CONTINUE
!
!     **************************************************
!     **  CHECK FOR SVG CAP <BUTT/ROUND/SQUARE/NONE>  **
!     **************************************************
!
      IPART1='SVG '
      IPART2='CAP '
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2)THEN
        ISVGCA=IHARG(NUMARG)
        IF(ISVGCA.EQ.'OFF')ISVGCA='NONE'
        IF(ISVGCA.NE.'ROUN' .AND. ISVGCA.NE.'SQUA'.AND.   &
           ISVGCA.NE.'NONE')ISVGCA='BUTT'
        IHV=ISVGCA
        GO TO 5160
      ENDIF
!
!     ***************************************************
!     **  CHECK FOR SVG JOIN <MITER/ROUND/BEVEL/NONE>  **
!     ***************************************************
!
      IPART1='SVG '
      IPART2='JOIN'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2)THEN
        ISVGJS=IHARG(NUMARG)
        IF(ISVGJS.EQ.'OFF')ISVGJS='NONE'
        IF(ISVGJS.NE.'ROUN' .AND. ISVGJS.NE.'BEVE' .AND.   &
           ISVGJS.NE.'NONE')ISVGJS='MITE'
        IHV=ISVGJS
        GO TO 5160
      ENDIF
!
!     ***************************************************
!     **  CHECK FOR SVG FOREGROUND COLOR <COLOR>       **
!     ***************************************************
!
      IPART1='SVG '
      IPART2='FORE'
      IPART3='COLO'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2.AND.   &
         IHARG(3).EQ.IPART3)THEN
        ISVGFC=IHARG(NUMARG)
        IHV=ISVGFC
        GO TO 5160
      ENDIF
!
!     ********************************************************
!     **  CHECK FOR SVG HARDWARE FILL <EVENODD/NONZERO/OFF> **
!     ********************************************************
!
      IPART1='SVG '
      IPART2='HARD'
      IPART3='FILL'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2.AND.   &
        IHARG(3).EQ.IPART3)THEN
        ISVGFS=IHV
        IF(ISVGFS.EQ.'NONE')ISVGFS='OFF'
        IF(ISVGFS.NE.'NONZ' .AND. ISVGFS.NE.'OFF ')ISVGFS='EVEN'
        IHV=ISVGFS
        GO TO 5160
      ENDIF
!
!     ******************************************
!     **  CHECK FOR SVG BACKUP FILE          **
!     **                <NONE/PNG/JPEG/GIF>  **
!     *****************************************
!
      IPART1='SVG '
      IPART2='BACK'
      IPART3='FILE'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2.AND.   &
         IHARG(3).EQ.IPART3)THEN
        IF(IHARG(NUMARG).EQ.'JPEG' .OR. IHARG(NUMARG).EQ.'JPG')THEN
          ISVGBU='JPG'
        ELSEIF(IHARG(NUMARG).EQ.'PNG')THEN
          ISVGBU='PNG'
        ELSEIF(IHARG(NUMARG).EQ.'GIF')THEN
          ISVGBU='GIF'
        ELSE
          ISVGBU='NONE'
        ENDIF
        IHV=ISVGBU
        GO TO 5160
      ENDIF
!
!     ******************************************************
!     **  CHECK FOR STYLE SHEET NAME                      **
!     **  THIS IS A FILE NAME THAT CAN BE UP TO 80        **
!     **  CHARACTERS.                                     **
!     ******************************************************
!
      IF(NUMARG.GE.2.AND.IHARG(1).EQ.'SVG '.AND.IHARG(2).EQ.'STYL'.AND.   &
      IHARG(3).EQ.'SHEE'.AND.IHARG(4).EQ.'NAME')THEN
!
        ISVGSN=' '
        NCTEMP=0
        IF(NUMARG.LE.2)GO TO 2750
        IF(IHARG(NUMARG).EQ.'OFF')GO TO 2750
        IF(IHARG(NUMARG).EQ.'AUTO')GO TO 2750
        IF(IHARG(NUMARG).EQ.'DEFA')GO TO 2750
!
!  CHECK THE POSITION OF THE WORD NAME
!  EXTRACT IANSLC FROM THE FIRST CHARACTER PAST "NAME" TO
!  THE LAST NON-BLANK CHARACTER
!
        DO 2730 I=1,IWIDTH
        IP1=I+1
        IP2=I+2
        IP3=I+3
        IP4=I+4
        IF(IP3.GT.IWIDTH)GO TO 2750
        IF(IANS(I).EQ.'N'.AND.IANS(IP1).EQ.'A'.AND.   &
        IANS(IP2).EQ.'M'.AND.IANS(IP3).EQ.'E'.AND.   &
        IANS(IP4).EQ.' ')GO TO 2735
 2730   CONTINUE
        GO TO 2750
!
 2735   CONTINUE
        ISTART=IP4+1
!
        DO 2740 I=ISTART,IWIDTH
          IF(IANS(I).EQ.' ')GO TO 2740
          ISTART=I
          GO TO 2745
 2740   CONTINUE
        GO TO 2750
 2745   CONTINUE
        ISTOP=ISTART+79
        IF(ISTOP.GT.IWIDTH)ISTOP=IWIDTH
        IF(ISTART.GT.ISTOP)GO TO 2750
        NCTEMP=ISTOP-ISTART+1
        ICOUNT=0
        DO 2748 I=ISTART,ISTOP
          ICOUNT=ICOUNT+1
          ISVGSN(ICOUNT:ICOUNT)=IANSLC(I)(1:1)
 2748   CONTINUE
        IFOUND='YES'
        IF(IFEEDB.EQ.'ON')THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,2751)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,2752)ISVGSN
          CALL DPWRST('XXX','BUG ')
        ENDIF
        GO TO 9000
!
 2750   CONTINUE
        ISVGSN='dataplot.css'
        IFOUND='YES'
        IF(IFEEDB.EQ.'ON')THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,2751)
          CALL DPWRST('XXX','BUG ')
 2751     FORMAT('THE SVG STYLE SHEET NAME HAS BEEN SET TO ')
          WRITE(ICOUT,2752)ISVGSN
 2752     FORMAT(A80)
          CALL DPWRST('XXX','BUG ')
        ENDIF
!
      ENDIF
!
!     ********************************************************
!     **  CHECK FOR SVG STYLE SHEET <NONE/INTERNAL/         **
!     **                EXTERNAL USE/EXTERNAL CREATE>       **
!     ********************************************************
!
      IPART1='SVG '
      IPART2='STYL'
      IPART3='SHEE'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2.AND.   &
        IHARG(3).EQ.IPART3)THEN
        IF(IHARG(4).EQ.'NONE'.OR.IHARG(4).EQ.'OFF ')THEN
          ISVGSS='NONE'
        ELSEIF(IHARG(4).EQ.'INTE')THEN
          ISVGSS='INTE'
        ELSEIF(IHARG(4).EQ.'EXTE')THEN
          IF(IHARG(5).EQ.'USE ')THEN
            ISVGSS='EXTU'
          ELSEIF(IHARG(5).EQ.'CREA')THEN
            ISVGSS='EXTC'
          ELSE
            ISVGSS='EXTU'
          ENDIF
        ENDIF
        IHV=ISVGSS
        GO TO 5160
      ENDIF
!
!     **************************************************************
!     **  ADDED JANUARY  2014                                     **
!     **  PROBE CAIRO FONT                                        **
!     **  PROBE CAIRO FONT WEIGHT <BOLD/NORM>                     **
!     **  PROBE CAIRO FONT SLANT <NORM/ITALIC>                    **
!     **  PROBE CAIRO CAP <BUTT/ROUND/SQUARE>                     **
!     **  PROBE CAIRO JOIN <MITER/ROUND/BEVEL>                    **
!     **  PROBE CAIRO HARDWARE FILL <ON/OFF>                      **
!     **************************************************************
!
!     ***********************************
!     **  CHECK FOR CAIRO FONT WEIGHT  **
!     ***********************************
!
      IPART1='CAIR'
      IPART2='FONT'
      IPART3='WEIG'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2.AND.   &
         IHARG(3).EQ.IPART3)THEN
        ICAIFW=IHARG(NUMARG)
        IF(ICAIFW.NE.'NORM')ICAIFW='BOLD'
        IHV=ICAIFW
        GO TO 5160
      ENDIF
!
!     ***********************************
!     **  CHECK FOR CAIRO FONT SLANT   **
!     ***********************************
!
      IPART1='CAIR'
      IPART2='FONT'
      IPART3='SLAN'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2.AND.   &
         IHARG(3).EQ.IPART3)THEN
        ICAISL=IHARG(NUMARG)
        IF(ICAISL.NE.'ITAL')ICAISL='NORM'
        IHV=ICAISL
        GO TO 5160
      ENDIF
!
!     ******************************************************
!     **  CHECK FOR FONT NAME                             **
!     **  NOTE THAT FONT NAME CAN BE UP TO 32 CHARACTERS  **
!     **  LONG, SO THIS HANDLED SOMEWHAT DIFFERENTLY THAN **
!     **  THE OTHER COMMANDS.                             **
!     ******************************************************
!
      IF(NUMARG.GE.2.AND.IHARG(1).EQ.'CAIR'.AND.   &
      IHARG(2).EQ.'FONT')THEN
!
        ICAIFN(1:32)='                                '
        NCTEMP=0
        IF(NUMARG.LE.2)GO TO 3970
        IF(IHARG(NUMARG).EQ.'OFF')GO TO 3970
        IF(IHARG(NUMARG).EQ.'AUTO')GO TO 3970
        IF(IHARG(NUMARG).EQ.'DEFA')GO TO 3970
!
!       CHECK THE POSITION OF THE WORD FONT
!       EXTRACT IANS FROM THE FIRST CHARACTER PAST "FONT" TO
!       THE LAST NON-BLANK CHARACTER
!
        DO 3930 I=1,IWIDTH
          IP1=I+1
          IP2=I+2
          IP3=I+3
          IP4=I+4
          IF(IP3.GT.IWIDTH)GO TO 3970
          IF(IANS(I).EQ.'F'.AND.IANS(IP1).EQ.'O'.AND.   &
            IANS(IP2).EQ.'N'.AND.IANS(IP3).EQ.'T'.AND.   &
            IANS(IP4).EQ.' ')GO TO 3935
 3930   CONTINUE
        GO TO 3970
!
 3935   CONTINUE
        ISTART=IP4+1
!
        ISTOP=IWIDTH
        DO 3940 I=IWIDTH,ISTART,-1
          ISTOP=I
          IF(IANS(I).NE.' ')GO TO 3945
 3940   CONTINUE
        GO TO 3970
 3945   CONTINUE
        IF(ISTART.GT.ISTOP)GO TO 3970
        NCTEMP=ISTOP-ISTART+1
        IF(NCTEMP.GT.32)THEN
          ISTOP=ISTART+31
          NCTEMP=80
        ENDIF
        ICOUNT=0
        DO 3948 I=ISTART,ISTOP
          ICOUNT=ICOUNT+1
          ICAIFN(ICOUNT:ICOUNT)=IANSLC(I)(1:1)
 3948   CONTINUE
        IFOUND='YES'
        IF(IFEEDB.EQ.'OFF')GO TO 9000
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,3971)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,3972)ICAIFN
        CALL DPWRST('XXX','BUG ')
        GO TO 9000
!
 3970   CONTINUE
        ICAIFN='Sans'
        IFOUND='YES'
        IF(IFEEDB.EQ.'OFF')GO TO 3979
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,3971)
 3971   FORMAT('THE CAIRO FONT FAMILY HAS BEEN SET TO ')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,3972)ICAIFN
 3972   FORMAT(A32)
        CALL DPWRST('XXX','BUG ')
 3979   CONTINUE
        GO TO 9000
      ENDIF
!
!     ****************************************************
!     **  CHECK FOR CAIRO CAP <BUTT/ROUND/SQUARE/NONE>  **
!     ****************************************************
!
      IPART1='CAIR'
      IPART2='CAP '
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2)THEN
        ICAICA=IHARG(NUMARG)
        IF(ICAICA.EQ.'OFF')ICAICA='NONE'
        IF(ICAICA.EQ.'FALS')ICAICA='NONE'
        IF(ICAICA.NE.'ROUN' .AND. ICAICA.NE.'SQUA'.AND.   &
           ICAICA.NE.'NONE')ICAICA='BUTT'
        IHV=ICAICA
        GO TO 5160
      ENDIF
!
!     *****************************************************
!     **  CHECK FOR CAIRO JOIN <MITER/ROUND/BEVEL/NONE>  **
!     *****************************************************
!
      IPART1='CAIR'
      IPART2='JOIN'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2)THEN
        ICAIJS=IHARG(NUMARG)
        IF(ICAIJS.EQ.'OFF')ICAIJS='NONE'
        IF(ICAIJS.EQ.'FALS')ICAIJS='NONE'
        IF(ICAIJS.NE.'ROUN' .AND. ICAIJS.NE.'BEVE' .AND.   &
           ICAIJS.NE.'NONE')ICAIJS='MITE'
        IHV=ICAIJS
        GO TO 5160
      ENDIF
!
!     ********************************************************
!     **  CHECK FOR CAIRO HARDWARE FILL <ON/OFF>            **
!     ********************************************************
!
      IPART1='CAIR'
      IPART2='HARD'
      IPART3='FILL'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2.AND.   &
        IHARG(3).EQ.IPART3)THEN
        ICAIFS=IHV
        IF(ICAIFS.EQ.'NONE' .OR. ICAIFS.EQ.'OFF ' .OR.   &
           ICAIFS.EQ.'FALS' .OR. ICAIFS.EQ.'NO  ')THEN
          ICAIFS='OFF'
        ELSE
          ICAIFS='ON'
        ENDIF
        IHV=ICAIFS
        GO TO 5160
      ENDIF
!
!     ********************************************************
!     **  CHECK FOR CAIRO BLANK PAGE <ON/OFF>               **
!     ********************************************************
!
      IPART1='CAIR'
      IPART2='BLAN'
      IPART3='PAGE'
      IF(IHARG(1).EQ.IPART1.AND.IHARG(2).EQ.IPART2.AND.   &
        IHARG(3).EQ.IPART3)THEN
        ICAIBP=IHV
        IF(ICAIBP.EQ.'YES ' .OR. ICAIBP.EQ.'ON' .OR.   &
           ICAIBP.EQ.'TRUE')THEN
          ICAIBP='ON'
        ELSE
          ICAIBP='OFF'
        ENDIF
        IHV=ICAIBP
        GO TO 5160
      ENDIF
!
!     ********************************************************
!     **  CHECK FOR CAIRO POINTS PER INCH <VALUE>           **
!     ********************************************************
!
      IPART1='CAIR'
      IPART2='POIN'
      IPART3='PER '
      IPART4='INCH'
      IF(IHARG(1).EQ.IPART1 .AND. IHARG(2).EQ.IPART2.AND.   &
         IHARG(3).EQ.IPART3 .AND. IHARG(4).EQ.IPART4)THEN
        CAIPPI=AV
        IVAL=INT(CAIPPI+0.5)
        CAIPPI=REAL(IVAL)
        IF(CAIPPI.LT.72.)CAIPPI=72.
        IF(CAIPPI.GT.600.)CAIPPI=600.
        AV=CAIPPI
        GO TO 5170
      ENDIF
!
!               ****************************
!               **  STEP 4--              **
!               **  SET   DATA VARIABLES  **
!               ****************************
!
      IPART1='MAXN'
      IPART2='K   '
      IF(IHARG(1).EQ.IPART1.AND.IHARG2(1).EQ.IPART2)MAXNK=IV
      IF(IHARG(1).EQ.IPART1.AND.IHARG2(1).EQ.IPART2)GO TO 5150
!
      IPART1='NK  '
      IPART2='    '
      IF(IHARG(1).EQ.IPART1.AND.IHARG2(1).EQ.IPART2)NK=IV
      IF(IHARG(1).EQ.IPART1.AND.IHARG2(1).EQ.IPART2)GO TO 5150
!
      IPART1='MAXC'
      IPART2='OL  '
      IF(IHARG(1).EQ.IPART1.AND.IHARG2(1).EQ.IPART2)MAXCOL=IV
      IF(IHARG(1).EQ.IPART1.AND.IHARG2(1).EQ.IPART2)GO TO 5150
!
      IPART1='NUMC'
      IPART2='OL  '
      IF(IHARG(1).EQ.IPART1.AND.IHARG2(1).EQ.IPART2)NUMCOL=IV
      IF(IHARG(1).EQ.IPART1.AND.IHARG2(1).EQ.IPART2)GO TO 5150
!
      IPART1='MAXN'
      IPART2='    '
      IF(IHARG(1).EQ.IPART1.AND.IHARG2(1).EQ.IPART2)MAXN=IV
      IF(IHARG(1).EQ.IPART1.AND.IHARG2(1).EQ.IPART2)GO TO 5150
!
      IPART1='N   '
      IPART2='    '
      IF(IHARG(1).EQ.IPART1.AND.IHARG2(1).EQ.IPART2)N=IV
      IF(IHARG(1).EQ.IPART1.AND.IHARG2(1).EQ.IPART2)GO TO 5150
!
      IPART1='MAXC'
      IPART2='HF  '
      IF(IHARG(1).EQ.IPART1.AND.IHARG2(1).EQ.IPART2)MAXCHF=IV
      IF(IHARG(1).EQ.IPART1.AND.IHARG2(1).EQ.IPART2)GO TO 5150
!
      IPART1='NUMC'
      IPART2='HF  '
      IF(IHARG(1).EQ.IPART1.AND.IHARG2(1).EQ.IPART2)NUMCHF=IV
      IF(IHARG(1).EQ.IPART1.AND.IHARG2(1).EQ.IPART2)GO TO 5150
!
      IPART1='MAXF'
      IPART2='UN  '
      IF(IHARG(1).EQ.IPART1.AND.IHARG2(1).EQ.IPART2)MAXFUN=IV
      IF(IHARG(1).EQ.IPART1.AND.IHARG2(1).EQ.IPART2)GO TO 5150
!
      IPART1='NUMF'
      IPART2='UN  '
      IF(IHARG(1).EQ.IPART1.AND.IHARG2(1).EQ.IPART2)NUMFUN=IV
      IF(IHARG(1).EQ.IPART1.AND.IHARG2(1).EQ.IPART2)GO TO 5150
!
      IPART1='MAXC'
      IPART2='HM  '
      IF(IHARG(1).EQ.IPART1.AND.IHARG2(1).EQ.IPART2)MAXCHM=IV
      IF(IHARG(1).EQ.IPART1.AND.IHARG2(1).EQ.IPART2)GO TO 5150
!
      IPART1='NPLO'
      IPART2='TP  '
      IF(IHARG(1).EQ.IPART1.AND.IHARG2(1).EQ.IPART2)NPLOTP=IV
      IF(IHARG(1).EQ.IPART1.AND.IHARG2(1).EQ.IPART2)GO TO 5150
!
      IPART1='ITRA'
      IPART2='NS  '
      IF(IHARG(1).EQ.IPART1.AND.IHARG2(1).EQ.IPART2)ITRANS=IHV
      IF(IHARG(1).EQ.IPART1.AND.IHARG2(1).EQ.IPART2)GO TO 5160
!
!  OCTOBER 1991.  BUG FIX:  ONLY CHANGE VALUE OF "IV" IF THIS IS THE
!  RIGHT CASE.  FOR EXAMPLE, SET HELP LINES 100 SETS TO 50 BECAUSE IV
!  CHANGED HERE.  CHANGE FOR 2 LIST CASES AND 2 HELP CASES.
!
      IPART1='LIST'
      IPART2='    '
!CCCC IF(IV.LE.0)IV=20
!CCCC IF(IV.GT.50)IV=50
!CCCC IF(NUMARG.GE.2.AND.
!CCCC1   IHARG(1).EQ.IPART1.AND.IHARG2(1).EQ.IPART2.AND.
!CCCC1   IHARG(2).EQ.'LINE')ILISMX=IV
!CCCC IF(NUMARG.GE.2.AND.
!CCCC1   IHARG(1).EQ.IPART1.AND.IHARG2(1).EQ.IPART2.AND.
!CCCC1   IHARG(2).EQ.'LINE')GO TO 5150
      IF(NUMARG.GE.2.AND.   &
         IHARG(1).EQ.IPART1.AND.IHARG2(1).EQ.IPART2.AND.   &
         IHARG(2).EQ.'LINE')THEN
        IF(IV.LE.0)IV=20
!CCCC THE FOLLOWING LINE WAS CHANGED APRIL 1993
!CCCC   IF(IV.GT.50)IV=50
        IF(IV.GT.MAXLIS)IV=MAXLIS
        ILISMX=IV
        GO TO 5150
      END IF
!
      IPART1='LIST'
      IPART2='    '
!CCCC IF(IV.LE.0)IV=20
!CCCC IF(IV.GT.50)IV=50
!CCCC IF(IHARG(1).EQ.IPART1.AND.IHARG2(1).EQ.IPART2)ILISMX=IV
!CCCC IF(IHARG(1).EQ.IPART1.AND.IHARG2(1).EQ.IPART2)GO TO 5150
      IF(IHARG(1).EQ.IPART1.AND.IHARG2(1).EQ.IPART2)THEN
        IF(IV.LE.0)IV=20
!CCCC THE FOLLOWING LINE WAS CHANGED APRIL 1993
!CCCC   IF(IV.GT.50)IV=50
        IF(IV.GT.MAXLIS)IV=MAXLIS
        ILISMX=IV
        GO TO 5150
      END IF
!
      IPART1='HELP'
      IPART2='    '
!CCCC THE FOLLOWING LINE WAS CHANGED JULY 1990
!CCCC IF(IV.LE.0)IV=24
!CCCC IF(IV.LE.0)IV=20
!CCCC IF(IV.GT.100000)IV=100000
!CCCC IF(NUMARG.GE.2.AND.
!CCCC1   IHARG(1).EQ.IPART1.AND.IHARG2(1).EQ.IPART2.AND.
!CCCC1   IHARG(2).EQ.'LINE')IHELMX=IV
!CCCC IF(NUMARG.GE.2.AND.
!CCCC1   IHARG(1).EQ.IPART1.AND.IHARG2(1).EQ.IPART2.AND.
!CCCC1   IHARG(2).EQ.'LINE')GO TO 5150
      IF(NUMARG.GE.2.AND.   &
         IHARG(1).EQ.IPART1.AND.IHARG2(1).EQ.IPART2.AND.   &
         IHARG(2).EQ.'LINE')THEN
        IF(IV.LE.0)IV=20
        IF(IV.GT.100000)IV=100000
        IHELMX=IV
        GO TO 5150
      END IF
!
      IPART1='HELP'
      IPART2='    '
!CCCC IF(IV.LE.0)IV=24
!CCCC IF(IV.GT.100000)IV=100000
!CCCC IF(IHARG(1).EQ.IPART1.AND.IHARG2(1).EQ.IPART2)IHELMX=IV
!CCCC IF(IHARG(1).EQ.IPART1.AND.IHARG2(1).EQ.IPART2)GO TO 5150
      IF(IHARG(1).EQ.IPART1.AND.IHARG2(1).EQ.IPART2)THEN
        IF(IV.LE.0)IV=20
        IF(IV.GT.100000)IV=100000
        IHELMX=IV
        GO TO 5150
      END IF
!
      IPART1='REPL'
      IPART2='ACE '
!CCCC THE FOLLOWING LINE WAS FIXED (SOFT-CODE BACKSLASH) APRIL 1989
!CCCC IF(NUMARG.LE.1)IHV='\'
      IF(NUMARG.LE.1)IHV=IBASLC
      IF(IHARG(1).EQ.IPART1.AND.IHARG2(1).EQ.IPART2)IREPCH=IHV(1:1)
      IF(IHARG(1).EQ.IPART1.AND.IHARG2(1).EQ.IPART2)GO TO 5160
!
      IPART1='IO  '
      IPART2='    '
      IF(NUMARG.LE.1)IHV='FLOA'
      IF(IHARG(1).EQ.IPART1.AND.IHARG2(1).EQ.IPART2)IOSW=IHV
      IF(IHARG(1).EQ.IPART1.AND.IHARG2(1).EQ.IPART2.AND.   &
      IFEEDB.EQ.'ON')GO TO 5160
      IF(IHARG(1).EQ.IPART1.AND.IHARG2(1).EQ.IPART2.AND.   &
      IFEEDB.EQ.'OFF')GO TO 5500
!
      IPART1='ICHA'
      IPART2='PA  '
      IF(IHARG(1).EQ.IPART1.AND.IHARG2(1).EQ.IPART2)IEL=IARG(2)
      IF(IHARG(1).EQ.IPART1.AND.IHARG2(1).EQ.IPART2)ICHAPA(IEL)=IHV
      IF(IHARG(1).EQ.IPART1.AND.IHARG2(1).EQ.IPART2)GO TO 5260
!
!CCCC THE FOLLOWING BOX WAS ADDED   MAY 1992
!               ****************************
!               **  STEP 5--              **
!               **  SET   OTHER VARIABLES **
!               ****************************
!
!CCCC THE FOLLOWING SECTION WAS ADDED   MAY 1992
      IPART1='IPL1'
      IPART2='CS  '
      IF(IHARG(1).EQ.IPART1.AND.IHARG2(1).EQ.IPART2)THEN
         IPL1CS=IHV12
         IFOUND='YES'
         WRITE(ICOUT,999)
      CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,7011)IPART1,IPART2,IPL1CS
 7011    FORMAT('THE FORTRAN 12-CHARACTER VARIABLE ',A4,A4,   &
      '    HAS JUST BEEN SET TO     ',A12)
      CALL DPWRST('XXX','BUG ')
         GO TO 9000
      ENDIF
!
!CCCC THE FOLLOWING SECTION WAS ADDED   MAY 1992
      IPART1='IPL2'
      IPART2='CS  '
      IF(IHARG(1).EQ.IPART1.AND.IHARG2(1).EQ.IPART2)THEN
         IPL2CS=IHV12
         IFOUND='YES'
         WRITE(ICOUT,999)
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,7012)IPART1,IPART2,IPL2CS
 7012    FORMAT('THE FORTRAN 12-CHARACTER VARIABLE ',A4,A4,   &
      '    HAS JUST BEEN SET TO     ',A12)
      CALL DPWRST('XXX','BUG ')
         GO TO 9000
      ENDIF
!
!CCCC THE FOLLOWING SECTION WAS ADDED   MAY 1992
      IPART1='IPST'
      IPART2='BP  '
      IF(IHARG(1).EQ.IPART1.AND.IHARG2(1).EQ.IPART2)IPSTBP=IHV
      IF(IHARG(1).EQ.IPART1.AND.IHARG2(1).EQ.IPART2)GO TO 5160
!
!CCCC THE FOLLOWING SECTION WAS ADDED   MAY 1992
      IPART1='IPST'
      IPART2='PN  '
      IF(IHARG(1).EQ.IPART1.AND.IHARG2(1).EQ.IPART2)IPSTPN=IV
      IF(IHARG(1).EQ.IPART1.AND.IHARG2(1).EQ.IPART2)GO TO 5150
!
      IPART1='IPST'
      IPART2='P2  '
      IF(IHARG(1).EQ.IPART1.AND.IHARG2(1).EQ.IPART2)IPSTP2=IV
      IF(IHARG(1).EQ.IPART1.AND.IHARG2(1).EQ.IPART2)GO TO 5150
!
!CCCC THE FOLLOWING SECTION WAS ADDED   MAY 1993
!CCCC THE FOLLOWING SECTION WAS CHANGED   DECEMBER 1993
      IPART1='MINM'
      IPART2='AX  '
      IF(IHARG(1).EQ.IPART1.AND.IHARG2(1).EQ.IPART2)THEN
         IF(IHARG(2).EQ.'MIN')IV=1
         IF(IHARG(2).EQ.'MAX')IV=2
         IF(IHARG(2).EQ.'MINI')IV=1
         IF(IHARG(2).EQ.'MAXI')IV=2
         IF(IHARG(2).EQ.'DEFA')IV=0
         IF(IHARG(2).EQ.'    ')IV=0
         IF(IV.LT.1 .OR. IV.GT.2)IV=0
         MINMAX=IV
         GO TO 5150
      ENDIF
!
!CCCC THE FOLLOWING BOX WAS ADDED   MAY 1992
!               ****************************
!               **  STEP 6--              **
!               **  WRITE OUT VALUES      **
!               ****************************
!
      IERROR='YES'
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,5131)
 5131 FORMAT('***** ERROR IN SET COMMAND--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,5132)
 5132 FORMAT('      THE SPECIFIED FORTRAN COMMON VARIABLE ')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,5133)
 5133 FORMAT('      IN THE SET   COMMAND WAS NOT FOUND.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,5134)IHARG(1),IHARG2(1)
 5134 FORMAT('      THE SPECIFIED FORTRAN COMMON VARIABLE WAS ',   &
      A4,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,5135)
 5135 FORMAT('      ILLUSTRATIVE EXAMPLE TO DEMONSTRATE')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,5136)
 5136 FORMAT('      THE PROPER FORM--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,5137)
 5137 FORMAT('      SUPPOSE THE ANALYST WISHES TO DUMP OUT')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,5138)
 5138 FORMAT('      THE CURRENT VALUE OF THE FORTRAN COMMON ')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,5139)
 5139 FORMAT('      VARIABLE   MAXCOL   ,')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,5140)
 5140 FORMAT('      THIS MAY BE DONE BY ENTERING')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,5141)
 5141 FORMAT('      SET   MAXCOL')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,5143)
 5143 FORMAT('      THE ENTERED COMMAND LINE WAS AS FOLLOWS--')
      CALL DPWRST('XXX','BUG ')
      IF(IWIDTH.GE.1)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,5145)(IANS(I),I=1,MIN(120,IWIDTH))
 5145   FORMAT(6X,120A1)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
      ENDIF
      GO TO 9000
!
 5150 CONTINUE
      IFOUND='YES'
      IF(IFEEDB.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,5151)IPART1,IPART2,IV
 5151   FORMAT('THE FORTRAN COMMON PARAMETER ',A4,A4,   &
               ' HAS JUST BEEN SET TO ',I8)
        CALL DPWRST('XXX','BUG ')
      ENDIF
      GO TO 9000
!
 5160 CONTINUE
      IFOUND='YES'
      IF(IFEEDB.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,5161)IPART1,IPART2,IHV
 5161   FORMAT('THE FORTRAN COMMON CHARACTER VARIABLE ',A4,2X,A4,   &
               ' HAS JUST BEEN SET TO ',A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
      GO TO 9000
!
 5165 CONTINUE
      IFOUND='YES'
      IF(IFEEDB.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,5166)IPART1,IPART2,IHV,IHV2
 5166   FORMAT('THE FORTRAN COMMON CHARACTER VARIABLE ',A4,2X,A4,   &
               ' HAS JUST BEEN SET TO ',2A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
      GO TO 9000
!
 5170 CONTINUE
      IFOUND='YES'
      IF(IFEEDB.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,5171)IPART1,IPART2,AV
 5171   FORMAT('THE FORTRAN COMMON SCALAR ',A4,A4,   &
               ' HAS JUST BEEN SET TO ',E15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
      GO TO 9000
!
 5250 CONTINUE
      IFOUND='YES'
      IF(IFEEDB.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,5251)IEL,IPART1,IPART2,IV
 5251   FORMAT('ELEMENT ',I8,' OF THE FORTRAN COMMON VECTOR ',A4,A4,   &
               ' HAS JUST BEEN SET TO ',I8)
        CALL DPWRST('XXX','BUG ')
      ENDIF
      GO TO 9000
!
 5260 CONTINUE
      IFOUND='YES'
      IF(IFEEDB.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,5261)IEL,IPART1,IPART2,IHV
 5261   FORMAT('ELEMENT ',I8,' OF THE FORTRAN COMMON VECTOR ',A4,A4,   &
               ' HAS JUST BEEN SET TO ',A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
      GO TO 9000
!
 5270 CONTINUE
      IFOUND='YES'
      IF(IFEEDB.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,5271)IEL,IPART1,IPART2,AV
 5271   FORMAT('ELEMENT ',I8,' OF THE FORTRAN COMMON VECTOR ',A4,A4,   &
               ' HAS JUST BEEN SET TO ',E15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
      GO TO 9000
!
 5360 CONTINUE
      IFOUND='YES'
      IF(IFEEDB.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,5361)IPART1,IPART2,ISTRIN(1:12)
 5361   FORMAT('THE FORTRAN COMMON CHARACTER VARIABLE ',A4,A4,   &
               ' HAS JUST BEEN SET TO ',A12)
        CALL DPWRST('XXX','BUG ')
      ENDIF
      GO TO 9000
!
 5370 CONTINUE
      IFOUND='YES'
      IF(IFEEDB.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,5371)IPART1,IPART2,ISTRIN(1:80)
 5371   FORMAT('THE FORTRAN COMMON CHAR. VAR. ',2A4,' = ',A80)
        CALL DPWRST('XXX','BUG ')
      ENDIF
      GO TO 9000
!
 5500 CONTINUE
      IFOUND='YES'
      GO TO 9000
!
!               *****************
!               **  STEP 90--  **
!               **   EXIT      **
!               *****************
!
 9000 CONTINUE
      IFILQU=IFILQZ
!
      IF(ISUBRO.EQ.'PSET')THEN
        WRITE(ICOUT,9011)
 9011   FORMAT('****** AT THE END OF DPSET')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9013)IFOUND,IERROR
 9013   FORMAT('IFOUND,IERROR = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE DPSET
      SUBROUTINE DPPROB(ILISMX,IREPCH,IOSW,                   &
                        IBUGUG,IBUGU2,IBUGU3,IBUGU4,ISUBRO,   &
                        IBUGEX,IBUGE2,IBUGHE,IBUGH2,IBUGLO,   &
                        IHELMX,IFTEXP,IFTORD,                 &
                        IFORSW,ICREAF,NCREAF,ICWRIF,NCWRIF,   &
                        IREARW,IWRIRW,NPLOTP,IPRITY,          &
                        IUNFOF,IUNFNR,IUNFMC,IMACRO,IMALEV,   &
                        IANSLO,ILOOST,ILOOLI,                 &
                        NUMIF,ISEED,                          &
                        IFOUND,IERROR)
!
!     PURPOSE--PROBE AND WRITE OUT THE VALUE
!              OF CERTAIN FORTRAN VARIABLES IN COMMON.
!     NOTE--THIS CAPABILITY IS USEFUL FOR IMPLEMENTATION AND DEBUGGING.
!     INPUT  ARGUMENTS--NONE
