!     UPDATED         --NOVEMBER   1993.  PROBE PATH
!     UPDATED         --JANUARY    1994.  WEIB MINMAX TO DPCOS2.INC
!     UPDATED         --JUNE       1994.  X11, POSTSCRIPT HARDWARE FILL
!     UPDATED         --APRIL      1995.  IUNFOF, IUNFNR, IUNFMC
!     UPDATED         --JULY       1995.  FIT ITER., SD, ADDITIVE CONST.
!     UPDATED         --FEBRUARY   1996.  PROBE MPATH
!     UPDATED         --MARCH      1996.  IRHSTG
!     UPDATED         --JULY       1996.  LAHEY DEVICE SWITCHES
!     UPDATED         --NOVEMBER   1996.  MICROSOFT QUICK-WIN SWITCHES
!     UPDATED         --APRIL      1997.  ICCHPR, INETSW
