!     UPDATED         --SEPTEMBER  1998.  SAVE PROBE VALUE AS INTERNAL
!                                         VARIABLE OR STRING.
!     UPDATED         --SEPTEMBER  1998.  IPPTBI, IQQPBI
!     UPDATED         --NOVEMBER   1998.  IRHSTG TO DPCOST.INC
!     UPDATED         --MARCH      1999.  IHBURL
!     UPDATED         --JULY       1999.  IAUTCP
!     UPDATED         --SEPTEMBER  1999.  ISPMLA
