!     UPDATED         --SEPTEMBER  1999.  ISPMLD
!     UPDATED         --SEPTEMBER  1999.  ISPMTA
!     UPDATED         --SEPTEMBER  1999.  ISPMFR
!     UPDATED         --SEPTEMBER  1999.  ISPMPT
!     UPDATED         --SEPTEMBER  1999.  ICPLLA
!     UPDATED         --SEPTEMBER  1999.  ICPLFI
!     UPDATED         --SEPTEMBER  1999.  ICPLTA
