!               *********************************************
!               **  STEP 12--                              **
!               **  TREAT THE    PROBE READ FORMAT    CASE **
!               *********************************************
!
!CCCC FOLLOWING SECTION ADDED JANUARY   2004.
!               ********************************************
!               **  STEP 20.A--                           **
!               **  PROBE READ DELIMITER                  **
!               **  PROBE READ NON-PRINTING CHARACTERS    **
!               **  PROBE READ SUBSET                     **
!               **  PROBE READ MISSING VALUE              **
!               **  PROBE READ PAD MISSING COLUMN         **
!               **  PROBE READ LINE                       **
!               **  PROBE READ DOLLAR SIGN IGNORE         **
!               **  PROBE READ TRAILING PLUS MINUS IGNORE **
!               **  PROBE READ COMMA IGNORE               **
!               ********************************************
!
      IPART1='READ'
      IPART2='DELI'
      IF(IHARG(1).EQ.'READ')THEN
        IF(IHARG(2).EQ.'DELI')THEN
          IHV=IREADL
          GO TO 5160
        ELSEIF(IHARG(2).EQ.'NONP' .AND. IHARG(3).EQ.'CHAR')THEN
          IHV=IREANP
          GO TO 5160
        ELSEIF(IHARG(2).EQ.'NON ' .AND. IHARG(3).EQ.'PRIN' .AND.   &
               IHARG(4).EQ.'CHAR')THEN
          IHV=IREANP
          GO TO 5160
        ELSEIF(IHARG(2).EQ.'SUBS')THEN
          IHV=IREASB
          GO TO 5160
        ELSEIF(IHARG(2).EQ.'MISS' .AND. IHARG(3).EQ.'VALU')THEN
          AV=PREAMV
          GO TO 5170
        ELSEIF(IHARG(2).EQ.'PAD ' .AND. IHARG(3).EQ.'MISS' .AND.   &
               IHARG(4).EQ.'COLU')THEN
          IHV=IREAPD
          GO TO 5160
        ELSEIF(IHARG(2).EQ.'COMM' .AND. IHARG(3).EQ.'IGNO')THEN
          IHV=IREACM
          GO TO 5160
        ELSEIF(IHARG(2).EQ.'DOLL' .AND. IHARG(3).EQ.'SIGN' .AND.   &
               IHARG(4).EQ.'IGNO')THEN
          IHV=IREADS
          GO TO 5160
        ELSEIF(IHARG(2).EQ.'PERC' .AND. IHARG(3).EQ.'SIGN' .AND.   &
               IHARG(4).EQ.'IGNO')THEN
          IHV=IREAPC
          GO TO 5160
        ELSEIF(IHARG(2).EQ.'ASTE' .AND. IHARG(3).EQ.'IGNO')THEN
          IHV=IREAAS
          GO TO 5160
        ELSEIF(IHARG(2).EQ.'TRAI' .AND. IHARG(3).EQ.'PLUS' .AND.   &
               IHARG(4).EQ.'MINU' .AND. IHARG(5).EQ.'IGNO')THEN
          IHV=IREAPM
          GO TO 5160
        ELSEIF(IHARG(2).EQ.'LEAD' .AND. IHARG(3).EQ.'LESS' .AND.   &
               IHARG(4).EQ.'THAN' .AND. IHARG(5).EQ.'IGNO')THEN
          IHV=IREALT
          GO TO 5160
        ELSEIF(IHARG(2).EQ.'LEAD' .AND. IHARG(3).EQ.'GREA' .AND.   &
               IHARG(4).EQ.'THAN' .AND. IHARG(5).EQ.'IGNO')THEN
          IHV=IREALT
          GO TO 5160
        ELSEIF(IHARG(2).EQ.'LEAD' .AND. IHARG(3).EQ.'LESS' .AND.   &
               IHARG(4).EQ.'THAN' .AND. IHARG(5).EQ.'GREA' .AND.   &
               IHARG(6).EQ.'THAN' .AND. IHARG(7).EQ.'IGNO')THEN
          IHV=IREALT
          GO TO 5160
        ELSEIF(IHARG(2).EQ.'CHAR' .AND. IHARG(3).EQ.'MISS' .AND.   &
               IHARG(4).EQ.'VALU')THEN
          IHV=IREAMC(1:4)
          IHV2=IREAMC(5:8)
          GO TO 5160
        ELSEIF(IHARG(2).EQ.'LINE')THEN
          IHV=IREALI
          GO TO 5160
        ELSEIF(IHARG(2).EQ.'REWI')THEN
          IF(NCREAF.GE.1)THEN
            IFOUND='YES'
            IF(IFEEDB.EQ.'ON')THEN
              WRITE(ICOUT,999)
              CALL DPWRST('XXX','BUG ')
              WRITE(ICOUT,1241)
 1241         FORMAT('THE (FORTRAN-LIKE) READ FORMAT IS CURRENTLY ',   &
                     'SET TO')
              CALL DPWRST('XXX','BUG ')
              WRITE(ICOUT,1242)(ICREAF(I:I),I=1,NCREAF)
 1242         FORMAT(80A1)
              CALL DPWRST('XXX','BUG ')
            ENDIF
            IPROBS(1:NCREAF)=ICREAF(1:NCREAF)
            NCPROB=NCREAF
            GO TO 8100
          ELSE
            IFOUND='YES'
            IF(IFEEDB.EQ.'ON')THEN
              WRITE(ICOUT,999)
              CALL DPWRST('XXX','BUG ')
              WRITE(ICOUT,1251)
 1251         FORMAT('THE (FORTRAN-LIKE) READ FORMAT IS CURRENTLY ',   &
                     'NULL.')
              CALL DPWRST('XXX','BUG ')
              WRITE(ICOUT,1252)
 1252         FORMAT('THUS SUBSEQUENT READS WILL BE FREE-FORMAT.')
              CALL DPWRST('XXX','BUG ')
              GO TO 9000
            ENDIF
          ENDIF
        ENDIF
      ENDIF
!
!               *********************************************
!               **  STEP 14--                              **
!               **  TREAT THE    PROBE READ REWIND    CASE **
!               *********************************************
!
      IF(NUMARG.GE.2.AND.IHARG(1).EQ.'READ'.AND.   &
         IHARG(2).EQ.'REWI')THEN
        IFOUND='YES'
        IF(IFEEDB.EQ.'ON')THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1421)IREARW
 1421     FORMAT('THE     READ REWIND    SWITCH IS CURRENTLY ',A4)
          CALL DPWRST('XXX','BUG ')
          IF(IREARW.EQ.'ON')THEN
            WRITE(ICOUT,1423)
 1423       FORMAT('THUS SUBSEQUENT READS WILL HAVE AN AUTOMATIC')
            CALL DPWRST('XXX','BUG ')
          ELSEIF(IREARW.EQ.'OFF')THEN
            WRITE(ICOUT,1424)
 1424       FORMAT('THUS SUBSEQUENT READS WILL HAVE NO AUTOMATIC')
            CALL DPWRST('XXX','BUG ')
          ENDIF
          WRITE(ICOUT,1425)
 1425     FORMAT('REWIND BEFORE THE READ OCCURS.')
          CALL DPWRST('XXX','BUG ')
        ENDIF
        IPROBS(1:4)=IREARW(1:4)
        NCPROB=4
        IF(IPROBS(1:2).EQ.'ON')NCPROB=2
        IF(IPROBS(1:3).EQ.'OFF')NCPROB=3
        GO TO 8100
      ENDIF
!
!               *********************************************
!               **  STEP 15--                              **
!               **  TREAT THE    PROBE WRITE REWIND   CASE **
!               *********************************************
