!               **  STEP 13--                              **
!               **  TREAT THE    PROBE WRITE FORMAT   CASE **
!               *********************************************
!
      IF(NUMARG.GE.1.AND.   &
        (IHARG(1).EQ.'WRIT' .OR. IHARG(1).EQ.'PRIN'))THEN
        IF(IHARG(2).EQ.'HEAD' .AND. IHARG(3).EQ.'FILE')GO TO 1390
!
        IF(NCWRIF.GE.1)THEN
          IFOUND='YES'
          IF(IFEEDB.EQ.'ON')THEN
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,1341)
 1341       FORMAT('THE (FORTRAN-LIKE) WRITE FORMAT IS CURRENTLY ',   &
                   'SET TO')
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,1342)(ICWRIF(I:I),I=1,NCWRIF)
 1342       FORMAT(80A1)
            CALL DPWRST('XXX','BUG ')
          ENDIF
          IPROBS(1:NCWRIF)=ICREAF(1:NCWRIF)
          NCPROB=NCWRIF
          GO TO 8100
        ELSEIF(NCWRIF.LE.0)THEN
          IFOUND='YES'
          IF(IFEEDB.EQ.'ON')THEN
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,1351)
 1351       FORMAT('THE (FORTRAN-LIKE) WRITE FORMAT IS CURRENTLY NULL.')
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,1352)
 1352       FORMAT('THUS SUBSEQUENT WRITES WILL BE FREE-FORMAT.')
            CALL DPWRST('XXX','BUG ')
            GO TO 9000
          ENDIF
        ENDIF
!
      ENDIF
!
 1390 CONTINUE
!
!               ***********************************************
!               **  STEP 14--                                **
!               **  TREAT THE  PROBE CALL COMMAND LINE  CASE **
!               ***********************************************
!
      IF(NUMARG.GE.1.AND.   &
        (IHARG(1).EQ.'CALL' .OR. IHARG(1).EQ.'MACR') .AND.   &
         IHARG(2).EQ.'COMM' .AND. IHARG(3).EQ.'LINE')THEN
!
        NCHAR=1
        DO 1391 II=1024,1,-1
          IF(IMCRCL.NE.' ')THEN
            NCHAR=II
            GO TO 1393
          ENDIF
 1391   CONTINUE
 1393   CONTINUE
        IFOUND='YES'
        IF(IFEEDB.EQ.'ON')THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1395)
 1395     FORMAT('THE CURRENT CALL COMMAND LINE IS:')
          CALL DPWRST('XXX','BUG ')
          IFORMT='(    A1)'
          WRITE(IFORMT(2:5),'(I4)')NCHAR
          WRITE(ICOUT,IFORMT)(IMCRCL(I:I),I=1,NCHAR)
          CALL DPWRST('XXX','BUG ')
        ENDIF
        IPROBS(1:NCHAR)=IMCRCL(1:NCHAR)
        NCPROB=NCHAR
        GO TO 8100
      ENDIF
