      IF(NUMARG.GE.3.AND. IHARG(1).EQ.'LATE' .AND.   &
        IHARG(2).EQ.'HEAD' .AND. IHARG(3).EQ.'FILE')THEN
        IFOUND='YES'
        IF(IFEEDB.EQ.'ON')THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1741)
 1741     FORMAT('THE LATEX HEADER FILE  = ')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1717)ILATHE
          CALL DPWRST('XXX','BUG ')
        ENDIF
        IPROBS(1:NCLATH)=ILATHE(1:NCLATH)
        NCPROB=NCLATH
        GO TO 8100
      ENDIF
!
!CCCC THE FOLLOWING SECTION WAS ADDED    OCTOBER  2014
!     *****************************************
!     **  CHECK FOR PROBE LATEX FOOTER FILE  **
