      IF(NUMARG.GE.3.AND. IHARG(1).EQ.'LATE' .AND.   &
        IHARG(2).EQ.'FOOT' .AND. IHARG(3).EQ.'FILE')THEN
        IFOUND='YES'
        IF(IFEEDB.EQ.'ON')THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1742)
 1742     FORMAT('THE LATEX FOOTER FILE  = ')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1717)ILATFO
