!
!CCCC THE FOLLOWING SECTION WAS ADDED        DECEMBER  2019.
!     ******************************************
!     **  PROBE HOME (OR USER PROFILE)        **
!     ******************************************
!
      IPART1='HOME'
      IPART2='    '
      IPART3='USER'
      IPART4='PROF'
