         (IHARG(1).EQ.IPART3 .AND. IHARG(2).EQ.IPART4))THEN
        IFOUND='YES'
        IF(IFEEDB.EQ.'ON')THEN
          WRITE(ICOUT,999)
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,67001)
67001     FORMAT('THE HOME (USER PROFILE) VARIABLE = ')
          CALL DPWRST('XXX','BUG ')
          WRITE(ICOUT,1717)UPROFI
          CALL DPWRST('XXX','BUG ')
        ENDIF
        IPROBS(1:NCUPRO)=UPROFI(1:NCUPRO)
        NCPROB=NCUPRO
        GO TO 8100
      ENDIF
!
!CCCC THE FOLLOWING SECTION WAS ADDED        DECEMBER  2019.
!     ******************************************
!     **  PROBE USER (OR USER NAME)           **
!     ******************************************
!
      IPART1='USER'
