                 '1 TO 250 RANGE.')
          CALL DPWRST('XXX','BUG ')
          GO TO 9000
        ENDIF
        IVAL=IFIETY(IV)
        IF(IVAL.EQ.1)THEN
          WRITE(ICOUT,25263)IV
25263     FORMAT('THE TYPE FOR FIELD ',I3,' FOR SUBSEQUENT READ ',   &
                 'COMMANDS IS SET TO CHARACTER.')
          CALL DPWRST('XXX','BUG ')
