         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,7074)IDMOD3(2)
 7074    FORMAT('THE FORTRAN 4-CHARACTER VARIABLE ',   &
      '     IDMOD3(2) HAS THE SETTING     ',A4)
         CALL DPWRST('XXX','BUG ')
         IPROBS(1:4)=IDMOD3(2)(1:4)
         NCPROB=4
         GO TO 8100
      ENDIF
!
      IF(IHARG(1).EQ.'IDMO'.AND.IHARG2(1).EQ.'3(3)')THEN
         IFOUND='YES'
         WRITE(ICOUT,999)
         CALL DPWRST('XXX','BUG ')
         WRITE(ICOUT,7076)IDMOD3(3)
 7076    FORMAT('THE FORTRAN 4-CHARACTER VARIABLE ',   &
      '     IDMOD3(3) HAS THE SETTING     ',A4)
         CALL DPWRST('XXX','BUG ')
         IPROBS(1:4)=IDMOD3(3)(1:4)
         NCPROB=4
         GO TO 8100
      ENDIF
!
!CCCC THE FOLLOWING SECTION WAS ADDED   MAY 1993
      IPART1='MINM'
      IPART2='AX  '
      IF(IHARG(1).EQ.IPART1.AND.IHARG2(1).EQ.IPART2)IV=MINMAX
      IF(IHARG(1).EQ.IPART1.AND.IHARG2(1).EQ.IPART2)GO TO 5150
!
!CCCC THE FOLLOWING BOX WAS ADDED   MAY 1992
!               ****************************
!               **  STEP 6--              **
!               **  WRITE OUT VALUES      **
!               ****************************
!
!
      IERROR='YES'
      WRITE(ICOUT,999)
  999 FORMAT(1X)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,5131)
 5131 FORMAT('***** ERROR IN DPPROB--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,5132)
 5132 FORMAT('      THE SPECIFIED FORTRAN COMMON VARIABLE ')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,5133)
 5133 FORMAT('      IN THE PROBE COMMAND WAS NOT FOUND.')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,5134)IHARG(1),IHARG2(1)
 5134 FORMAT('      THE SPECIFIED FORTRAN COMMON VARIABLE WAS ',   &
      A4,A4)
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,5135)
 5135 FORMAT('      ILLUSTRATIVE EXAMPLE TO DEMONSTRATE')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,5136)
 5136 FORMAT('      THE PROPER FORM--')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,5137)
 5137 FORMAT('      SUPPOSE THE ANALYST WISHES TO DUMP OUT')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,5138)
 5138 FORMAT('      THE CURRENT VALUE OF THE FORTRAN COMMON ')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,5139)
 5139 FORMAT('      VARIABLE   MAXCOL   ,')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,5140)
 5140 FORMAT('      THIS MAY BE DONE BY ENTERING')
      CALL DPWRST('XXX','BUG ')
      WRITE(ICOUT,5141)
 5141 FORMAT('      PROBE MAXCOL')
      CALL DPWRST('XXX','BUG ')
      GO TO 9000
!
 5150 CONTINUE
      IFOUND='YES'
      IF(IFEEDB.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,5151)IPART1,IPART2,IV
 5151   FORMAT('THE FORTRAN COMMON SCALAR ',A4,2X,A4,   &
               ' HAS THE VALUE ',I8)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      APROBE=REAL(IV)
      GO TO 8000
!
 5160 CONTINUE
      IFOUND='YES'
      IF(IFEEDB.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,5161)IPART1,IPART2,IHV
 5161   FORMAT('THE FORTRAN COMMON CHARACTER ',A4,2X,A4,   &
               ' HAS THE SETTING     ',A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
 5163 CONTINUE
      IPROBS=' '
      IPROBS(1:4)=IHV(1:4)
      NCPROB=4
      GO TO 8100
!
 5165 CONTINUE
      IFOUND='YES'
      IF(IFEEDB.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,5166)IPART1,IPART2,IHV,IHV2
 5166   FORMAT('THE FORTRAN COMMON CHARACTER ',A4,2X,A4,   &
               ' HAS THE SETTING     ',2A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      IPROBS=' '
      IPROBS(1:4)=IHV(1:4)
      IPROBS(5:8)=IHV2(1:4)
      NCPROB=8
      GO TO 8100
!
59165 CONTINUE
      IFOUND='YES'
      IF(IFEEDB.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,59166)IPART1,IPART2,IPROBS(1:80)
59166   FORMAT('THE FORTRAN COMMON CHARACTER ',A4,2X,A4,   &
               ' HAS THE SETTING     ',A80)
        CALL DPWRST('XXX','BUG ')
      ENDIF
      GO TO 8100
!
 5170 CONTINUE
      IFOUND='YES'
      IF(IFEEDB.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,5171)IPART1,IPART2,AV
 5171   FORMAT('THE FORTRAN COMMON SCALAR ',A4,A4,   &
               ' HAS THE VALUE ',E15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
 5173 CONTINUE
      APROBE=AV
      GO TO 8000
!
 5250 CONTINUE
      IFOUND='YES'
      IF(IFEEDB.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,5251)IEL,IPART1,IPART2,IV
 5251   FORMAT('ELEMENT ',I8,' OF THE FORTRAN COMMON VARIABLE ',2A4,   &
               ' HAS THE VALUE ',I8)
        CALL DPWRST('XXX','BUG ')
      ENDIF
      APROBE=REAL(IV+0.5)
      GO TO 8000
!
 5260 CONTINUE
      IFOUND='YES'
      IF(IFEEDB.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,5261)IEL,IPART1,IPART2,IHV
 5261   FORMAT('ELEMENT ',I8,' OF THE FORTRAN COMMON VARIABLE ',2A4,   &
               ' HAS THE SETTING     ',A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
      IPROBS(1:4)=IHV(1:4)
      NCPROB=4
      GO TO 8100
!
 5270 CONTINUE
      IFOUND='YES'
      IF(IFEEDB.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,5271)IEL,IPART1,IPART2,AV
 5271   FORMAT('ELEMENT ',I8,' OF THE FORTRAN COMMON VARIABLE ',2A4,   &
               ' HAS THE VALUE ',E15.7)
        CALL DPWRST('XXX','BUG ')
      ENDIF
      APROBE=AV
      GO TO 8000
!
 5360 CONTINUE
      IFOUND='YES'
      IF(IFEEDB.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,5361)IPART1,IPART2,ISTRIN(1:12)
 5361   FORMAT('THE FORTRAN COMMON CHARACTER VARIABLE ',A4,A4,   &
               ' HAS THE SETTING ',A12)
        CALL DPWRST('XXX','BUG ')
      ENDIF
      IPROBS(1:12)=ISTRIN(1:12)
      NCPROB=12
      GO TO 8100
!
 5370 CONTINUE
      IFOUND='YES'
      IF(IFEEDB.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,5371)IPART1,IPART2,ISTRIN
 5371   FORMAT('THE FORTRAN COMMON CHAR. VAR. ',2A4,   &
               ' = ',A80)
        CALL DPWRST('XXX','BUG ')
      ENDIF
      IPROBS(1:80)=ISTRIN(1:80)
      NCPROB=80
      GO TO 8100
!
 5410 CONTINUE
      IFOUND='YES'
      IF(IFEEDB.EQ.'ON')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,5411)NUMNAM
 5411   FORMAT('NUMNAM = ',I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,5412)
 5412   FORMAT('I,IHNAME(I),IHNAME2(I),IUSE(I),IN(I),',   &
               'IVALUE(I),IVALU2(I),VALUE(I)')
        CALL DPWRST('XXX','BUG ')
        DO 5413 I=1,NUMNAM
          WRITE(ICOUT,5414)I,IHNAME(I),IHNAM2(I),IUSE(I),IN(I),   &
                           IVALUE(I),IVALU2(I),VALUE(I)
 5414     FORMAT(I8,3(2X,A4),3I8,E15.7)
          CALL DPWRST('XXX','BUG ')
 5413   CONTINUE
      ENDIF
      GO TO 9000
!
!               ********************
!               **  STEP 80--     **
!               **  UPDATE APROBE **
!               ********************
!
 8000 CONTINUE
      CALL DPADDP('PROB','EVAL',APROBE,IHOST1,ISUBN0,   &
      IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
      IANS,IWIDTH,IBUGUG,IERROR)
      GO TO 9000
!
!               ********************
!               **  STEP 81--     **
!               **  UPDATE IPROBS **
!               ********************
!
 8100 CONTINUE
      NJUNK=NCPROB
      DO 8110 J=NJUNK,1,-1
        NCPROB=J
        IF(IPROBS(J:J).NE.' ')GO TO 8112
 8110 CONTINUE
 8112 CONTINUE
!
      DO 5110 I=1,NCPROB
        IFUNC3(I)(1:4)='    '
        IFUNC3(I)(1:1)=IPROBS(I:I)
5110  CONTINUE
      CALL UPDATF('PROB','ESTR',IFUNC3,NCPROB,'CHAD','NO  ',   &
         IHNAME,IHNAM2,IUSE,IN,IVSTAR,IVSTOP,   &
         NUMNAM,MAXNAM,IANS,IWIDTH,ILISTL,NEWNAM,MAXN3,   &
         IFUNC,NUMCHF,MAXCHF,IBUGUG,ILOCN,IFOUND,IERROR)
!
!CCCC JUNE 2002.  IF PROBS IS <ON/OFF> OR <OPEN/CLOSED>, THEN
!CCCC SET APROBE TO 1/0.
!
      IF(IPROBS(1:3).EQ.'OFF' .OR. IPROBS(1:6).EQ.'CLOSED' .OR.   &
         IPROBS(1:2).EQ.'NO')THEN
         APROBE=0.0
         CALL DPADDP('PROB','EVAL',APROBE,IHOST1,ISUBN0,   &
                     IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
                     IANS,IWIDTH,IBUGUG,IERROR)
      ELSEIF(IPROBS(1:2).EQ.'ON' .OR. IPROBS(1:4).EQ.'OPEN' .OR.   &
         IPROBS(1:3).EQ.'YES')THEN
         APROBE=1.0
         CALL DPADDP('PROB','EVAL',APROBE,IHOST1,ISUBN0,   &
                     IHNAME,IHNAM2,IUSE,VALUE,IVALUE,NUMNAM,MAXNAM,   &
                     IANS,IWIDTH,IBUGUG,IERROR)
      ENDIF
      GO TO 9000
!
!               *****************
!               **  STEP 90--  **
!               **   EXIT      **
!               *****************
!
 9000 CONTINUE
      RETURN
      END SUBROUTINE DPPROB
      SUBROUTINE INITPC(IBUGIN)
!
!     PURPOSE--THIS IS SUBROUTING INITPC.
!              (THE   PC    AT THE END OF    INITPC   STANDS FOR   PLOT CO
!              THIS SUBROUTINE INITIALIZES PLOT CONTROL VARIABLES AND PARAMETERS
!     WRITTEN BY--JAMES J. FILLIBEN
!                 STATISTICAL ENGINEERING DIVISION
!                 INFORMATION TECHNOLOGY LABORATORY
!                 NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY
!                 GAITHERSBURG, MD 20899
!                 PHONE--301-975-2855
!     NOTE--DATAPLOT IS A REGISTERED TRADEMARK
!           OF THE NATIONAL INSTITUTE OF STANDARDS AND TECHNOLOGY.
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--82.6
!     ORIGINAL VERSION--SEPTEMBER 1980.
!     UPDATED         --MARCH     1981.
!     UPDATED         --APRIL     1981.
!     UPDATED         --JUNE      1981.
!     UPDATED         --AUGUST    1981.
!     UPDATED         --SEPTEMBER 1981.
!     UPDATED         --OCTOBER   1981.
!     UPDATED         --NOVEMBER  1981.
!     UPDATED         --MAY       1982.
!     UPDATED         --DECEMBER  1987. FINAL CURSOR POS. FOR TEK TO QMS (ALAN)
!     UPDATED         --SEPTEMBER 1988. (MOVE 3-D EYE, ETC. TO INIT3D)
!     UPDATED         --JANUARY   1989. (NON-SOLID REGION FILL INFINITE LOOP)
!     UPDATED         --FEBRUARY  1989. Z AXIS (FOR 3-D) SETTINGS
!     UPDATED         --FEBRUARY  1989. SOFT-CODING (ALAN)
!     UPDATED         --APRIL     1989. SOFT-CODED BACKSLASH FOR UNIX
!     UPDATED         --APRIL     1989. ANIMATION SWITCH
!     UPDATED         --APRIL     1989. BOX COLOR FROM BLUE TO WHITE
!     UPDATED         --JULY      1989. CHANGE Y & ZLABEL DISPLACEMENT
!     UPDATED         --AUGUST    1990. WINDOW MANAGER
!     UPDATED         --AUGUST    1990. MENU SELECTOR
!     UPDATED         --JUNE      1992. DEFAULT BACKGROUND TO WHITE
!     UPDATED         --AUGUST    1992. BOX SHADOW HEIGHT & WIDTH
!     UPDATED         --AUGUST    1992. BOX DEFAULTS
!     UPDATED         --OCTOBER   1992. ADD CHARACTER STATEMENTS
!     UPDATED         --OCTOBER   1993. ADD REGION BASE INTERPOLATE
!     UPDATED         --MARCH     1994. ADD REGION BASE POLYGON
!     UPDATED         --DECEMBER  1994. EXACT CHARACTER MAPPING
!     UPDATED         --NOVEMBER  1997. NEW SETTINGS
!     UPDATED         --FEBRUARY  1998. ILINPO, ICHAPO
!     UPDATED         --SEPTEMBER 1998. AMPSCH, AMPSCW
!     UPDATED         --OCTOBER   1999. I..LJU, P..LOF
!     UPDATED         --NOVEMBER  1999. I..LDI, P..LAN
!     UPDATED         --NOVEMBER  1999. SUBREGIONS
!     UPDATED         --DECEMBER  1999. LEGEND UNITS
!     UPDATED         --MAY       2015. EMBED SETTINGS
!     UPDATED         --JANUARY   2018. ICHATY, ILINTY
!     UPDATED         --OCTOBER   2018. PX1LXC, PX1LYC
!     UPDATED         --OCTOBER   2018. PX2LXC, PX2LYC
!     UPDATED         --OCTOBER   2018. PX3LXC, PX3LYC
!     UPDATED         --OCTOBER   2018. PY1LXC, PY1LYC
!     UPDATED         --OCTOBER   2018. PY2LXC, PY2LYC
!     UPDATED         --FEBRUARY  2019. PX1ZGA, PX2ZGA, PY1ZGA, PY2ZGA
!     UPDATED         --NOVEMBER  2020. INITITIALIZE RGB COLORS
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      CHARACTER*4 IBUGIN
!
      CHARACTER*4 IDEFGC
!
!CCCC THE FOLLOWING 4 LINES WERE ADDED OCTOBER 1992
!
      CHARACTER*4 IDEFWM
      CHARACTER*4 IWINMA
      CHARACTER*4 IDEFMS
      CHARACTER*4 IMENSE
!
!-----COMMON----------------------------------------------------------
!
      INCLUDE 'DPCOPA.INC'
      INCLUDE 'DPCOMC.INC'
      INCLUDE 'DPCOPC.INC'
      INCLUDE 'DPCODG.INC'
      INCLUDE 'DPCOST.INC'
!CCCC THE FOLLOWING LINE WAS INSERTED APRIL 1989
      INCLUDE 'DPCONP.INC'
!
!-----COMMON VARIABLES (GENERAL)--------------------------------------
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IF(IBUGIN.EQ.'ON')THEN
        WRITE(ICOUT,90)
   90   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,95)
   95   FORMAT('***** AT THE BEGINNING OF INITPC--')
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               ***********************
!               **  DEFINE DEFAULTS  **
!               ***********************
!
!     THE FOLLOWING CHANGE WAS MADE AT THE SUGGESTION
!     OF MIKE STOLNICKI
!
!CCCC IDEFGC='RED'
!CCCC AUGUST 1992.  DEFAULT BACKGROUND IS WHITE, SET TO BLACK
!CCCC IDEFGC='WHIT'
      IDEFGC='BLAC'
!
      IDEFPA='SOLI'
      IDEFFO='TEKT'
      IDEFCA='UPPE'
      IDEFJU='LEFT'
      IDEFDI='HORI'
      IDEFAU='RADI'
      IDEFFI='OFF'
      IDEFCO=IDEFGC
!CCCC THE FOLLOWING LINE WAS ADDED         DECEMBER 1994
!CCCC IDCMAP = DEFAULT CHARACTER MAPPING   DECEMBER 1994
      IDCMAP='RANK'
!CCCC THE FOLLOWING LINE WAS ADDED         DECEMBER 1999
      IDEFUZ='SCRE'
!
      IDEFDP=(-1)
!
      PDEFHE=2.0
!CCCC PDEFWI=1.5
      PDEFWI=1.0
!CCCC PDEFVG=1.0
      PDEFVG=0.75
!CCCC PDEFHG=0.75
      PDEFHG=0.25
      ADEFAN=0.0
      PDEFTH=0.1
      PDEFLE=1.0
!     FEBRUARY, 1988: INITIALIZE CHARACTER OFFSET
      PDEFOF=0.0
!
!CCCC PDEFDS=3.5
      PDEFDS=3.0
!
!CCCC THE FOLLOWING LINE WAS FIXED TO CURE INVISIBLE TEK 4115 BOXES APRIL 1989
!CCCC IDEFXC='BLUE'
!CCCC AUGUST 1992.  DEFAULT BACKGROUND IS WHITE, SET TO BLACK
!CCCC IDEFXC='WHIT'
      IDEFXC='BLAC'
      PDEFGA=1.0
!CCCC TEKTRONIX CHARACTER CUTOFFS ARE 2.75 2.2 1.65
!
      PDEFL2=1.0
      PDEFL3=1.0
      PDEFGA=1.0
      PDEFG2=1.0
      PDEFG3=1.0
!
      IDEFCR='ON'
      IDEFLF='ON'
!CCCC THE FOLLOWING LINE WAS FIXED (SOFT-CODE BACKSLASH) APRIL 1989
      IDEFSY=IBASLC
      IDEFSP='PROP'
      PDEFMR=50.0
!
!CCCC THE FOLLOWING 2 LINES WERE ADDED AUGUST 1992
!CCCC FOR BOX SHADOW HEIGHT & WIDTH AUGUST 1992
      PDEFSH=0.8
      PDEFSW=0.6
!
!               ****************************
!               **  TREAT THE ARROW CASE  **
!               ****************************
!
!     MAXARR=100
      MAXARR=MAXAR
      NUMARR=0
!
      DO 100 I=1,MAXARR
        IARRPA(I)=IDEFPA
        IARRCO(I)=IDEFCO
        IARRC2(I,1)=-1
        IARRC2(I,2)=-1
        IARRC2(I,3)=-1
        IARHFI(I)=IDEFFI
        PARRTH(I)=PDEFTH
        PARHLE(I)=PDEFWI
        PARHWI(I)=PDEFWI
        PARRXC(I,1)=CPUMIN
        PARRXC(I,2)=CPUMIN
        PARRYC(I,1)=CPUMIN
        PARRYC(I,2)=CPUMIN
  100 CONTINUE
!
!               ***************************************************
!               **  TREAT THE BACKGROUND AND MARGIN COLORS CASE  **
!               ***************************************************
!
!CCCC THE FOLLOWING LINE WAS FIXED JUNE 1992 (JJF)
!CCCC TO ACCOMODATE TURBO C FRONT END WHITE BACKGROUND JUNE 1992 (JJF)
!CCCC IDEFBK='BLUE'
      IDEFBK='WHIT'
      IBACCO=IDEFBK
      IBACC2(1)=-1
      IBACC2(2)=-1
      IBACC2(3)=-1
!
!CCCC AUGUST 1992.  MAKE MARGIN SAME COLOR AS BACKGROUND
!CCCC MARCH  2021.  MAKE DEFAULT MARGIN COLOR "NULL" TO INDICATE
!CCCC               MARGIN SHOULD BE SAME COLOR AS BACKGROUND
!
!CCCC IDEFMC='BLUE'
!CCCC IDEFMC='BLUE'
!CCCC IDEFMC='WHIT'
      IDEFMC='NULL'
      IMARCO=IDEFMC
      IMARC2(1)=-1
      IMARC2(2)=-1
      IMARC2(3)=-1
!
!CCCC THE FOLLOWING ANIMATION CHUNCK WAS ADDED APRIL 1989
!               **************************************************
!               **  TREAT THE ANIMATION SWITCH CASE             **
!               **************************************************
!
      IANISW='OFF'
!
!               **************************
!               **  TREAT THE BOX CASE  **
!               **************************
!
!     MAXBOX=100
      MAXBOX=MAXBX
      NUMBOX=0
!
      DO 500 I=1,MAXBOX
        IBOBFI(I)=IDEFFI
        IBOBCO(I)=IDEFCO
        IBOBC2(I,1)=-1
        IBOBC2(I,2)=-1
        IBOBC2(I,3)=-1
        IBOPPA(I)=IDEFPA
!CCCC   AUGUST 1992.  FOLLOWING LINE MODIFIED
!CCCC   IBOPCO(I)=IDEFCO
        IBOBPA(I)=IDEFPA
!CCCC   AUGUST 1992. FOLLOWING LINE MODIFIED
!CCCC   IBOFPA(I)=IDEFPA
        IBOFPA(I)=IDEFFI
        IBOFCO(I)=IDEFXC
        IBOFC2(I,1)=-1
        IBOFC2(I,2)=-1
        IBOFC2(I,3)=-1
        PBOPTH(I)=PDEFTH
        PBOPGA(I)=PDEFGA
        PBOFTH(I)=PDEFTH
!CCCC   THE FOLLOWING 2 LINES WERE ADDED AUGUST 1992
!CCCC   FOR BOX SHADOW HEIGHT & WIDTH AUGUST 1992
        PBOSHE(I)=PDEFSH
        PBOSWI(I)=PDEFSW
        PBOXXC(I,1)=CPUMIN
        PBOXXC(I,2)=CPUMIN
        PBOXYC(I,1)=CPUMIN
        PBOXYC(I,2)=CPUMIN
  500 CONTINUE
!
!               *********************************
!               **  TREAT THE CHARACTERS CASE  **
!               *********************************
!
!     MAXCHA=100
      MAXCHA=MAXCH2
!CCCC THE FOLLOWING LINE WAS ADDED     DECEMBER 1994
!CCCC ICHMAP = CHARACTER MAPPING       DECEMBER 1994
      ICHMAP=IDCMAP
!
      DO 700 I=1,MAXCHA
        ICHAPA(I)='    '
!CCCC   ADD FOLLOWING LINE FEBRUARY 1998.
        ICHAPO(I)='    '
        ICHAFO(I)=IDEFFO
        ICHACA(I)=IDEFCA
        ICHAJU(I)='CECE'
        ICHADI(I)=IDEFDI
        ICHAFI(I)=IDEFFI
        ICHACO(I)=IDEFCO
        ICHAC2(I,1)=-1
        ICHAC2(I,2)=-1
        ICHAC2(I,3)=-1
        ICHATY(I)='DD'
        PCHAHE(I)=PDEFHE
        PCHAWI(I)=PDEFWI
        PCHAVG(I)=PDEFVG
        PCHAHG(I)=PDEFHG
        PCHATH(I)=PDEFTH
        ACHAAN(I)=ADEFAN
        PCHAHO(I)=PDEFOF
        PCHAVO(I)=PDEFOF
  700 CONTINUE
!
!               *********************************
!               **  TREAT THE CROSS-HAIR CASE  **
!               *********************************
!
!               ****************************
!               **  TREAT THE FRAME CASE  **
!               ****************************
!
      IX1FSW='ON'
      IX2FSW='ON'
      IY1FSW='ON'
      IY2FSW='ON'
!
      IX1FPA=IDEFPA
      IX2FPA=IDEFPA
      IY1FPA=IDEFPA
      IY2FPA=IDEFPA
!
      IX1FCO=IDEFCO
      IX2FCO=IDEFCO
      IY1FCO=IDEFCO
      IY2FCO=IDEFCO
      IX1FC2(1)=-1
      IX1FC2(2)=-1
      IX1FC2(3)=-1
      IX2FC2(1)=-1
      IX2FC2(2)=-1
      IX2FC2(3)=-1
      IY1FC2(1)=-1
      IY1FC2(2)=-1
      IY1FC2(3)=-1
      IY2FC2(1)=-1
      IY2FC2(2)=-1
      IY2FC2(3)=-1
!
      PFRATH=PDEFTH
!
!               *****************************
!               **  TREAT THE LIMITS CASE  **
!               *****************************
!
      PXMIN=15.0
      PYMIN=20.0
      PXMAX=85.0
      PYMAX=90.0
!
      PWXMIN=0.0
      PWYMIN=0.0
      PWXMAX=100.0
      PWYMAX=100.0
!
      IX1MIN='FLOA'
      IX1MAX='FLOA'
      IY1MIN='FLOA'
      IY1MAX='FLOA'
      IZ1MIN='FLOA'
      IZ1MAX='FLOA'
!
      IX2MIN='FLOA'
      IX2MAX='FLOA'
      IY2MIN='FLOA'
      IY2MAX='FLOA'
      IZ2MIN='FLOA'
      IZ2MAX='FLOA'
!
