        IPATC2(I,2)=-1
        IPATC2(I,3)=-1
        PPATHE(I)=PDEFPH
        PPATWI(I)=PDEFPW
        PPATSP(I)=PDEFPS
        PPATTH(I)=PDEFPT
 1200 CONTINUE
!
!               ****************************
!               **  STEP XX--             **
!               **  TREAT THE SPIKE CASE  **
!               ****************************
!
      IDEFSS='OFF'
      IDEFSL='SOLI'
      IDEFSC=IDEFGC
      IDEFSD='V'
      PDEFST=0.1
      ADEFSB=0.0
!     MAXSPI=100
      MAXSPI=MAXSP
!
      DO 1300 I=1,MAXSPI
        ISPISW(I)=IDEFSS
        ISPILI(I)=IDEFSL
        ISPICO(I)=IDEFSC
        ISPIC2(I,1)=-1
        ISPIC2(I,2)=-1
        ISPIC2(I,3)=-1
        ISPIDI(I)=IDEFSD
        PSPITH(I)=PDEFST
        ASPIBA(I)=ADEFSB
 1300 CONTINUE
!
!      ----------BARS----------------------------------------------
!
!               ****************************
!               **  STEP XX--             **
!               **  TREAT THE BARS  CASE  **
!               ****************************
!
      IDEBSW='OFF'
      IDEBBL='SOLI'
      IDEBBC=IDEFGC
      IDEBFS='OFF'
      IDEBFC=IDEFGC
      IDEBPT='SOLI'
      IDEBPL='SOLI'
      IDEBPC=IDEFGC
      IDEBTY='2'
      IDEBDI='V'
      ADEBBA=0.0
      ADEBWI=CPUMIN
      PDEBBT=0.1
      PDEBPT=0.1
      PDEBPS=1.0
!     MAXBAR=100
      MAXBAR=MAXBA
!
      DO 1400 I=1,MAXBAR
        IBARSW(I)=IDEBSW
        IBABLI(I)=IDEBBL
        IBABCO(I)=IDEBBC
        IBABC2(I,1)=-1
        IBABC2(I,2)=-1
        IBABC2(I,3)=-1
        IBAFSW(I)=IDEBFS
        IBAFCO(I)=IDEBFC
        IBAFC2(I,1)=-1
        IBAFC2(I,2)=-1
        IBAFC2(I,3)=-1
        IBAPTY(I)=IDEBPT
        IBAPLI(I)=IDEBPL
        IBAPCO(I)=IDEBPC
        IBAPC2(I,1)=-1
        IBAPC2(I,2)=-1
        IBAPC2(I,3)=-1
        IBARTY(I)=IDEBTY
        IBARDI(I)=IDEBDI
        ABARBA(I)=ADEBBA
        ABARWI(I)=ADEBWI
        PBABTH(I)=PDEBBT
        PBAPTH(I)=PDEBPT
        PBAPSP(I)=PDEBPS
 1400 CONTINUE
!
!     ----------END OF BARS-------------------------------------------------
!
!      ----------REGIONS----------------------------------------------
!
!               *******************************
!               **  STEP XX--                **
!               **  TREAT THE REGIONS  CASE  **
!               *******************************
!
      IDERSW='OFF'
      IDERBL='SOLI'
      IDERBC=IDEFGC
      IDERFS='OFF'
      IDERFC=IDEFGC
      IDERPT='SOLI'
      IDERPL='SOLI'
      IDERPC=IDEFGC
      ADERBA=0.0
      ADERWI=CPUMIN
      PDERBT=0.1
      PDERPT=0.1
      PDEBPS=1.0
!CCCC THE FOLLOWING LINE WAS INSERTED JANUARY 1989
!CCCC TO FIX INFINITE LOOP IN GRFIRE IN NON-SOLID REGION FILL (JANUARY 1989)
!CCCC DEFINE DEFAULT REGION PATTERN SPACING (JANUARY 1989)
      PDERPS=1.0
!
!     MAXREG=100
      MAXREG=MAXRG
!
      DO 1500 I=1,MAXREG
        IREGSW(I)=IDERSW
        IREBLI(I)=IDERBL
        IREBCO(I)=IDERBC
        IREBC2(I,1)=-1
        IREBC2(I,2)=-1
        IREBC2(I,3)=-1
        IREFSW(I)=IDERFS
        IREFCO(I)=IDERFC
        IREFC2(I,1)=-1
        IREFC2(I,2)=-1
        IREFC2(I,3)=-1
        IREPTY(I)=IDERPT
        IREPLI(I)=IDERPL
        IREPCO(I)=IDERPC
        IREPC2(I,1)=-1
        IREPC2(I,2)=-1
        IREPC2(I,3)=-1
        AREGBA(I)=ADERBA
        AREGWI(I)=ADERWI
        PREBTH(I)=PDERBT
        PREPTH(I)=PDERPT
        PBAPSP(I)=PDEBPS
!CCCC   THE FOLLOWING LINE WAS INSERTED JANUARY 1989
!CCCC   TO FIX INFINITE LOOP IN GRFIRE IN NON-SOLID REGION FILL (JANUARY 1989)
        PREPSP(I)=PDERPS
 1500 CONTINUE
!CCCC OCTOBER 1993.  ADD FOLLOWING LINE
      IREBIN='OFF'
!CCCC MARCH 1994.  ADD FOLLOWING LINE
      IREBPL='OFF'
!
!     ----------END OF REGIONS----------------------------------------
!
!      ----------MARKERS----------------------------------------------
!
!               *******************************
!               **  STEP XX--                **
!               **  TREAT THE MARKERS  CASE  **
!               *******************************
!
      IDEMSW='OFF'
      IDEMBL='SOLI'
      IDEMBC=IDEFGC
      IDEMFS='OFF'
      IDEMFC=IDEFGC
      IDEMPT='SOLI'
      IDEMPL='SOLI'
      IDEMPC=IDEFGC
      ADEMBA=0.0
      ADEMWI=CPUMIN
      PDEMBT=0.1
      PDEMPT=0.1
      PDEBPS=1.0
!     MAXMAR=100
      MAXMAR=MAXMR
!
      DO 1600 I=1,MAXMAR
        IMARSW(I)=IDEMSW
        IMABLI(I)=IDEMBL
        IMABCO(I)=IDEMBC
        IMABC2(I,1)=-1
        IMABC2(I,2)=-1
        IMABC2(I,3)=-1
        IMAFSW(I)=IDEMFS
        IMAFCO(I)=IDEMFC
        IMAFC2(I,1)=-1
        IMAFC2(I,2)=-1
        IMAFC2(I,3)=-1
        IMAPTY(I)=IDEMPT
        IMAPLI(I)=IDEMPL
        IMAPCO(I)=IDEMPC
        IMAPC2(I,1)=-1
        IMAPC2(I,2)=-1
        IMAPC2(I,3)=-1
        AMARBA(I)=ADEMBA
        AMARWI(I)=ADEMWI
        PMABTH(I)=PDEMBT
        PMAPTH(I)=PDEMPT
        PMAPSP(I)=PDEBPS
 1600 CONTINUE
!
!     ----------END OF MARKERS-------------------------------------------------
!
!      ----------TEXTS----------------------------------------------
!
!               *****************************
!               **  STEP XX--              **
!               **  TREAT THE TEXTS  CASE  **
!               *****************************
!
      IDETSW='OFF'
      IDETBL='SOLI'
      IDETBC=IDEFGC
      IDETFS='OFF'
      IDETFC=IDEFGC
      IDETPT='SOLI'
      IDETPL='SOLI'
      IDETPC=IDEFGC
      ADETBA=0.0
      ADETWI=CPUMIN
      PDETBT=0.1
      PDETPT=0.1
      PDEBPS=1.0
!     MAXTEX=100
      MAXTEX=MAXTX
!
      DO 1700 I=1,MAXTEX
        ITEXSW(I)=IDETSW
        ITEBLI(I)=IDETBL
        ITEBCO(I)=IDETBC
        ITEBC2(I,1)=-1
        ITEBC2(I,2)=-1
        ITEBC2(I,3)=-1
        ITEFSW(I)=IDETFS
        ITEFCO(I)=IDETFC
        ITEFC2(I,1)=-1
        ITEFC2(I,2)=-1
        ITEFC2(I,3)=-1
        ITEPTY(I)=IDETPT
        ITEPLI(I)=IDETPL
        ITEPCO(I)=IDETPC
        ITEPC2(I,1)=-1
        ITEPC2(I,2)=-1
        ITEPC2(I,3)=-1
        ATEXBA(I)=ADETBA
        ATEXWI(I)=ADETWI
        PTEBTH(I)=PDETBT
        PTEPTH(I)=PDETPT
        PTEPSP(I)=PDEBPS
 1700 CONTINUE
!
!     ----------END OF TEXTS-------------------------------------------------
!
!               ****************************************************
!               **  TREAT THE START CHARACTER/END CHARACTER CASE  **
!               ****************************************************
!
      PXSTAR=50.0
      PYSTAR=50.0
!
      PXEND=50.0
      PYEND=50.0
!
      ITEXCR=IDEFCR
      ITEXLF=IDEFLF
      PTEXMR=PDEFMR
!
      ITEXSY=IDEFSY
      ITEXSP=IDEFSP
!  FOLLOWING ADDED MAY,1988.
!
!               ****************************************************
!               **  TREAT THE ORIENTATION                   CASE  **
!               ****************************************************
!
      IORNSW='FULL'
!
!CCCC THE FOLLOWING SECTION WAS ADDED AUGUST 1990
!               **************************************************
!               **  TREAT THE WINDOW MANAGER CASE               **
!               **  TREAT THE MENU SELECTOR CASE                **
!               **************************************************
!
      IDEFWM='GENE'
      IWINMA=IDEFWM
      IDEFMS='NUMB'
      IMENSE=IDEFMS
!
!CCCC THE FOLLOWING SECTION WAS ADDED SEPTEMBER 1998
!               **************************************************
!               **  TREAT THE MULTIPLOT SCALE FACTOR CASE       **
!               **************************************************
!
      AMPSCH=1.0
      AMPSCW=1.0
!
!CCCC THE FOLLOWING SECTION WAS ADDED NOVEMBER 1999
!               **************************************************
!               **  TREAT THE SUBREGIONS             CASE       **
!               **************************************************
!
      IDEFSB='OFF'
      ISUBNU=0
      DO 1800 I=1,MAXSUB
        ISUBSW(I)=IDEFSB
        ISUBTY(I)='BOX'
        ASUBXL(I)=CPUMIN
        ASUBXU(I)=CPUMAX
        ASUBYL(I)=CPUMIN
        ASUBYU(I)=CPUMAX
 1800 CONTINUE
!
!CCCC THE FOLLOWING SECTION WAS ADDED MAY 2015
!               **************************************************
!               **  TREAT THE EMBED                  CASE       **
!               **************************************************
!
      IEMBSW='OFF'
      IEMBJH='LEFT'
      IEMBJV='BOTT'
!
      IEMCNT=0
!
      PEMXC1=CPUMIN
      PEMXC2=CPUMIN
      PEMXY1=CPUMIN
      PEMXY2=CPUMIN
      PEMXMN=CPUMIN
      PEMXMX=CPUMIN
      PEMYMN=CPUMIN
      PEMYMX=CPUMIN
      PEMHEI=CPUMIN
      PEMWID=CPUMIN
      PEMPOX=CPUMIN
      PEMPOY=CPUMIN
!
!               *******************************
!               **  EXIT AND RETURN TO MAIN  **
!               *******************************
!
      IF(IBUGIN.EQ.'ON')THEN
        WRITE(ICOUT,9990)
 9990   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9995)
 9995   FORMAT('***** AT THE END       OF INITPC--')
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE INITPC
      SUBROUTINE PRINFI(FILE1,IFTYPE,IBUGS2,ISUBRO,IERROR)
!
!     PURPOSE--COPY A FILE TO THE PRINTER
!
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--92/4
!     ORIGINAL VERSION--MARCH     1992.
!     UPDATED         --APRIL     1992. MAKE HOST DEPENDENT (ALAN)
!                                       USE DPSYS2 TO MAKE OPERATING
!                                       SYSTEM DEPENDENT CALL
!     UPDATED         --MAY       1992. COPY --> PRINT FOR PC
!     UPDATED         --JANUARY   1994. NOTE--PRINTING VAX/ALPHA
!     UPDATED         --AUGUST    1997. FOR WINDOWS 95, USE COPY
!                                       INSTEAD OF PRINT
!     UPDATED         --FEBRUARY  1998. SUPPORT USE OF SET PRINTER
!                                       FOR UNIX AND WINDOWS 95/NT
!     UPDATED         --NOVEMBER  1998. SUPPORT NEW LAHEY COMPILER
!     UPDATED         --NOVEMBER  2002. FOR PC, USE GSPRINT COMMAND
!                                       (REQUIRES GS 6.50 OR HIGHER)
!     UPDATED         --NOVEMBER  2015. SOME TWEAKS FOR WINDOWS
!     UPDATED         --MARCH     2019. SET SYSTEM PERSIST
!                                       SET SYSTEM HIDDEN
!     UPDATED         --MARCH     2019. RECODE
!     UPDATED         --MARCH     2019. FOR WINDOWS, USE WORDPAD TO
!                                       PRINT
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      INCLUDE 'DPCOPA.INC'
!
!CCCC CHARACTER*80 FILE1
!CCCC CHARACTER*80 FILE2
      CHARACTER (LEN=*) :: FILE1
      CHARACTER (LEN=MAXFNC) :: FILE2
      CHARACTER*4 IFTYPE
      CHARACTER*4 IBUGS2
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
!
      CHARACTER*1 IQUOTE
      CHARACTER*4 ISSAV1
      CHARACTER*4 ISSAV2
      CHARACTER*512 ISTRIN
!
!-----COMMON VARIABLES (GENERAL)--------------------------------------
!
!  APRIL 1992.  ADD HOST INCLUDE FILE
!
      INCLUDE 'DPCOHO.INC'
      INCLUDE 'DPCOST.INC'
      INCLUDE 'DPCONP.INC'
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IF(IBUGS2.EQ.'ON'.OR.ISUBRO.EQ.'INFI')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF PRINFI--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)IBUGS2,ISUBRO,IERROR,ISYSPE,ISYSHI
   53   FORMAT('IBUGS2,ISUBRO,IERROR,ISYSPE,ISYSHI = ',4(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,54)FILE1(1:80)
   54   FORMAT('FILE1 = ',A80)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,61)IHOST1,IHMOD1,IOPSY1,ICOMPI,ISITE
   61   FORMAT('HOST,MODEL,OP-SYS,COMPILER,SITE = ',4(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,67)IPRNGS,IFTYPE
   67   FORMAT('IPRNGS,IFTYPE = ',A4,2X,A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!     2019/03: IF FILE CONTAINS A SPACE, THEN MAKE SURE FILE NAME IS
!              QUOTED.
!
!              STEP 1: CHECK FOR SPACE IN FILE NAME
!
      CALL STRLEZ(FILE1,MAXFNC,N1)
      IFLAG=0
      DO 120 II=1,N1
        IF(FILE1(II:II).EQ.' ')THEN
          IF(FILE1(1:1).NE.'"' .OR. FILE1(N1:N1).NE.'"')THEN
            IFLAG=1
          ENDIF
          GO TO 129
        ENDIF
  120 CONTINUE
  129 CONTINUE
!
!              STEP 2: ENCLOSE IN QUOTES IF NEEDED
!
      IF(IFLAG.EQ.1 .AND. FILE1(1:1).NE.'"')THEN
        DO 130 II=N1,1,-1
          FILE1(II+1:II+1)=FILE1(II:II)
  130   CONTINUE
        FILE1(1:1)='"'
        FILE1(N1+2:N1+2)='"'
        N1=N1+2
      ENDIF
!
!  APRIL 1992.  ADD HOST DEPENDENT BRANCH
!
!               ********************************
!               **  STEP 1--                  **
!               **  STEP THROUGH EACH HOST    **
!               ********************************
!
      ISTRIN=' '
      IQUOTE='"'
      IBASLC=CHAR(92)
!
      IF(IHOST1.EQ.'IBM-')THEN
!
!               **************************************
!               **  STEP 2A--                       **
!               **  IBM/PC 386 WITH INTEL COMPILER  **
!               **  USE COPY INSTEAD OF PRINT!      **
!               **  ALSO USE PRINTER ID             **
!               **************************************
!
!       MARCH 2019: USE WORDPAD TO PRINT TO DEFAULT PRINTER
!
!                      WRITE.EXE /p <filename>
!
!                   (EARLIER METHODS REQUIRED SETTING THE PRINTER, ALSO
!                   GSPRINT IS ONLY FOR POSTSCRIPT/PDF FILES).
!
!                   THIS COULD ALSO BE DONE USING "NOTEPAD /p".  HOWEVER,
!                   WORDPAD SUPPORTS A GREATER NUMBER OF FILE TYPES (E.G.,
!                   RTF, DOC) AND CAN HANDLE LINUX/MAC LINE FEED/CARRIAGE
!                   RETURN CONVENTIONS.
!
!                   THE PP COMMAND IS USED TO PRINT A POSTSCRIPT FILE.
!                   USE THE COMMAND (2002/11):
!
!                      GSPRINT.EXE -printer "printer-name"   file-name
!
!                   2015/11: MAKE A FEW TWEAKS.
!
!                       1. IF PRINTER IS SET TO "DEFAULT" OR "NULL",
!                          OMIT THE -printer OPTION.
!
!                       2. IF PRINTER IS SET TO "PRN:", "LPT1:", OR
!                          "LPT2:", USE "-port" INSTEAD OF "-printer".
!
!                       3. MAKE SURE PRINTER NAME IS ENCLOSED IN QUOTES.
!
!                   FOR POSTSCRIPT, ALWAYS USE THE GSPRINT METHOD.
!                   THE "COPY" METHOD IS NO LONGER SUPPORTED.
!
        IF(IFTYPE.EQ.'ASCI')THEN
!
!         ASCII FILE: USE WORDPAD
!
          N0=1
          ISTRIN(N0:N0+12)='WRITE.EXE /p '
          N0=N0+12
          ISTRIN(N0+1:N0+N1)=FILE1(1:N1)
          N0=N0+N1
!
          ISSAV1=ISYSPE
          ISSAV2=ISYSHI
          ISYSPE='OFF'
          ISYSHI='ON'
          IF(IFLAG.EQ.1)ISYSHI='OFF'
          CALL DPSYS2(ISTRIN,N0,ISUBRO,IERROR)
          ISYSPE=ISSAV1
          ISYSHI=ISSAV2
        ELSE
!
!         POSTSCRIPT FILE: USE WORDPAD
!
          N0=0
          IF(IGSVPA(1:1).NE.IQUOTE)THEN
            ISTRIN(1:1)=IQUOTE
            ISTRIN(2:NCGSPA+1)=IGSVPA(1:NCGSPA)
            N0=NCGSPA+1
          ELSE
            ISTRIN(1:NCGSPA)=IGSVPA(1:NCGSPA)
            N0=NCGSPA
          ENDIF
          IF(IGSVPA(NCGSPA:NCGSPA).NE.IBASLC)THEN
            N0=N0+1
            ISTRIN(N0:N0)=IBASLC
          ENDIF
          N0=N0+1
          ISTRIN(N0:N0+10)='GSPRINT.EXE'
          N0=N0+10
          IF(IGSVPA(1:1).NE.IQUOTE)THEN
            N0=N0+1
            ISTRIN(N0:N0)=IQUOTE
          ENDIF
          N0=N0+1
          ISTRIN(N0:N0)=' '
          FILE2=' '
!
          IF(IPRNTR(1:7).EQ.'DEFAULT' .OR. IPRNTR(1:4).EQ.'NULL')THEN
            CONTINUE
          ELSEIF(IPRNTR(1:7).EQ.'default'.OR.IPRNTR(1:4).EQ.'null')THEN
            CONTINUE
          ELSEIF(IPRNTR(1:4).EQ.'PRN:' .OR. IPRNTR(1:4).EQ.'prn:')THEN
            N0=N0+1
            ISTRIN(N0:N0+10)='-port PRN: '
            N0=N0+10
          ELSEIF(IPRNTR(1:5).EQ.'LPT1:' .OR. IPRNTR(1:5).EQ.'lpt1:')THEN
            N0=N0+1
            ISTRIN(N0:N0+11)='-port LPT1: '
            N0=N0+11
          ELSEIF(IPRNTR(1:5).EQ.'LPT2:' .OR. IPRNTR(1:5).EQ.'lpt2:')THEN
            N0=N0+1
            ISTRIN(N0:N0+11)='-port LPT2: '
            N0=N0+11
          ELSEIF(NCPRNT.GT.0)THEN
            N0=N0+1
            ISTRIN(N0:N0+8)='-printer '
            N0=N0+8
            IF(IPRNTR(1:1).NE.IQUOTE)THEN
              FILE2(1:1)=IQUOTE
              FILE2(2:NCPRNT+1)=IPRNTR(1:NCPRNT)
              N2=NCPRNT+1
              IF(IPRNTR(NCPRNT:NCPRNT).NE.IQUOTE)THEN
                N2=N2+1
                FILE2(N2:N2)=IQUOTE
              ENDIF
            ELSE
              N2=NCPRNT
              FILE2(1:N2)=IPRNTR(1:N2)
              IF(IPRNTR(NCPRNT:NCPRNT).NE.IQUOTE)THEN
                N2=N2+1
                FILE2(N2:N2)=IQUOTE
              ENDIF
            ENDIF
            CALL STRLEZ(FILE2,MAXFNC,N2)
            ISTRIN(N0+1:N0+1+N2)=FILE2(1:N2)
            N0=N0+1+N2
            N0=N0+1
            ISTRIN(N0:N0)=' '
          ENDIF
!
          CALL STRLEZ(FILE1,MAXFNC,N1)
          N0=N0+1
          ISTRIN(N0:N0+N1)=FILE1(1:N1)
          N0=N0+N1
!
          IF(IBUGS2.EQ.'ON'.OR.ISUBRO.EQ.'INFI')THEN
            WRITE(ICOUT,999)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,1111)
 1111       FORMAT('***** FROM THE MIDDLE OF PRINFI--')
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,1112)FILE1(1:80)
 1112       FORMAT('FILE1 = ',A80)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,1113)FILE2(1:80)
 1113       FORMAT('FILE2 = ',A80)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,1114)N0,N1,N2
 1114       FORMAT('N0,N1,N2 = ',3I8)
            CALL DPWRST('XXX','BUG ')
            WRITE(ICOUT,1115)ISTRIN(1:110)
 1115       FORMAT('ISTRIN = ',A110)
            CALL DPWRST('XXX','BUG ')
          ENDIF
!
          CALL DPSYS2(ISTRIN,N0,ISUBRO,IERROR)
        ENDIF
      ELSEIF(IOPSY1.EQ.'UNIX')THEN
!
!               ************************************
!               **  STEP 2C--                     **
!               **  UNIX OPERATING SYSTEM         **
!               **  USE  lpr  TO DEFAULT PRINTER. **
!               ************************************
!
!CCCC   ADD SUPPORT FOR SET PRINTER COMMAND     FEBRUARY 1998.
!
        IF(NCPRNT.LE.0)THEN
          N0=4
          ISTRIN(1:N0)='lpr '
        ELSE
          N0=6
          ISTRIN(1:N0)='lpr -P'
          N0=N0+1
          ISTRIN(N0+1:N0+NCPRNT)=IPRNTR(1:NCPRNT)
          N0=N0+NCPRNT+1
          ISTRIN(N0:N0)=' '
        ENDIF
!
        ISTRIN(N0+1:N0+N1)=FILE1(1:N1)
        N0=N0+N1+1
        ISTRIN(N0:N0)=' '
        CALL DPSYS2(ISTRIN,N0,ISUBRO,IERROR)
      ELSEIF(IHOST1.EQ.'NVE')THEN
!
!               ********************************
!               **  STEP 2B--                 **
!               **  CYBER WITH NOS/VE         **
!               **  USE PRINT_FILE TO DEFAULT **
!               **  PRINTER.  NO PROVISION YET**
!               **  FOR NAMING PRINTER.       **
!               ********************************
!
        N0=11
        ISTRIN(1:N0)='PRINT_FILE '
        ISTRIN(N0+1:N0+N1)=FILE1(1:N1)
        N0=N0+N1+1
        ISTRIN(N0:N0)=' '
        CALL DPSYS2(ISTRIN,N012,ISUBRO,IERROR)
      ELSEIF(IHOST1.EQ.'VAX')THEN
!
!               ********************************
!               **  STEP 2D--                 **
!               **  VAX/VMS                   **
!               **  USE PRINT.    USE DEFAULT **
!               **  PRINTER.  NO PROVISION YET**
!               **  FOR NAMING PRINTER.       **
!               ********************************
!
!     NOTE--ON A VAX OR AN ALPHA (RUNNING VMS),      JANUARY 1994
!           TO MAKE THE    PP   (PRINT A PLOT)       JANUARY 1994
!           COMMAND WORK, THEN THE STRING            JANUARY 1994
!              PRINT DPPL2F.DAT                      JANUARY 1994
!           SHOULD GET CHANGED TO                    JANUARY 1994
!              PRINT /QUEUE=something DPPL2F.DAT     JANUARY 1994
!           (E.G., PRINT/QUEUE=DPPRINTER DPPL2F.DAT) JANUARY 1994
!           AND THEN HAVE THE ANALYST DEFINE         JANUARY 1994
!           DPPRINTER (VIA  ASSIGN DPPRINTER = etc.) JANUARY 1994
!           EITHER OUTSIDE OF DATAPLOT               JANUARY 1994
!           IN HIS/HER VAX LOGIN FILE, OR            JANUARY 1994
!           INSIDE DATAPLOT VIA                      JANUARY 1994
!           DATAPLOT'S     SYSTEM     COMMAND        JANUARY 1994
!           (E.G., SYSTEM ASSIGN DPPRINTER = etc.)   JANUARY 1994
!
!               ********************************
!
!
        N0=6
        ISTRIN(1:N0)='PRINT '
        ISTRIN(N0+1:N0+N1)=FILE1(1:N1)
        N0=N0+N1+1
        ISTRIN(N0:N0)=' '
        CALL DPSYS2(ISTRIN,N0,ISUBRO,IERROR)
      ELSE
!
!               ********************************
!               **  STEP 2E--                 **
!               **  UNSUPPORTED SYSTEMS.      **
!               ********************************
!
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,8011)
 8011   FORMAT('THE PRINT FILE CAPABILITY NOT SUPPORTED')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,8012)IHOST1
 8012   FORMAT('ON HOST ',A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,8013)
 8013   FORMAT('CONTACT YOUR SITE INSTALLER.')
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
      IF(IBUGS2.EQ.'ON'.OR.ISUBRO.EQ.'INFI')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF PRINFI--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9013)IERROR
 9013   FORMAT('IERROR = ',A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9015)FILE1(1:80)
 9015   FORMAT('FILE1 = ',A80)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9017)FILE2(1:80)
 9017   FORMAT('FILE2 = ',A80)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9019)N0,N1,N2
 9019   FORMAT('N0,N1,N2,N012 = ',4I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9021)ISTRIN(1:MIN(255,N0))
 9021   FORMAT('ISTRIN = ',A255)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9023)IPRNGS
 9023   FORMAT('IPRNGS = ',A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE PRINFI
      SUBROUTINE COPYFI(FILE1,FILE2,IBUGS2,ISUBRO,IERROR)
!
!     PURPOSE--COPY A FILE TO ANOTHER FILE
!
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--92/4
!     ORIGINAL VERSION--MARCH     1992.
!     UPDATED         --APRIL     1992. ADD OPERATING SYSTEM BRANCHES
!     UPDATED         --MARCH     2019. SET SYSTEM PERSIST
!                                       SET SYSTEM HIDDEN
!     UPDATED         --MARCH     2019. RECODE
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      INCLUDE 'DPCOPA.INC'
!
!CCCC CHARACTER*80 FILE1
!CCCC CHARACTER*80 FILE2
      CHARACTER (LEN=*) :: FILE1
      CHARACTER (LEN=*) :: FILE2
      CHARACTER*4 IBUGS2
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
      CHARACTER*4 ISSAV1
      CHARACTER*4 ISSAV2
!
!CCCC CHARACTER*255 ISTRIN
      CHARACTER (LEN=MAXSTR) :: ISTRIN
!
!-----COMMON VARIABLES (GENERAL)--------------------------------------
!
!  APRIL 1992.  ADD FOLLOWING INCLUDE FILE
!
      INCLUDE 'DPCOHO.INC'
      INCLUDE 'DPCOST.INC'
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IF(IBUGS2.EQ.'ON'.OR.ISUBRO.EQ.'PYFI')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF COPYFI--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)IBUGS2,ISUBRO,IERROR,ISYSPE,ISYSHI
   53   FORMAT('IBUGS2,ISUBRO,IERROR,ISYSPE,ISYSHI = ',4(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,54)FILE1(1:80)
   54   FORMAT('FILE1 = ',A80)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,55)FILE2(1:80)
   55   FORMAT('FILE2 = ',A80)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,61)IHOST1,IHMOD1,IOPSYS1,ICOMPI,ISITE
   61   FORMAT('HOST,MODEL,OP-SYS,ICOMPI,ISITE = ',4(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!     2019/03: CHECK FOR SPACES IN FILE NAME.  IF FOUND, THEN
!              QUOTE THE FILE NAME (BUT CHECK IF FILE NAME IS
!              ALREADY QUOTED).
!
      IFLAG=0
      CALL STRLEZ(FILE1,MAXFNC,N1)
      DO 110 II=1,N1
        IF(FILE1(II:II).EQ.' ')THEN
          IF(FILE1(1:1).NE.'"' .OR. FILE1(N1:N1).NE.'"')THEN
            IFLAG=1
          ENDIF
          GO TO 119
        ENDIF
  110 CONTINUE
  119 CONTINUE
!
      CALL STRLEZ(FILE2,MAXFNC,N2)
      DO 120 II=1,N2
        IF(FILE2(II:II).EQ.' ')THEN
          IF(FILE2(1:1).NE.'"' .OR. FILE2(N2:N2).NE.'"')THEN
            IFLAG=1
          ENDIF
          GO TO 129
        ENDIF
  120 CONTINUE
  129 CONTINUE
!
      IF(IFLAG.EQ.1)THEN
        DO 130 II=N1,1,-1
          FILE1(II+1:II+1)=FILE1(II:II)
  130   CONTINUE
        FILE1(1:1)='"'
        N1=N1+2
        FILE1(N1:N1)='"'
!
        DO 140 II=N2,1,-1
          FILE2(II+1:II+1)=FILE2(II:II)
  140   CONTINUE
        FILE2(1:1)='"'
        N2=N2+2
        FILE2(N2:N2)='"'
      ENDIF
!
      ISTRIN=' '
!
!     APRIL 1992.  ADD HOST DEPENDENT BRANCHES
!
!               ********************************
!               **  STEP 1--                  **
!               **  STEP THROUGH EACH HOST    **
!               ********************************
!
      IF(IHOST1.EQ.'IBM-')THEN
!
!               ********************************
!               **  STEP 2A--                 **
!               **  WINDOWS                   **
!               ********************************
!
        N0=5
        ISTRIN(1:N0)='COPY '
        ISTRIN(N0+1:N0+N1)=FILE1(1:N1)
        N0=N0+N1+1
        ISTRIN(N0:N0)=' '
        ISTRIN(N0+1:N0+N2)=FILE2(1:N2)
        N0=N0+N2
!
        IF(IHOST1.EQ.'IBM-'.AND.ICOMPI.EQ.'OTG ')THEN
!CCCC     CALL CISSUE(ISTRIN(1:N0),IFAIL)
!CCCC     IERROR='NO'
!CCCC     IF(IFAIL.EQ.1)IERROR='YES'
        ELSE
          ISSAV1=ISYSPE
          ISSAV2=ISYSHI
          ISYSPE='OFF'
          IF(IFLAG.EQ.0)THEN
            ISYSHI='ON'
          ELSE
            ISYSHI='OFF'
          ENDIF
          CALL DPSYS2(ISTRIN,N0,ISUBRO,IERROR)
          ISYSPE=ISSAV1
          ISYSHI=ISSAV2
        ENDIF
      ELSEIF(IHOST1.EQ.'NVE')THEN
!
!               ********************************
!               **  STEP 2B--                 **
!               **  CYBER WITH NOS/VE         **
!               **  USE COPY_FILE COMMAND     **
!               ********************************
!
!
        N0=10
        ISTRIN(1:N0)='COPY_FILE '
        ISTRIN(N0+1:N0+N1)=FILE1(1:N1)
        N0=N0+N1+1
        ISTRIN(N0:N0)=' '
        ISTRIN(N0+1:N0+N2)=FILE2(1:N2)
        N0=N0+N2
        CALL DPSYS2(ISTRIN,N0,ISUBRO,IERROR)
      ELSEIF(IOPSY1.EQ.'UNIX')THEN
!
!               ********************************
!               **  STEP 2C--                 **
!               **  UNIX OPERATING SYSTEM     **
!               **  USE cp        COMMAND     **
!               ********************************
!
        N0=3
        ISTRIN(1:N0)='cp '
        ISTRIN(N0+1:N0+N1)=FILE1(1:N1)
        N0=N0+N1+1
        ISTRIN(N0:N0)=' '
        ISTRIN(N0+1:N0+N2)=FILE2(1:N2)
        N0=N0+N2
        CALL DPSYS2(ISTRIN,N0,ISUBRO,IERROR)
      ELSEIF(IHOST1.EQ.'VAX')THEN
!
!               ********************************
!               **  STEP 2D--                 **
!               **  VAX/VMS                   **
!               **  USE COPY      COMMAND     **
!               ********************************
!
        N0=5
        ISTRIN(1:N0)='COPY '
        ISTRIN(N0+1:N0+N1)=FILE1(1:N1)
        N0=N0+N1+1
        ISTRIN(N0:N0)=' '
        ISTRIN(N0+1:N0+N2)=FILE2(1:N2)
        N0=N0+N2
        CALL DPSYS2(ISTRIN,N0,ISUBRO,IERROR)
      ELSE
!
!               ********************************
!               **  STEP 2E--                 **
!               **  UNSUPPORTED SYSTEMS.      **
!               ********************************
!
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,8011)
 8011   FORMAT('THE COPY FILE CAPABILITY NOT SUPPORTED')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,8012)IHOST1
 8012   FORMAT('ON HOST ',A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,8013)
 8013   FORMAT('CONTACT YOUR SITE INSTALLER.')
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
      IF(IBUGS2.EQ.'ON'.OR.ISUBRO.EQ.'PYFI')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF COPYFI--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9013)IERROR
 9013   FORMAT('IERROR = ',A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9022)FILE1(1:80)
 9022   FORMAT('FILE1 = ',A80)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9023)FILE2(1:80)
 9023   FORMAT('FILE2 = ',A80)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9024)N0,N1,N2,N012
 9024   FORMAT('N0,N1,N2,N012 = ',4I8)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9025)ISTRIN(1:80)
 9025   FORMAT('ISTRIN = ',A80)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE COPYFI
      SUBROUTINE VIEWFI(FILE1,ICASE2,IBUGS2,ISUBRO,IERROR)
!
!     PURPOSE--VIEW DPPL2F.DAT USING POSTSCRIPT VIEWER
!              (PSVIEW COMMAND)
!
!     LANGUAGE--ANSI FORTRAN (1977)
!     VERSION NUMBER--2011/9
!     ORIGINAL VERSION--SEPTEMBER 2011.
!     UPDATED         --OCTOBER   2015. USE "WINEXEC" FOR WINDOWS
!     UPDATED         --JUNE      2016. WINEXEC SEEMS TO HAVE AN
!                                       ISSUE, SO TURN THIS OPTION
!                                       OFF FOR NOW.
!     UPDATED         --JUNE      2016. IF SET POSTSCRIPT DEVICE
!                                       COMMAND ENTERED, OPTION
!                                       TO SET THE FILE TO THE
!                                       CONVERTED FILE INSTEAD
!     UPDATED         --MARCH     2019. SET SYSTEM PERSIST
!                                       SET SYSTEM HIDDEN
!     UPDATED         --DECEMBER  2019. ALLOW VIEWING PDF AND IMAGE
!                                       FILES AS WELL AS POSTSCRIPT
!                                       FILES.
!
!-----CHARACTER STATEMENTS FOR NON-COMMON VARIABLES-------------------
!
      INCLUDE 'DPCOPA.INC'
!
!CCCC CHARACTER*80 FILE1
      CHARACTER (LEN=*) :: FILE1
      CHARACTER*4 ICASE2
      CHARACTER*4 IBUGS2
      CHARACTER*4 ISUBRO
      CHARACTER*4 IERROR
      CHARACTER*1 IQUOTE
      CHARACTER*4 ISSAV1
      CHARACTER*4 ISSAV2
      CHARACTER*4 ICLESV
      CHARACTER*4 ICASE
!
!CCCC CHARACTER*255 ISTRIN
      CHARACTER (LEN=MAXSTR) :: ISTRIN
!
!-----COMMON VARIABLES (GENERAL)--------------------------------------
!
      INCLUDE 'DPCOHO.INC'
      INCLUDE 'DPCOST.INC'
      INCLUDE 'DPCONP.INC'
!
!     2016/06: SAVE CONVERTED FILE FROM DPDEP2
!
      CHARACTER (LEN=MAXFNC) :: FILE2
      COMMON/ICFILE/FILE2,NCFIL2
!
      INCLUDE 'DPCOP2.INC'
!
!-----START POINT-----------------------------------------------------
!
      IF(IBUGS2.EQ.'ON'.OR.ISUBRO.EQ.'EWFI')THEN
        WRITE(ICOUT,999)
  999   FORMAT(1X)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,51)
   51   FORMAT('***** AT THE BEGINNING OF VIEWFI--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,53)ICASE2,IBUGS2,ISUBRO,IERROR
   53   FORMAT('ICASE2,IBUGS2,ISUBRO,IERROR = ',3(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,54)FILE1(1:80)
   54   FORMAT('FILE1 = ',A80)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,56)IPSTVW(1:80)
   56   FORMAT('POSTSCRIPT VIEWER = ',A80)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,57)IPDFVW(1:80)
   57   FORMAT('PDF VIEWER = ',A80)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,58)IIMAVW(1:80)
   58   FORMAT('IMAGE VIEWER = ',A80)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,59)IBCKVW(1:80)
   59   FORMAT('BACKUP VIEWER = ',A80)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,61)IHOST1,IHMOD1,IOPSYS1,ICOMPI,ISITE
   61   FORMAT(' HOST,MODEL,OP-SYS,COMPILER,SITE = ',5(A4,2X),A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               ********************************
!               **  STEP 1--                  **
!               **  STEP THROUGH EACH HOST    **
!               ********************************
!
!     2016/06: IF SET POSTSCRIPT CONVERT IS SET, VIEW THE
!              CONVERTED FILE INSTEAD OF THE ORIGINAL
!              POSTSCRIPT FILE.
!
      IF(ICASE2.EQ.'FILE')THEN
        CALL STRLEZ(FILE1,MAXFNC,N1)
        FILE2(1:N1)=FILE1(1:N1)
      ELSEIF(ICASE2.EQ.'IPL1')THEN
!CCCC   CALL STRLEZ(FILE1,MAXFNC,N1)
!CCCC   FILE2(1:N1)=FILE1(1:N1)
        IF(IPSTDV.EQ.'NULL' .OR. NCFIL2.EQ.0)THEN
          CALL STRLEZ(FILE1,MAXFNC,N1)
          FILE2(1:N1)=FILE1(1:N1)
        ELSE
          N1=NCFIL2
        ENDIF
      ELSEIF(ICASE2.EQ.'IPL2')THEN
        IF(IPSTDV.EQ.'NULL' .OR. NCFIL2.EQ.0)THEN
          CALL STRLEZ(FILE1,MAXFNC,N1)
          FILE2(1:N1)=FILE1(1:N1)
        ELSE
          N1=NCFIL2
        ENDIF
      ENDIF
!
      IF(IBUGS2.EQ.'ON'.OR.ISUBRO.EQ.'EWFI')THEN
        WRITE(ICOUT,94)N1,FILE2
   94   FORMAT('N1,FILE2 = ',I5,2X,A80)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!     NOTE 2019/12: CHECK FOR VARIOUS FILE EXTENSIONS:
!
!                   .DAT   - USE POSTSCRIPT VIEWER
!                            (THESE ARE TYPICALLY DPPL1F.DAT OR
!                            DPPL2F.DAT)
!                   .PS    - USE POSTSCRIPT VIEWER
!                   .PDF   - USE PDF VIEWER
!                   .GIF   - USE IMAGE VIEWER
!                   .JPG   - USE IMAGE VIEWER
!                   .TIF   - USE IMAGE VIEWER
!                   .PNG   - USE IMAGE VIEWER
!
!                   IF AN UNKNOWN EXTENSION GIVEN, THEN USE IMAGE
!                   VIEWER.
!
      ICASE='UNKN'
      IF(N1.GE.4)THEN
        DO 110 II=N1-2,1,-1
          IF(FILE2(II:II).EQ.'.')THEN
            IF(FILE2(II+1:II+3).EQ.'DAT' .OR.   &
               FILE2(II+1:II+3).EQ.'dat')THEN
              ICASE='DAT'
            ELSEIF(FILE2(II+1:II+2).EQ.'PS' .OR.   &
                   FILE2(II+1:II+2).EQ.'ps')THEN
              ICASE='POST'
            ELSEIF(FILE2(II+1:II+3).EQ.'EPS' .OR.   &
                   FILE2(II+1:II+3).EQ.'eps')THEN
              ICASE='POST'
            ELSEIF(FILE2(II+1:II+3).EQ.'PDF' .OR.   &
                   FILE2(II+1:II+3).EQ.'pdf')THEN
              ICASE='PDF'
            ELSEIF(FILE2(II+1:II+3).EQ.'PNG' .OR.   &
                   FILE2(II+1:II+3).EQ.'png')THEN
              ICASE='IMAG'
            ELSEIF(FILE2(II+1:II+3).EQ.'JPG' .OR.   &
                   FILE2(II+1:II+3).EQ.'jpg')THEN
              ICASE='IMAG'
            ELSEIF(FILE2(II+1:II+3).EQ.'JPEG' .OR.   &
                   FILE2(II+1:II+3).EQ.'jpeg')THEN
              ICASE='IMAG'
            ELSEIF(FILE2(II+1:II+3).EQ.'GIF' .OR.   &
                   FILE2(II+1:II+3).EQ.'gif')THEN
              ICASE='IMAG'
            ELSEIF(FILE2(II+1:II+3).EQ.'TIF' .OR.   &
                   FILE2(II+1:II+3).EQ.'tif')THEN
              ICASE='IMAG'
            ELSEIF(FILE2(II+1:II+3).EQ.'BMP' .OR.   &
                 FILE2(II+1:II+3).EQ.'bmp')THEN
              ICASE='IMAG'
            ELSEIF(FILE2(II+1:II+3).EQ.'SVG' .OR.   &
                   FILE2(II+1:II+3).EQ.'svg')THEN
              ICASE='IMAG'
            ENDIF
            GO TO 119
          ENDIF
  110   CONTINUE
  119   CONTINUE
      ENDIF
!
      IF(IBUGS2.EQ.'ON'.OR.ISUBRO.EQ.'EWFI')THEN
        WRITE(ICOUT,116)ICASE
  116   FORMAT('ICASE = ',A4)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      N0=0
      IFLAG=0
      IFLAG9=0
      DO 120 II=1,N1
        IF(FILE2(II:II).EQ.' ')THEN
          IF(FILE2(1:1).NE.'"' .OR. FILE2(N1:N1).NE.'"')THEN
            IFLAG=1
          ENDIF
          GO TO 129
        ENDIF
  120 CONTINUE
  129 CONTINUE
!
      ISTRIN=' '
      IF(IOPSY1.EQ.'UNIX' .AND.   &
        (ICASE.EQ.'POST' .OR. ICASE.EQ.'DAT') .AND.   &
         NCPSVW.LE.0)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,3001)
 3001   FORMAT('***** ERROR IN VIEW PLOT--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,3003)
 3003   FORMAT('      NO POSTSCRIPT VIEWER DEFINED.')
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ELSEIF(IOPSY1.EQ.'UNIX' .AND. ICASE.EQ.'PDF' .AND.   &
         NCPDVW.LE.0)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,3001)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,3005)
 3005   FORMAT('      NO PDF VIEWER DEFINED.')
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ELSEIF(IOPSY1.EQ.'UNIX' .AND.   &
            (ICASE.EQ.'IMAG' .OR. ICASE.EQ.'UNKN') .AND.   &
         NCIMVW.LE.0)THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,3001)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,3007)
 3007   FORMAT('      NO IMAGE VIEWER DEFINED.')
        CALL DPWRST('XXX','BUG ')
        IERROR='YES'
        GO TO 9000
      ELSE
        IQUOTE='"'
!
        IFLAG2=0
        DO 3110 II=1,NCPSVW
          IF(IPSTVW(II:II).EQ.' ')THEN
            IFLAG2=1
            GO TO 3119
          ENDIF
 3110   CONTINUE
 3119   CONTINUE
!
        IFLAG3=0
        DO 3120 II=1,NCPDVW
          IF(IPDFVW(II:II).EQ.' ')THEN
            IFLAG3=1
            GO TO 3129
          ENDIF
 3120   CONTINUE
 3129   CONTINUE
!
        IFLAG4=0
        DO 3130 II=1,NCIMVW
          IF(IIMAVW(II:II).EQ.' ')THEN
            IFLAG4=1
            GO TO 3139
          ENDIF
 3130   CONTINUE
 3139   CONTINUE
!
        IFLAG5=0
        DO 3140 II=1,NCBKVW
          IF(IBCKVW(II:II).EQ.' ')THEN
            IFLAG5=1
            GO TO 3149
          ENDIF
 3140   CONTINUE
 3149   CONTINUE
!
        IF(ICASE.EQ.'POST')THEN
          N0=NCPSVW
          IF(IFLAG2.EQ.1)THEN
            ISTRIN(1:1)=IQUOTE
            N0=1
            IFLAG9=1
          ELSE
            N0=0
          ENDIF
          ISTRIN(N0+1:N0+NCPSVW)=IPSTVW(1:NCPSVW)
          N0=N0+NCPSVW
          IF(IFLAG2.EQ.1)THEN
            ISTRIN(N0+1:N0+1)=IQUOTE
            N0=N0+1
          ENDIF
        ELSEIF(ICASE.EQ.'DAT')THEN
          IF((IOPSY2.EQ.'MAC ' .AND. IPSTVW(1:4).EQ.'open') .OR.   &
             (IOPSY1.EQ.'UNIX' .AND. IPSTVW(1:8).EQ.'xdg-open'))THEN
            N0=NCBKVW
            IF(IFLAG5.EQ.1)THEN
              ISTRIN(1:1)=IQUOTE
              N0=1
              IFLAG9=1
            ELSE
              N0=0
            ENDIF
            ISTRIN(N0+1:N0+NCBKVW)=IBCKVW(1:NCBKVW)
            N0=N0+NCBKVW
            IF(IFLAG5.EQ.1)THEN
              ISTRIN(N0+1:N0+1)=IQUOTE
              N0=N0+1
            ENDIF
          ELSE
            N0=NCPSVW
            IF(IFLAG2.EQ.1)THEN
              ISTRIN(1:1)=IQUOTE
              N0=1
              IFLAG9=1
            ELSE
              N0=0
            ENDIF
            ISTRIN(N0+1:N0+NCPSVW)=IPSTVW(1:NCPSVW)
            N0=N0+NCPSVW
            IF(IFLAG2.EQ.1)THEN
              ISTRIN(N0+1:N0+1)=IQUOTE
              N0=N0+1
            ENDIF
          ENDIF
        ELSEIF(ICASE.EQ.'PDF')THEN
          N0=NCPDVW
          IF(IFLAG3.EQ.1)THEN
            ISTRIN(1:1)=IQUOTE
            N0=1
            IFLAG9=1
          ELSE
            N0=0
          ENDIF
          ISTRIN(N0+1:N0+NCPDVW)=IPDFVW(1:NCPDVW)
          N0=N0+NCPDVW
          IF(IFLAG3.EQ.1)THEN
            ISTRIN(N0+1:N0+1)=IQUOTE
            N0=N0+1
          ENDIF
        ELSEIF(ICASE.EQ.'IMAG' .OR. ICASE.EQ.'UNKN')THEN
          N0=NCIMVW
          IF(IFLAG4.EQ.1)THEN
            ISTRIN(1:1)=IQUOTE
            N0=1
            IFLAG9=1
          ELSE
            N0=0
          ENDIF
          ISTRIN(N0+1:N0+NCIMVW)=IIMAVW(1:NCIMVW)
          N0=N0+NCIMVW
          IF(IFLAG4.EQ.1)THEN
            ISTRIN(N0+1:N0+1)=IQUOTE
            N0=N0+1
          ENDIF
        ENDIF
      ENDIF
      N0=N0+1
      ISTRIN(N0:N0)=' '
!
!     2019/03: IF FILE CONTAINS A SPACE, THEN MAKE SURE FILE NAME IS
!              QUOTED.
!
      IF(IFLAG.EQ.1)THEN
        N0=N0+1
        ISTRIN(N0:N0)='"'
        ISTRIN(N0+1:N0+N1)=FILE2(1:N1)
        N0=N0+N1
        N0=N0+1
        ISTRIN(N0:N0)='"'
      ELSE
        ISTRIN(N0+1:N0+N1)=FILE2(1:N1)
        N0=N0+N1
      ENDIF
!CCCC N0=N0+1
!CCCC ISTRIN(N0:N0)=' '
!
      IF(IBUGS2.EQ.'ON'.OR.ISUBRO.EQ.'EWFI')THEN
        WRITE(ICOUT,3090)N0,ISTRIN(1:MIN(255,n0))
 3090   FORMAT('N0,ISTRIN = ',I5,2X,255A1)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      IF(IOPSY1.EQ.'PC-D')THEN
!
!               ********************************
!               **  STEP 2A--                 **
!               **  PC WINDOWS                **
!               ********************************
!
        ISSAV1=ISYSPE
        ISSAV2=ISYSHI
        ICLESV=ICLEWT
        ISYSPE='OFF'
        ICLEWT='OFF'
        ISYSHI='ON'
        IF(IFLAG.EQ.1 .OR. IFLAG9.EQ.1)THEN
!CCCC     ISYSHI='OFF'
        ENDIF
        CALL DPSYS2(ISTRIN,N0,ISUBRO,IERROR)
        ISYSPE=ISSAV1
        ISYSHI=ISSAV2
        ICLEWT=ICLESV
      ELSEIF(IOPSY1.EQ.'UNIX')THEN
!
!               ********************************
!               **  STEP 2C--                 **
!               **  UNIX OPERATING SYSTEM     **
!               ********************************
!
        CALL DPSYS2(ISTRIN,N0,ISUBRO,IERROR)
      ELSE
!
!               ********************************
!               **  STEP 2E--                 **
!               **  UNSUPPORTED SYSTEMS.      **
!               ********************************
!
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,8011)
 8011   FORMAT('THE VIEW PLOT CAPABILITY IS NOT SUPPORTED')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,8012)IHOST1
 8012   FORMAT('ON HOST ',A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,8013)
 8013   FORMAT('CONTACT YOUR SITE INSTALLER.')
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
!               *****************
!               **  STEP 90--  **
!               **  EXIT       **
!               *****************
!
 9000 CONTINUE
      IF(IBUGS2.EQ.'ON'.OR.ISUBRO.EQ.'EWFI')THEN
        WRITE(ICOUT,999)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9011)
 9011   FORMAT('***** AT THE END       OF VIEWFI--')
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9013)N0,N1,IERROR
 9013   FORMAT('N0,N1,IERROR = ',2I8,2X,A4)
        CALL DPWRST('XXX','BUG ')
        WRITE(ICOUT,9015)ISTRIN(1:MIN(255,N0))
 9015   FORMAT('ISTRIN(1:N0) = ',255A1)
        CALL DPWRST('XXX','BUG ')
      ENDIF
!
      RETURN
      END SUBROUTINE VIEWFI
